// ═══════════════════════════════════════════════════════════════
// REACT-STYLE EXAMPLE: Closure in useEffect
// ═══════════════════════════════════════════════════════════════

function simulateReactComponent() {
    let count= 0;

    function useState(initial) {
        let state= initial;
        const setState = (newValue)=> {
            state= newValue;
            // In React, this would trigger re-render
            console.log('State updated to:', state);
        };
