function outer() {
    var y = 2;

    function inner() {
        var z = 3;
        console.log(x);  // ✅ 1 (from global)
        console.log(y);  // ✅ 2 (from outer)
        console.log(z);  // ✅ 3 (from inner itself)
    }

    inner();
    console.log(x);      // ✅ 1
    console.log(y);      // ✅ 2
    console.log(z);      // ❌ ReferenceError
}

outer();
