🧠 7.3 — Promise Chaining
JavaScript
function step1() {
    return new Promise(function(resolve) {
        setTimeout(function() {
            console.log("Step 1 complete");
            resolve(10);
        }, 1000);
    });
}

function step2(value) {
    return new Promise(function(resolve) {
        setTimeout(function() {
            console.log("Step 2 received:", value);
            resolve(value * 2);
        }, 1000);
    });
