    });
text
┌──────────────────────────────────────────────────────────────┐
│  Promise.all([p1, p2, p3])                                   │
│                                                              │
│  - Waits for ALL promises to resolve                         │
│  - Returns array of results in SAME ORDER as input           │
│  - If ANY promise rejects → immediately rejects              │
│  - Use case: Parallel independent operations                 │
└──────────────────────────────────────────────────────────────┘
Promise.allSettled() — Wait for all, regardless of outcome
JavaScript
var p1 = Promise.resolve("Success");
var p2 = Promise.reject("Failed");
var p3 = Promise.resolve("Also Success");

Promise.allSettled([p1, p2, p3])
    .then(function(results) {
        console.log(results);
    });
text
Output:
[
    { status: "fulfilled", value: "Success" },
    { status: "rejected", reason: "Failed" },
    { status: "fulfilled", value: "Also Success" }
]

Unlike Promise.all, it NEVER rejects.
It waits for ALL to settle and reports each result.
Promise.race() — First to settle wins
JavaScript
var slow = new Promise(function(resolve) {
    setTimeout(function() { resolve("Slow"); }, 3000);
});

var fast = new Promise(function(resolve) {
    setTimeout(function() { resolve("Fast"); }, 1000);
});

Promise.race([slow, fast])
    .then(function(winner) {
        console.log("Winner:", winner);  // "Winner: Fast"
    });
Promise.any() — First to SUCCEED wins
JavaScript
var p1 = Promise.reject("Error 1");
var p2 = new Promise(function(resolve) {
    setTimeout(function() { resolve("Success 2"); }, 1000);
});
var p3 = Promise.reject("Error 3");

Promise.any([p1, p2, p3])
    .then(function(value) {
        console.log(value);  // "Success 2"
    })
    .catch(function(err) {
        // Only if ALL reject → AggregateError
        console.log("All failed:", err);
    });

