console.log(name);  // "Rahul"
console.log(age);   // 25
console.log(city);  // "Mumbai"

// Renaming variables
var { name: personName, age: personAge } = person;
console.log(personName);  // "Rahul"
console.log(personAge);   // 25

// Default values
var { name, country = "India" } = person;
console.log(country);  // "India" (default)

