var result = count || 10;
console.log(result);  // 10 (BUG! 0 is a valid value)

// Nullish coalescing only checks null/undefined:
var count = 0;
var result = count ?? 10;
console.log(result);  // 0 (correct!)

// More examples:
console.log(null ?? "default");       // "default"
console.log(undefined ?? "default");  // "default"
console.log(0 ?? "default");          // 0
console.log("" ?? "default");         // ""
console.log(false ?? "default");      // false

// Compare with ||:
console.log(0 || "default");          // "default" (0 is falsy)
console.log("" || "default");         // "default" ("" is falsy)
console.log(false || "default");      // "default" (false is falsy)
