🧠 9.2 — Try/Catch/Finally
JavaScript
try {
    // Code that might throw an error
    var result = riskyOperation();
    console.log("Success:", result);

} catch (error) {
    // Handle the error
    console.error("Error name:", error.name);
    console.error("Error message:", error.message);
    console.error("Stack trace:", error.stack);

} finally {
    // ALWAYS runs, regardless of success or failure
    console.log("Cleanup complete");
}
text
┌──────────────────────────────────────────────────────────────┐
│  TRY/CATCH/FINALLY RULES                                     │
│                                                              │
│  1. try block is REQUIRED                                    │
│  2. catch OR finally (or both) is REQUIRED                   │
│  3. finally ALWAYS runs (even if catch throws)               │
│  4. If try has return, finally still runs BEFORE return       │
│  5. catch only catches RUNTIME errors, not syntax errors     │
└──────────────────────────────────────────────────────────────┘
Return with Finally:
JavaScript
function test() {
    try {
        return "from try";
    } finally {
        console.log("finally runs!");
        // If you return here, it OVERRIDES try's return
    }
}

console.log(test());
text
Output:
finally runs!
from try

But if finally has its own return:
function test() {
    try {
        return "from try";
    } finally {
        return "from finally";  // This OVERRIDES!
    }
}
console.log(test());  // "from finally"

🧠 9.3 — Custom Error Classes
JavaScript
class ValidationError extends Error {
    constructor(field, message) {
        super(message);
        this.name = "ValidationError";
        this.field = field;
    }
}

class NotFoundError extends Error {
    constructor(resource, id) {
        super(resource + " with ID " + id + " not found");
        this.name = "NotFoundError";
        this.resource = resource;
        this.resourceId = id;
    }
}

class AuthError extends Error {
    constructor(message) {
        super(message || "Authentication required");
        this.name = "AuthError";
        this.statusCode = 401;
    }
}

// Usage:
function validateUser(user) {
    if (!user.name) {
        throw new ValidationError("name", "Name is required");
    }
    if (!user.email) {
        throw new ValidationError("email", "Email is required");
    }
    if (user.age < 0 || user.age > 150) {
        throw new ValidationError("age", "Invalid age");
    }
}

try {
    validateUser({ name: "", email: "test@test.com", age: 25 });
} catch (error) {
    if (error instanceof ValidationError) {
        console.log("Validation failed on field:", error.field);
        console.log("Message:", error.message);
    } else if (error instanceof NotFoundError) {
        console.log("Resource not found:", error.resource);
    } else {
        console.log("Unknown error:", error.message);
        throw error;  // Re-throw if we can't handle it
    }
}

🧠 9.4 — Async Error Handling
JavaScript
// ❌ WRONG — catch won't work for async errors
try {
    setTimeout(function() {
        throw new Error("Async error!");
    }, 1000);
} catch (error) {
    // This will NEVER catch the error!
    console.log("Caught:", error);
}
// The error goes UNHANDLED and crashes

// ✅ CORRECT — Handle async errors inside the callback
setTimeout(function() {
    try {
        throw new Error("Async error!");
    } catch (error) {
        console.log("Caught:", error.message);
    }
}, 1000);

// ✅ CORRECT — With Promises
async function fetchData() {
    try {
        var response = await fetch("/api/data");
        if (!response.ok) {
            throw new Error("HTTP " + response.status);
        }
        return await response.json();
    } catch (error) {
        console.error("Fetch failed:", error.message);
        return null;  // Return fallback value
    }
}

// ✅ Global error handlers:
// Browser:
window.addEventListener("error", function(event) {
    console.error("Global error:", event.error);
});

window.addEventListener("unhandledrejection", function(event) {
    console.error("Unhandled promise rejection:", event.reason);
});

// Node.js:
process.on("uncaughtException", function(error) {
    console.error("Uncaught:", error);
    process.exit(1);
});

process.on("unhandledRejection", function(reason) {
    console.error("Unhandled rejection:", reason);
});

```

**🧠 9.5 — Error Handling Best Practices**

```
┌──────────────────────────────────────────────────────────────┐
│  ERROR HANDLING BEST PRACTICES                               │
│                                                              │
│  1. Be SPECIFIC — catch specific error types                 │
│  2. Don't SWALLOW errors — always log or re-throw            │
│  3. Use CUSTOM error classes for business logic              │
│  4. Add CONTEXT to errors (which operation failed)           │
│  5. Use GLOBAL handlers as safety net, not primary strategy  │
│  6. FAIL FAST — detect errors early                          │
│  7. Return MEANINGFUL fallback values when appropriate       │
│  8. NEVER use try/catch for flow control                     │
│  9. Always handle Promise rejections                         │
│  10. Log errors with STACK TRACES for debugging              │
└──────────────────────────────────────────────────────────────┘
Centralized Error Handler Pattern:
JavaScript
class AppError extends Error {
    constructor(message, statusCode, isOperational) {
        super(message);
        this.name = "AppError";
        this.statusCode = statusCode || 500;
        this.isOperational = isOperational !== undefined ? isOperational : true;
    }
}

function handleError(error) {
    // Log all errors
    console.error({
        name: error.name,
        message: error.message,
        stack: error.stack,
        timestamp: new Date().toISOString()
    });

    if (error instanceof AppError && error.isOperational) {
        // Known operational error — handle gracefully
        return {
            success: false,
            message: error.message,
            code: error.statusCode
        };
    }

    // Unknown/programming error — alert and possibly restart
    console.error("CRITICAL: Unexpected error!");
    // In production: send to error tracking service (Sentry, etc.)
    return {
        success: false,
        message: "Internal server error",
        code: 500
    };
}

// Usage:
try {
    throw new AppError("User not found", 404);
} catch (error) {
    var response = handleError(error);
    console.log(response);
    // { success: false, message: "User not found", code: 404 }
}

```

