# **📘 MODULE 10: Memory Management & Garbage Collection**

---

## **🧠 10.1 — How Memory Works in JavaScript**

```
┌──────────────────────────────────────────────────────────────┐
│  JAVASCRIPT MEMORY MODEL                                     │
│                                                              │
│  ┌─────────────────────────────────────────────────────┐     │
│  │                    STACK                             │     │
│  │  (Primitive values & references)                    │     │
│  │                                                     │     │
│  │  var x = 10;        → 10 stored directly            │     │
│  │  var s = "hello";   → "hello" stored directly       │     │
│  │  var obj = {...};   → REFERENCE stored (pointer)    │     │
│  │                                                     │     │
│  │  Fast access, limited size, auto-managed             │     │
│  └─────────────────────────────────────────────────────┘     │
│                                                              │
│  ┌─────────────────────────────────────────────────────┐     │
│  │                    HEAP                              │     │
│  │  (Objects, arrays, functions)                       │     │
│  │                                                     │     │
│  │  { name: "Rahul", age: 25 }  ← obj points here     │     │
│  │  [1, 2, 3, 4, 5]            ← array data here      │     │
│  │  function() { ... }          ← function body here   │     │
│  │                                                     │     │
│  │  Large, dynamic, garbage collected                   │     │
│  └─────────────────────────────────────────────────────┘     │
└──────────────────────────────────────────────────────────────┘

🧠 10.2 — Garbage Collection: Mark-and-Sweep
text
┌──────────────────────────────────────────────────────────────┐
│  MARK-AND-SWEEP ALGORITHM                                    │
│                                                              │
│  Phase 1: MARK                                               │
│  - Start from "roots" (global object, current call stack)    │
│  - Follow ALL references from roots                          │
│  - Mark every reachable object as "alive"                    │
│                                                              │
│  Phase 2: SWEEP                                              │
│  - Scan entire heap                                          │
│  - Any object NOT marked → garbage → FREE memory            │
│                                                              │
│  KEY CONCEPT:                                                │
│  An object is garbage when NO reference chain exists          │
│  from any root to that object.                               │
└──────────────────────────────────────────────────────────────┘
JavaScript
// Object becomes garbage:
var obj = { name: "Rahul" };
obj = null;  // No more reference → eligible for GC

// Circular reference (handled by mark-and-sweep):
function circular() {
    var a = {};
    var b = {};
    a.ref = b;
    b.ref = a;
    // Both a and b reference each other
    // But after function ends, no root references either
    // Mark-and-sweep correctly identifies both as garbage
}
circular();
// a and b are garbage collected despite circular references

🧠 10.3 — Common Memory Leaks
Leak 1: Accidental Global Variables
JavaScript
// ❌ LEAK
function process() {
    leakedVar = "I'm accidentally global!";  // No var/let/const
    this.anotherLeak = "Also global in non-strict mode";
}
process();
// leakedVar stays in memory FOREVER

// ✅ FIX: Use strict mode
"use strict";
function process() {
    leakedVar = "value";  // ReferenceError in strict mode!
}
Leak 2: Forgotten Timers
JavaScript
// ❌ LEAK
var data = loadHugeData();
setInterval(function() {
    processData(data);  // data can never be garbage collected
}, 1000);

// ✅ FIX: Clear interval when done
var intervalId = setInterval(function() {
    processData(data);
}, 1000);

// When no longer needed:
clearInterval(intervalId);
data = null;
Leak 3: Detached DOM Elements
JavaScript
// ❌ LEAK
var elements = [];
function addElement() {
    var el = document.createElement("div");
    document.body.appendChild(el);
    elements.push(el);  // Reference kept in array
}

function removeElement() {
    var el = elements.pop();
    document.body.removeChild(el);
    // el is removed from DOM but still referenced in array!
    // It stays in memory
}

// ✅ FIX: Remove all references
function removeElement() {
    var el = elements.pop();
    if (el && el.parentNode) {
        document.body.removeChild(el);
    }
    // el reference goes out of scope → garbage collected
}
Leak 4: Closures Capturing Large Data
JavaScript
// ❌ LEAK
function createHandler() {
    var hugeData = new Array(1000000).fill("x");

    return function() {
        // Only needs hugeData.length but closes over entire array
        console.log(hugeData.length);
    };
}

var handler = createHandler();
// hugeData (millions of items) stays in memory

// ✅ FIX
function createHandler() {
    var hugeData = new Array(1000000).fill("x");
    var length = hugeData.length;  // Extract what we need

    return function() {
        console.log(length);  // Only closes over a number
    };
    // hugeData can be garbage collected
}

🧠 10.4 — WeakMap and WeakSet
JavaScript
// Regular Map — holds strong references
var map = new Map();
var obj = { name: "Rahul" };
map.set(obj, "some data");
obj = null;
// Object is STILL in memory because map holds a reference!
console.log(map.size);  // 1

// WeakMap — holds weak references
var weakMap = new WeakMap();
var obj2 = { name: "Priya" };
weakMap.set(obj2, "some data");
obj2 = null;
// Object CAN be garbage collected!
// WeakMap doesn't prevent GC
text
┌──────────────────────────────────────────────────────────────┐
│  WeakMap / WeakSet                                           │
│                                                              │
│  - Keys must be OBJECTS (not primitives)                     │
│  - Keys are held WEAKLY (don't prevent garbage collection)  │
│  - NOT iterable (no forEach, no size property)              │
│  - Perfect for: metadata, caching, private data             │
│                                                              │
│  Use Case: Storing data about DOM elements                   │
│  var elementData = new WeakMap();                            │
│  elementData.set(domElement, { clicks: 0 });                │
│  // When element is removed from DOM, data is auto-cleaned  │
└──────────────────────────────────────────────────────────────┘
Practical WeakMap Example — Private Data:
JavaScript
var privateData = new WeakMap();

class User {
    constructor(name, password) {
        this.name = name;
        privateData.set(this, { password: password });
    }

    checkPassword(input) {
        return privateData.get(this).password === input;
    }
}

var user = new User("Rahul", "secret123");
console.log(user.name);                    // "Rahul"
console.log(user.password);                // undefined (truly private!)
console.log(user.checkPassword("wrong"));  // false
console.log(user.checkPassword("secret123")); // true

user = null;
// Both the user object AND the private data are garbage collected

