🧠 11.2 — Immutability
JavaScript
// ❌ MUTATION — modifying original data
var users = [
    { name: "Rahul", age: 25 },
    { name: "Priya", age: 22 }
];

users.push({ name: "Amit", age: 28 });  // Mutates original!
users[0].age = 26;  // Mutates original!

// ✅ IMMUTABLE — creating new data
var users = [
    { name: "Rahul", age: 25 },
    { name: "Priya", age: 22 }
];

// Add user (new array)
