reduce — Accumulate to a single value:
JavaScript
var numbers = [1, 2, 3, 4, 5];

// Sum
var sum = numbers.reduce(function(accumulator, current) {
    return accumulator + current;
}, 0);
console.log(sum);  // 15

// Max value
var max = numbers.reduce(function(max, current) {
    return current > max ? current : max;
}, -Infinity);
console.log(max);  // 5

// Group by property
var people = [
    { name: "Rahul", dept: "Engineering" },
    { name: "Priya", dept: "Design" },
    { name: "Amit", dept: "Engineering" },
    { name: "Sara", dept: "Design" },
    { name: "Vijay", dept: "Engineering" }
];

var grouped = people.reduce(function(groups, person) {
    var dept = person.dept;
    if (!groups[dept]) {
        groups[dept] = [];
    }
    groups[dept].push(person);
    return groups;
}, {});

console.log(grouped);
// {
//   Engineering: [{ name: "Rahul", ... }, { name: "Amit", ... }, { name: "Vijay", ... }],
//   Design: [{ name: "Priya", ... }, { name: "Sara", ... }]
// }

// Count occurrences
var fruits = ["apple", "banana", "apple", "orange", "banana", "apple"];

var counts = fruits.reduce(function(acc, fruit) {
    acc[fruit] = (acc[fruit] || 0) + 1;
    return acc;
}, {});

console.log(counts);  // { apple: 3, banana: 2, orange: 1 }

🧠 11.4 — Function Composition
JavaScript
function add10(x) { return x + 10; }
function multiply2(x) { return x * 2; }
function subtract5(x) { return x - 5; }

// Manual composition:
var result = subtract5(multiply2(add10(5)));
console.log(result);  // subtract5(multiply2(15)) = subtract5(30) = 25

// Compose function (right to left):
function compose() {
    var fns = Array.prototype.slice.call(arguments);
    return function(x) {
        return fns.reduceRight(function(acc, fn) {
            return fn(acc);
        }, x);
    };
}

var transform = compose(subtract5, multiply2, add10);
console.log(transform(5));   // 25
console.log(transform(10));  // 35

// Pipe function (left to right — more intuitive):
function pipe() {
    var fns = Array.prototype.slice.call(arguments);
    return function(x) {
        return fns.reduce(function(acc, fn) {
            return fn(acc);
        }, x);
    };
}

var transform = pipe(add10, multiply2, subtract5);
console.log(transform(5));   // 25 (same result, reads left to right)

🧠 11.5 — Currying
JavaScript
// Regular function:
function add(a, b, c) {
    return a + b + c;
}
console.log(add(1, 2, 3));  // 6

// Curried version:
function curriedAdd(a) {
    return function(b) {
        return function(c) {
            return a + b + c;
        };
    };
}

console.log(curriedAdd(1)(2)(3));  // 6

// Partial application:
var addOne = curriedAdd(1);
var addOneAndTwo = addOne(2);
console.log(addOneAndTwo(3));  // 6
console.log(addOneAndTwo(10)); // 13

// Generic curry function:
function curry(fn) {
    return function curried() {
        var args = Array.prototype.slice.call(arguments);
        if (args.length >= fn.length) {
            return fn.apply(null, args);
        }
        return function() {
            var nextArgs = Array.prototype.slice.call(arguments);
            return curried.apply(null, args.concat(nextArgs));
        };
    };
}

var curriedSum = curry(add);
console.log(curriedSum(1)(2)(3));     // 6
console.log(curriedSum(1, 2)(3));     // 6
console.log(curriedSum(1)(2, 3));     // 6
console.log(curriedSum(1, 2, 3));     // 6
text
┌──────────────────────────────────────────────────────────────┐
│  CURRYING                                                    │
│                                                              │
│  Transform a function with multiple arguments into a         │
│  sequence of functions each taking a single argument.        │
│                                                              │
│  f(a, b, c) → f(a)(b)(c)                                    │
│                                                              │
│  Benefits:                                                   │
│  - Create specialized functions via partial application      │
│  - Better function composition                               │
│  - Delay execution until all arguments are available         │
└──────────────────────────────────────────────────────────────┘
Practical Currying Example:
JavaScript
// Curried API request builder
function request(method) {
    return function(baseUrl) {
        return function(endpoint) {
            return function(data) {
                console.log(method + " " + baseUrl + endpoint);
                console.log("Data:", data);
                // return fetch(baseUrl + endpoint, { method, body: data });
            };
        };
    };
}

var post = request("POST");
var apiPost = post("https://api.example.com");
var createUser = apiPost("/users");
var createOrder = apiPost("/orders");

createUser({ name: "Rahul" });
// POST https://api.example.com/users
// Data: { name: "Rahul" }

createOrder({ item: "Book", qty: 2 });
// POST https://api.example.com/orders
// Data: { item: "Book", qty: 2 }

