## **🧠 A.1 — Array.prototype.map Polyfill**

### **Theory First**

```
text
┌──────────────────────────────────────────────────────────────┐
│  WHAT map() DOES                                             │
│                                                              │
│  1. Takes a callback function                                │
│  2. Calls it for EVERY element in the array                  │
│  3. Collects return values into a NEW array                  │
│  4. Does NOT modify the original array                       │
│  5. Returns array of SAME length                             │
│                                                              │
│  Callback receives: (element, index, originalArray)          │
└──────────────────────────────────────────────────────────────┘
```

### **Implementation**

```javascript
Array.prototype.myMap = function(callback,thisArg) {
    // Safety check
    if (typeof callback!== "function") {
        throw new TypeError(callback+ " is not a function");
    }

    var result= [];
    var arr= this;// The array on which myMap is called

    for (var i= 0; i< arr.length; i++) {
        // Check if index exists (handles sparse arrays)
        if (iin arr) {
            result[i]= callback.call(thisArg, arr[i], i, arr);
        }
    }

    return result;
};

// Test:
var numbers= [1,2,3,4,5];

var doubled= numbers.myMap(function(num) {
    return num* 2;
});

console.log(doubled);// [2, 4, 6, 8, 10]
console.log(numbers);// [1, 2, 3, 4, 5] (unchanged)

// Test with index and thisArg:
var result= numbers.myMap(function(num,index) {
    return this.prefix+ (num* index);
}, { prefix:"Value: " });

console.log(result);
// ["Value: 0", "Value: 2", "Value: 6", "Value: 12", "Value: 20"]

// Test with sparse array:
var sparse= [1, ,3, ,5];
var mapped= sparse.myMap(function(x) {return x* 2; });
console.log(mapped);// [2, empty, 6, empty, 10]
```

