## **🧠 A.3 — Array.prototype.reduce Polyfill**

```javascript
Array.prototype.myReduce = function(callback,initialValue) {
    if (typeof callback!== "function") {
        throw new TypeError(callback+ " is not a function");
    }

    var arr= this;
    var accumulator;
    var startIndex;

    // Determine starting accumulator and index
    if (arguments.length >= 2) {
        // initialValue provided
        accumulator= initialValue;
        startIndex= 0;
    }else {
        // No initialValue — use first element
        if (arr.length === 0) {
            throw new TypeError("Reduce of empty array with no initial value");
        }

        // Find first existing element (handle sparse arrays)
        var found= false;
        for (var j= 0; j< arr.length; j++) {
            if (jin arr) {
                accumulator= arr[j];
                startIndex= j+ 1;
                found= true;
                break;
            }
        }

        if (!found) {
            throw new TypeError("Reduce of empty array with no initial value");
        }
    }

    for (var i= startIndex; i< arr.length; i++) {
        if (iin arr) {
            accumulator= callback(accumulator, arr[i], i, arr);
        }
    }

    return accumulator;
};

// Test — Sum:
var sum= [1,2,3,4,5].myReduce(function(acc,curr) {
    return acc+ curr;
},0);
console.log(sum);// 15

// Test — Without initial value:
