    acc[fruit]= (acc[fruit]|| 0)+ 1;
    return acc;
}, {});
console.log(counts);// { apple: 3, banana: 2, orange: 1 }

// Test — Empty array error:
try {
    [].myReduce(function(a,b) {return a+ b; });
}catch (e) {
    console.log(e.message);// "Reduce of empty array with no initial value"
}
