## **🧠 A.8 — Array.prototype.flat Polyfill**

```javascript
Array.prototype.myFlat = function(depth) {
    // Default depth is 1
    if (depth=== undefined) {
        depth= 1;
    }

    var result= [];
    var arr= this;

    function flatten(array,currentDepth) {
        for (var i= 0; i< array.length; i++) {
            if (iin array) {
                if (Array.isArray(array[i])&& currentDepth< depth) {
                    flatten(array[i], currentDepth+ 1);
                }else {
                    result.push(array[i]);
                }
            }
        }
    }

    flatten(arr,0);
    return result;
};

// Test:
console.log([1, [2,3], [4, [5,6]]].myFlat());
// [1, 2, 3, 4, [5, 6]]  (depth 1)

console.log([1, [2,3], [4, [5,6]]].myFlat(2));
// [1, 2, 3, 4, 5, 6]  (depth 2)

console.log([1, [2, [3, [4, [5]]]]].myFlat(Infinity));
// [1, 2, 3, 4, 5]  (fully flattened)

// Non-recursive version:
Array.prototype.myFlatIterative = function(depth) {
    if (depth=== undefined) depth= 1;

    var stack= this.map(function(item) {return [item,0]; });
    var result= [];

    while (stack.length > 0) {
        var pair= stack.shift();
        var item= pair[0];
        var currentDepth= pair[1];

        if (Array.isArray(item)&& currentDepth< depth) {
            for (var i= 0; i< item.length; i++) {
                stack.unshift([item[item.length - 1 - i], currentDepth+ 1]);
            }
        }else {
            result.push(item);
        }
    }

    return result;
};
