Function.prototype.myCall = function(context) {
    // If context is null/undefined, use global object
    if (context=== null || context=== undefined) {
        context= typeof window!== "undefined" ? window: global;
    }

    // Convert primitives to objects
    context= Object(context);

    // Create a unique property name to avoid conflicts
    var uniqueKey= Symbol("fn");

    // Attach the function to the context temporarily
    context[uniqueKey]= this;

    // Get the remaining arguments
    var args= [];
    for (var i= 1; i< arguments.length; i++) {
        args.push(arguments[i]);
    }

    // Call the function with the context
    var result= context[uniqueKey].apply(context, args);

    // Clean up
    delete context[uniqueKey];

    return result;
};

