## **🧠 A.12 — Promise from Scratch**

```javascript
function MyPromise(executor) {
    var self= this;
    self.state= "pending";
    self.value= undefined;
    self.reason= undefined;
    self.onFulfilledCallbacks= [];
    self.onRejectedCallbacks= [];

    function resolve(value) {
        if (self.state=== "pending") {
            self.state= "fulfilled";
            self.value= value;
            self.onFulfilledCallbacks.forEach(function(fn) {
                fn(self.value);
            });
        }
    }

    function reject(reason) {
        if (self.state=== "pending") {
            self.state= "rejected";
            self.reason= reason;
            self.onRejectedCallbacks.forEach(function(fn) {
                fn(self.reason);
            });
        }
    }

    try {
        executor(resolve, reject);
    }catch (error) {
        reject(error);
    }
}

MyPromise.prototype.then = function(onFulfilled,onRejected) {
    var self= this;

    // Default handlers
    onFulfilled= typeof onFulfilled=== "function"
        ? onFulfilled
        : function(value) {return value; };
    onRejected= typeof onRejected=== "function"
        ? onRejected
        : function(reason) {throw reason; };

    var promise2= new MyPromise(function(resolve,reject) {
        function handleFulfilled(value) {
            // Use setTimeout to make it async (microtask simulation)
            setTimeout(function() {
                try {
                    var result= onFulfilled(value);
                    resolvePromise(promise2, result, resolve, reject);
                }catch (error) {
                    reject(error);
                }
            },0);
        }

        function handleRejected(reason) {
            setTimeout(function() {
                try {
                    var result= onRejected(reason);
                    resolvePromise(promise2, result, resolve, reject);
                }catch (error) {
                    reject(error);
                }
            },0);
        }

        if (self.state=== "fulfilled") {
            handleFulfilled(self.value);
        }else if (self.state=== "rejected") {
            handleRejected(self.reason);
        }else {
            // pending
            self.onFulfilledCallbacks.push(handleFulfilled);
            self.onRejectedCallbacks.push(handleRejected);
        }
    });

    return promise2;
};

function resolvePromise(promise2,result,resolve,reject) {
    if (promise2=== result) {
        return reject(new TypeError("Chaining cycle detected"));
    }

    if (resultinstanceof MyPromise) {
        result.then(resolve, reject);
    }else {
        resolve(result);
    }
}

MyPromise.prototype.catch = function(onRejected) {
    return this.then(null, onRejected);
};

MyPromise.prototype.finally = function(callback) {
    return this.then(
        function(value) {
            callback();
            return value;
        },
        function(reason) {
            callback();
            throw reason;
        }
    );
};

MyPromise.resolve = function(value) {
    return new MyPromise(function(resolve) {
        resolve(value);
    });
};

MyPromise.reject = function(reason) {
    return new MyPromise(function(resolve,reject) {
        reject(reason);
    });
};

// Test:
var p= new MyPromise(function(resolve,reject) {
    setTimeout(function() {
        resolve("Success!");
    },1000);
});

p.then(function(value) {
    console.log("1:", value);// "1: Success!"
    return "Next value";
}).then(function(value) {
    console.log("2:", value);// "2: Next value"
}).catch(function(err) {
    console.log("Error:", err);
});

// Test chaining:
MyPromise.resolve(1)
    .then(function(val) {return val+ 1; })
    .then(function(val) {return val* 3; })
    .then(function(val) {
        console.log("Final:", val);// "Final: 6"
    });
```

