## **🧠 A.17 — Debounce Implementation**

```
text
┌──────────────────────────────────────────────────────────────┐
│  DEBOUNCE                                                    │
│                                                              │
│  Delays function execution until AFTER a specified           │
│  time has passed since the LAST call.                        │
│                                                              │
│  Use case: Search input — wait until user stops typing       │
│                                                              │
│  Timeline:                                                   │
│  Call─Call─Call─Call───────────[Execute]                      │
│       ↑                  ↑                                   │
│       Each call          Wait period after                   │
│       resets timer       LAST call                           │
└──────────────────────────────────────────────────────────────┘
```

```javascript
function debounce(fn,delay,immediate) {
    var timer= null;

    return function() {
        var context= this;
        var args= arguments;

        var callNow= immediate&& !timer;

        clearTimeout(timer);

        timer= setTimeout(function() {
            timer= null;
            if (!immediate) {
                fn.apply(context, args);
            }
        }, delay);

        if (callNow) {
            fn.apply(context, args);
        }
    };
}

// Test — Search input:
var searchAPI= debounce(function(query) {
    console.log("Searching for:", query);
    // fetch('/api/search?q=' + query)
},300);

// Simulating rapid typing:
searchAPI("R");
searchAPI("Ra");
searchAPI("Rah");
searchAPI("Rahu");
searchAPI("Rahul");
// Only "Searching for: Rahul" prints (after 300ms)

// Advanced version with cancel and flush:
function advancedDebounce(fn,delay) {
    var timer= null;
    var lastArgs= null;
    var lastContext= null;

    function debounced() {
        lastArgs= arguments;
        lastContext= this;

        clearTimeout(timer);

        timer= setTimeout(function() {
            fn.apply(lastContext, lastArgs);
            timer= null;
            lastArgs= null;
            lastContext= null;
        }, delay);
    }

    debounced.cancel = function() {
        clearTimeout(timer);
        timer= null;
        lastArgs= null;
        lastContext= null;
    };

    debounced.flush = function() {
        if (timer) {
            clearTimeout(timer);
            fn.apply(lastContext, lastArgs);
            timer= null;
            lastArgs= null;
            lastContext= null;
        }
    };

    return debounced;
}
