## **🧠 A.18 — Throttle Implementation**

```
text
┌──────────────────────────────────────────────────────────────┐
│  THROTTLE                                                    │
│                                                              │
│  Ensures function is called at most ONCE per specified       │
│  time period, regardless of how many times it's triggered.   │
│                                                              │
│  Use case: Scroll event — execute max once per 200ms         │
│                                                              │
│  Timeline:                                                   │
│  [Execute]─skip─skip─[Execute]─skip─skip─[Execute]          │
│  ├────── interval ──────┤                                    │
└──────────────────────────────────────────────────────────────┘
```

```javascript
function throttle(fn,interval) {
    var lastTime= 0;
    var timer= null;

    return function() {
        var context= this;
        var args= arguments;
        var now= Date.now();

        var remaining= interval- (now- lastTime);

        if (remaining<= 0) {
            // Enough time has passed — execute immediately
            if (timer) {
                clearTimeout(timer);
                timer= null;
            }
            lastTime= now;
            fn.apply(context, args);
        }else if (!timer) {
            // Schedule trailing call
            timer= setTimeout(function() {
                lastTime= Date.now();
                timer= null;
                fn.apply(context, args);
            }, remaining);
        }
    };
}

// Simple throttle (leading only):
function simpleThrottle(fn,interval) {
    var lastTime= 0;

    return function() {
        var now= Date.now();
        if (now- lastTime>= interval) {
            lastTime= now;
            fn.apply(this,arguments);
        }
    };
}

// Test — Scroll handler:
var handleScroll= throttle(function() {
    console.log("Scroll position:", window.scrollY);
},200);

// window.addEventListener("scroll", handleScroll);
// Fires at most once every 200ms during scrolling
```

