## **🧠 A.19 — Deep Clone**

```javascript
function deepClone(obj) {
    // Handle null, undefined, primitives
    if (obj=== null || typeof obj!== "object") {
        return obj;
    }

    // Handle Date
    if (objinstanceof Date) {
        return new Date(obj.getTime());
    }

    // Handle RegExp
    if (objinstanceof RegExp) {
        return new RegExp(obj.source, obj.flags);
    }

    // Handle Array
    if (Array.isArray(obj)) {
        var arrCopy= [];
        for (var i= 0; i< obj.length; i++) {
            arrCopy[i]= deepClone(obj[i]);
        }
        return arrCopy;
    }

    // Handle Object
    var objCopy= {};
    var keys= Object.keys(obj);
    for (var j= 0; j< keys.length; j++) {
        objCopy[keys[j]]= deepClone(obj[keys[j]]);
    }

    return objCopy;
}

// Advanced version handling circular references:
function deepCloneAdvanced(obj,visited) {
    if (obj=== null || typeof obj!== "object")return obj;

    if (!visited) visited= new WeakMap();

    // Check for circular reference
    if (visited.has(obj)) {
        return visited.get(obj);
    }

    var clone;

    if (objinstanceof Date) {
        clone= new Date(obj.getTime());
    }else if (objinstanceof RegExp) {
        clone= new RegExp(obj.source, obj.flags);
    }else if (objinstanceof Map) {
        clone= new Map();
        visited.set(obj, clone);
        obj.forEach(function(value,key) {
            clone.set(deepCloneAdvanced(key, visited),deepCloneAdvanced(value, visited));
        });
        return clone;
    }else if (objinstanceof Set) {
        clone= new Set();
        visited.set(obj, clone);
        obj.forEach(function(value) {
            clone.add(deepCloneAdvanced(value, visited));
        });
        return clone;
    }else if (Array.isArray(obj)) {
        clone= [];
        visited.set(obj, clone);
        for (var i= 0; i< obj.length; i++) {
            clone[i]= deepCloneAdvanced(obj[i], visited);
        }
        return clone;
    }else {
        clone= Object.create(Object.getPrototypeOf(obj));
        visited.set(obj, clone);
        var keys= Object.keys(obj);
        for (var j= 0; j< keys.length; j++) {
            clone[keys[j]]= deepCloneAdvanced(obj[keys[j]], visited);
        }
        return clone;
    }

    return clone;
}

