function EventEmitter() {
    this.events= {};
}

EventEmitter.prototype.on = function(event,listener) {
    if (!this.events[event]) {
        this.events[event]= [];
    }
    this.events[event].push(listener);
    return this;// Allow chaining
};

EventEmitter.prototype.off = function(event,listener) {
    if (!this.events[event])return this;

    this.events[event]= this.events[event].filter(function(fn) {
        return fn!== listener&& fn._original!== listener;
    });

    return this;
};

EventEmitter.prototype.emit = function(event) {
    if (!this.events[event])return false;

    var args= Array.prototype.slice.call(arguments,1);
    var listeners= this.events[event].slice();// Copy to avoid mutation issues

    listeners.forEach(function(listener) {
        listener.apply(null, args);
    });

    return true;
};

EventEmitter.prototype.once = function(event,listener) {
    var self= this;

    function wrapper() {
        listener.apply(null,arguments);
        self.off(event, wrapper);
    }

    wrapper._original= listener;// For off() to find it
    this.on(event, wrapper);

    return this;
};

EventEmitter.prototype.removeAllListeners = function(event) {
    if (event) {
        delete this.events[event];
    }else {
        this.events= {};
    }
    return this;
};

EventEmitter.prototype.listenerCount = function(event) {
    return this.events[event]? this.events[event].length : 0;
};

