## **🧠 A.22 — LRU Cache Implementation**

```
text
┌──────────────────────────────────────────────────────────────┐
│  LRU CACHE (Least Recently Used)                             │
│                                                              │
│  Fixed-size cache that evicts the LEAST recently used         │
│  item when the cache is full.                                │
│                                                              │
│  Operations:                                                 │
│  get(key)        → O(1) — return value if exists             │
│  put(key, value) → O(1) — insert/update, evict if full       │
│                                                              │
│  Data Structure: HashMap + Doubly Linked List                │
│  HashMap for O(1) lookup                                     │
│  Linked list for O(1) ordering                               │
└──────────────────────────────────────────────────────────────┘
```

```javascript
function LRUCache(capacity) {
    this.capacity= capacity;
    this.cache= new Map();// Map maintains insertion order
}

LRUCache.prototype.get = function(key) {
    if (!this.cache.has(key)) {
        return -1;
    }

    // Move to end (most recently used)
    var value= this.cache.get(key);
    this.cache.delete(key);
    this.cache.set(key, value);

    return value;
};

LRUCache.prototype.put = function(key,value) {
    if (this.cache.has(key)) {
        // Remove old entry
        this.cache.delete(key);
    }else if (this.cache.size>= this.capacity) {
        // Remove least recently used (first entry in Map)
        var firstKey= this.cache.keys().next().value;
        this.cache.delete(firstKey);
    }

    this.cache.set(key, value);
};

// Test:
var cache= new LRUCache(3);

cache.put("a",1);
cache.put("b",2);
cache.put("c",3);
console.log(cache.get("a"));// 1 (a is now most recently used)

cache.put("d",4);// Cache full! Evicts "b" (least recently used)
console.log(cache.get("b"));// -1 (evicted!)
console.log(cache.get("c"));// 3
console.log(cache.get("d"));// 4

// Implementation without Map (using doubly linked list):
function LRUCacheLinkedList(capacity) {
    this.capacity= capacity;
    this.map= {};
    this.size= 0;

    // Dummy head and tail
    this.head= { key:null, value:null, prev:null, next:null };
    this.tail= { key:null, value:null, prev:null, next:null };
    this.head.next= this.tail;
    this.tail.prev= this.head;
}

LRUCacheLinkedList.prototype._addToFront = function(node) {
    node.next= this.head.next;
    node.prev= this.head;
    this.head.next.prev= node;
    this.head.next= node;
};

LRUCacheLinkedList.prototype._removeNode = function(node) {
    node.prev.next= node.next;
    node.next.prev= node.prev;
};

LRUCacheLinkedList.prototype._moveToFront = function(node) {
    this._removeNode(node);
    this._addToFront(node);
};

LRUCacheLinkedList.prototype.get = function(key) {
    if (!(keyin this.map))return -1;

    var node= this.map[key];
    this._moveToFront(node);
    return node.value;
};

LRUCacheLinkedList.prototype.put = function(key,value) {
    if (keyin this.map) {
        var node= this.map[key];
        node.value= value;
        this._moveToFront(node);
    }else {
        if (this.size>= this.capacity) {
            // Remove LRU (node before tail)
            var lru= this.tail.prev;
            this._removeNode(lru);
            delete this.map[lru.key];
            this.size--;
        }

        var newNode= { key: key, value: value, prev:null, next:null };
        this._addToFront(newNode);
        this.map[key]= newNode;
        this.size++;
    }
};
