// Advanced memoize with custom key and max size:
function advancedMemoize(fn,options) {
    options= options|| {};
    var maxSize= options.maxSize|| Infinity;
    var keyFn= options.keyFn|| function() {
        return JSON.stringify(Array.prototype.slice.call(arguments));
    };

    var cache= new Map();

    var memoized = function() {
        var key= keyFn.apply(null,arguments);

        if (cache.has(key)) {
            // Move to end (LRU behavior)
            var value= cache.get(key);
            cache.delete(key);
            cache.set(key, value);
            return value;
        }

        var result= fn.apply(this,arguments);

        if (cache.size>= maxSize) {
            // Remove oldest entry
            var firstKey= cache.keys().next().value;
            cache.delete(firstKey);
        }

        cache.set(key, result);
        return result;
    };

    memoized.clear = function() { cache.clear(); };
    memoized.size = function() {return cache.size; };

    return memoized;
}

