## **🧠 A.28 — classNames Utility (Like the npm package)**

```javascript
function classNames() {
    var classes= [];

    for (var i= 0; i< arguments.length; i++) {
        var arg= arguments[i];

        if (!arg)continue;

        var argType= typeof arg;

        if (argType=== "string" || argType=== "number") {
            classes.push(arg);
        }else if (Array.isArray(arg)) {
            var inner= classNames.apply(null, arg);
            if (inner) classes.push(inner);
        }else if (argType=== "object") {
            var keys= Object.keys(arg);
            for (var j= 0; j< keys.length; j++) {
                if (arg[keys[j]]) {
                    classes.push(keys[j]);
                }
            }
        }
    }

    return classes.join(" ");
}

// Test:
console.log(classNames("btn","btn-primary"));
// "btn btn-primary"

console.log(classNames("btn", {"btn-active":true,"btn-disabled":false }));
// "btn btn-active"

console.log(classNames("btn", ["extra", { special:true }]));
// "btn extra special"

console.log(classNames(null,undefined,false,"valid",0,""));
// "valid"
