// Deep partial type for overrides
type DeepPartial<T>= {
    [P in keyof T]?: T[P]extends object ? DeepPartial<T[P]>: T[P];
};

// Default config
const defaultConfig: AppConfig = {
    database: {
        host:"localhost",
        port:5432,
        username:"admin",
        password:"secret"
