});

//
// HARD 2: Type-safe event emitter
//

// Create a type-safe event emitter where events and their
// payload types are strictly enforced

// SOLUTION:
interface EventMap {
    userCreated: {id: number;name: string };
    userDeleted: {id: number };
    messageReceived: {from: string;content: string;timestamp: Date };
    error: Error;
}

class TypedEventEmitter<T extends Record<string,any>> {
    private listeners: {
        [K in keyof T]?: Array<(payload: T[K])=> void>;
    }= {};

    on<K extends keyof T>(
        event: K,
        callback: (payload: T[K])=> void
    ): ()=> void {
        if (!this.listeners[event]) {
            this.listeners[event]= [];
        }
        this.listeners[event]!.push(callback);

        // Return unsubscribe function
        return ()=> this.off(event, callback);
    }

    off<K extends keyof T>(
        event: K,
        callback: (payload: T[K])=> void
    ): void {
        const callbacks = this.listeners[event];
        if (callbacks) {
            const index = callbacks.indexOf(callback);
            if (index> -1) {
                callbacks.splice(index,1);
            }
        }
    }

    emit<K extends keyof T>(event: K,payload: T[K]): void {
        const callbacks = this.listeners[event];
        if (callbacks) {
            callbacks.forEach(callback => callback(payload));
        }
    }

    once<K extends keyof T>(
        event: K,
        callback: (payload: T[K])=> void
    ): ()=> void {
        const wrapper = (payload: T[K])=> {
            callback(payload);
            this.off(event, wrapper);
        };
        return this.on(event, wrapper);
    }
}

// Usage
const emitter = new TypedEventEmitter<EventMap>();

// ✅ Correctly typed
emitter.on("userCreated", (payload)=> {
    console.log(payload.id);// number
    console.log(payload.name);// string
});

// ✅ Type error if wrong payload
// emitter.emit("userCreated", { id: "1" }); // Error: id should be number

// ✅ Autocomplete works
emitter.emit("messageReceived", {
    from:"John",
    content:"Hello",
    timestamp:new Date()
});

