### 🎯 2.1 Type Annotations vs Inference

```

/*
TYPE ANNOTATIONS VS INFERENCE
ANNOTATION = You explicitly tell TypeScript the type
INFERENCE  = TypeScript figures out the type automatically
Rule: Let TypeScript infer when possible, annotate when
necessary or for clarity.
*/

//
// TYPE INFERENCE EXAMPLES
//

// Variable inference
let inferredString= "hello";// Type: string
let inferredNumber= 42;// Type: number
let inferredBoolean= true;// Type: boolean
let inferredArray= [1,2,3];// Type: number[]

// Const inference (more specific)
const constString = "hello";// Type: "hello" (literal)
const constNumber = 42;// Type: 42 (literal)

// Object inference
const person = {
    name:"John",// Type: string (not "John")
    age:30          // Type: number (not 30)
};
// Type: { name: string; age: number }

// Array inference
const mixed = [1,"two",true];// Type: (string | number | boolean)[]
const numbers = [1,2,3];// Type: number[]

// Function return inference
function add(a: number,b: number) {
    return a+ b;// Return type inferred as number
}

//
// WHEN TO USE EXPLICIT ANNOTATIONS
//

// 1. Function parameters (always)
function greet(name: string): void {
    console.log(`Hello, ${name}`);
}

// 2. When inference is too broad
const config: {readonly apiKey: string }= {
    apiKey:"secret123"
};

// 3. Delayed initialization
let userId: string;
// ... later
userId= "user_123";

// 4. Complex return types for documentation
interface ApiResponse<T> {
    data: T;
    status: number;
}

function fetchUser(id: number): Promise<ApiResponse<User>> {
    // Return type annotation helps readers
    return fetch(`/api/users/${id}`).then(r => r.json());
}

// 5. When type needs to be wider than inferred
let ids: (string | number)[]= [];
ids.push(1);
ids.push("two");

//
// CONTEXTUAL TYPING
//

// TypeScript infers types based on context

// Callback parameter types are inferred
const nums = [1,2,3];
nums.forEach(n => {
    // n is inferred as number
    console.log(n.toFixed(2));
});

// Event handler types are inferred
document.addEventListener("click",event => {
    // event is inferred as MouseEvent
    console.log(event.clientX, event.clientY);
});

// Array methods
const doubled = nums.map(n => n* 2);// Type: number[]
const filtered = nums.filter(n => n> 1);// Type: number[]

//
// BEST PRACTICES
//

// ✅ DO: Let inference work for variables
const name = "John";// No need for : string

// ✅ DO: Annotate function parameters
function process(data: string): void { }

// ✅ DO: Annotate when inference is wrong
const response: ApiResponse<User>= await fetchUser(1);

// ❌ DON'T: Over-annotate obvious types
const age: number = 30;// Redundant

// ❌ DON'T: Leave complex types to inference without review
const complicated = someComplexFunction();// Review the inferred type

