/*
UNION & INTERSECTION TYPES
UNION (|)        = Type can be A OR B
INTERSECTION (&) = Type must be A AND B
*/

//
// UNION TYPES (|)
//

// Basic union
type StringOrNumber = string | number;

let value: StringOrNumber = "hello";
value= 42;// ✅ OK

// Function with union parameter
function printId(id: string | number): void {
    console.log(`ID: ${id}`);
}

printId(101);// ✅ OK
printId("user_1");// ✅ OK

// Working with unions requires narrowing
function getLength(value: string | number): number {
    // value.length;  // ❌ Error: number doesn't have length

    if (typeof value=== "string") {
        return value.length;// ✅ OK - TypeScript knows it's string
    }
    return value.toString().length;
}

// Union of literal types (very useful!)
type Status = "pending" | "approved" | "rejected";
type HttpMethod = "GET" | "POST" | "PUT" | "DELETE";
type Direction = "north" | "south" | "east" | "west";

function move(direction: Direction): void {
    // Only valid directions allowed
}
move("north");// ✅
// move("up");  // ❌ Error

// Union of object types
interface Bird {
    type: "bird";
    flySpeed: number;
}

interface Fish {
    type: "fish";
    swimSpeed: number;
}

type Animal = Bird | Fish;

function getSpeed(animal: Animal): number {
    // Must narrow before accessing specific properties
    if (animal.type=== "bird") {
        return animal.flySpeed;
    }
    return animal.swimSpeed;
}

//
// INTERSECTION TYPES (&)
//

// Combining object types
interface Person {
    name: string;
    age: number;
}

interface Employee {
    employeeId: string;
    department: string;
}

type EmployeePerson = Person & Employee;

const employee: EmployeePerson = {
    name:"John",
    age:30,
    employeeId:"E123",
    department:"Engineering"
};

// Intersection with conflicting types
interface A {
    x: number;
    y: string;
}

interface B {
    x: string;// Different type for x!
}

type AB = A & B;
// AB.x is type: number & string = never (impossible!)

// Practical use: Mixins
interface Timestamps {
    createdAt: Date;
    updatedAt: Date;
}

interface SoftDelete {
    deletedAt: Date | null;
    isDeleted: boolean;
}

interface BaseEntity {
    id: string;
}

// Compose types
type User = BaseEntity & Timestamps & {
    email: string;
    name: string;
};

type DeletableUser = User & SoftDelete;

//
// COMBINING UNION AND INTERSECTION
//

// Common pattern: Base + Variants
interface BaseEvent {
    timestamp: Date;
    userId: string;
}

interface ClickEvent {
    type: "click";
    element: string;
    x: number;
    y: number;
}

interface KeyEvent {
    type: "key";
    key: string;
    modifiers: string[];
}

// Union of intersections
type AppEvent = BaseEvent & (ClickEvent | KeyEvent);

function handleEvent(event: AppEvent): void {
    console.log(event.timestamp, event.userId);// Always available

    if (event.type=== "click") {
        console.log(event.x, event.y);// ClickEvent properties
    }else {
        console.log(event.key);// KeyEvent properties
    }
}

//
// REAL-WORLD PATTERNS
//

// API Response pattern
interface SuccessResponse<T> {
    status: "success";
    data: T;
}

interface ErrorResponse {
    status: "error";
    error: {
        code: string;
        message: string;
    };
}

type ApiResponse<T>= SuccessResponse<T>| ErrorResponse;

async function fetchData<T>(url: string): Promise<ApiResponse<T>> {
    try {
        const response = await fetch(url);
        const data = await response.json();
        return { status:"success", data };
    }catch (e) {
        return {
            status:"error",
            error: { code:"FETCH_ERROR", message:String(e) }
        };
    }
}

// Usage with type narrowing
async function getUser(id: number): Promise<User | null> {
    const response = await fetchData<User>(`/api/users/${id}`);

    if (response.status=== "success") {
        return response.data;// TypeScript knows this is SuccessResponse
    }

    console.error(response.error.message);// TypeScript knows this is ErrorResponse
    return null;
}

