### 🎯 2.3 Type Aliases vs Interfaces

```
TypeScript
/*
TYPE ALIASES VS INTERFACES
TYPE ALIAS (type)
• Can represent ANY type (primitives, unions, tuples)
• Cannot be extended (but can use intersections)
• Cannot be reopened/merged
INTERFACE
• Only for object shapes
• Can be extended with 'extends'
• Can be reopened/merged (declaration merging)
*/

//
// BASIC DIFFERENCES
//

// TYPE ALIAS - Can be anything
type ID = string | number;
type Name = string;
type Coordinates = [number,number];
type Callback = (data: string)=> void;
type Status = "active" | "inactive";

// INTERFACE - Only objects
interface User {
    id: number;
    name: string;
}

// Both can define object shapes
type UserType = {
    id: number;
    name: string;
};

interface UserInterface {
    id: number;
    name: string;
}

//
// EXTENDING / COMBINING
//

// Interface extends interface
interface Animal {
    name: string;
}

interface Dog extends Animal {
    breed: string;
}

// Interface extends multiple interfaces
interface Pet extends Animal {
    owner: string;
}

interface ServiceDog extends Dog,Pet {
    service: "guide" | "therapy" | "search";
}

// Type uses intersection
type AnimalType = {
    name: string;
};

type DogType = AnimalType & {
    breed: string;
};

// Interface extends type
type Timestamps = {
    createdAt: Date;
    updatedAt: Date;
};

interface Article extends Timestamps {
    title: string;
    content: string;
}

// Type uses interface
interface BaseEntity {
    id: string;
}

type Product = BaseEntity & {
    name: string;
    price: number;
};

//
// DECLARATION MERGING (Interface only!)
//

// Interfaces with same name are merged
interface Window {
    myCustomProperty: string;
}

// Now Window has myCustomProperty!
// window.myCustomProperty = "hello";

// This is useful for augmenting libraries
interface Array<T> {
    customMethod(): T[];
}

// Type aliases CANNOT be merged
type Point = {x: number };
// type Point = { y: number }; // ❌ Error: Duplicate identifier

//
// UNIQUE TO TYPE ALIASES
//

// Union types
type Result = "success" | "error";
// interface Result = "success" | "error"; // ❌ Not possible

// Tuple types
type Pair = [string,number];
// interface Pair = [string, number]; // ❌ Not possible

// Mapped types
type Readonly<T>= {
    readonly [K in keyof T]: T[K];
};

// Conditional types
type NonNullable<T>= T extends null | undefined ? never : T;

//
// UNIQUE TO INTERFACES
//

// Declaration merging (as shown above)

// Implements in classes (technically both work)
interface Printable {
    print(): void;
}

class Document implements Printable {
    print() {
        console.log("Printing...");
    }
}

//
// BEST PRACTICES / WHEN TO USE WHICH
//

/*
USE INTERFACE WHEN:
Defining object shapes that might be extended
Creating contracts for classes
Building public APIs (library authors)
Declaration merging is needed
You want better error messages (sometimes)

USE TYPE ALIAS WHEN:
Creating unions or intersections
Working with tuples
Creating function types
Using mapped or conditional types
Type cannot be expressed as an object
You don't need declaration merging
*/

// Real-world example: API types

// Interface for entities (can be extended)
interface BaseEntity {
    id: string;
    createdAt: Date;
    updatedAt: Date;
}

interface User extends BaseEntity {
    email: string;
    name: string;
    role: UserRole;
}

interface Post extends BaseEntity {
    title: string;
    content: string;
    authorId: string;
}

// Type for unions and utility
type UserRole = "admin" | "user" | "guest";
type CreateUserInput = Omit<User,"id" | "createdAt" | "updatedAt">;
type UpdateUserInput = Partial<CreateUserInput>;

// Type for API response (uses union)
type ApiResponse<T>=
    | {status: "success";data: T }
    | {status: "error";error: string };

// Type for function signatures
type EventHandler<T>= (event: T)=> void;
type AsyncOperation<T>= ()=> Promise<T>;

