//
// MEDIUM 1: Create a type-safe form handler
//

// Create types for a form with:
// - Different field types (text, email, number, select)
// - Validation rules
// - Error states

// SOLUTION:
type FieldType = "text" | "email" | "number" | "select" | "checkbox";

interface ValidationRule {
    type: "required" | "minLength" | "maxLength" | "pattern" | "min" | "max";
    value?: number | string | RegExp;
    message: string;
}

interface BaseField {
    name: string;
    label: string;
    placeholder?: string;
    validation?: ValidationRule[];
}

interface TextField extends BaseField {
    type: "text" | "email";
    value: string;
}

interface NumberField extends BaseField {
    type: "number";
    value: number;
    min?: number;
    max?: number;
}

interface SelectField extends BaseField {
    type: "select";
    value: string;
    options: Array<{label: string;value: string }>;
}

interface CheckboxField extends BaseField {
    type: "checkbox";
    value: boolean;
}

type FormField = TextField | NumberField | SelectField | CheckboxField;

interface FormState {
    fields: FormField[];
    errors: Record<string,string[]>;
    isValid: boolean;
    isSubmitting: boolean;
}

// Type-safe form handler
function getFieldValue<T extends FormField>(field: T): T["value"] {
    return field.value;
}

function validateField(field: FormField): string[] {
    const errors: string[]= [];

    if (!field.validation)return errors;

    for (const rule of field.validation) {
        switch (rule.type) {
            case "required":
                if (field.type=== "checkbox") {
                    if (!field.value) errors.push(rule.message);
                }else if (!field.value) {
                    errors.push(rule.message);
                }
                break;
            case "minLength":
                if (
                    (field.type=== "text" || field.type=== "email")&&
                    field.value.length < (rule.valueas number)
                ) {
                    errors.push(rule.message);
                }
                break;
            // ... more validation rules
        }
    }

    return errors;
}

//
// MEDIUM 2: Create a discriminated union for state machines
//

// Model a fetch request lifecycle

// SOLUTION:
interface IdleState {
    status: "idle";
}

interface LoadingState {
    status: "loading";
    startedAt: Date;
}

interface SuccessState<T> {
    status: "success";
    data: T;
    completedAt: Date;
}

interface ErrorState {
    status: "error";
    error: Error;
    failedAt: Date;
    retryCount: number;
}

type FetchState<T>= IdleState | LoadingState | SuccessState<T>| ErrorState;

// Usage with exhaustive checking
function renderFetchState<T>(state: FetchState<T>): string {
    switch (state.status) {
        case "idle":
            return "Ready to fetch";
        case "loading":
            return `Loading since ${state.startedAt.toISOString()}`;
        case "success":
            return `Loaded: ${JSON.stringify(state.data)}`;
        case "error":
            return `Error: ${state.error.message} (Retry #${state.retryCount})`;
        default:
            // Exhaustive check - this should never happen
            const _exhaustive: never = state;
            return _exhaustive;
    }
}

// State machine transitions
function transition<T>(
    state: FetchState<T>,
    action:
        | {type: "FETCH_START" }
        | {type: "FETCH_SUCCESS";data: T }
        | {type: "FETCH_ERROR";error: Error }
        | {type: "RESET" }
): FetchState<T> {
    switch (action.type) {
        case "FETCH_START":
            return { status:"loading", startedAt:new Date() };

        case "FETCH_SUCCESS":
            return {
                status:"success",
                data: action.data,
                completedAt:new Date()
            };

        case "FETCH_ERROR":
            return {
                status:"error",
                error: action.error,
                failedAt:new Date(),
                retryCount: state.status=== "error" ? state.retryCount+ 1 : 1
            };

        case "RESET":
            return { status:"idle" };
    }
}

