TypeScript
//
// HARD 1: Build a type-safe builder pattern
//

// Create a query builder that:
// - Enforces correct method chaining order
// - Provides type-safe column selection
// - Validates where clause types

// SOLUTION:
interface TableSchema {
    users: {
        id: number;
        name: string;
        email: string;
        age: number;
        isActive: boolean;
    };
    posts: {
        id: number;
        title: string;
        content: string;
        authorId: number;
        publishedAt: Date | null;
    };
}

type Tables = keyof TableSchema;
type Columns<T extends Tables>= keyof TableSchema[T];
type ColumnType<T extends Tables,C extends Columns<T>>= TableSchema[T][C];

// Builder states
interface InitialState {}
interface TableSelected<T extends Tables> {
    table: T;
}
interface ColumnsSelected<T extends Tables,C extends Columns<T>> {
    table: T;
    columns: C[];
}
interface WhereAdded<T extends Tables,C extends Columns<T>> {
    table: T;
    columns: C[];
    hasWhere: true;
}

// Query builder with type-safe chaining
class QueryBuilder<State = InitialState> {
    private query: {
        table?: string;
        columns?: string[];
        where?: string[];
        orderBy?: string;
        limit?: number;
    }= {};

    from<T extends Tables>(
        this: QueryBuilder<InitialState>,
        table: T
    ): QueryBuilder<TableSelected<T>> {
        const builder = this as any;
        builder.query.table= table;
        return builder;
    }

    select<T extends Tables,C extends Columns<T>>(
        this: QueryBuilder<TableSelected<T>>,
        ...columns: C[]
    ): QueryBuilder<ColumnsSelected<T,C>> {
        const builder = this as any;
        builder.query.columns= columns;
        return builder;
    }

    where<
        T extendsTables,
        C extends Columns<T>,
        Col extendsC
    >(
        this: QueryBuilder<ColumnsSelected<T,C>>,
        column: Col,
        operator: "=" | "!=" | ">" | "<" | "LIKE",
        value: ColumnType<T,Col>
    ): QueryBuilder<WhereAdded<T,C>> {
        const builder = this as any;
        if (!builder.query.where) builder.query.where= [];
        builder.query.where.push(`${String(column)} ${operator} ${JSON.stringify(value)}`);
        return builder;
    }

    andWhere<
        T extendsTables,
        C extends Columns<T>,
        Col extendsC
    >(
        this: QueryBuilder<WhereAdded<T,C>>,
        column: Col,
        operator: "=" | "!=" | ">" | "<" | "LIKE",
        value: ColumnType<T,Col>
    ): QueryBuilder<WhereAdded<T,C>> {
        const builder = this as any;
        builder.query.where.push(`${String(column)} ${operator} ${JSON.stringify(value)}`);
        return builder;
    }

    orderBy<T extends Tables,C extends Columns<T>>(
        this: QueryBuilder<ColumnsSelected<T,C>| WhereAdded<T,C>>,
        column: C,
        direction: "ASC" | "DESC" = "ASC"
    ): this {
        (this as any).query.orderBy= `${String(column)} ${direction}`;
        return this;
    }

    limit(
        this: QueryBuilder<ColumnsSelected<any,any>| WhereAdded<any,any>>,
        count: number
    ): this {
        (this as any).query.limit= count;
        return this;
    }

    build(): string {
        const {table,columns,where,orderBy,limit }= (this as any).query;
        let sql= `SELECT ${columns?.join(", ")|| "*"} FROM ${table}`;
        if (where?.length) sql+= ` WHERE ${where.join(" AND ")}`;
        if (orderBy) sql+= ` ORDER BY ${orderBy}`;
        if (limit) sql+= ` LIMIT ${limit}`;
        return sql;
    }
}

// Usage
const query = new QueryBuilder()
    .from("users")
    .select("id","name","email")
    .where("age",">",18)// ✅ age must be number
    .andWhere("isActive","=",true)// ✅ isActive must be boolean
    .orderBy("name","DESC")
    .limit(10)
    .build();

// ❌ These would cause type errors:
// .where("age", ">", "18")        // Error: string not assignable to number
// .where("invalid", "=", 1)       // Error: "invalid" not in columns
// .select("id").select("name")    // Error: select() not available after select()

//
// HARD 2: Type-safe path accessor
//

// Create a type that extracts the type at a nested path

// SOLUTION:
type PathKeys<T>= T extends object
    ? {
        [K in keyof T]: K extends string
            ? T[K]extends object
                ? K | `${K}.${PathKeys<T[K]>}`
                : K
            : never;
    }[keyof T]
    : never;

type PathValue<T,P extends string>= P extends `${infer Key}.${infer Rest}`
    ? Key extends keyof T
        ? PathValue<T[Key],Rest>
        : never
    : P extends keyof T
        ? T[P]
        : never;

// Usage
interface DeepObject {
    user: {
        profile: {
            name: string;
            age: number;
            address: {
                city: string;
                country: string;
            };
        };
        settings: {
            theme: "light" | "dark";
            notifications: boolean;
        };
    };
    meta: {
        version: number;
    };
}

type AllPaths = PathKeys<DeepObject>;
// "user" | "user.profile" | "user.profile.name" | "user.profile.age" |
// "user.profile.address" | "user.profile.address.city" | ...

type NameType = PathValue<DeepObject,"user.profile.name">;// string
type ThemeType = PathValue<DeepObject,"user.settings.theme">;// "light" | "dark"

// Type-safe get function
function get<T,P extends PathKeys<T>>(obj: T,path: P): PathValue<T,P> {
    const keys = (pathas string).split(".");
    let result: any = obj;
    for (const key of keys) {
        result= result[key];
    }
    return result;
}

// Usage
declare const obj: DeepObject;
const name = get(obj,"user.profile.name");// Type: string
const theme = get(obj,"user.settings.theme");// Type: "light" | "dark"
// get(obj, "invalid.path"); // ❌ Error

