// Create a function 'format' that:
// - If given a Date, returns formatted string
// - If given a number, returns formatted currency
// - If given a string, returns trimmed and lowercase

// SOLUTION:
function format(value: Date): string;
function format(value: number): string;
function format(value: string): string;
function format(value: Date | number | string): string {
    if (valueinstanceof Date) {
        return value.toISOString().split("T")[0];
    }
    if (typeof value=== "number") {
        return `$${value.toFixed(2)}`;
    }
    return value.trim().toLowerCase();
}

