//
// HARD: Type-safe curry function
//

// Implement a type-safe curry function

// SOLUTION:
type Curry<F extends (...args: any[])=> any>=
    Parameters<F>extends [infer First,...infer Rest]
        ? Rest extends []
            ? F
            : (arg: First)=> Curry<(...args: Rest)=> ReturnType<F>>
        : F;

function curry<F extends (...args: any[])=> any>(fn: F): Curry<F> {
    return function curried(...args: any[]): any {
        if (args.length >= fn.length) {
            return fn(...args);
        }
        return (...more: any[])=> curried(...args,...more);
    }as Curry<F>;
}

// Usage
function add(a: number,b: number,c: number): number {
    return a+ b+ c;
}

const curriedAdd = curry(add);
const add1 = curriedAdd(1);// (b: number) => (c: number) => number
const add1And2 = add1(2);// (c: number) => number
const result = add1And2(3);// 6

// Or chain directly
const result2 = curry(add)(1)(2)(3);// 6

