// Basic generic class
class Box<T> {
    private content: T;

    constructor(content: T) {
        this.content= content;
    }

    getContent(): T {
        return this.content;
    }

    setContent(content: T): void {
        this.content= content;
    }
}

const stringBox = new Box("hello");
const numberBox = new Box(42);

// Generic class with multiple type parameters
class Map<K,V> {
    private items: Array<{key: K;value: V }>= [];

    set(key: K,value: V): void {
        const existing = this.items.find(item => item.key=== key);
        if (existing) {
            existing.value= value;
        }else {
            this.items.push({ key, value });
        }
    }

    get(key: K): V | undefined {
        return this.items.find(item => item.key=== key)?.value;
    }

    has(key: K): boolean {
        return this.items.some(item => item.key=== key);
    }
}

// Generic class extending another generic class
class ObservableBox<T>extends Box<T> {
    private listeners: Array<(value: T)=> void>= [];

    subscribe(listener: (value: T)=> void): ()=> void {
        this.listeners.push(listener);
        return ()=> {
            this.listeners= this.listeners.filter(l => l!== listener);
        };
    }

    setContent(content: T): void {
        super.setContent(content);
        this.listeners.forEach(l => l(content));
    }
}

