### 🎯 4.2 Conditional Types

```typescript
/*
╔═══════════════════════════════════════════════════════════════╗
║                   CONDITIONAL TYPES                           ║
╠═══════════════════════════════════════════════════════════════╣
║                                                               ║
║  Syntax: T extends U ? X : Y                                 ║
║                                                               ║
║  "If T is assignable to U, the type is X, otherwise Y"       ║
║                                                               ║
╚═══════════════════════════════════════════════════════════════╝
*/

// ═══════════════════════════════════════════════════════════
// BASIC CONDITIONAL TYPES
// ═══════════════════════════════════════════════════════════

// Simple conditional
type IsString<T>= T extends string ? true : false;

type A = IsString<string>;// true
type B = IsString<number>;// false

// Conditional with literal types
type IsArray<T>= T extends any[]? "array" : "not array";

type C = IsArray<string[]>;// "array"
type D = IsArray<string>;// "not array"

// Conditional returning types
type UnwrapArray<T>= T extends (infer U)[]? U : T;

type E = UnwrapArray<string[]>;// string
type F = UnwrapArray<number>;// number

// ═══════════════════════════════════════════════════════════
// INFER KEYWORD
// ═══════════════════════════════════════════════════════════

// Extract return type
type ReturnType<T>= T extends (...args: any[])=> infer R ? R : never;

type FuncReturn = ReturnType<()=> string>;// string

// Extract parameter types
type Parameters<T>= T extends (...args: infer P)=> any ? P : never;

type FuncParams = Parameters<(a: string,b: number)=> void>;// [string, number]

// Extract promise value
type Awaited<T>= T extends Promise<infer U>? Awaited<U>: T;

type PromiseValue = Awaited<Promise<Promise<string>>>;// string

// Extract array element type
type ArrayElement<T>= T extends (infer U)[]? U : never;

type Element = ArrayElement<string[]>;// string

// Multiple infers
type FirstAndLast<T extends any[]>= T extends [infer F,...any[],infer L]
    ? [F,L]
    : T extends [infer Only]
        ? [Only,Only]
        : never;

type FL1 = FirstAndLast<[1,2,3,4]>;// [1, 4]
type FL2 = FirstAndLast<[1]>;// [1, 1]
type FL3 = FirstAndLast<[]>;// never

// ═══════════════════════════════════════════════════════════
// DISTRIBUTIVE CONDITIONAL TYPES
// ═══════════════════════════════════════════════════════════

/*
When conditional type acts on a union type, it distributes
over each member of the union.
*/

type ToArray<T>= T extends any ? T[]: never;

// Distribution happens!
type Distributed = ToArray<string | number>;// string[] | number[]

// Prevent distribution with tuple
type ToArrayNoDistribute<T>= [T]extends [any]? T[]: never;

type NotDistributed = ToArrayNoDistribute<string | number>;// (string | number)[]

// Practical example: Exclude and Extract
type MyExclude<T,U>= T extends U ? never : T;
type MyExtract<T,U>= T extends U ? T : never;

type Numbers = 1 | 2 | 3 | 4 | 5;

type SmallNumbers = MyExtract<Numbers,1 | 2 | 3>;// 1 | 2 | 3
type BigNumbers = MyExclude<Numbers,1 | 2 | 3>;// 4 | 5

// ═══════════════════════════════════════════════════════════
// COMPLEX CONDITIONAL TYPE EXAMPLES
// ═══════════════════════════════════════════════════════════

// Flatten nested arrays
type Flatten<T>= T extends (infer U)[]
    ? Flatten<U>
    : T;

type Nested = number[][][];
type Flat = Flatten<Nested>;// number

// Get function this type
type ThisType<T>= T extends (this: infer U,...args: any[])=> any
    ? U
    : never;

function greet(this: {name: string }) {
    return `Hello, ${this.name}`;
}

type GreetThis = ThisType<typeof greet>;// { name: string }

// Make only certain keys optional
type PartialBy<T,K extends keyof T>= Omit<T,K>& Partial<Pick<T,K>>;

interface User {
    id: number;
    name: string;
    email: string;
}

type UserOptionalEmail = PartialBy<User,"email">;
// { id: number; name: string; email?: string }

// ═══════════════════════════════════════════════════════════
// CONDITIONAL TYPES IN PRACTICE
// ═══════════════════════════════════════════════════════════

// API Response handler
type ApiResult<T>= T extends void
    ? {success: boolean }
    : {success: boolean;data: T };

function createHandler<T>(): (data: T)=> ApiResult<T> {
    return (data)=> {
        if (data=== undefined || data=== null) {
            return { success:true }as ApiResult<T>;
        }
        return { success:true, data }as ApiResult<T>;
    };
}

// Type-safe config
type ConfigValue<T extends string>=
    T extends `${infer _}Enabled` ? boolean :
    T extends `${infer _}Count` ? number :
    T extends `${infer _}Name` ? string :
    unknown;

interface Config {
    featureEnabled: ConfigValue<"featureEnabled">;// boolean
    maxCount: ConfigValue<"maxCount">;// number
    userName: ConfigValue<"userName">;// string
}

// Event handler types
type EventHandler<T>= T extends keyof HTMLElementEventMap
    ? (event: HTMLElementEventMap[T])=> void
    : (event: Event)=> void;

type ClickHandler = EventHandler<"click">;// (event: MouseEvent) => void
type InputHandler = EventHandler<"input">;// (event: Event) => void

