### 🎯 4.3 Mapped Types

```typescript
/*
╔═══════════════════════════════════════════════════════════════╗
║                     MAPPED TYPES                              ║
╠═══════════════════════════════════════════════════════════════╣
║                                                               ║
║  Mapped types allow you to create new types by transforming  ║
║  existing types, property by property.                       ║
║                                                               ║
║  Syntax: { [K in Keys]: Type }                               ║
║                                                               ║
╚═══════════════════════════════════════════════════════════════╝
*/

// ═══════════════════════════════════════════════════════════
// BASIC MAPPED TYPES
// ═══════════════════════════════════════════════════════════

// Make all properties optional
type MyPartial<T>= {
    [K in keyof T]?: T[K];
};

// Make all properties required
type MyRequired<T>= {
    [K in keyof T]-?: T[K];// -? removes optionality
};

// Make all properties readonly
type MyReadonly<T>= {
    readonly [K in keyof T]: T[K];
};

// Make all properties mutable
type Mutable<T>= {
    -readonly [K in keyof T]: T[K];// -readonly removes readonly
};

// Usage
interface User {
    readonly id: number;
    name: string;
    email?: string;
}

type PartialUser = MyPartial<User>;
// { id?: number; name?: string; email?: string }

type MutableUser = Mutable<User>;
// { id: number; name: string; email?: string }

// ═══════════════════════════════════════════════════════════
// KEY REMAPPING (TypeScript 4.1+)
// ═══════════════════════════════════════════════════════════

// Add prefix to all keys
type Prefixed<T,P extends string>= {
    [K in keyof T as `${P}${Capitalize<string & K>}`]: T[K];
};

interface User {
    name: string;
    age: number;
}

type PrefixedUser = Prefixed<User,"user">;
// { userName: string; userAge: number }

// Create getters
type Getters<T>= {
    [K in keyof T as `get${Capitalize<string & K>}`]: ()=> T[K];
};

type UserGetters = Getters<User>;
// { getName: () => string; getAge: () => number }

// Create setters
type Setters<T>= {
    [K in keyof T as `set${Capitalize<string & K>}`]: (value: T[K])=> void;
};

// Filter properties by type
type OnlyStrings<T>= {
    [K in keyof T as T[K]extends string ? K : never]: T[K];
};

interface Mixed {
    name: string;
    age: number;
    email: string;
    isActive: boolean;
}

type StringProps = OnlyStrings<Mixed>;
// { name: string; email: string }

// Exclude certain keys
type OmitByKey<T,K extends keyof T>= {
    [P in keyof T as P extends K ? never : P]: T[P];
};

// ═══════════════════════════════════════════════════════════
// COMBINING MAPPED TYPES WITH CONDITIONALS
// ═══════════════════════════════════════════════════════════

// Make specific keys optional
type PartialBy<T,K extends keyof T>= {
    [P in keyof T as P extends K ? never : P]: T[P];
}& {
    [P in K]?: T[P];
};

// Simplify intersection
type Simplify<T>= {
    [K in keyof T]: T[K];
};

type Result = Simplify<PartialBy<User,"email">>;
// { id: number; name: string; email?: string }

// Make only certain types optional
type OptionalNullable<T>= {
    [K in keyof T as null extends T[K]? K : never]?: T[K];
}& {
    [K in keyof T as null extends T[K]? never : K]: T[K];
};

// Deep partial
type DeepPartial<T>= {
    [K in keyof T]?: T[K]extends object
        ? DeepPartial<T[K]>
        : T[K];
};

// Deep required
type DeepRequired<T>= {
    [K in keyof T]-?: T[K]extends object
        ? DeepRequired<T[K]>
        : T[K];
};

// ═══════════════════════════════════════════════════════════
// PRACTICAL MAPPED TYPE PATTERNS
// ═══════════════════════════════════════════════════════════

// Form state type
type FormState<T>= {
    values: T;
    errors: { [K in keyof T]?: string };
    touched: { [K in keyof T]?: boolean };
    isValid: boolean;
    isSubmitting: boolean;
