        case "square":
            return 10 * 10;
        case "triangle":
            return (10 * 10)/ 2;
        default:
            // If we add a new shape and forget to handle it,
            // this will cause a compile error
            const exhaustiveCheck: never = shape;
            throw new Error(`Unhandled shape: ${exhaustiveCheck}`);
    }
}

