    add(a,b) {
        return a+ b;
    },
    subtract: (a,b)=> a- b
    // multiply is optional
};

// ═══════════════════════════════════════════════════════════
// CALLABLE AND CONSTRUCTABLE INTERFACES
// ═══════════════════════════════════════════════════════════

// Callable interface (function signature)
interface Greeting {
    (name: string): string;
}

const greet: Greeting = (name)=> `Hello, ${name}!`;

// Constructable interface (class signature)
interface PersonConstructor {
    new (name: string,age: number): Person;
}

class PersonClass implements Person {
    constructor(public name: string,public age: number) {}
}

function createPerson(ctor: PersonConstructor,name: string,age: number): Person {
    return new ctor(name, age);
}

const person = createPerson(PersonClass,"John",30);

// Combined callable and constructable
interface DateConstructor {
    (): string;// Callable
    new (): Date;// Constructable
    new (value: number): Date;// Constructable with arg
    parse(s: string): number;// Static method
}

// ═══════════════════════════════════════════════════════════
// HYBRID TYPES
// ═══════════════════════════════════════════════════════════

interface Counter {
    (start: number): void;// Callable
    count: number;// Property
    reset(): void;// Method
    increment(): number;// Method
}

function createCounter(): Counter {
    const counter = function(start: number) {
        counter.count= start;
    }as Counter;

    counter.count= 0;

    counter.reset = function() {
        counter.count= 0;
    };

    counter.increment = function() {
        return ++counter.count;
    };

    return counter;
}

const counter = createCounter();
counter(10);// Set count to 10
console.log(counter.count);// 10
console.log(counter.increment());// 11
counter.reset();
console.log(counter.count);// 0

