### 🎯 3.2 Mapped Types

```typescript
// ═══════════════════════════════════════════════════════════
// BASIC MAPPED TYPES
// ═══════════════════════════════════════════════════════════

// Make all properties optional
type Partial<T>= {
    [P in keyof T]?: T[P];
};

// Make all properties required
type Required<T>= {
    [P in keyof T]-?: T[P];// -? removes optional modifier
};

// Make all properties readonly
type Readonly<T>= {
    readonly [P in keyof T]: T[P];
};

// Make all properties mutable
type Mutable<T>= {
    -readonly [P in keyof T]: T[P];// -readonly removes readonly
};

// Example usage
interface User {
    id: number;
    name: string;
    email?: string;
}

type PartialUser = Partial<User>;
// { id?: number; name?: string; email?: string; }

type RequiredUser = Required<User>;
// { id: number; name: string; email: string; }

type ReadonlyUser = Readonly<User>;
// { readonly id: number; readonly name: string; readonly email?: string; }

// ═══════════════════════════════════════════════════════════
// KEY REMAPPING (TypeScript 4.1+)
// ═══════════════════════════════════════════════════════════

// Rename keys with template literals
type Getters<T>= {
    [P in keyof T as `get${Capitalize<string & P>}`]: ()=> T[P];
};

interface Person {
    name: string;
    age: number;
}

type PersonGetters = Getters<Person>;
// { getName: () => string; getAge: () => number; }

// Filter keys
type OnlyStrings<T>= {
    [P in keyof T as T[P]extends string ? P : never]: T[P];
};

interface Mixed {
    name: string;
    age: number;
    email: string;
    active: boolean;
}

type StringProps = OnlyStrings<Mixed>;
// { name: string; email: string; }

// ═══════════════════════════════════════════════════════════
// PRACTICAL MAPPED TYPES
// ═══════════════════════════════════════════════════════════

// Event handlers
type EventHandlers<T>= {
    [P in keyof T as `on${Capitalize<string & P>}Change`]: (value: T[P])=> void;
};

interface FormData {
    username: string;
    password: string;
    rememberMe: boolean;
}

type FormHandlers = EventHandlers<FormData>;
// {
//     onUsernameChange: (value: string) => void;
//     onPasswordChange: (value: string) => void;
//     onRememberMeChange: (value: boolean) => void;
// }

// Nullable properties
type Nullable<T>= {
    [P in keyof T]: T[P]| null;
};

type NullableUser = Nullable<User>;
// { id: number | null; name: string | null; email: string | null; }

// Deep readonly
type DeepReadonly<T>= {
    readonly [P in keyof T]: T[P]extends object
        ? DeepReadonly<T[P]>
        : T[P];
};

interface NestedObject {
    level1: {
        level2: {
            value: string;
        };
    };
}

type ReadonlyNested = DeepReadonly<NestedObject>;
// All levels are readonly

