### 🎯 3.3 Conditional Types

```typescript
// ═══════════════════════════════════════════════════════════
// BASIC CONDITIONAL TYPES
// ═══════════════════════════════════════════════════════════

// Syntax: T extends U ? X : Y

type IsString<T>= T extends string ? true : false;

type A = IsString<string>;// true
type B = IsString<number>;// false
type C = IsString<"hello">;// true

// ═══════════════════════════════════════════════════════════
// DISTRIBUTIVE CONDITIONAL TYPES
// ═══════════════════════════════════════════════════════════

// When T is a union, conditional types distribute over each member

type ToArray<T>= T extends unknown ? T[]: never;

type StringOrNumberArray = ToArray<string | number>;
// string[] | number[]  (not (string | number)[])

// Prevent distribution with tuple
type ToArrayNonDistributive<T>= [T]extends [unknown]? T[]: never;

type StringOrNumberArrayND = ToArrayNonDistributive<string | number>;
// (string | number)[]

// ═══════════════════════════════════════════════════════════
// INFER KEYWORD
// ═══════════════════════════════════════════════════════════

// Extract return type
type ReturnType<T>= T extends (...args: any[])=> infer R ? R : never;

type Func = ()=> string;
type FuncReturn = ReturnType<Func>;// string

// Extract parameter types
type Parameters<T>= T extends (...args: infer P)=> any ? P : never;

type FuncParams = Parameters<(a: string,b: number)=> void>;
// [a: string, b: number]

// Extract array element type
type ElementType<T>= T extends (infer E)[]? E : never;

type StringArrayElement = ElementType<string[]>;// string

// Extract promise value type
type Awaited<T>= T extends Promise<infer U>? Awaited<U>: T;

type PromiseString = Awaited<Promise<string>>;// string
type NestedPromise = Awaited<Promise<Promise<number>>>;// number

// ═══════════════════════════════════════════════════════════
// PRACTICAL CONDITIONAL TYPES
// ═══════════════════════════════════════════════════════════

// Extract function argument types
type FirstArgument<T>= T extends (first: infer F,...args: any[])=> any
    ? F
    : never;

type First = FirstArgument<(name: string,age: number)=> void>;// string

// Get property type
type PropType<T,K extends keyof T>= T extends { [key in K]: infer V }
    ? V
    : never;

interface User {
    id: number;
    name: string;
}

type IdType = PropType<User,"id">;// number

// Flatten type
type Flatten<T>= T extends Array<infer U>? Flatten<U>: T;

type NestedArray = number[][][];
type Flat = Flatten<NestedArray>;// number

// ═══════════════════════════════════════════════════════════
// BUILT-IN CONDITIONAL TYPES
// ═══════════════════════════════════════════════════════════

// Exclude<T, U> - Exclude types from T that are assignable to U
type T1 = Exclude<"a" | "b" | "c","a">;
// "b" | "c"

// Extract<T, U> - Extract types from T that are assignable to U
type T2 = Extract<"a" | "b" | "c","a" | "f">;
// "a"

// NonNullable<T> - Exclude null and undefined
type T3 = NonNullable<string | null | undefined>;
// string

// ReturnType<T> - Get function return type
type T4 = ReturnType<()=> string>;
// string

// InstanceType<T> - Get instance type of constructor
class MyClass {
    value = 42;
}
type T5 = InstanceType<typeof MyClass>;
// MyClass

