// Deep partial
type DeepPartial<T>= {
    [P in keyof T]?: T[P]extends object
        ? DeepPartial<T[P]>
        : T[P];
};

// Deep required
type DeepRequired<T>= {
    [P in keyof T]-?: T[P]extends object
        ? DeepRequired<T[P]>
        : T[P];
};

// Tree structure
interface TreeNode<T> {
    value: T;
    children: TreeNode<T>[];
}

function mapTree<T,U>(
    node: TreeNode<T>,
    fn: (value: T)=> U
): TreeNode<U> {
    return {
        value:fn(node.value),
        children: node.children.map(child => mapTree(child, fn))
    };
}

// ═══════════════════════════════════════════════════════════
// VARIANCE IN GENERICS
// ═══════════════════════════════════════════════════════════

// Covariance (out) - can use more specific type
interface Producer<out T> {
    produce(): T;
}

// Contravariance (in) - can use more general type
interface Consumer<in T> {
    consume(value: T): void;
}

// Invariance - must be exact type
interface Processor<T> {
    process(value: T): T;
}

// Example
class Animal {
    name = "animal";
}

class Dog extends Animal {
    breed = "unknown";
}

// Covariance example
const dogProducer: Producer<Dog>= {
    produce: ()=> new Dog()
};

const animalProducer: Producer<Animal>= dogProducer;// ✅ OK

// Contravariance example
const animalConsumer: Consumer<Animal>= {
    consume: (animal)=> console.log(animal.name)
};

const dogConsumer: Consumer<Dog>= animalConsumer;// ✅ OK

