// Polymorphism
function printShapeInfo(shape: Shape): void {
    console.log(`${shape.name}: Area = ${shape.getArea()}`);
}

printShapeInfo(circle);// "Circle: Area = 78.54..."
printShapeInfo(rectangle);// "Rectangle: Area = 24"

