### 🎯 6.3 Implementing Interfaces

```typescript
// ═══════════════════════════════════════════════════════════
// CLASS IMPLEMENTING INTERFACE
// ═══════════════════════════════════════════════════════════

interface Serializable {
    serialize(): string;
    deserialize(data: string): void;
}

interface Comparable<T> {
    compareTo(other: T): number;
}

interface Printable {
    print(): void;
}

class Product implements Serializable,Comparable<Product>,Printable {
    constructor(
        public id: string,
        public name: string,
        public price: number
    ) {}

    serialize(): string {
        return JSON.stringify({ id:this.id, name:this.name, price:this.price });
    }

    deserialize(data: string): void {
        const parsed = JSON.parse(data);
        this.id= parsed.id;
        this.name= parsed.name;
        this.price= parsed.price;
    }

    compareTo(other: Product): number {
        return this.price- other.price;
    }

    print(): void {
        console.log(`Product: ${this.name} - $${this.price}`);
    }
}

// ═══════════════════════════════════════════════════════════
// EXTENDING INTERFACE AND IMPLEMENTING
// ═══════════════════════════════════════════════════════════

interface Entity {
    id: string;
    createdAt: Date;
    updatedAt: Date;
}

interface Auditable extends Entity {
    createdBy: string;
    updatedBy: string;
}

abstract class BaseEntity implements Entity {
    id: string;
    createdAt: Date;
    updatedAt: Date;

    constructor() {
        this.id= crypto.randomUUID();
        this.createdAt= new Date();
        this.updatedAt= new Date();
    }

    touch(): void {
        this.updatedAt= new Date();
    }
}

class AuditableEntity extends BaseEntity implements Auditable {
    createdBy: string;
    updatedBy: string;

    constructor(userId: string) {
        super();
        this.createdBy= userId;
        this.updatedBy= userId;
    }

    update(userId: string): void {
        this.touch();
        this.updatedBy= userId;
    }
}

// ═══════════════════════════════════════════════════════════
// INTERFACE VS ABSTRACT CLASS
// ═══════════════════════════════════════════════════════════

/*
╔═══════════════════════════════════════════════════════════════╗
║           INTERFACE vs ABSTRACT CLASS                         ║
╠═══════════════════════════════════════════════════════════════╣
║                                                               ║
║  INTERFACE:                                                   ║
║  • Only declares shape (no implementation)                    ║
║  • Can implement multiple interfaces                          ║
║  • No runtime cost (erased during compilation)                ║
║  • Can be merged (declaration merging)                        ║
║                                                               ║
║  ABSTRACT CLASS:                                              ║
║  • Can have implementation                                    ║
║  • Can only extend one class                                  ║
║  • Has runtime cost (exists in JS)                           ║
║  • Can have constructors and access modifiers                 ║
║  • Can have non-abstract (concrete) methods                   ║
║                                                               ║
╚═══════════════════════════════════════════════════════════════╝
*/

// Use interface when you just need a contract
interface Logger {
    log(message: string): void;
    error(message: string): void;
}

// Use abstract class when you need shared implementation
abstract class BaseLogger implements Logger {
    protected formatMessage(level: string,message: string): string {
        return `[${new Date().toISOString()}] [${level}] ${message}`;
    }

    log(message: string): void {
        console.log(this.formatMessage("INFO", message));
    }

    abstract error(message: string): void;
}

class ConsoleLogger extends BaseLogger {
    error(message: string): void {
        console.error(this.formatMessage("ERROR", message));
    }
}

class FileLogger extends BaseLogger {
    constructor(private filePath: string) {
        super();
    }

    error(message: string): void {
        // Write to file instead of console
        const formatted = this.formatMessage("ERROR", message);
        // fs.appendFileSync(this.filePath, formatted + "\n");
    }
}

