```typescript
// Enable in tsconfig.json: "experimentalDecorators": true

// ═══════════════════════════════════════════════════════════
// CLASS DECORATORS
// ═══════════════════════════════════════════════════════════

// Basic class decorator
function Sealed(constructor: Function) {
    Object.seal(constructor);
    Object.seal(constructor.prototype);
}

@Sealed
class Greeter {
    greeting: string;

    constructor(message: string) {
        this.greeting= message;
    }

    greet() {
        return `Hello, ${this.greeting}`;
    }
}

// Class decorator factory
function Logger(prefix: string) {
    return function<T extends {new (...args: any[]): {} }>(constructor: T) {
        return class extends constructor {
            constructor(...args: any[]) {
                super(...args);
                console.log(`${prefix}: Created instance of ${constructor.name}`);
            }
        };
    };
}

@Logger("DEBUG")
class UserService {
    constructor(public name: string) {}
}

const service = new UserService("TestService");
// Logs: "DEBUG: Created instance of UserService"

// ═══════════════════════════════════════════════════════════
// METHOD DECORATORS
// ═══════════════════════════════════════════════════════════

function Log(target: any,propertyKey: string,descriptor: PropertyDescriptor) {
    const originalMethod = descriptor.value;

    descriptor.value = function(...args: any[]) {
        console.log(`Calling ${propertyKey} with args:`, args);
        const result = originalMethod.apply(this, args);
        console.log(`Result:`, result);
        return result;
    };

    return descriptor;
}

function Measure(target: any,propertyKey: string,descriptor: PropertyDescriptor) {
    const originalMethod = descriptor.value;

    descriptor.value = function(...args: any[]) {
        const start = performance.now();
        const result = originalMethod.apply(this, args);
        const end = performance.now();
        console.log(`${propertyKey} took ${end - start}ms`);
        return result;
    };

    return descriptor;
}

function Memoize(target: any,propertyKey: string,descriptor: PropertyDescriptor) {
    const originalMethod = descriptor.value;
    const cache = new Map<string,any>();

    descriptor.value = function(...args: any[]) {
        const key = JSON.stringify(args);

        if (cache.has(key)) {
            return cache.get(key);
        }

        const result = originalMethod.apply(this, args);
        cache.set(key, result);
        return result;
    };

    return descriptor;
}

class Calculator {
    @Log
    @Measure
    add(a: number,b: number): number {
        return a+ b;
    }

    @Memoize
    fibonacci(n: number): number {
        if (n<= 1)return n;
        return this.fibonacci(n- 1)+ this.fibonacci(n- 2);
    }
}

// ═══════════════════════════════════════════════════════════
// PROPERTY DECORATORS
// ═══════════════════════════════════════════════════════════

function MinLength(length: number) {
    return function(target: any,propertyKey: string) {
        let value: string;

        const getter = ()=> value;
        const setter = (newValue: string)=> {
            if (newValue.length < length) {
                throw new Error(`${propertyKey} must be at least ${length} characters`);
            }
            value= newValue;
        };

        Object.defineProperty(target, propertyKey, {
            get: getter,
            set: setter,
            enumerable:true,
            configurable:true
        });
    };
}

function Required(target: any,propertyKey: string) {
    let value: any;

    const getter = ()=> {
        if (value=== undefined || value=== null) {
            throw new Error(`${propertyKey} is required`);
        }
        return value;
    };

    const setter = (newValue: any)=> {
        value= newValue;
    };

    Object.defineProperty(target, propertyKey, {
        get: getter,
        set: setter,
        enumerable:true,
        configurable:true
    });
}

class User {
    @MinLength(3)
    username: string;

    @Required
    email: string;

    constructor(username: string,email: string) {
        this.username= username;
        this.email= email;
    }
}

// ═══════════════════════════════════════════════════════════
// PARAMETER DECORATORS
// ═══════════════════════════════════════════════════════════

function Validate(target: any,propertyKey: string,parameterIndex: number) {
    const existingValidators: number[]=
        Reflect.getOwnMetadata("validators", target, propertyKey)|| [];
    existingValidators.push(parameterIndex);
    Reflect.defineMetadata("validators", existingValidators, target, propertyKey);
}

class UserService2 {
    createUser(@Validatename: string, @Validateemail: string) {
        // Validation logic would check decorated parameters
        return { name, email };
    }
}

// ═══════════════════════════════════════════════════════════
// DECORATOR COMPOSITION
// ═══════════════════════════════════════════════════════════

function First() {
    console.log("First(): factory");
    return function(target: any,propertyKey: string,descriptor: PropertyDescriptor) {
        console.log("First(): decorator");
    };
}

function Second() {
    console.log("Second(): factory");
    return function(target: any,propertyKey: string,descriptor: PropertyDescriptor) {
        console.log("Second(): decorator");
    };
}

class ExampleClass {
    @First()
