/*
Output order:
First(): factory
Second(): factory
Second(): decorator  <- Decorators apply bottom-up
First(): decorator
*/

// ═══════════════════════════════════════════════════════════
// PRACTICAL DECORATOR: API Controller
// ═══════════════════════════════════════════════════════════

const routes: Map<string, {method: string;path: string;handler: Function }>= new Map();

function Controller(basePath: string) {
    return function<T extends {new (...args: any[]): {} }>(constructor: T) {
        Reflect.defineMetadata("basePath", basePath, constructor);
        return constructor;
    };
}

function Get(path: string) {
    return function(target: any,propertyKey: string,descriptor: PropertyDescriptor) {
        routes.set(propertyKey, {
            method:"GET",
            path,
            handler: descriptor.value
        });
    };
}

function Post(path: string) {
    return function(target: any,propertyKey: string,descriptor: PropertyDescriptor) {
        routes.set(propertyKey, {
            method:"POST",
            path,
            handler: descriptor.value
        });
    };
}

@Controller("/api/users")
class UserController {
    @Get("/")
    getAll() {
        return [{ id:1, name:"John" }];
    }

    @Get("/:id")
    getById(id: string) {
        return { id, name:"John" };
    }

    @Post("/")
    create(data: any) {
        return { id:2,...data };
    }
}

