// ═══════════════════════════════════════════════════════════
// MEDIUM 1: Implement a type-safe event emitter
// ═══════════════════════════════════════════════════════════

// Create a type-safe event emitter where:
// - Events are defined as an interface
// - on() and emit() are properly typed
// - Wrong event names or payload types cause errors

// SOLUTION:
interface EventMap {
    [event: string]: any;
}

class TypedEventEmitter<T extends EventMap> {
    private listeners = new Map<keyof T,Set<Function>>();

    on<K extends keyof T>(event: K,callback: (data: T[K])=> void): ()=> void {
        if (!this.listeners.has(event)) {
            this.listeners.set(event,new Set());
        }
        this.listeners.get(event)!.add(callback);

        return ()=> {
            this.listeners.get(event)?.delete(callback);
        };
    }

    emit<K extends keyof T>(event: K,data: T[K]): void {
        this.listeners.get(event)?.forEach(cb => cb(data));
    }
}

// Usage:
interface AppEvents {
    login: {userId: string;timestamp: Date };
    logout: {userId: string };
    error: {message: string;code: number };
}

const emitter = new TypedEventEmitter<AppEvents>();

emitter.on("login", (data)=> {
    // data is { userId: string; timestamp: Date }
    console.log(data.userId);
});

emitter.emit("login", { userId:"123", timestamp:new Date() });// ✅
// emitter.emit("login", { wrong: "data" }); // ❌ Error

