// ═══════════════════════════════════════════════════════════

// Implement DeepPartial<T> that makes all properties optional recursively

// SOLUTION:
type DeepPartial<T>= T extends object
    ? { [P in keyof T]?: DeepPartial<T[P]> }
    : T;

interface NestedConfig {
    database: {
        host: string;
        port: number;
        credentials: {
            username: string;
            password: string;
        };
    };
    cache: {
        enabled: boolean;
        ttl: number;
