// ═══════════════════════════════════════════════════════════
// HARD 1: Implement a type-safe SQL query builder
// ═══════════════════════════════════════════════════════════

// Create a query builder with full type safety

type Equals<X,Y>=
    (<T>()=> T extends X ? 1 : 2)extends (<T>()=> T extends Y ? 1 : 2)
        ? true
        : false;

type ColumnType = string | number | boolean | Date | null;

interface TableSchema {
    [column: string]: ColumnType;
}

type WhereClause<T extends TableSchema>= {
    [K in keyof T]?: T[K]| {$gt?: T[K];$lt?: T[K];$in?: T[K][] };
};

type OrderDirection = "ASC" | "DESC";
type OrderClause<T extends TableSchema>= {
    [K in keyof T]?: OrderDirection;
};

class QueryBuilder<
    T extends TableSchema,
    Selected extends keyof T = keyof T
> {
    private _select: (keyof T)[]= [];
    private _where: WhereClause<T>= {};
    private _orderBy: OrderClause<T>= {};
    private _limit?: number;
    private _offset?: number;

    constructor(private tableName: string) {}

    select<K extends keyof T>(...columns: K[]): QueryBuilder<T,K> {
        this._select= columns;
        return this as any;
    }

    where(conditions: WhereClause<T>): this {
        this._where= {...this._where,...conditions };
        return this;
    }

    orderBy(order: OrderClause<T>): this {
        this._orderBy= order;
        return this;
    }

    limit(count: number): this {
        this._limit= count;
        return this;
    }

    offset(count: number): this {
        this._offset= count;
        return this;
    }

    toSQL(): string {
        const columns = this._select.length > 0
            ? this._select.join(", ")
            : "*";

        let sql= `SELECT ${columns} FROM ${this.tableName}`;

        // Add WHERE
        const whereConditions = Object.entries(this._where)
            .map(([key,value])=> {
                if (typeof value=== "object" && value!== null) {
                    const conditions: string[]= [];
                    if ("$gt" in value) conditions.push(`${key} > ${value.$gt}`);
                    if ("$lt" in value) conditions.push(`${key} < ${value.$lt}`);
                    if ("$in" in value) conditions.push(`${key} IN (${value.$in!.join(", ")})`);
                    return conditions.join(" AND ");
                }
                return `${key} = ${JSON.stringify(value)}`;
            });

        if (whereConditions.length > 0) {
            sql+= ` WHERE ${whereConditions.join(" AND ")}`;
        }

        // Add ORDER BY
        const orderConditions = Object.entries(this._orderBy)
            .map(([key,dir])=> `${key} ${dir}`);

        if (orderConditions.length > 0) {
            sql+= ` ORDER BY ${orderConditions.join(", ")}`;
        }

        if (this._limit) sql+= ` LIMIT ${this._limit}`;
        if (this._offset) sql+= ` OFFSET ${this._offset}`;

        return sql;
    }

    // Type-safe execute that returns correct shape
    async execute(): Promise<Pick<T,Selected>[]> {
        // Simulated execution
        console.log("Executing:",this.toSQL());
        return []as Pick<T,Selected>[];
    }
}

// Usage
