// ═══════════════════════════════════════════════════════════
// HARD 2: Implement a type-safe state machine
// ═══════════════════════════════════════════════════════════

type StateMachineConfig<
    States extends string,
    Events extends string
>= {
    initial: States;
    states: {
        [S in States]: {
            on?: {
                [E in Events]?: States;
            };
        };
    };
};

type TransitionEvent<
    Config extends StateMachineConfig<string,string>,
    CurrentState extends keyof Config["states"]
>= Config["states"][CurrentState]extends {on: infer On }
    ? keyof On
    : never;

type NextState<
    Config extends StateMachineConfig<string,string>,
    CurrentState extends keyof Config["states"],
    Event extends TransitionEvent<Config,CurrentState>
>= Config["states"][CurrentState]extends {on: infer On }
    ? Event extends keyof On
        ? On[Event]
        : never
    : never;

class StateMachine<
    Config extends StateMachineConfig<string,string>,
    CurrentState extends keyof Config["states"]= Config["initial"]
> {
    private currentState: CurrentState;

    constructor(private config: Config) {
        this.currentState= config.initialas CurrentState;
    }

    getState(): CurrentState {
        return this.currentState;
    }

    send<E extends TransitionEvent<Config,CurrentState>>(
        event: E
    ): StateMachine<Config,NextState<Config,CurrentState,E>> {
        const transitions = this.config.states[this.currentStateas string].on;

        if (transitions&& eventin transitions) {
            this.currentState= (transitionsas any)[event];
        }

        return this as any;
    }
}

// Usage
