    initial:"red",
    states: {
        red: {
            on: { TIMER:"green" }
        },
        green: {
            on: { TIMER:"yellow" }
        },
        yellow: {
            on: { TIMER:"red" }
        }
    }
}as const;

type TrafficLightConfig = typeof trafficLightConfig;

