// ═══════════════════════════════════════════════════════════
// HARD 3: Implement type-safe dependency injection container
// ═══════════════════════════════════════════════════════════

type Constructor<T = any>= new (...args: any[])=> T;

type DependencyKey = string | symbol;

interface ServiceDefinition<T> {
    factory: ()=> T;
    singleton?: boolean;
}

class Container {
    private services = new Map<DependencyKey,ServiceDefinition<any>>();
    private singletons = new Map<DependencyKey,any>();

    register<T>(
        key: DependencyKey,
        factory: ()=> T,
        options: {singleton?: boolean }= {}
    ): void {
        this.services.set(key, {
            factory,
            singleton: options.singleton?? false
        });
    }

    resolve<T>(key: DependencyKey): T {
        const definition = this.services.get(key);

        if (!definition) {
            throw new Error(`Service not found: ${String(key)}`);
        }

        if (definition.singleton) {
            if (!this.singletons.has(key)) {
                this.singletons.set(key, definition.factory());
            }
            return this.singletons.get(key);
        }

        return definition.factory();
    }
}

// Type-safe container with inference
interface ServiceMap {
    [key: string]: any;
}

class TypedContainer<T extends ServiceMap = {}> {
    private container = new Container();

    register<K extends string,V>(
        key: K,
        factory: ()=> V,
        options?: {singleton?: boolean }
    ): TypedContainer<T & Record<K,V>> {
        this.container.register(key, factory, options);
        return this as any;
    }

    resolve<K extends keyof T>(key: K): T[K] {
        return this.container.resolve(keyas string);
    }
}

// Usage
interface UserRepository {
    findById(id: string): Promise<{id: string;name: string }>;
}

interface Logger {
    log(message: string): void;
}

const container = new TypedContainer()
    .register("logger", ()=> ({
        log: (msg: string)=> console.log(msg)
    }), { singleton:true })
    .register("userRepo", ()=> ({
        findById:async (id: string)=> ({ id, name:"John" })
    }));

const logger = container.resolve("logger");// Logger type
const userRepo = container.resolve("userRepo");// UserRepository type
// container.resolve("invalid");                // ❌ Error

