            {/* Ternary operator */}
            <p>{user.isAdmin? "Admin User" : "Regular User"}</p>

            {/* Logical AND for conditional rendering */}
            {user.isAdmin&& <span className="badge">Admin</span>}

            {/* Array mapping */}
