// ═══════════════════════════════════════════════════════════
// JSX GOTCHAS AND BEST PRACTICES
// ═══════════════════════════════════════════════════════════

function JSXGotchas() {
    // 1. className instead of class
    // <div class="container"> ❌
    <div className="container"></div>// ✅

    // 2. htmlFor instead of for
    // <label for="input"> ❌
    <label htmlFor="input"></label>// ✅

    // 3. camelCase for attributes
    // <div onclick={fn} tabindex="0"> ❌
    <div onClick={fn}tabIndex={0}></div>// ✅

    // 4. style must be an object
    // <div style="color: red"> ❌
    <div style={{ color:'red', fontSize:'16px' }}></div>// ✅

    // 5. Boolean attributes
    <input disabled />// Same as disabled={true}
    <input disabled={false} />// Not disabled

    // 6. Spreading props
    const props = { id:'myId', className:'myClass' };
    <div {...props} />// Spreads all props

    // 7. Fragments - avoid extra DOM nodes
    return (
        <>
            <Header />
            <Main />
            <Footer />
        </>
    );

    // With key (can't use shorthand)
    return items.map(item => (
        <React.Fragment key={item.id}>
            <dt>{item.term}</dt>
            <dd>{item.description}</dd>
        </React.Fragment>
    ));

    // 8. Comments in JSX
    return (
        <div>
            {/* This is a comment */}
            <p>Content</p>
        </div>
