    // 9. Whitespace handling
    <p>Hello World</p>// "Hello World"
    <p>Hello    World</p>// "Hello World" (collapsed)
    <p>Hello{' '}World</p>// "Hello World" (explicit space)

    // 10. Dangerously set HTML (XSS risk!)
    <div dangerouslySetInnerHTML={{ __html: htmlString }} />
}

// ═══════════════════════════════════════════════════════════
// CONDITIONAL RENDERING PATTERNS
// ═══════════════════════════════════════════════════════════

function ConditionalRendering({isLoggedIn,isAdmin,user,notifications }) {
    // Pattern 1: if/else (early return)
