    // Fix:
    // {count > 0 && <span>{count}</span>}
    // or
    // {count ? <span>{count}</span> : null}

    // Pattern 4: Nullish coalescing
    return <p>{user.nickname?? user.name?? 'Anonymous'}</p>;

