// ═══════════════════════════════════════════════════════════
// LIST RENDERING AND KEYS
// ═══════════════════════════════════════════════════════════

function ListRendering() {
    const items = [
        { id:'a', name:'Apple' },
        { id:'b', name:'Banana' },
        { id:'c', name:'Cherry' },
    ];

    // ✅ GOOD: Use unique, stable IDs
    return (
        <ul>
            {items.map(item => (
                <li key={item.id}>{item.name}</li>
            ))}
        </ul>
    );

    // ❌ BAD: Using index as key (causes issues with reordering)
    // items.map((item, index) => <li key={index}>{item.name}</li>)

    // ❌ BAD: Using random keys (recreates elements every render)
    // items.map(item => <li key={Math.random()}>{item.name}</li>)

    // When index as key is OK:
    // 1. List is static (never reordered or filtered)
    // 2. Items have no IDs
    // 3. List is never filtered or reordered
}

/*
WHY KEYS MATTER:

Without proper keys:
┌─────────────────────────────────────────┐
│ Before: [A, B, C]  After: [B, C, A]     │
│                                         │
│ React thinks:                           │
│   - Item 0: A → B (update content)      │
│   - Item 1: B → C (update content)      │
│   - Item 2: C → A (update content)      │
│                                         │
│ 3 DOM updates! All content changed!     │
└─────────────────────────────────────────┘

With proper keys:
┌─────────────────────────────────────────┐
│ Before: [A, B, C]  After: [B, C, A]     │
│                                          │
│ React knows:                             │
│   - Key "a" moved to position 2          │
│   - Key "b" moved to position 0          │
│   - Key "c" moved to position 1          │
│                                          │
│ Just reorder DOM nodes! Much faster!     │
└─────────────────────────────────────────┘
*/

