### 🎯 2.2 useEffect Deep Dive

```
// ═══════════════════════════════════════════════════════════
// useEffect FUNDAMENTALS
// ═══════════════════════════════════════════════════════════

import { useState, useEffect }from 'react';

/*
useEffect MENTAL MODEL:

┌─────────────────────────────────────────────────────────────┐
│                                                             │
│  useEffect(() => {                                          │
│      // EFFECT: Runs after render                           │
│      // Synchronizes component with external system         │
│                                                             │
│      return () => {                                         │
│          // CLEANUP: Runs before next effect or unmount     │
│      };                                                     │
│  }, [dependencies]);                                        │
│                                                             │
│  Dependencies control WHEN effect runs:                     │
│  • No deps array: After every render                        │
│  • Empty array []: Only on mount                            │
│  • [a, b]: When a or b change                               │
│                                                             │
└─────────────────────────────────────────────────────────────┘
*/

function EffectExamples() {
    const [count,setCount]= useState(0);
    const [userId,setUserId]= useState(1);

    // 1. Run on every render (usually not what you want)
    useEffect(()=> {
        console.log('Runs after every render');
    });

    // 2. Run only on mount (like componentDidMount)
    useEffect(()=> {
        console.log('Runs only once on mount');

        return ()=> {
            console.log('Cleanup on unmount');
        };
    }, []);

    // 3. Run when dependency changes
    useEffect(()=> {
        console.log('Count changed:', count);
    }, [count]);

    // 4. Multiple dependencies
    useEffect(()=> {
        console.log('Count or userId changed');
    }, [count, userId]);

    return <div>{count}</div>;
}

// ═══════════════════════════════════════════════════════════
// DATA FETCHING PATTERN
// ═══════════════════════════════════════════════════════════

function UserProfile({userId }) {
    const [user,setUser]= useState(null);
    const [loading,setLoading]= useState(true);
    const [error,setError]= useState(null);

    useEffect(()=> {
        // Reset state on userId change
        setLoading(true);
        setError(null);
        setUser(null);

        // Create abort controller for cleanup
        const abortController = new AbortController();

        async function fetchUser() {
            try {
                const response = await fetch(`/api/users/${userId}`, {
                    signal: abortController.signal
                });

                if (!response.ok) {
                    throw new Error('Failed to fetch user');
                }

                const data = await response.json();
                setUser(data);
            }catch (err) {
                // Ignore abort errors
                if (err.name!== 'AbortError') {
                    setError(err.message);
                }
            }finally {
                // Only set loading false if not aborted
                if (!abortController.signal.aborted) {
                    setLoading(false);
                }
            }
        }

        fetchUser();

        // Cleanup: Cancel request on unmount or userId change
        return ()=> {
            abortController.abort();
        };
    }, [userId]);

    if (loading)return <Spinner />;
    if (error)return <Error message={error} />;
    if (!user)return null;

    return <div>{user.name}</div>;
}

