// useEffect vs useLayoutEffect
// ═══════════════════════════════════════════════════════════

/*
┌─────────────────────────────────────────────────────────────┐
│                    RENDER CYCLE                             │
├─────────────────────────────────────────────────────────────┤
│  1. React renders component (virtual DOM)                   │
│  2. React commits changes to real DOM                       │
│  3. useLayoutEffect runs (BLOCKING)                         │
│  4. Browser paints screen                                   │
│  5. useEffect runs (NON-BLOCKING)                          │
└─────────────────────────────────────────────────────────────┘

Use useLayoutEffect when:
• You need to measure DOM elements
• You need to make visual changes before paint
• You need to prevent visual flickering
*/

function MeasureExample() {
    const [height,setHeight]= useState(0);
    const divRef = useRef(null);

    // useLayoutEffect - runs before paint
    useLayoutEffect(()=> {
        // Measure and update before user sees anything
        setHeight(divRef.current.getBoundingClientRect().height);
    }, []);

    return <div ref={divRef}>Content with height: {height}</div>;
}

function TooltipPosition({text }) {
    const [tooltipPos,setTooltipPos]= useState({ x:0, y:0 });
    const targetRef = useRef(null);

    // Prevents flicker - positions before paint
    useLayoutEffect(()=> {
        const rect = targetRef.current.getBoundingClientRect();
        setTooltipPos({
            x: rect.left+ rect.width/ 2,
            y: rect.top- 10
        });
    }, []);

    return (
        <>
            <button ref={targetRef}>Hover me</button>
            <Tooltip position={tooltipPos}>{text}</Tooltip>
        </>
    );
}

