// ═══════════════════════════════════════════════════════════
// useCallback - MEMOIZE FUNCTIONS
// ═══════════════════════════════════════════════════════════

/*
useCallback MENTAL MODEL:

┌─────────────────────────────────────────────────────────────┐
│                                                             │
│  const memoizedFn = useCallback(() => {                     │
│      doSomething(a, b);                                     │
│  }, [a, b]);                                                │
│                                                             │
│  • Caches the FUNCTION itself                               │
│  • Returns same function reference if deps unchanged        │
│  • useCallback(fn, deps) === useMemo(() => fn, deps)        │
│                                                             │
└─────────────────────────────────────────────────────────────┘
*/

function SearchComponent() {
    const [query,setQuery]= useState('');
    const [results,setResults]= useState([]);

    // ❌ New function every render
    const handleSearch = (searchQuery)=> {
        fetch(`/api/search?q=${searchQuery}`)
            .then(res => res.json())
            .then(setResults);
    };

    // ✅ Same function reference
    const handleSearchMemoized = useCallback((searchQuery)=> {
        fetch(`/api/search?q=${searchQuery}`)
            .then(res => res.json())
            .then(setResults);
    }, []);// No deps - function doesn't use external values

    // With dependencies
    const handleSearchWithContext = useCallback((searchQuery)=> {
        fetch(`/api/search?q=${searchQuery}&filter=${filter}`)
            .then(res => res.json())
            .then(setResults);
    }, [filter]);// Recreate when filter changes

    return (
        <div>
            <SearchInput onSearch={handleSearchMemoized} />
            <ResultsList results={results} />
        </div>
    );
}

// ═══════════════════════════════════════════════════════════
// useCallback WITH memo() - PREVENTING RE-RENDERS
// ═══════════════════════════════════════════════════════════

// Memoized child component
const ExpensiveList = memo(function ExpensiveList({items,onItemClick }) {
    console.log('ExpensiveList rendered');

    return (
        <ul>
            {items.map(item => (
                <li key={item.id}onClick={()=> onItemClick(item.id)}>
                    {item.name}
