// ═══════════════════════════════════════════════════════════
// WHEN TO USE useMemo/useCallback
// ═══════════════════════════════════════════════════════════

/*
USE WHEN:
1. Expensive computations that shouldn't run on every render
2. Referential equality matters (passing to memo() children)
3. Dependencies of other hooks (useEffect deps)
4. Value used in dependency array of another hook

DON'T USE WHEN:
1. The computation is cheap
2. The value is primitive (already stable reference)
3. No memoized children care about the reference
4. Premature optimization

RULE: Profile first, optimize second!
*/

function OptimizationDecision() {
    const [count,setCount]= useState(0);

    // ❌ Unnecessary - simple computation
    const doubled = useMemo(()=> count* 2, [count]);

    // ✅ Just do it directly
    const doubledSimple = count* 2;

    // ❌ Unnecessary - no memoized child uses this
    const handleClick = useCallback(()=> {
        console.log('clicked');
    }, []);

    // ✅ Necessary - passed to memoized child
    const handleItemClick = useCallback((id)=> {
        setSelected(id);
    }, []);

    return (
        <div>
            <button onClick={handleClick}>Click</button>
            <MemoizedChild onItemClick={handleItemClick} />
        </div>
    );
}

