import { createContext, useContext, useState, useMemo }from 'react';

/*
CONTEXT MENTAL MODEL:

┌─────────────────────────────────────────────────────────────┐
│                                                             │
│  Context provides a way to pass data through the            │
│  component tree without manually passing props at           │
│  every level ("prop drilling")                              │
│                                                             │
│       App (Provider)                                        │
│        ├── Header                                           │
│        │    └── UserMenu (Consumer) ← Gets value directly   │
│        ├── Sidebar                                          │
│        │    └── UserInfo (Consumer) ← Gets value directly   │
│        └── Main                                             │
│             └── Content                                     │
│                  └── UserProfile (Consumer)                 │
│                                                             │
└─────────────────────────────────────────────────────────────┘
*/

// ═══════════════════════════════════════════════════════════
// BASIC CONTEXT PATTERN
// ═══════════════════════════════════════════════════════════

// 1. Create context
const ThemeContext = createContext(null);

// 2. Create provider component
function ThemeProvider({children }) {
    const [theme,setTheme]= useState('light');

    const toggleTheme = ()=> {
        setTheme(prev => prev=== 'light' ? 'dark' : 'light');
    };

    // Memoize value to prevent unnecessary re-renders
    const value = useMemo(()=> ({
        theme,
        toggleTheme
    }), [theme]);

    return (
        <ThemeContext.Provider value={value}>
            {children}
        </ThemeContext.Provider>
    );
}

// 3. Create custom hook for consuming
function useTheme() {
    const context = useContext(ThemeContext);

    if (context=== null) {
        throw new Error('useTheme must be used within ThemeProvider');
    }

    return context;
}

// 4. Use in components
function ThemedButton() {
    const {theme,toggleTheme }= useTheme();

    return (
        <button
            style={{
                backgroundColor: theme=== 'light' ? '#fff' : '#333',
                color: theme=== 'light' ? '#333' : '#fff'
            }}
            onClick={toggleTheme}
        >
            Toggle Theme
        </button>
    );
}

// 5. Wrap app with provider
function App() {
    return (
        <ThemeProvider>
            <Header />
            <Main />
            <Footer />
        </ThemeProvider>
    );
}

