// Action types
const TODO_ACTIONS = {
    ADD:'ADD',
    REMOVE:'REMOVE',
    TOGGLE:'TOGGLE',
    EDIT:'EDIT',
    CLEAR_COMPLETED:'CLEAR_COMPLETED',
    TOGGLE_ALL:'TOGGLE_ALL',
    SET_FILTER:'SET_FILTER'
};

// Initial state
const initialTodoState = {
    todos: [],
    filter:'all',// 'all' | 'active' | 'completed'
    nextId:1
};

// Reducer
function todoReducer(state,action) {
    switch (action.type) {
        case TODO_ACTIONS.ADD:
            return {
                ...state,
                todos: [
                    ...state.todos,
                    {
                        id: state.nextId,
                        text: action.payload,
                        completed:false
                    }
                ],
                nextId: state.nextId+ 1
            };

        case TODO_ACTIONS.REMOVE:
            return {
                ...state,
                todos: state.todos.filter(todo => todo.id!== action.payload)
            };

        case TODO_ACTIONS.TOGGLE:
            return {
                ...state,
                todos: state.todos.map(todo =>
                    todo.id=== action.payload
                        ? {...todo, completed:!todo.completed }
                        : todo
                )
            };

        case TODO_ACTIONS.EDIT:
            return {
                ...state,
                todos: state.todos.map(todo =>
                    todo.id=== action.payload.id
                        ? {...todo, text: action.payload.text }
                        : todo
                )
            };

        case TODO_ACTIONS.CLEAR_COMPLETED:
            return {
                ...state,
                todos: state.todos.filter(todo => !todo.completed)
            };

        case TODO_ACTIONS.TOGGLE_ALL:
            const allCompleted = state.todos.every(todo => todo.completed);
            return {
                ...state,
                todos: state.todos.map(todo => ({
                    ...todo,
                    completed:!allCompleted
                }))
            };

        case TODO_ACTIONS.SET_FILTER:
            return {
                ...state,
                filter: action.payload
            };

        default:
            return state;
    }
}

// Action creators (optional but helpful)
const todoActions = {
    add: (text)=> ({ type:TODO_ACTIONS.ADD, payload: text }),
    remove: (id)=> ({ type:TODO_ACTIONS.REMOVE, payload: id }),
    toggle: (id)=> ({ type:TODO_ACTIONS.TOGGLE, payload: id }),
    edit: (id,text)=> ({ type:TODO_ACTIONS.EDIT, payload: { id, text } }),
    clearCompleted: ()=> ({ type:TODO_ACTIONS.CLEAR_COMPLETED }),
    toggleAll: ()=> ({ type:TODO_ACTIONS.TOGGLE_ALL }),
    setFilter: (filter)=> ({ type:TODO_ACTIONS.SET_FILTER, payload: filter })
};

function TodoApp() {
    const [state,dispatch]= useReducer(todoReducer, initialTodoState);
    const [inputValue,setInputValue]= useState('');

    const filteredTodos = useMemo(()=> {
        switch (state.filter) {
            case 'active':
                return state.todos.filter(todo => !todo.completed);
            case 'completed':
                return state.todos.filter(todo => todo.completed);
            default:
                return state.todos;
        }
    }, [state.todos, state.filter]);

    const handleSubmit = (e)=> {
        e.preventDefault();
        if (inputValue.trim()) {
            dispatch(todoActions.add(inputValue.trim()));
            setInputValue('');
        }
    };

    return (
        <div className="todo-app">
            <form onSubmit={handleSubmit}>
                <input
                    value={inputValue}
                    onChange={(e)=> setInputValue(e.target.value)}
