// ═══════════════════════════════════════════════════════════
// useAsync - Complete async state management
// ═══════════════════════════════════════════════════════════

function useAsync(asyncFunction,immediate = true) {
    const [status,setStatus]= useState('idle');
    const [data,setData]= useState(null);
    const [error,setError]= useState(null);

    const execute = useCallback(async (...params)=> {
        setStatus('pending');
        setError(null);

        try {
            const response = await asyncFunction(...params);
            setData(response);
            setStatus('success');
            return response;
        }catch (err) {
            setError(err);
            setStatus('error');
            throw err;
        }
    }, [asyncFunction]);

    useEffect(()=> {
        if (immediate) {
            execute();
        }
    }, [execute, immediate]);

    return {
        execute,
        status,
        data,
        error,
        isIdle: status=== 'idle',
        isPending: status=== 'pending',
        isSuccess: status=== 'success',
        isError: status=== 'error'
    };
}

// ═══════════════════════════════════════════════════════════
// useForm - Form state management
// ═══════════════════════════════════════════════════════════

function useForm(initialValues,validate) {
    const [values,setValues]= useState(initialValues);
    const [errors,setErrors]= useState({});
    const [touched,setTouched]= useState({});
    const [isSubmitting,setIsSubmitting]= useState(false);

    const handleChange = useCallback((e)=> {
        const {name,value,type,checked }= e.target;
        setValues(prev => ({
            ...prev,
            [name]: type=== 'checkbox' ? checked: value
        }));
    }, []);

    const handleBlur = useCallback((e)=> {
        const {name }= e.target;
        setTouched(prev => ({...prev, [name]:true }));
    }, []);

    const handleSubmit = useCallback((onSubmit)=> async (e)=> {
        e.preventDefault();

        // Validate all fields
        const validationErrors = validate? validate(values): {};
        setErrors(validationErrors);

        // Mark all as touched
        const allTouched = Object.keys(values).reduce(
            (acc,key)=> ({...acc, [key]:true }), {}
        );
        setTouched(allTouched);

        // If no errors, submit
        if (Object.keys(validationErrors).length === 0) {
            setIsSubmitting(true);
            try {
                await onSubmit(values);
            }finally {
                setIsSubmitting(false);
            }
        }
    }, [values, validate]);

    const reset = useCallback(()=> {
        setValues(initialValues);
        setErrors({});
        setTouched({});
        setIsSubmitting(false);
    }, [initialValues]);

    const setFieldValue = useCallback((name,value)=> {
        setValues(prev => ({...prev, [name]: value }));
    }, []);

    const setFieldError = useCallback((name,error)=> {
        setErrors(prev => ({...prev, [name]: error }));
    }, []);

    return {
        values,
        errors,
        touched,
        isSubmitting,
        handleChange,
        handleBlur,
        handleSubmit,
        reset,
        setFieldValue,
        setFieldError,
        getFieldProps: (name)=> ({
            name,
            value: values[name]|| '',
            onChange: handleChange,
            onBlur: handleBlur
        }),
        getFieldMeta: (name)=> ({
            touched: touched[name],
            error: errors[name]
        })
    };
}

// Usage
function SignupForm() {
    const validate = (values)=> {
        const errors = {};
        if (!values.email) errors.email= 'Required';
        else if (!/\S+@\S+\.\S+/.test(values.email)) errors.email= 'Invalid email';
        if (!values.password) errors.password= 'Required';
        else if (values.password.length < 8) errors.password= 'Min 8 characters';
        return errors;
    };

    const form = useForm({ email:'', password:'' }, validate);

    const onSubmit = async (values)=> {
        await registerUser(values);
    };

    return (
        <form onSubmit={form.handleSubmit(onSubmit)}>
            <div>
                <input {...form.getFieldProps('email')}type="email" />
                {form.touched.email&& form.errors.email&& (
                    <span className="error">{form.errors.email}</span>
                )}
            </div>
            <div>
                <input {...form.getFieldProps('password')}type="password" />
                {form.touched.password&& form.errors.password&& (
                    <span className="error">{form.errors.password}</span>
                )}
            </div>
            <button type="submit" disabled={form.isSubmitting}>
                {form.isSubmitting? 'Submitting...' : 'Sign Up'}
            </button>
        </form>
    );
}

