// ═══════════════════════════════════════════════════════════

/*
A component re-renders when:
1. Its state changes
2. Its props change
3. Its parent re-renders
4. Context it consumes changes
5. Custom hook state changes

RE-RENDER FLOW:
┌─────────────────────────────────────────────────────────────┐
│                                                             │
│  Parent re-renders                                          │
│       ↓                                                     │
│  All children re-render (by default)                        │
│       ↓                                                     │
│  React creates new virtual DOM                              │
│       ↓                                                     │
│  React diffs with previous virtual DOM                      │
│       ↓                                                     │
│  React updates only changed DOM nodes                       │
│                                                             │
└─────────────────────────────────────────────────────────────┘
*/

// ═══════════════════════════════════════════════════════════
// DEMONSTRATION OF RE-RENDERS
// ═══════════════════════════════════════════════════════════

function Parent() {
    const [count,setCount]= useState(0);
    console.log('Parent rendered');

    return (
        <div>
            <button onClick={()=> setCount(c => c+ 1)}>
                Count: {count}
            </button>
            <Child />          {/* Re-renders every time! */}
            <ExpensiveChild /> {/* Also re-renders! */}
        </div>
    );
}

function Child() {
    console.log('Child rendered');
    return <div>Child</div>;
}

function ExpensiveChild() {
    console.log('ExpensiveChild rendered');
    // Expensive computation here...
    return <div>Expensive Child</div>;
}

