// ═══════════════════════════════════════════════════════════
// React.memo - PREVENT UNNECESSARY RE-RENDERS
// ═══════════════════════════════════════════════════════════

import { memo, useState, useCallback, useMemo }from 'react';

// Wrap component with memo
const MemoizedChild = memo(function Child({name }) {
    console.log('Child rendered');
    return <div>Hello, {name}</div>;
});

// With custom comparison function
const MemoizedWithCompare = memo(
    function Child({user }) {
        return <div>{user.name}</div>;
    },
    (prevProps,nextProps)=> {
        // Return true if props are equal (skip re-render)
        // Return false if props are different (re-render)
        return prevProps.user.id=== nextProps.user.id;
    }
);

// ═══════════════════════════════════════════════════════════
// COMMON MEMO PITFALLS
// ═══════════════════════════════════════════════════════════

function Parent() {
    const [count,setCount]= useState(0);

    // ❌ PITFALL 1: Inline object - new reference every render
    return (
        <MemoizedChild
            style={{ color:'red' }}// New object every render!
            data={{ count }}// Memo is useless!
        />
    );

    // ✅ FIX: Memoize objects
    const style = useMemo(()=> ({ color:'red' }), []);
    const data = useMemo(()=> ({ count }), [count]);

    return <MemoizedChild style={style}data={data} />;
}

function Parent2() {
    const [count,setCount]= useState(0);

    // ❌ PITFALL 2: Inline function - new reference every render
    return (
        <MemoizedChild
            onClick={()=> console.log('clicked')}// New function!
        />
    );

    // ✅ FIX: useCallback
    const handleClick = useCallback(()=> {
        console.log('clicked');
    }, []);

    return <MemoizedChild onClick={handleClick} />;
}

function Parent3() {
    const [count,setCount]= useState(0);

    // ❌ PITFALL 3: Children as inline JSX
    return (
        <MemoizedWrapper>
            <div>This is a new element every render!</div>
        </MemoizedWrapper>
    );

    // ✅ FIX: Memoize children or use component reference
    const children = useMemo(()=> <div>Static content</div>, []);
    return <MemoizedWrapper>{children}</MemoizedWrapper>;
}

// ═══════════════════════════════════════════════════════════
// WHEN TO USE memo()
// ═══════════════════════════════════════════════════════════

/*
USE memo() WHEN:
1. Component renders often with same props
2. Component is expensive to render
3. Component receives primitive props or memoized objects

DON'T USE memo() WHEN:
1. Component already renders quickly
2. Props change most of the time
3. You're just guessing without measuring

ALWAYS PROFILE FIRST!
*/

// Good candidate for memo
const ExpensiveList = memo(function ExpensiveList({items,onItemClick }) {
    console.log('Rendering list with', items.length,'items');

    return (
        <ul>
            {items.map(item => (
                <li key={item.id}onClick={()=> onItemClick(item.id)}>
                    {/* Complex rendering */}
                    <ComplexItemRenderer item={item} />
                </li>
            ))}
        </ul>
    );
});

// Parent must provide stable props
function ParentWithStableProps() {
    const [selectedId,setSelectedId]= useState(null);
    const [items]= useState(generateItems());

    const handleItemClick = useCallback((id)=> {
        setSelectedId(id);
    }, []);

    return (
        <div>
            <p>Selected: {selectedId}</p>
            <ExpensiveList
                items={items}
                onItemClick={handleItemClick}
            />
        </div>
    );
}

