// ═══════════════════════════════════════════════════════════
// LIST VIRTUALIZATION
// ═══════════════════════════════════════════════════════════

import { useRef, useState, useCallback }from 'react';

// Simple virtualization implementation
function VirtualizedList({items,itemHeight,containerHeight }) {
    const [scrollTop,setScrollTop]= useState(0);
    const containerRef = useRef(null);

    // Calculate visible range
    const startIndex = Math.floor(scrollTop/ itemHeight);
    const endIndex = Math.min(
        startIndex+ Math.ceil(containerHeight/ itemHeight)+ 1,
        items.length
    );

    // Add buffer for smooth scrolling
    const bufferSize = 5;
    const visibleStartIndex = Math.max(0, startIndex- bufferSize);
    const visibleEndIndex = Math.min(items.length, endIndex+ bufferSize);

    const visibleItems = items.slice(visibleStartIndex, visibleEndIndex);

    const handleScroll = useCallback((e)=> {
        setScrollTop(e.target.scrollTop);
    }, []);

    const totalHeight = items.length * itemHeight;
    const offsetY = visibleStartIndex* itemHeight;

    return (
        <div
            ref={containerRef}
            onScroll={handleScroll}
            style={{
                height: containerHeight,
                overflow:'auto'
            }}
        >
            {/* Spacer to maintain scroll height */}
            <div style={{ height: totalHeight, position:'relative' }}>
                {/* Positioned items */}
                <div style={{
                    position:'absolute',
                    top: offsetY,
                    left:0,
                    right:0
                }}>
                    {visibleItems.map((item,index)=> (
                        <div
                            key={item.id}
                            style={{ height: itemHeight }}
                        >
                            {item.content}
                        </div>
                    ))}
                </div>
            </div>
        </div>
    );
}

