### 🎯 4.2 React Fiber Architecture

```
// ═══════════════════════════════════════════════════════════
// FIBER ARCHITECTURE EXPLAINED
// ═══════════════════════════════════════════════════════════

/*
FIBER is React's internal reconciliation algorithm (React 16+)

PROBLEMS WITH OLD RECONCILER (Stack Reconciler):
- Synchronous, recursive processing
- Couldn't pause work
- Long updates blocked main thread
- No prioritization

FIBER SOLUTIONS:
1. INCREMENTAL RENDERING
   - Split work into chunks
   - Can pause, abort, or resume work
   - Yields to browser between chunks

2. PRIORITY LEVELS
   - High: User interactions, animations
   - Normal: Data updates
   - Low: Analytics, non-visible updates

3. CONCURRENT MODE
   - Multiple versions of UI in memory
   - Seamless transitions

FIBER NODE STRUCTURE:
┌─────────────────────────────────────────────────────────────┐
│                                                             │
│  FiberNode {                                                │
│    type: Component/string,                                  │
│    key: string | null,                                      │
│    props: object,                                           │
│    stateNode: DOM node | Component instance,                │
│                                                             │
│    // Fiber links (linked list)                             │
│    return: Fiber | null,      // parent                     │
│    child: Fiber | null,       // first child                │
│    sibling: Fiber | null,     // next sibling               │
│                                                             │
│    // Work tracking                                         │
│    alternate: Fiber | null,   // previous version           │
│    effectTag: number,         // what to do                 │
│    nextEffect: Fiber | null,  // next fiber with effect     │
│  }                                                          │
│                                                             │
└─────────────────────────────────────────────────────────────┘

FIBER TREE VISUALIZATION:

         App (Fiber)
         ├── child → Header (Fiber)
         │            ├── child → Logo
         │            └── sibling → Nav
         ├── sibling → null
         └── return → HostRoot

WORK LOOP:
┌─────────────────────────────────────────────────────────────┐
│                                                             │
│  while (workInProgress !== null && !shouldYield()) {        │
│      workInProgress = performUnitOfWork(workInProgress);    │
│  }                                                          │
│                                                             │
│  // If there's more work, schedule next chunk               │
│  if (workInProgress !== null) {                             │
│      requestIdleCallback(workLoop);                         │
│  }                                                          │
│                                                             │
└─────────────────────────────────────────────────────────────┘
*/

// ═══════════════════════════════════════════════════════════
// PHASES IN FIBER
// ═══════════════════════════════════════════════════════════

/*
TWO MAIN PHASES:

PHASE 1: RENDER (Reconciliation) - INTERRUPTIBLE
- Build work-in-progress fiber tree
- Calculate changes needed
- Can be paused, aborted, restarted
- No side effects!

Called lifecycle methods (Class Components):
- constructor
- getDerivedStateFromProps
- shouldComponentUpdate
- render

PHASE 2: COMMIT - SYNCHRONOUS, UNINTERRUPTIBLE
- Apply all changes to DOM
- Run effects and lifecycle methods
- Must complete in one go

Called lifecycle methods:
- getSnapshotBeforeUpdate
- componentDidMount
- componentDidUpdate
- componentWillUnmount
*/

// ═══════════════════════════════════════════════════════════
// CONCURRENT FEATURES
// ═══════════════════════════════════════════════════════════

import {
    useTransition,
    useDeferredValue,
    startTransition
}from 'react';

// useTransition - Mark updates as non-urgent
function SearchResults() {
    const [query,setQuery]= useState('');
    const [results,setResults]= useState([]);
    const [isPending,startTransition]= useTransition();

    const handleChange = (e)=> {
        // Urgent: Update input immediately
        setQuery(e.target.value);

        // Non-urgent: Can be interrupted
        startTransition(()=> {
            setResults(searchFor(e.target.value));
        });
    };

    return (
        <div>
            <input value={query}onChange={handleChange} />
            {isPending&& <Spinner />}
            <ResultsList results={results} />
        </div>
    );
}

// useDeferredValue - Defer a value update
function FilteredList({query,items }) {
    // deferredQuery lags behind query during heavy updates
    const deferredQuery = useDeferredValue(query);

    // Show stale results while computing new ones
    const isStale = query!== deferredQuery;

    const filteredItems = useMemo(
        ()=> items.filter(item =>
            item.name.toLowerCase().includes(deferredQuery.toLowerCase())
        ),
        [items, deferredQuery]
    );

    return (
        <div style={{ opacity: isStale? 0.7 : 1 }}>
            <ul>
                {filteredItems.map(item => (
                    <li key={item.id}>{item.name}</li>
                ))}
            </ul>
        </div>
    );
}

// startTransition - Outside component
function handleTabChange(setTab,tab) {
    startTransition(()=> {
        setTab(tab);
    });
}

