// ═══════════════════════════════════════════════════════════
// ADVANCED ERROR BOUNDARY WITH RESET CAPABILITY
// ═══════════════════════════════════════════════════════════

interface AdvancedErrorBoundaryProps {
    children: ReactNode;
    fallbackRender?: (props: {
        error: Error;
        resetError: () => void;
    }) => ReactNode;
    onReset?: () => void;
    resetKeys?: any[];
}

class AdvancedErrorBoundary extends Component<
    AdvancedErrorBoundaryProps,
    ErrorBoundaryState
> {
    constructor(props: AdvancedErrorBoundaryProps) {
        super(props);
        this.state = {
            hasError: false,
            error: null,
            errorInfo: null
        };
    }

    static getDerivedStateFromError(error: Error): Partial<ErrorBoundaryState> {
        return { hasError: true, error };
    }

    componentDidCatch(error: Error, errorInfo: ErrorInfo): void {
        this.setState({ errorInfo });
    }

    // Reset when resetKeys change
    componentDidUpdate(prevProps: AdvancedErrorBoundaryProps): void {
        if (this.state.hasError && this.props.resetKeys) {
            const hasResetKeyChanged = this.props.resetKeys.some(
                (key, index) => key !== prevProps.resetKeys?.[index]
            );

            if (hasResetKeyChanged) {
                this.resetError();
            }
        }
    }

    resetError = (): void => {
        this.props.onReset?.();
        this.setState({
            hasError: false,
            error: null,
            errorInfo: null
        });
    };

    render(): ReactNode {
        if (this.state.hasError && this.state.error) {
            if (this.props.fallbackRender) {
                return this.props.fallbackRender({
                    error: this.state.error,
                    resetError: this.resetError
                });
            }

            return (
                <div>
                    <h2>Error occurred</h2>
                    <button onClick={this.resetError}>Retry</button>
                </div>
            );
        }

        return this.props.children;
    }
}

// ═══════════════════════════════════════════════════════════
// ERROR BOUNDARY HOOK (using react-error-boundary library pattern)
// ═══════════════════════════════════════════════════════════

import { useState, useCallback } from 'react';

interface UseErrorBoundaryReturn {
    error: Error | null;
    resetError: () => void;
    showBoundary: (error: Error) => void;
}

function useErrorBoundary(): UseErrorBoundaryReturn {
    const [error, setError] = useState<Error | null>(null);

    const resetError = useCallback(() => {
        setError(null);
    }, []);

    const showBoundary = useCallback((error: Error) => {
        setError(error);
    }, []);

    if (error) {
        throw error; // Re-throw to be caught by ErrorBoundary
    }

    return { error, resetError, showBoundary };
}

// Usage in component
function DataFetcher() {
    const { showBoundary } = useErrorBoundary();

    const fetchData = async () => {
        try {
            const response = await fetch('/api/data');
            if (!response.ok) {
                throw new Error('Failed to fetch');
            }
            return response.json();
        } catch (error) {
            showBoundary(error as Error);
        }
    };

    return <button onClick={fetchData}>Fetch Data</button>;
}

// ═══════════════════════════════════════════════════════════
// SPECIALIZED ERROR BOUNDARIES
// ═══════════════════════════════════════════════════════════

// API Error Boundary
interface ApiError extends Error {
    status?: number;
    code?: string;
}

class ApiErrorBoundary extends Component<
    { children: ReactNode },
    { error: ApiError | null }
> {
    state = { error: null };

    static getDerivedStateFromError(error: ApiError) {
        return { error };
    }

    render() {
        const { error } = this.state;

        if (error) {
            switch (error.status) {
                case 401:
                    return <RedirectToLogin />;
                case 403:
                    return <AccessDenied />;
                case 404:
                    return <NotFound />;
                case 500:
                    return <ServerError onRetry={() => this.setState({ error: null })} />;
                default:
                    return <GenericError error={error} />;
            }
        }

        return this.props.children;
    }
}

// Feature-specific Error Boundary
function FeatureErrorBoundary({
    children,
    featureName
}: {
    children: ReactNode;
    featureName: string;
}) {
    return (
        <ErrorBoundary
            fallback={
                <div className="feature-error">
                    <h3>{featureName} is temporarily unavailable</h3>
                    <p>Please try again later</p>
                </div>
            }
            onError={(error, info) => {
                // Log with feature context
                logError({
                    feature: featureName,
                    error: error.message,
                    stack: info.componentStack
                });
            }}
        >
            {children}
        </ErrorBoundary>
    );
}

