// ERROR BOUNDARY USAGE PATTERNS
// ═══════════════════════════════════════════════════════════

function App() {
    return (
        // Top-level boundary for catastrophic errors
        <ErrorBoundary
            fallback={<FullPageError />}
            onError={(error) => reportCriticalError(error)}
        >
            <Header />

            <main>
                {/* Feature-level boundaries */}
                <FeatureErrorBoundary featureName="Dashboard">
                    <Dashboard />
                </FeatureErrorBoundary>

                <FeatureErrorBoundary featureName="User Profile">
                    <UserProfile />
                </FeatureErrorBoundary>

