// ═══════════════════════════════════════════════════════════
// HANDLING ASYNC ERRORS
// ═══════════════════════════════════════════════════════════

// Error boundaries don't catch async errors by default
// Use this pattern to handle them:

function useAsyncError() {
    const [_, setError] = useState();

    return useCallback((error: Error) => {
        setError(() => {
            throw error;
        });
    }, []);
}

function AsyncComponent() {
    const throwError = useAsyncError();

    useEffect(() => {
        async function fetchData() {
            try {
                await someAsyncOperation();
            } catch (error) {
                throwError(error as Error); // Will be caught by ErrorBoundary
            }
        }

        fetchData();
    }, [throwError]);

    return <div>Content</div>;
}

// ═══════════════════════════════════════════════════════════
// SUSPENSE + ERROR BOUNDARY COMBINATION
// ═══════════════════════════════════════════════════════════

import { Suspense } from 'react';

function DataSection() {
    return (
        <ErrorBoundary fallback={<ErrorFallback />}>
            <Suspense fallback={<LoadingSpinner />}>
                <AsyncDataComponent />
            </Suspense>
        </ErrorBoundary>
    );
}

// Combined component for common pattern
function AsyncBoundary({
    children,
    loadingFallback,
    errorFallback
}: {
    children: ReactNode;
    loadingFallback: ReactNode;
    errorFallback: ReactNode;
}) {
    return (
        <ErrorBoundary fallback={errorFallback}>
            <Suspense fallback={loadingFallback}>
                {children}
            </Suspense>
        </ErrorBoundary>
    );
}

