### 4.4 Portals

```
// ═══════════════════════════════════════════════════════════
// WHAT ARE PORTALS?
// ═══════════════════════════════════════════════════════════

/*
╔═══════════════════════════════════════════════════════════════╗
║                       REACT PORTALS                           ║
╠═══════════════════════════════════════════════════════════════╣
║                                                               ║
║  Portals render children into a DOM node outside the parent  ║
║  component's DOM hierarchy, while maintaining React's         ║
║  component hierarchy (events bubble up, context works, etc.)  ║
║                                                               ║
║  Use cases:                                                   ║
║  • Modals and dialogs                                         ║
║  • Tooltips and popovers                                      ║
║  • Floating menus                                             ║
║  • Notifications/Toasts                                       ║
║                                                               ║
╚═══════════════════════════════════════════════════════════════╝
*/

import { createPortal } from 'react-dom';
import { ReactNode, useEffect, useState, useRef } from 'react';

// ═══════════════════════════════════════════════════════════
// BASIC PORTAL
// ═══════════════════════════════════════════════════════════

function Portal({ children }: { children: ReactNode }) {
    const [mounted, setMounted] = useState(false);

    useEffect(() => {
        setMounted(true);
        return () => setMounted(false);
    }, []);

    if (!mounted) return null;

    return createPortal(
        children,
        document.body
    );
}

// ═══════════════════════════════════════════════════════════
// PORTAL WITH CUSTOM CONTAINER
// ═══════════════════════════════════════════════════════════

interface PortalProps {
    children: ReactNode;
    containerId?: string;
}

function CustomPortal({ children, containerId = 'portal-root' }: PortalProps) {
    const [container, setContainer] = useState<HTMLElement | null>(null);

    useEffect(() => {
        let portalContainer = document.getElementById(containerId);
        let created = false;

        if (!portalContainer) {
            portalContainer = document.createElement('div');
            portalContainer.id = containerId;
            document.body.appendChild(portalContainer);
            created = true;
        }

        setContainer(portalContainer);

        return () => {
            if (created && portalContainer?.parentNode) {
                portalContainer.parentNode.removeChild(portalContainer);
            }
        };
    }, [containerId]);

    if (!container) return null;

    return createPortal(children, container);
}
// ═══════════════════════════════════════════════════════════
// MODAL COMPONENT WITH PORTAL
// ═══════════════════════════════════════════════════════════

interface ModalProps {
    isOpen: boolean;
    onClose: () => void;
    title?: string;
    children: ReactNode;
    closeOnOverlayClick?: boolean;
    closeOnEscape?: boolean;
}

function Modal({
    isOpen,
    onClose,
    title,
    children,
    closeOnOverlayClick = true,
    closeOnEscape = true
}: ModalProps) {
    const modalRef = useRef<HTMLDivElement>(null);
    const previousActiveElement = useRef<Element | null>(null);

    // Handle escape key
    useEffect(() => {
        if (!isOpen || !closeOnEscape) return;

        const handleEscape = (e: KeyboardEvent) => {
            if (e.key === 'Escape') {
                onClose();
            }
        };

        document.addEventListener('keydown', handleEscape);
        return () => document.removeEventListener('keydown', handleEscape);
    }, [isOpen, closeOnEscape, onClose]);

    // Trap focus and manage body scroll
    useEffect(() => {
        if (!isOpen) return;

        // Save current focus
        previousActiveElement.current = document.activeElement;

        // Focus modal
        modalRef.current?.focus();

        // Prevent body scroll
        const originalOverflow = document.body.style.overflow;
        document.body.style.overflow = 'hidden';

        return () => {
            document.body.style.overflow = originalOverflow;
            // Restore focus
            (previousActiveElement.current as HTMLElement)?.focus();
        };
    }, [isOpen]);

    // Focus trap
    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key !== 'Tab') return;

        const focusableElements = modalRef.current?.querySelectorAll(
            'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
        );

        if (!focusableElements?.length) return;

        const firstElement = focusableElements[0] as HTMLElement;
        const lastElement = focusableElements[focusableElements.length - 1] as HTMLElement;

        if (e.shiftKey && document.activeElement === firstElement) {
            e.preventDefault();
            lastElement.focus();
        } else if (!e.shiftKey && document.activeElement === lastElement) {
            e.preventDefault();
            firstElement.focus();
        }
    };

    if (!isOpen) return null;

    return createPortal(
        <div
            className="modal-overlay"
            onClick={closeOnOverlayClick ? onClose : undefined}
            aria-modal="true"
            role="dialog"
            aria-labelledby="modal-title"
        >
            <div
                ref={modalRef}
                className="modal-content"
                onClick={(e) => e.stopPropagation()}
                onKeyDown={handleKeyDown}
                tabIndex={-1}
            >
                <header className="modal-header">
                    {title && <h2 id="modal-title">{title}</h2>}
                    <button
                        onClick={onClose}
                        aria-label="Close modal"
                        className="modal-close"
                    >
                        ×
                    </button>
                </header>
                <div className="modal-body">
                    {children}
                </div>
            </div>
        </div>,
        document.body
    );
}

// Modal CSS
const modalStyles = `
.modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.5);
