```
// ═══════════════════════════════════════════════════════════
// TOOLTIP WITH PORTAL
// ═══════════════════════════════════════════════════════════

interface TooltipProps {
    content: ReactNode;
    children: ReactNode;
    position?: 'top' | 'bottom' | 'left' | 'right';
    delay?: number;
}

function Tooltip({
    content,
    children,
    position = 'top',
    delay = 200
}: TooltipProps) {
    const [isVisible, setIsVisible] = useState(false);
    const [coords, setCoords] = useState({ x: 0, y: 0 });
    const triggerRef = useRef<HTMLDivElement>(null);
    const timeoutRef = useRef<NodeJS.Timeout>();

    const showTooltip = () => {
        timeoutRef.current = setTimeout(() => {
            if (triggerRef.current) {
                const rect = triggerRef.current.getBoundingClientRect();

                let x = rect.left + rect.width / 2;
                let y = rect.top;

                switch (position) {
                    case 'bottom':
                        y = rect.bottom;
                        break;
                    case 'left':
                        x = rect.left;
                        y = rect.top + rect.height / 2;
                        break;
                    case 'right':
                        x = rect.right;
                        y = rect.top + rect.height / 2;
                        break;
                }

                setCoords({ x, y });
                setIsVisible(true);
            }
        }, delay);
    };

    const hideTooltip = () => {
        if (timeoutRef.current) {
            clearTimeout(timeoutRef.current);
        }
        setIsVisible(false);
    };

    useEffect(() => {
        return () => {
            if (timeoutRef.current) {
                clearTimeout(timeoutRef.current);
            }
        };
    }, []);

    return (
        <>
            <div
                ref={triggerRef}
                onMouseEnter={showTooltip}
                onMouseLeave={hideTooltip}
                onFocus={showTooltip}
                onBlur={hideTooltip}
            >
                {children}
            </div>

            {isVisible && createPortal(
                <div
                    className={`tooltip tooltip-${position}`}
                    style={{
                        position: 'fixed',
                        left: coords.x,
                        top: coords.y,
                        transform: getTooltipTransform(position)
                    }}
                    role="tooltip"
                >
                    {content}
                </div>,
                document.body
            )}
        </>
    );
}

function getTooltipTransform(position: string): string {
    switch (position) {
        case 'top': return 'translate(-50%, -100%) translateY(-8px)';
        case 'bottom': return 'translate(-50%, 0) translateY(8px)';
        case 'left': return 'translate(-100%, -50%) translateX(-8px)';
        case 'right': return 'translate(0, -50%) translateX(8px)';
        default: return '';
    }
}

// ═══════════════════════════════════════════════════════════
// NOTIFICATION/TOAST SYSTEM WITH PORTAL
// ═══════════════════════════════════════════════════════════

interface Toast {
    id: string;
    message: string;
    type: 'success' | 'error' | 'warning' | 'info';
    duration?: number;
}

interface ToastContextValue {
    addToast: (toast: Omit<Toast, 'id'>) => void;
    removeToast: (id: string) => void;
}

const ToastContext = createContext<ToastContextValue | null>(null);

function ToastProvider({ children }: { children: ReactNode }) {
    const [toasts, setToasts] = useState<Toast[]>([]);

    const addToast = useCallback((toast: Omit<Toast, 'id'>) => {
        const id = crypto.randomUUID();
        setToasts(prev => [...prev, { ...toast, id }]);

        // Auto remove after duration
        if (toast.duration !== 0) {
            setTimeout(() => {
                removeToast(id);
            }, toast.duration || 5000);
        }
    }, []);

    const removeToast = useCallback((id: string) => {
        setToasts(prev => prev.filter(t => t.id !== id));
    }, []);

    return (
        <ToastContext.Provider value={{ addToast, removeToast }}>
            {children}
            {createPortal(
                <div className="toast-container">
                    {toasts.map(toast => (
                        <div
                            key={toast.id}
                            className={`toast toast-${toast.type}`}
                            role="alert"
                        >
                            <span>{toast.message}</span>
                            <button
                                onClick={() => removeToast(toast.id)}
                                aria-label="Dismiss"
                            >
                                ×
                            </button>
                        </div>
                    ))}
                </div>,
                document.body
            )}
        </ToastContext.Provider>
    );
}

function useToast() {
    const context = useContext(ToastContext);
    if (!context) {
        throw new Error('useToast must be used within ToastProvider');
    }
    return context;
}

// Usage
function NotificationExample() {
    const { addToast } = useToast();

    return (
        <button
            onClick={() => addToast({
                message: 'Operation successful!',
                type: 'success'
            })}
        >
            Show Toast
        </button>
    );
}

// ═══════════════════════════════════════════════════════════
// DROPDOWN MENU WITH PORTAL
// ═══════════════════════════════════════════════════════════

interface DropdownProps {
    trigger: ReactNode;
    children: ReactNode;
    align?: 'left' | 'right';
}

function Dropdown({ trigger, children, align = 'left' }: DropdownProps) {
    const [isOpen, setIsOpen] = useState(false);
    const [position, setPosition] = useState({ top: 0, left: 0 });
    const triggerRef = useRef<HTMLButtonElement>(null);
    const menuRef = useRef<HTMLDivElement>(null);

    // Calculate position when opening
    useEffect(() => {
        if (isOpen && triggerRef.current) {
            const rect = triggerRef.current.getBoundingClientRect();
            setPosition({
                top: rect.bottom + window.scrollY,
                left: align === 'left'
                    ? rect.left + window.scrollX
                    : rect.right + window.scrollX
            });
        }
    }, [isOpen, align]);

    // Close on outside click
    useEffect(() => {
        if (!isOpen) return;

        const handleClickOutside = (e: MouseEvent) => {
            if (
                !triggerRef.current?.contains(e.target as Node) &&
                !menuRef.current?.contains(e.target as Node)
            ) {
                setIsOpen(false);
            }
        };

        document.addEventListener('click', handleClickOutside);
        return () => document.removeEventListener('click', handleClickOutside);
    }, [isOpen]);

    return (
        <>
            <button
                ref={triggerRef}
                onClick={() => setIsOpen(!isOpen)}
                aria-haspopup="true"
                aria-expanded={isOpen}
            >
                {trigger}
            </button>

            {isOpen && createPortal(
                <div
                    ref={menuRef}
                    className="dropdown-menu"
                    style={{
                        position: 'absolute',
                        top: position.top,
                        left: position.left,
                        transform: align === 'right' ? 'translateX(-100%)' : 'none'
                    }}
                    role="menu"
                >
                    {children}
                </div>,
                document.body
            )}
        </>
    );
}

