## 4.5 Refs and ForwardRef

```
// ═══════════════════════════════════════════════════════════
// UNDERSTANDING REFS
// ═══════════════════════════════════════════════════════════

/*
╔═══════════════════════════════════════════════════════════════╗
║                         REACT REFS                            ║
╠═══════════════════════════════════════════════════════════════╣
║                                                               ║
║  Refs provide a way to:                                       ║
║  • Access DOM elements directly                               ║
║  • Store mutable values that don't trigger re-renders         ║
║  • Reference child component instances                        ║
║                                                               ║
║  When to use refs:                                            ║
║  • Managing focus, text selection, media playback             ║
║  • Triggering imperative animations                           ║
║  • Integrating with third-party DOM libraries                 ║
║  • Storing previous values or interval IDs                    ║
║                                                               ║
╚═══════════════════════════════════════════════════════════════╝
*/

import {
    useRef,
    useEffect,
    useImperativeHandle,
    forwardRef,
    useCallback,
    RefObject,
    MutableRefObject
} from 'react';

// ═══════════════════════════════════════════════════════════
// BASIC REF USAGE
// ═══════════════════════════════════════════════════════════

// DOM element ref
function TextInput() {
    const inputRef = useRef<HTMLInputElement>(null);

    const focusInput = () => {
        inputRef.current?.focus();
    };

    const selectAll = () => {
        inputRef.current?.select();
    };

    return (
        <div>
            <input ref={inputRef} type="text" />
            <button onClick={focusInput}>Focus</button>
            <button onClick={selectAll}>Select All</button>
        </div>
    );
}

// Mutable value ref (doesn't trigger re-render)
function Timer() {
    const [count, setCount] = useState(0);
    const intervalRef = useRef<NodeJS.Timeout | null>(null);
    const countRef = useRef(count); // Track current count

    // Keep countRef in sync with count
    useEffect(() => {
        countRef.current = count;
    }, [count]);

    const start = () => {
        if (intervalRef.current) return;

        intervalRef.current = setInterval(() => {
            setCount(prev => prev + 1);
        }, 1000);
    };

    const stop = () => {
        if (intervalRef.current) {
            clearInterval(intervalRef.current);
            intervalRef.current = null;
        }
    };

    const logCount = () => {
        // Access current count without closure issues
        console.log('Current count:', countRef.current);
    };

    useEffect(() => {
        return () => stop();
    }, []);

    return (
        <div>
            <p>Count: {count}</p>
            <button onClick={start}>Start</button>
            <button onClick={stop}>Stop</button>
            <button onClick={logCount}>Log Count</button>
        </div>
    );
}
// ═══════════════════════════════════════════════════════════
// PREVIOUS VALUE REF
// ═══════════════════════════════════════════════════════════

function usePrevious<T>(value: T): T | undefined {
    const ref = useRef<T>();

    useEffect(() => {
        ref.current = value;
    }, [value]);

    return ref.current;
}

function Counter() {
    const [count, setCount] = useState(0);
    const prevCount = usePrevious(count);

    return (
        <div>
            <p>Current: {count}</p>
            <p>Previous: {prevCount}</p>
            <button onClick={() => setCount(c => c + 1)}>+</button>
        </div>
    );
}

// ═══════════════════════════════════════════════════════════
// CALLBACK REF
// ═══════════════════════════════════════════════════════════

function MeasuredComponent() {
    const [height, setHeight] = useState(0);

    // Callback ref - called when element is mounted/unmounted
    const measuredRef = useCallback((node: HTMLDivElement | null) => {
        if (node !== null) {
            setHeight(node.getBoundingClientRect().height);
        }
    }, []);

    return (
        <div>
            <div ref={measuredRef} style={{ padding: '20px' }}>
                Content with dynamic height
            </div>
            <p>Height: {height}px</p>
        </div>
    );
}

// Reusable callback ref hook
function useCallbackRef<T extends HTMLElement>(
    callback: (node: T | null) => void
): RefObject<T> {
    const ref = useRef<T>(null);

    const setRef = useCallback((node: T | null) => {
        // Handle old ref
        if (ref.current) {
            callback(null);
        }

        // Handle new ref
        if (node) {
            callback(node);
        }

        // @ts-ignore - we know this is safe
        ref.current = node;
    }, [callback]);

    return { current: ref.current } as RefObject<T>;
}

