// ═══════════════════════════════════════════════════════════
// COMPLEX FORM WITH IMPERATIVE HANDLE
// ═══════════════════════════════════════════════════════════

interface FormHandle {
    submit: () => void;
    reset: () => void;
    validate: () => boolean;
    getValues: () => Record<string, string>;
    setFieldValue: (field: string, value: string) => void;
    setFieldError: (field: string, error: string) => void;
}

interface FormFieldConfig {
    name: string;
    label: string;
    type?: string;
    required?: boolean;
    validate?: (value: string) => string | null;
}

interface FormProps {
    fields: FormFieldConfig[];
    onSubmit: (values: Record<string, string>) => void;
}

const Form = forwardRef<FormHandle, FormProps>(({ fields, onSubmit }, ref) => {
    const [values, setValues] = useState<Record<string, string>>({});
    const [errors, setErrors] = useState<Record<string, string>>({});

    useImperativeHandle(ref, () => ({
        submit() {
            if (this.validate()) {
                onSubmit(values);
            }
        },

        reset() {
            setValues({});
            setErrors({});
        },

        validate() {
            const newErrors: Record<string, string> = {};

            fields.forEach(field => {
                const value = values[field.name] || '';

                if (field.required && !value) {
                    newErrors[field.name] = `${field.label} is required`;
                } else if (field.validate) {
                    const error = field.validate(value);
                    if (error) {
                        newErrors[field.name] = error;
                    }
                }
            });

            setErrors(newErrors);
            return Object.keys(newErrors).length === 0;
        },

        getValues() {
            return { ...values };
        },

        setFieldValue(field: string, value: string) {
            setValues(prev => ({ ...prev, [field]: value }));
        },

        setFieldError(field: string, error: string) {
            setErrors(prev => ({ ...prev, [field]: error }));
        }
    }), [fields, values, onSubmit]);

    const handleChange = (name: string, value: string) => {
        setValues(prev => ({ ...prev, [name]: value }));
        // Clear error when user types
        if (errors[name]) {
            setErrors(prev => {
                const { [name]: _, ...rest } = prev;
                return rest;
            });
        }
    };

    return (
        <form onSubmit={(e) => e.preventDefault()}>
            {fields.map(field => (
                <div key={field.name} className="form-field">
                    <label htmlFor={field.name}>{field.label}</label>
                    <input
                        id={field.name}
                        type={field.type || 'text'}
                        value={values[field.name] || ''}
                        onChange={(e) => handleChange(field.name, e.target.value)}
                    />
                    {errors[field.name] && (
                        <span className="error">{errors[field.name]}</span>
                    )}
                </div>
            ))}
        </form>
    );
});

Form.displayName = 'Form';

// ═══════════════════════════════════════════════════════════
// MULTIPLE REFS
// ═══════════════════════════════════════════════════════════

// Merge multiple refs
function mergeRefs<T>(...refs: (RefObject<T> | ((instance: T | null) => void) | null)[]) {
    return (instance: T | null) => {
        refs.forEach(ref => {
            if (typeof ref === 'function') {
                ref(instance);
            } else if (ref) {
                (ref as MutableRefObject<T | null>).current = instance;
            }
        });
    };
}

const InputWithMultipleRefs = forwardRef<HTMLInputElement, InputProps>(
    (props, forwardedRef) => {
        const localRef = useRef<HTMLInputElement>(null);

        useEffect(() => {
            // Can use localRef for internal logic
            console.log('Input mounted:', localRef.current);
        }, []);

        return (
            <input
                ref={mergeRefs(localRef, forwardedRef)}
                {...props}
            />
        );
    }
);

// Hook for merging refs
function useMergedRef<T>(...refs: (RefObject<T> | ((instance: T | null) => void) | null)[]) {
    return useCallback(mergeRefs(...refs), refs);
}

// ═══════════════════════════════════════════════════════════
// REF WITH INTERSECTION OBSERVER
// ═══════════════════════════════════════════════════════════

function useIntersectionObserver<T extends HTMLElement>(
    options: IntersectionObserverInit = {}
): [RefObject<T>, boolean] {
    const ref = useRef<T>(null);
    const [isIntersecting, setIsIntersecting] = useState(false);

    useEffect(() => {
        const element = ref.current;
        if (!element) return;

        const observer = new IntersectionObserver(([entry]) => {
            setIsIntersecting(entry.isIntersecting);
        }, options);

        observer.observe(element);

        return () => observer.disconnect();
    }, [options.threshold, options.root, options.rootMargin]);

    return [ref, isIntersecting];
}

function LazyImage({ src, alt }: { src: string; alt: string }) {
    const [ref, isVisible] = useIntersectionObserver<HTMLDivElement>({
        threshold: 0.1
    });
    const [loaded, setLoaded] = useState(false);

    return (
        <div ref={ref} className="lazy-image-container">
            {isVisible && (
                <img
                    src={src}
                    alt={alt}
                    onLoad={() => setLoaded(true)}
                    className={loaded ? 'loaded' : 'loading'}
                />
            )}
            {!loaded && <div className="placeholder">Loading...</div>}
        </div>
    );
}

