## 5.1 Local State Patterns

```
// ═══════════════════════════════════════════════════════════
// STATE MANAGEMENT OVERVIEW
// ═══════════════════════════════════════════════════════════

/*
╔═══════════════════════════════════════════════════════════════╗
║                  STATE MANAGEMENT LAYERS                      ║
╠═══════════════════════════════════════════════════════════════╣
║                                                               ║
║  1. LOCAL STATE (useState, useReducer)                        ║
║     • Component-specific UI state                             ║
║     • Form inputs, toggles, modals                            ║
║                                                               ║
║  2. LIFTED STATE                                              ║
║     • Shared between siblings                                 ║
║     • Lifted to common ancestor                               ║
║                                                               ║
║  3. CONTEXT                                                   ║
║     • Theme, user authentication                              ║
║     • Data that many components need                          ║
║                                                               ║
║  4. EXTERNAL STATE (Redux, Zustand, etc.)                     ║
║     • Complex state logic                                     ║
║     • Time-travel debugging                                   ║
║     • Large applications                                      ║
║                                                               ║
║  5. SERVER STATE (React Query, SWR)                           ║
║     • Remote data fetching                                    ║
║     • Caching, synchronization                                ║
║                                                               ║
║  6. URL STATE                                                 ║
║     • Filters, pagination                                     ║
║     • Shareable/bookmarkable state                            ║
║                                                               ║
╚═══════════════════════════════════════════════════════════════╝
*/

// ═══════════════════════════════════════════════════════════
// USESTATE ADVANCED PATTERNS
// ═══════════════════════════════════════════════════════════

import { useState, useCallback, useMemo } from 'react';

// Pattern 1: Lazy initialization
function ExpensiveComponent() {
    // Function is called only once on initial render
    const [data, setData] = useState(() => {
        console.log('Computing initial state...');
        return computeExpensiveInitialState();
    });

    return <div>{data}</div>;
}

// Pattern 2: Object state
interface FormState {
    name: string;
    email: string;
    age: number;
}

function FormWithObjectState() {
    const [form, setForm] = useState<FormState>({
        name: '',
        email: '',
        age: 0
    });

    // Update single field
    const updateField = <K extends keyof FormState>(
        field: K,
        value: FormState[K]
    ) => {
        setForm(prev => ({ ...prev, [field]: value }));
    };

    // Reset form
    const resetForm = () => {
        setForm({ name: '', email: '', age: 0 });
    };

    return (
        <form>
            <input
                value={form.name}
                onChange={(e) => updateField('name', e.target.value)}
            />
            <input
                value={form.email}
                onChange={(e) => updateField('email', e.target.value)}
            />
            <input
                type="number"
                value={form.age}
                onChange={(e) => updateField('age', parseInt(e.target.value))}
            />
            <button type="button" onClick={resetForm}>Reset</button>
        </form>
    );
}

// Pattern 3: Array state
interface Todo {
    id: string;
    text: string;
    completed: boolean;
}

function TodoList() {
    const [todos, setTodos] = useState<Todo[]>([]);

    const addTodo = (text: string) => {
        setTodos(prev => [
            ...prev,
            { id: crypto.randomUUID(), text, completed: false }
        ]);
    };

    const toggleTodo = (id: string) => {
        setTodos(prev => prev.map(todo =>
            todo.id === id
                ? { ...todo, completed: !todo.completed }
                : todo
        ));
    };

    const removeTodo = (id: string) => {
        setTodos(prev => prev.filter(todo => todo.id !== id));
    };

    const updateTodo = (id: string, text: string) => {
        setTodos(prev => prev.map(todo =>
            todo.id === id ? { ...todo, text } : todo
        ));
    };

    const reorderTodos = (fromIndex: number, toIndex: number) => {
        setTodos(prev => {
            const result = [...prev];
            const [removed] = result.splice(fromIndex, 1);
            result.splice(toIndex, 0, removed);
            return result;
        });
    };

    return (
        <div>
            {todos.map((todo, index) => (
                <TodoItem
                    key={todo.id}
                    todo={todo}
                    onToggle={() => toggleTodo(todo.id)}
                    onRemove={() => removeTodo(todo.id)}
                />
            ))}
        </div>
    );
}
