```
// ═══════════════════════════════════════════════════════════
// USEREDUCER FOR COMPLEX STATE
// ═══════════════════════════════════════════════════════════

import { useReducer, Reducer } from 'react';

// Define state and actions
interface CartState {
    items: Array<{ id: string; name: string; quantity: number; price: number }>;
    total: number;
    discount: number;
    isLoading: boolean;
    error: string | null;
}

type CartAction =
    | { type: 'ADD_ITEM'; payload: { id: string; name: string; price: number } }
    | { type: 'REMOVE_ITEM'; payload: { id: string } }
    | { type: 'UPDATE_QUANTITY'; payload: { id: string; quantity: number } }
    | { type: 'APPLY_DISCOUNT'; payload: { discount: number } }
    | { type: 'CLEAR_CART' }
    | { type: 'SET_LOADING'; payload: boolean }
    | { type: 'SET_ERROR'; payload: string | null };

const initialCartState: CartState = {
    items: [],
    total: 0,
    discount: 0,
    isLoading: false,
    error: null
};

function calculateTotal(items: CartState['items'], discount: number): number {
    const subtotal = items.reduce((sum, item) => sum + item.price * item.quantity, 0);
    return subtotal * (1 - discount);
}

const cartReducer: Reducer<CartState, CartAction> = (state, action) => {
    switch (action.type) {
        case 'ADD_ITEM': {
            const existingItem = state.items.find(item => item.id === action.payload.id);

            let newItems: CartState['items'];
            if (existingItem) {
                newItems = state.items.map(item =>
                    item.id === action.payload.id
                        ? { ...item, quantity: item.quantity + 1 }
                        : item
                );
            } else {
                newItems = [...state.items, { ...action.payload, quantity: 1 }];
            }

            return {
                ...state,
                items: newItems,
                total: calculateTotal(newItems, state.discount)
            };
        }

        case 'REMOVE_ITEM': {
            const newItems = state.items.filter(item => item.id !== action.payload.id);
            return {
                ...state,
                items: newItems,
                total: calculateTotal(newItems, state.discount)
            };
        }

        case 'UPDATE_QUANTITY': {
            const newItems = state.items.map(item =>
                item.id === action.payload.id
                    ? { ...item, quantity: Math.max(0, action.payload.quantity) }
                    : item
            ).filter(item => item.quantity > 0);

            return {
                ...state,
                items: newItems,
                total: calculateTotal(newItems, state.discount)
            };
        }

        case 'APPLY_DISCOUNT': {
            const discount = Math.min(1, Math.max(0, action.payload.discount));
            return {
                ...state,
                discount,
                total: calculateTotal(state.items, discount)
            };
        }

        case 'CLEAR_CART':
            return initialCartState;

        case 'SET_LOADING':
            return { ...state, isLoading: action.payload };

        case 'SET_ERROR':
            return { ...state, error: action.payload };

        default:
            return state;
    }
};

// Cart hook
function useCart() {
    const [state, dispatch] = useReducer(cartReducer, initialCartState);

    const actions = useMemo(() => ({
        addItem: (id: string, name: string, price: number) =>
            dispatch({ type: 'ADD_ITEM', payload: { id, name, price } }),

        removeItem: (id: string) =>
            dispatch({ type: 'REMOVE_ITEM', payload: { id } }),

        updateQuantity: (id: string, quantity: number) =>
            dispatch({ type: 'UPDATE_QUANTITY', payload: { id, quantity } }),

        applyDiscount: (discount: number) =>
            dispatch({ type: 'APPLY_DISCOUNT', payload: { discount } }),

        clearCart: () =>
            dispatch({ type: 'CLEAR_CART' })
    }), []);

    return { state, ...actions };
}

// ═══════════════════════════════════════════════════════════
// IMMER FOR IMMUTABLE UPDATES
// ═══════════════════════════════════════════════════════════

import { useImmerReducer } from 'use-immer';

interface NestedState {
    user: {
        profile: {
            name: string;
            settings: {
                theme: string;
                notifications: {
                    email: boolean;
                    push: boolean;
                };
            };
        };
    };
    posts: Array<{
        id: string;
        comments: Array<{ id: string; text: string }>;
    }>;
}

type NestedAction =
    | { type: 'UPDATE_NAME'; payload: string }
    | { type: 'TOGGLE_EMAIL_NOTIFICATIONS' }
    | { type: 'ADD_COMMENT'; payload: { postId: string; text: string } };

function nestedReducer(draft: NestedState, action: NestedAction) {
    switch (action.type) {
        case 'UPDATE_NAME':
            // Direct mutation with Immer!
            draft.user.profile.name = action.payload;
            break;

        case 'TOGGLE_EMAIL_NOTIFICATIONS':
            draft.user.profile.settings.notifications.email =
                !draft.user.profile.settings.notifications.email;
            break;

        case 'ADD_COMMENT':
            const post = draft.posts.find(p => p.id === action.payload.postId);
            if (post) {
                post.comments.push({
                    id: crypto.randomUUID(),
                    text: action.payload.text
                });
            }
            break;
    }
}

function NestedStateComponent() {
    const [state, dispatch] = useImmerReducer(nestedReducer, initialNestedState);

    return (
        <div>
            <h1>{state.user.profile.name}</h1>
            <button onClick={() => dispatch({ type: 'TOGGLE_EMAIL_NOTIFICATIONS' })}>
                Toggle Email Notifications
            </button>
        </div>
    );
}
