## 5.2 Context API Advanced Patterns

```
// ═══════════════════════════════════════════════════════════
// OPTIMIZED CONTEXT PATTERN
// ═══════════════════════════════════════════════════════════

import { createContext, useContext, useReducer, useMemo, ReactNode } from 'react';

// Split context into state and dispatch to prevent unnecessary re-renders
interface AuthState {
    user: { id: string; name: string; email: string } | null;
    isLoading: boolean;
    error: string | null;
}

type AuthAction =
    | { type: 'LOGIN_START' }
    | { type: 'LOGIN_SUCCESS'; payload: AuthState['user'] }
    | { type: 'LOGIN_FAILURE'; payload: string }
    | { type: 'LOGOUT' };

const AuthStateContext = createContext<AuthState | null>(null);
const AuthDispatchContext = createContext<React.Dispatch<AuthAction> | null>(null);

function authReducer(state: AuthState, action: AuthAction): AuthState {
    switch (action.type) {
        case 'LOGIN_START':
            return { ...state, isLoading: true, error: null };
        case 'LOGIN_SUCCESS':
            return { user: action.payload, isLoading: false, error: null };
        case 'LOGIN_FAILURE':
            return { user: null, isLoading: false, error: action.payload };
        case 'LOGOUT':
            return { user: null, isLoading: false, error: null };
        default:
            return state;
    }
}

function AuthProvider({ children }: { children: ReactNode }) {
    const [state, dispatch] = useReducer(authReducer, {
        user: null,
        isLoading: false,
        error: null
    });

    return (
        <AuthStateContext.Provider value={state}>
            <AuthDispatchContext.Provider value={dispatch}>
                {children}
            </AuthDispatchContext.Provider>
        </AuthStateContext.Provider>
    );
}

function useAuthState() {
    const context = useContext(AuthStateContext);
    if (context === null) {
        throw new Error('useAuthState must be used within AuthProvider');
    }
    return context;
}

function useAuthDispatch() {
    const context = useContext(AuthDispatchContext);
    if (context === null) {
        throw new Error('useAuthDispatch must be used within AuthProvider');
    }
    return context;
}

// Custom hook with actions
function useAuth() {
    const state = useAuthState();
    const dispatch = useAuthDispatch();

    const actions = useMemo(() => ({
        login: async (email: string, password: string) => {
            dispatch({ type: 'LOGIN_START' });
            try {
                const user = await loginApi(email, password);
                dispatch({ type: 'LOGIN_SUCCESS', payload: user });
            } catch (error) {
                dispatch({ type: 'LOGIN_FAILURE', payload: (error as Error).message });
            }
        },

        logout: () => {
            dispatch({ type: 'LOGOUT' });
        }
    }), [dispatch]);

    return { ...state, ...actions };
}

// ═══════════════════════════════════════════════════════════
// CONTEXT WITH SELECTORS (Preventing unnecessary re-renders)
// ═══════════════════════════════════════════════════════════

import { useSyncExternalStore } from 'react';

interface Store<T> {
    getState: () => T;
    setState: (partial: Partial<T> | ((state: T) => Partial<T>)) => void;
    subscribe: (listener: () => void) => () => void;
}

function createStore<T extends object>(initialState: T): Store<T> {
    let state = initialState;
    const listeners = new Set<() => void>();

    return {
        getState: () => state,

        setState: (partial) => {
            const nextState = typeof partial === 'function'
                ? partial(state)
                : partial;
            state = { ...state, ...nextState };
            listeners.forEach(listener => listener());
        },

        subscribe: (listener) => {
            listeners.add(listener);
            return () => listeners.delete(listener);
        }
    };
}

// Usage with context
interface AppState {
    user: { name: string } | null;
    theme: 'light' | 'dark';
    notifications: number;
}

const StoreContext = createContext<Store<AppState> | null>(null);

function useStore<T>(selector: (state: AppState) => T): T {
    const store = useContext(StoreContext);
    if (!store) {
        throw new Error('useStore must be used within StoreProvider');
    }

    return useSyncExternalStore(
        store.subscribe,
        () => selector(store.getState()),
        () => selector(store.getState())
    );
}

// Components only re-render when their selected state changes
function NotificationBadge() {
    // Only re-renders when notifications change
    const notifications = useStore(state => state.notifications);
    return <span className="badge">{notifications}</span>;
}

function ThemeToggle() {
    // Only re-renders when theme changes
    const theme = useStore(state => state.theme);
    const store = useContext(StoreContext)!;

    return (
        <button onClick={() => store.setState({
            theme: theme === 'light' ? 'dark' : 'light'
        })}>
            Current: {theme}
        </button>
    );
}

// ═══════════════════════════════════════════════════════════
// COMPOUND CONTEXT PATTERN
// ═══════════════════════════════════════════════════════════

interface TabsContextValue {
    activeTab: string;
    setActiveTab: (tab: string) => void;
}

const TabsContext = createContext<TabsContextValue | null>(null);

function useTabs() {
    const context = useContext(TabsContext);
    if (!context) {
        throw new Error('Tabs components must be used within Tabs');
    }
    return context;
}

interface TabsProps {
    defaultTab?: string;
    children: ReactNode;
    onChange?: (tab: string) => void;
}

function Tabs({ defaultTab, children, onChange }: TabsProps) {
    const [activeTab, setActiveTab] = useState(defaultTab || '');

    const handleSetActiveTab = useCallback((tab: string) => {
        setActiveTab(tab);
        onChange?.(tab);
    }, [onChange]);

    const value = useMemo(() => ({
        activeTab,
        setActiveTab: handleSetActiveTab
    }), [activeTab, handleSetActiveTab]);

    return (
        <TabsContext.Provider value={value}>
            <div className="tabs">{children}</div>
        </TabsContext.Provider>
    );
}

function TabList({ children }: { children: ReactNode }) {
    return <div className="tab-list" role="tablist">{children}</div>;
}

function Tab({ value, children }: { value: string; children: ReactNode }) {
    const { activeTab, setActiveTab } = useTabs();
    const isActive = activeTab === value;

    return (
        <button
            role="tab"
            aria-selected={isActive}
            className={`tab ${isActive ? 'active' : ''}`}
            onClick={() => setActiveTab(value)}
        >
            {children}
        </button>
    );
}

function TabPanels({ children }: { children: ReactNode }) {
    return <div className="tab-panels">{children}</div>;
}

function TabPanel({ value, children }: { value: string; children: ReactNode }) {
    const { activeTab } = useTabs();

    if (activeTab !== value) return null;

    return (
        <div role="tabpanel" className="tab-panel">
            {children}
        </div>
    );
}

// Attach sub-components
Tabs.List = TabList;
Tabs.Tab = Tab;
Tabs.Panels = TabPanels;
Tabs.Panel = TabPanel;

// Usage
function TabsExample() {
    return (
        <Tabs defaultTab="tab1" onChange={(tab) => console.log('Changed to:', tab)}>
            <Tabs.List>
                <Tabs.Tab value="tab1">Tab 1</Tabs.Tab>
                <Tabs.Tab value="tab2">Tab 2</Tabs.Tab>
                <Tabs.Tab value="tab3">Tab 3</Tabs.Tab>
            </Tabs.List>
            <Tabs.Panels>
                <Tabs.Panel value="tab1">Content 1</Tabs.Panel>
                <Tabs.Panel value="tab2">Content 2</Tabs.Panel>
                <Tabs.Panel value="tab3">Content 3</Tabs.Panel>
            </Tabs.Panels>
        </Tabs>
    );
}
