```
// ═══════════════════════════════════════════════════════════
// ZUSTAND - SIMPLE AND POWERFUL STATE MANAGEMENT
// ═══════════════════════════════════════════════════════════

import { create } from 'zustand';
import { devtools, persist, subscribeWithSelector } from 'zustand/middleware';
import { immer } from 'zustand/middleware/immer';

// Basic store
interface CounterStore {
    count: number;
    increment: () => void;
    decrement: () => void;
    reset: () => void;
    incrementBy: (amount: number) => void;
}

const useCounterStore = create<CounterStore>((set) => ({
    count: 0,
    increment: () => set((state) => ({ count: state.count + 1 })),
    decrement: () => set((state) => ({ count: state.count - 1 })),
    reset: () => set({ count: 0 }),
    incrementBy: (amount) => set((state) => ({ count: state.count + amount }))
}));

// Usage in component
function Counter() {
    const { count, increment, decrement } = useCounterStore();

    return (
        <div>
            <span>{count}</span>
            <button onClick={increment}>+</button>
            <button onClick={decrement}>-</button>
        </div>
    );
}

// Select specific state (prevents unnecessary re-renders)
function CountDisplay() {
    const count = useCounterStore((state) => state.count);
    return <span>{count}</span>;
}

// ═══════════════════════════════════════════════════════════
// COMPLEX STORE WITH MIDDLEWARE
// ═══════════════════════════════════════════════════════════

interface User {
    id: string;
    name: string;
    email: string;
}

interface Product {
    id: string;
    name: string;
    price: number;
}

interface CartItem {
    product: Product;
    quantity: number;
}

interface AppStore {
    // State
    user: User | null;
    cart: CartItem[];
    wishlist: Product[];
    isLoading: boolean;

    // User actions
    login: (email: string, password: string) => Promise<void>;
    logout: () => void;

    // Cart actions
    addToCart: (product: Product) => void;
    removeFromCart: (productId: string) => void;
    updateQuantity: (productId: string, quantity: number) => void;
    clearCart: () => void;

    // Wishlist actions
    addToWishlist: (product: Product) => void;
    removeFromWishlist: (productId: string) => void;

    // Computed values
    cartTotal: () => number;
    cartItemCount: () => number;
}

const useAppStore = create<AppStore>()(
    devtools(
        persist(
            immer((set, get) => ({
                // Initial state
                user: null,
                cart: [],
                wishlist: [],
                isLoading: false,

                // User actions
                login: async (email, password) => {
                    set({ isLoading: true });
                    try {
                        const user = await loginApi(email, password);
                        set({ user, isLoading: false });
                    } catch (error) {
                        set({ isLoading: false });
                        throw error;
                    }
                },

                logout: () => {
                    set({ user: null, cart: [], wishlist: [] });
                },

                // Cart actions (using immer for mutations)
                addToCart: (product) => {
                    set((state) => {
                        const existingItem = state.cart.find(
                            item => item.product.id === product.id
                        );

                        if (existingItem) {
                            existingItem.quantity += 1;
                        } else {
                            state.cart.push({ product, quantity: 1 });
                        }
                    });
                },

                removeFromCart: (productId) => {
                    set((state) => {
                        state.cart = state.cart.filter(
                            item => item.product.id !== productId
                        );
                    });
                },

                updateQuantity: (productId, quantity) => {
                    set((state) => {
                        const item = state.cart.find(
                            item => item.product.id === productId
                        );
                        if (item) {
                            if (quantity <= 0) {
                                state.cart = state.cart.filter(
                                    i => i.product.id !== productId
                                );
                            } else {
                                item.quantity = quantity;
                            }
                        }
                    });
                },

                clearCart: () => {
                    set({ cart: [] });
                },

                // Wishlist actions
                addToWishlist: (product) => {
                    set((state) => {
                        if (!state.wishlist.find(p => p.id === product.id)) {
                            state.wishlist.push(product);
                        }
                    });
                },

                removeFromWishlist: (productId) => {
                    set((state) => {
                        state.wishlist = state.wishlist.filter(
                            p => p.id !== productId
                        );
                    });
                },

                // Computed values
                cartTotal: () => {
                    return get().cart.reduce(
                        (total, item) => total + item.product.price * item.quantity,
                        0
                    );
                },

                cartItemCount: () => {
                    return get().cart.reduce(
                        (count, item) => count + item.quantity,
                        0
                    );
                }
            })),
            {
                name: 'app-storage',
                partialize: (state) => ({
                    cart: state.cart,
                    wishlist: state.wishlist
                })
            }
        ),
        { name: 'AppStore' }
    )
);

// ═══════════════════════════════════════════════════════════
// SLICES PATTERN FOR LARGE STORES
// ═══════════════════════════════════════════════════════════

// Define slice types
interface UserSlice {
    user: User | null;
    login: (email: string, password: string) => Promise<void>;
    logout: () => void;
}

interface CartSlice {
    cart: CartItem[];
    addToCart: (product: Product) => void;
    removeFromCart: (productId: string) => void;
}

interface UISlice {
    theme: 'light' | 'dark';
    sidebarOpen: boolean;
    toggleTheme: () => void;
    toggleSidebar: () => void;
}

// Create slices
const createUserSlice: StateCreator<
    UserSlice & CartSlice & UISlice,
    [],
    [],
    UserSlice
> = (set) => ({
    user: null,
    login: async (email, password) => {
        const user = await loginApi(email, password);
        set({ user });
    },
    logout: () => set({ user: null })
});

const createCartSlice: StateCreator<
    UserSlice & CartSlice & UISlice,
    [],
    [],
    CartSlice
> = (set) => ({
    cart: [],
    addToCart: (product) => set((state) => ({
        cart: [...state.cart, { product, quantity: 1 }]
    })),
    removeFromCart: (productId) => set((state) => ({
        cart: state.cart.filter(item => item.product.id !== productId)
    }))
});

const createUISlice: StateCreator<
    UserSlice & CartSlice & UISlice,
    [],
    [],
    UISlice
> = (set) => ({
    theme: 'light',
    sidebarOpen: false,
    toggleTheme: () => set((state) => ({
        theme: state.theme === 'light' ? 'dark' : 'light'
    })),
    toggleSidebar: () => set((state) => ({
        sidebarOpen: !state.sidebarOpen
    }))
});

// Combine slices
const useBoundStore = create<UserSlice & CartSlice & UISlice>()((...a) => ({
    ...createUserSlice(...a),
    ...createCartSlice(...a),
    ...createUISlice(...a)
}));

// ═══════════════════════════════════════════════════════════
// ASYNC ACTIONS AND SUBSCRIPTIONS
// ═══════════════════════════════════════════════════════════

const useProductStore = create<{
    products: Product[];
    isLoading: boolean;
    error: string | null;
    fetchProducts: () => Promise<void>;
    fetchProductById: (id: string) => Promise<Product>;
}>()(
    subscribeWithSelector((set, get) => ({
        products: [],
        isLoading: false,
        error: null,

        fetchProducts: async () => {
            set({ isLoading: true, error: null });
            try {
                const products = await fetchProductsApi();
                set({ products, isLoading: false });
            } catch (error) {
                set({ error: (error as Error).message, isLoading: false });
            }
        },

        fetchProductById: async (id) => {
            const cached = get().products.find(p => p.id === id);
            if (cached) return cached;

            const product = await fetchProductApi(id);
            set((state) => ({
                products: [...state.products, product]
            }));
            return product;
        }
    }))
);

// Subscribe to state changes
useProductStore.subscribe(
    (state) => state.products,
    (products, previousProducts) => {
        console.log('Products changed:', products.length);
    }
);
