// Prefetch in loader (React Router)
const userLoader = (queryClient: QueryClient) => async ({ params }) => {
    const { userId } = params;

    await queryClient.ensureQueryData({
        queryKey: ['user', userId],
        queryFn: () => fetchUser(userId!)
    });

    return null;
};
// ═══════════════════════════════════════════════════════════
// DEPENDENT QUERIES
// ═══════════════════════════════════════════════════════════

function useUserPosts(userId: string) {
    // First query
    const userQuery = useQuery({
        queryKey: ['user', userId],
        queryFn: () => fetchUser(userId)
    });

    // Dependent query - only runs after user is fetched
    const postsQuery = useQuery({
        queryKey: ['posts', userId],
        queryFn: () => fetchUserPosts(userId),
        enabled: !!userQuery.data // Only run when user data exists
    });

    return {
        user: userQuery.data,
        posts: postsQuery.data,
        isLoading: userQuery.isLoading || postsQuery.isLoading
    };
}

// ═══════════════════════════════════════════════════════════
// PARALLEL QUERIES
// ═══════════════════════════════════════════════════════════

import { useQueries } from '@tanstack/react-query';

function useMultipleUsers(userIds: string[]) {
    return useQueries({
        queries: userIds.map(id => ({
            queryKey: ['user', id],
            queryFn: () => fetchUser(id)
        }))
    });
}

function Dashboard({ userIds }: { userIds: string[] }) {
    const userQueries = useMultipleUsers(userIds);

    const isLoading = userQueries.some(query => query.isLoading);
    const users = userQueries
        .filter(query => query.data)
        .map(query => query.data);

    if (isLoading) return <LoadingSpinner />;

    return (
        <div>
            {users.map(user => (
                <UserCard key={user.id} user={user} />
            ))}
        </div>
    );
}
