// Custom comparison function
const UserCardCustom = memo(
    function UserCard({ user, onSelect }: UserCardProps) {
        return (
            <div onClick={() => onSelect(user.id)}>
                <h3>{user.name}</h3>
                <p>{user.email}</p>
            </div>
        );
    },
    (prevProps, nextProps) => {
        // Return true if props are equal (skip re-render)
        // Return false to re-render
        return prevProps.user.id === nextProps.user.id &&
               prevProps.user.name === nextProps.user.name;
    }
);

// ═══════════════════════════════════════════════════════════
// USEMEMO - VALUE MEMOIZATION
// ═══════════════════════════════════════════════════════════

interface Product {
    id: string;
    name: string;
    price: number;
    category: string;
}

function ProductList({ products, filter, sortBy }: {
    products: Product[];
    filter: string;
    sortBy: 'name' | 'price';
}) {
    // Expensive computation - memoized
    const filteredAndSortedProducts = useMemo(() => {
        console.log('Computing filtered products...');

        let result = products;

        // Filter
        if (filter) {
            result = result.filter(p =>
                p.name.toLowerCase().includes(filter.toLowerCase()) ||
                p.category.toLowerCase().includes(filter.toLowerCase())
            );
        }

        // Sort
        result = [...result].sort((a, b) => {
            if (sortBy === 'price') return a.price - b.price;
            return a.name.localeCompare(b.name);
        });

        return result;
    }, [products, filter, sortBy]); // Only recompute when these change

    // Computed stats - also memoized
    const stats = useMemo(() => ({
        total: filteredAndSortedProducts.length,
        avgPrice: filteredAndSortedProducts.reduce((sum, p) => sum + p.price, 0) /
                  filteredAndSortedProducts.length || 0,
        minPrice: Math.min(...filteredAndSortedProducts.map(p => p.price)),
        maxPrice: Math.max(...filteredAndSortedProducts.map(p => p.price))
    }), [filteredAndSortedProducts]);

    return (
        <div>
            <div className="stats">
                <span>Total: {stats.total}</span>
                <span>Avg: ${stats.avgPrice.toFixed(2)}</span>
            </div>
            {filteredAndSortedProducts.map(product => (
                <ProductCard key={product.id} product={product} />
            ))}
        </div>
    );
}

