// USECALLBACK - FUNCTION MEMOIZATION
// ═══════════════════════════════════════════════════════════

function ParentComponent() {
    const [items, setItems] = useState<string[]>([]);
    const [selectedId, setSelectedId] = useState<string | null>(null);

    // Without useCallback - new function every render
    // const handleSelect = (id: string) => setSelectedId(id);

    // With useCallback - same function reference
    const handleSelect = useCallback((id: string) => {
        setSelectedId(id);
    }, []); // Empty deps = never changes

    // With dependencies
    const handleAdd = useCallback((item: string) => {
        setItems(prev => [...prev, item]);
        // Do something with selectedId
        console.log('Selected:', selectedId);
    }, [selectedId]); // Recreate when selectedId changes

    // Using functional update to avoid dependencies
    const handleRemove = useCallback((id: string) => {
        setItems(prev => prev.filter(item => item !== id));
    }, []); // No deps needed!

    return (
        <div>
            {items.map(item => (
                <MemoizedItem
                    key={item}
                    item={item}
                    onSelect={handleSelect}
                    onRemove={handleRemove}
                />
            ))}
        </div>
    );
}

// ═══════════════════════════════════════════════════════════
// WHEN TO USE MEMOIZATION
// ═══════════════════════════════════════════════════════════

/*
╔═══════════════════════════════════════════════════════════════╗
║               MEMOIZATION DECISION GUIDE                      ║
╠═══════════════════════════════════════════════════════════════╣
║                                                               ║
║  USE React.memo WHEN:                                         ║
║  • Component renders often with same props                    ║
║  • Component is expensive to render                           ║
║  • Parent re-renders frequently                               ║
║                                                               ║
║  USE useMemo WHEN:                                            ║
║  • Expensive calculations on every render                     ║
║  • Creating objects/arrays passed to memoized children        ║
║  • Derived state from props                                   ║
║                                                               ║
║  USE useCallback WHEN:                                        ║
║  • Passing callbacks to memoized children                     ║
║  • Callback is dependency of useEffect                        ║
║  • Callback is passed to many children                        ║
║                                                               ║
║  DON'T USE WHEN:                                              ║
║  • Component is simple and fast                               ║
║  • Props change on every render anyway                        ║
║  • Premature optimization (measure first!)                    ║
║                                                               ║
╚═══════════════════════════════════════════════════════════════╝
*/

// Example: When memoization helps
function ExpensiveList({ items, onItemClick }: {
    items: Item[];
    onItemClick: (id: string) => void;
}) {
    // ✅ Good - handler is stable, memoized children work
    const handleClick = useCallback((id: string) => {
        onItemClick(id);
    }, [onItemClick]);

    return (
        <ul>
            {items.map(item => (
                <MemoizedListItem
                    key={item.id}
                    item={item}
                    onClick={handleClick}
                />
            ))}
        </ul>
    );
}

// Example: When memoization doesn't help
function SimpleCounter() {
    const [count, setCount] = useState(0);

    // ❌ Unnecessary - increment is always called with same result
    // const increment = useCallback(() => {
    //     setCount(c => c + 1);
    // }, []);

    // ✅ Just use regular function
    const increment = () => setCount(c => c + 1);

    return <button onClick={increment}>{count}</button>;
}

