// ═══════════════════════════════════════════════════════════
// ADVANCED MEMOIZATION PATTERNS
// ═══════════════════════════════════════════════════════════

// Pattern 1: Memoized context value
function AppProvider({ children }: { children: ReactNode }) {
    const [user, setUser] = useState<User | null>(null);
    const [theme, setTheme] = useState<'light' | 'dark'>('light');

    // Memoize context value to prevent unnecessary re-renders
    const authValue = useMemo(() => ({
        user,
        login: async (email: string, password: string) => {
            const user = await loginApi(email, password);
            setUser(user);
        },
        logout: () => setUser(null)
    }), [user]);

    const themeValue = useMemo(() => ({
        theme,
        toggleTheme: () => setTheme(t => t === 'light' ? 'dark' : 'light')
    }), [theme]);

    return (
        <AuthContext.Provider value={authValue}>
            <ThemeContext.Provider value={themeValue}>
                {children}
            </ThemeContext.Provider>
        </AuthContext.Provider>
    );
}

// Pattern 2: Extracting static parts
function DataTable({ data, columns, onRowClick }: DataTableProps) {
    // Extract static header to prevent re-renders
    const tableHeader = useMemo(() => (
        <thead>
            <tr>
                {columns.map(col => (
                    <th key={col.key}>{col.label}</th>
                ))}
            </tr>
        </thead>
    ), [columns]);

    const handleRowClick = useCallback((row: Row) => {
        onRowClick?.(row);
    }, [onRowClick]);

    return (
        <table>
            {tableHeader}
            <tbody>
                {data.map(row => (
                    <MemoizedTableRow
                        key={row.id}
                        row={row}
                        columns={columns}
                        onClick={handleRowClick}
                    />
                ))}
            </tbody>
        </table>
    );
}

// Pattern 3: Selector pattern for derived state
function useUserStats(users: User[]) {
    const activeCount = useMemo(
        () => users.filter(u => u.isActive).length,
        [users]
    );

    const adminCount = useMemo(
        () => users.filter(u => u.role === 'admin').length,
        [users]
    );

    const usersByRole = useMemo(() => {
        return users.reduce((acc, user) => {
            acc[user.role] = (acc[user.role] || 0) + 1;
            return acc;
        }, {} as Record<string, number>);
    }, [users]);

    return { activeCount, adminCount, usersByRole };
}
