```
// ═══════════════════════════════════════════════════════════
// VIRTUALIZATION WITH REACT-WINDOW
// ═══════════════════════════════════════════════════════════

import { FixedSizeList, VariableSizeList, FixedSizeGrid } from 'react-window';
import AutoSizer from 'react-virtualized-auto-sizer';

interface Item {
    id: string;
    name: string;
    description: string;
}

// Fixed size list
function VirtualizedList({ items }: { items: Item[] }) {
    const Row = ({ index, style }: { index: number; style: React.CSSProperties }) => {
        const item = items[index];
        return (
            <div style={style} className="list-item">
                <h4>{item.name}</h4>
                <p>{item.description}</p>
            </div>
        );
    };

    return (
        <AutoSizer>
            {({ height, width }) => (
                <FixedSizeList
                    height={height}
                    width={width}
                    itemCount={items.length}
                    itemSize={80} // Each row is 80px
                >
                    {Row}
                </FixedSizeList>
            )}
        </AutoSizer>
    );
}

// Variable size list (dynamic heights)
function DynamicHeightList({ items }: { items: Item[] }) {
    const listRef = useRef<VariableSizeList>(null);
    const rowHeights = useRef<Map<number, number>>(new Map());

    const getRowHeight = (index: number) => {
        return rowHeights.current.get(index) || 100;
    };

    const setRowHeight = (index: number, height: number) => {
        if (rowHeights.current.get(index) !== height) {
            rowHeights.current.set(index, height);
            listRef.current?.resetAfterIndex(index);
        }
    };

    const Row = ({ index, style }: { index: number; style: React.CSSProperties }) => {
        const rowRef = useRef<HTMLDivElement>(null);
        const item = items[index];

        useEffect(() => {
            if (rowRef.current) {
                setRowHeight(index, rowRef.current.getBoundingClientRect().height);
            }
        }, [index, item]);

        return (
            <div style={style}>
                <div ref={rowRef} className="variable-row">
                    <h4>{item.name}</h4>
                    <p>{item.description}</p>
                </div>
            </div>
        );
    };

    return (
        <AutoSizer>
            {({ height, width }) => (
                <VariableSizeList
                    ref={listRef}
                    height={height}
                    width={width}
                    itemCount={items.length}
                    itemSize={getRowHeight}
                    estimatedItemSize={100}
                >
                    {Row}
                </VariableSizeList>
            )}
        </AutoSizer>
    );
}

// Grid virtualization
function VirtualizedGrid({ items, columnCount }: {
    items: Item[];
    columnCount: number;
}) {
    const rowCount = Math.ceil(items.length / columnCount);

    const Cell = ({
        columnIndex,
        rowIndex,
        style
    }: {
        columnIndex: number;
        rowIndex: number;
        style: React.CSSProperties;
    }) => {
        const index = rowIndex * columnCount + columnIndex;
        if (index >= items.length) return null;

        const item = items[index];

        return (
            <div style={style} className="grid-cell">
                <div className="card">
                    <h4>{item.name}</h4>
                </div>
            </div>
        );
    };

    return (
        <AutoSizer>
            {({ height, width }) => (
                <FixedSizeGrid
                    height={height}
                    width={width}
                    columnCount={columnCount}
                    columnWidth={width / columnCount}
                    rowCount={rowCount}
                    rowHeight={200}
                >
                    {Cell}
                </FixedSizeGrid>
            )}
        </AutoSizer>
    );
}

