import { useVirtualizer } from '@tanstack/react-virtual';

function TanstackVirtualList({ items }: { items: Item[] }) {
    const parentRef = useRef<HTMLDivElement>(null);

    const virtualizer = useVirtualizer({
        count: items.length,
        getScrollElement: () => parentRef.current,
        estimateSize: () => 80,
        overscan: 5 // Render 5 extra items above/below visible area
    });

    return (
        <div
            ref={parentRef}
            style={{ height: '500px', overflow: 'auto' }}
        >
            <div
                style={{
                    height: `${virtualizer.getTotalSize()}px`,
                    width: '100%',
                    position: 'relative'
                }}
            >
                {virtualizer.getVirtualItems().map(virtualRow => {
                    const item = items[virtualRow.index];

                    return (
                        <div
                            key={virtualRow.key}
                            style={{
                                position: 'absolute',
                                top: 0,
                                left: 0,
                                width: '100%',
                                height: `${virtualRow.size}px`,
                                transform: `translateY(${virtualRow.start}px)`
                            }}
                        >
                            <div className="item">
                                <h4>{item.name}</h4>
                                <p>{item.description}</p>
                            </div>
                        </div>
                    );
                })}
            </div>
        </div>
    );
}

// Infinite scroll with virtualization
function InfiniteVirtualList() {
    const parentRef = useRef<HTMLDivElement>(null);
    const [items, setItems] = useState<Item[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [hasMore, setHasMore] = useState(true);

    const loadMore = useCallback(async () => {
        if (isLoading || !hasMore) return;

        setIsLoading(true);
        const newItems = await fetchItems(items.length, 20);
        setItems(prev => [...prev, ...newItems]);
        setHasMore(newItems.length === 20);
        setIsLoading(false);
    }, [isLoading, hasMore, items.length]);

    const virtualizer = useVirtualizer({
        count: hasMore ? items.length + 1 : items.length,
        getScrollElement: () => parentRef.current,
        estimateSize: () => 80,
        overscan: 5
    });

    const virtualItems = virtualizer.getVirtualItems();

    // Load more when approaching end
    useEffect(() => {
        const lastItem = virtualItems[virtualItems.length - 1];
        if (lastItem && lastItem.index >= items.length - 1 && hasMore && !isLoading) {
            loadMore();
        }
    }, [virtualItems, items.length, hasMore, isLoading, loadMore]);

    return (
        <div
            ref={parentRef}
            style={{ height: '500px', overflow: 'auto' }}
        >
            <div
                style={{
                    height: `${virtualizer.getTotalSize()}px`,
                    position: 'relative'
                }}
            >
                {virtualItems.map(virtualRow => {
                    const isLoaderRow = virtualRow.index >= items.length;
                    const item = items[virtualRow.index];

                    return (
                        <div
                            key={virtualRow.key}
                            style={{
                                position: 'absolute',
                                top: 0,
                                left: 0,
                                width: '100%',
                                transform: `translateY(${virtualRow.start}px)`
                            }}
                        >
                            {isLoaderRow ? (
                                <div className="loader">Loading...</div>
                            ) : (
                                <div className="item">
                                    <h4>{item.name}</h4>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
}
