# 📚 Section 7: React Patterns

## 🎯 7.1 Compound Components

```
// ═══════════════════════════════════════════════════════════
// COMPOUND COMPONENTS PATTERN
// ═══════════════════════════════════════════════════════════

import { createContext, useContext, useState, ReactNode } from 'react';

// Accordion compound component
interface AccordionContextValue {
    openItems: Set<string>;
    toggleItem: (id: string) => void;
    allowMultiple: boolean;
}

const AccordionContext = createContext<AccordionContextValue | null>(null);

function useAccordionContext() {
    const context = useContext(AccordionContext);
    if (!context) {
        throw new Error('Accordion components must be used within Accordion');
    }
    return context;
}

interface AccordionProps {
    children: ReactNode;
    allowMultiple?: boolean;
    defaultOpen?: string[];
}

function Accordion({ children, allowMultiple = false, defaultOpen = [] }: AccordionProps) {
    const [openItems, setOpenItems] = useState<Set<string>>(new Set(defaultOpen));

    const toggleItem = (id: string) => {
        setOpenItems(prev => {
            const next = new Set(prev);

            if (next.has(id)) {
                next.delete(id);
            } else {
                if (!allowMultiple) {
                    next.clear();
                }
                next.add(id);
            }

            return next;
        });
    };

    return (
        <AccordionContext.Provider value={{ openItems, toggleItem, allowMultiple }}>
            <div className="accordion">{children}</div>
        </AccordionContext.Provider>
    );
}

interface AccordionItemProps {
    id: string;
    children: ReactNode;
}

function AccordionItem({ id, children }: AccordionItemProps) {
    const { openItems } = useAccordionContext();
    const isOpen = openItems.has(id);

    return (
        <div className={`accordion-item ${isOpen ? 'open' : ''}`} data-id={id}>
            {children}
        </div>
    );
}

function AccordionHeader({ children }: { children: ReactNode }) {
    const { toggleItem } = useAccordionContext();
    const itemElement = useRef<HTMLElement | null>(null);

    const handleClick = () => {
        const item = itemElement.current?.closest('.accordion-item');
        const id = item?.getAttribute('data-id');
        if (id) toggleItem(id);
    };

    return (
        <button
            ref={el => { itemElement.current = el; }}
            className="accordion-header"
            onClick={handleClick}
        >
            {children}
        </button>
    );
}

function AccordionPanel({ children }: { children: ReactNode }) {
    return <div className="accordion-panel">{children}</div>;
}

// Attach sub-components
Accordion.Item = AccordionItem;
Accordion.Header = AccordionHeader;
Accordion.Panel = AccordionPanel;

// Usage
function AccordionExample() {
    return (
        <Accordion allowMultiple defaultOpen={['item1']}>
            <Accordion.Item id="item1">
                <Accordion.Header>Section 1</Accordion.Header>
                <Accordion.Panel>Content for section 1</Accordion.Panel>
            </Accordion.Item>

            <Accordion.Item id="item2">
                <Accordion.Header>Section 2</Accordion.Header>
                <Accordion.Panel>Content for section 2</Accordion.Panel>
            </Accordion.Item>

            <Accordion.Item id="item3">
                <Accordion.Header>Section 3</Accordion.Header>
                <Accordion.Panel>Content for section 3</Accordion.Panel>
            </Accordion.Item>
        </Accordion>
    );
}
// ═══════════════════════════════════════════════════════════
// SELECT/DROPDOWN COMPOUND COMPONENT
// ═══════════════════════════════════════════════════════════

interface SelectContextValue {
    value: string;
    onChange: (value: string) => void;
    isOpen: boolean;
    setIsOpen: (open: boolean) => void;
    highlightedIndex: number;
    setHighlightedIndex: (index: number) => void;
}

const SelectContext = createContext<SelectContextValue | null>(null);

function useSelectContext() {
    const context = useContext(SelectContext);
    if (!context) {
        throw new Error('Select components must be used within Select');
    }
    return context;
}

interface SelectProps {
    value: string;
    onChange: (value: string) => void;
    children: ReactNode;
}

function Select({ value, onChange, children }: SelectProps) {
    const [isOpen, setIsOpen] = useState(false);
    const [highlightedIndex, setHighlightedIndex] = useState(-1);

    return (
        <SelectContext.Provider value={{
            value,
            onChange,
            isOpen,
            setIsOpen,
            highlightedIndex,
            setHighlightedIndex
        }}>
            <div className="select">{children}</div>
        </SelectContext.Provider>
    );
}

function SelectTrigger({ children, placeholder }: {
    children?: ReactNode;
    placeholder?: string;
}) {
    const { value, isOpen, setIsOpen } = useSelectContext();

    return (
        <button
            className="select-trigger"
            onClick={() => setIsOpen(!isOpen)}
            aria-expanded={isOpen}
        >
            {children || value || placeholder}
        </button>
    );
}

function SelectContent({ children }: { children: ReactNode }) {
    const { isOpen, setIsOpen } = useSelectContext();
    const ref = useRef<HTMLDivElement>(null);

    useClickOutside(ref, () => setIsOpen(false));

    if (!isOpen) return null;

    return createPortal(
        <div ref={ref} className="select-content" role="listbox">
            {children}
        </div>,
        document.body
    );
}

function SelectOption({ value, children }: { value: string; children: ReactNode }) {
    const { value: selectedValue, onChange, setIsOpen } = useSelectContext();
    const isSelected = selectedValue === value;

    const handleSelect = () => {
        onChange(value);
        setIsOpen(false);
    };

    return (
        <div
            className={`select-option ${isSelected ? 'selected' : ''}`}
            role="option"
            aria-selected={isSelected}
            onClick={handleSelect}
        >
            {children}
        </div>
    );
}

Select.Trigger = SelectTrigger;
Select.Content = SelectContent;
Select.Option = SelectOption;

// Usage
function SelectExample() {
    const [country, setCountry] = useState('');

    return (
        <Select value={country} onChange={setCountry}>
            <Select.Trigger placeholder="Select a country" />
            <Select.Content>
                <Select.Option value="us">United States</Select.Option>
                <Select.Option value="uk">United Kingdom</Select.Option>
                <Select.Option value="ca">Canada</Select.Option>
            </Select.Content>
        </Select>
    );
}
