## 🎯 7.2 Render Props and HOCs

```
// ═══════════════════════════════════════════════════════════
// RENDER PROPS PATTERN
// ═══════════════════════════════════════════════════════════

// Mouse position tracker
interface MousePosition {
    x: number;
    y: number;
}

interface MouseTrackerProps {
    children: (position: MousePosition) => ReactNode;
}

function MouseTracker({ children }: MouseTrackerProps) {
    const [position, setPosition] = useState<MousePosition>({ x: 0, y: 0 });

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            setPosition({ x: e.clientX, y: e.clientY });
        };

        window.addEventListener('mousemove', handleMouseMove);
        return () => window.removeEventListener('mousemove', handleMouseMove);
    }, []);

    return <>{children(position)}</>;
}

// Usage
function MouseTrackerExample() {
    return (
        <MouseTracker>
            {({ x, y }) => (
                <div>
                    Mouse position: {x}, {y}
                </div>
            )}
        </MouseTracker>
    );
}

// ═══════════════════════════════════════════════════════════
// HIGHER-ORDER COMPONENTS (HOC)
// ═══════════════════════════════════════════════════════════

// withAuth HOC
interface WithAuthProps {
    user: User;
}

function withAuth<P extends WithAuthProps>(
    WrappedComponent: React.ComponentType<P>
) {
    return function WithAuthComponent(
        props: Omit<P, keyof WithAuthProps>
    ) {
        const { user, isLoading } = useAuth();

        if (isLoading) {
            return <LoadingSpinner />;
        }

        if (!user) {
            return <Navigate to="/login" />;
        }

        return <WrappedComponent {...(props as P)} user={user} />;
    };
}

// Usage
interface DashboardProps extends WithAuthProps {
    title: string;
}

function Dashboard({ user, title }: DashboardProps) {
    return (
        <div>
            <h1>{title}</h1>
            <p>Welcome, {user.name}!</p>
        </div>
    );
}

const ProtectedDashboard = withAuth(Dashboard);

// withLoading HOC
interface WithLoadingProps {
    isLoading: boolean;
}

function withLoading<P extends object>(
    WrappedComponent: React.ComponentType<P>,
    LoadingComponent: React.ComponentType = LoadingSpinner
) {
    return function WithLoadingComponent(
        props: P & WithLoadingProps
    ) {
        const { isLoading, ...rest } = props;

        if (isLoading) {
            return <LoadingComponent />;
        }

        return <WrappedComponent {...(rest as P)} />;
    };
}
// ═══════════════════════════════════════════════════════════
// CUSTOM HOOK VS RENDER PROPS VS HOC
// ═══════════════════════════════════════════════════════════

/*
╔═══════════════════════════════════════════════════════════════╗
║          PATTERN COMPARISON                                   ║
╠═══════════════════════════════════════════════════════════════╣
║                                                               ║
║  CUSTOM HOOKS (Preferred):                                    ║
║  ✅ Most flexible and composable                              ║
║  ✅ No wrapper component overhead                             ║
║  ✅ Easy to test                                              ║
║  ✅ Type-safe with TypeScript                                 ║
║                                                               ║
║  RENDER PROPS:                                                ║
║  ✅ Good for dynamic children                                 ║
║  ✅ Explicit data flow                                        ║
║  ❌ Can lead to "callback hell"                               ║
║  ❌ Extra component in tree                                   ║
║                                                               ║
║  HOCs:                                                        ║
║  ✅ Good for cross-cutting concerns                           ║
║  ✅ Can wrap multiple components                              ║
║  ❌ Props collision                                           ║
║  ❌ Wrapper hell in DevTools                                  ║
║  ❌ Harder to type correctly                                  ║
║                                                               ║
╚═══════════════════════════════════════════════════════════════╝
*/

// Same functionality as hook (preferred)
function useMousePosition() {
    const [position, setPosition] = useState({ x: 0, y: 0 });

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            setPosition({ x: e.clientX, y: e.clientY });
        };

        window.addEventListener('mousemove', handleMouseMove);
        return () => window.removeEventListener('mousemove', handleMouseMove);
    }, []);

    return position;
}

// Usage - much cleaner!
function ComponentWithMousePosition() {
    const { x, y } = useMousePosition();

    return (
        <div>
            Mouse: {x}, {y}
        </div>
    );
}
