## 🎯 7.3 Headless Components

```
// ═══════════════════════════════════════════════════════════
// HEADLESS COMPONENT PATTERN
// ═══════════════════════════════════════════════════════════

// Headless = Logic without UI
// Consumer provides the UI, component provides the behavior

// Headless Toggle
interface UseToggleReturn {
    isOn: boolean;
    toggle: () => void;
    setOn: () => void;
    setOff: () => void;
}

function useToggle(initialState = false): UseToggleReturn {
    const [isOn, setIsOn] = useState(initialState);

    const toggle = useCallback(() => setIsOn(prev => !prev), []);
    const setOn = useCallback(() => setIsOn(true), []);
    const setOff = useCallback(() => setIsOn(false), []);

    return { isOn, toggle, setOn, setOff };
}

// Usage - consumer controls the UI
function ToggleExample() {
    const { isOn, toggle } = useToggle();

    return (
        <button onClick={toggle}>
            {isOn ? '🌙 Dark Mode' : '☀️ Light Mode'}
        </button>
    );
}

// ═══════════════════════════════════════════════════════════
// HEADLESS DISCLOSURE (Show/Hide)
// ═══════════════════════════════════════════════════════════

interface UseDisclosureReturn {
    isOpen: boolean;
    open: () => void;
    close: () => void;
    toggle: () => void;
    getButtonProps: () => {
        onClick: () => void;
        'aria-expanded': boolean;
        'aria-controls': string;
    };
    getPanelProps: () => {
        id: string;
        hidden: boolean;
    };
}

function useDisclosure(id: string): UseDisclosureReturn {
    const [isOpen, setIsOpen] = useState(false);

    const open = useCallback(() => setIsOpen(true), []);
    const close = useCallback(() => setIsOpen(false), []);
    const toggle = useCallback(() => setIsOpen(prev => !prev), []);

    const getButtonProps = useCallback(() => ({
        onClick: toggle,
        'aria-expanded': isOpen,
        'aria-controls': `${id}-panel`
    }), [id, isOpen, toggle]);

    const getPanelProps = useCallback(() => ({
        id: `${id}-panel`,
        hidden: !isOpen
    }), [id, isOpen]);

    return {
        isOpen,
        open,
        close,
        toggle,
        getButtonProps,
        getPanelProps
    };
}

// Usage
function DisclosureExample() {
    const { isOpen, getButtonProps, getPanelProps } = useDisclosure('faq-1');

    return (
        <div>
            <button {...getButtonProps()}>
                What is React? {isOpen ? '▼' : '▶'}
            </button>
            <div {...getPanelProps()}>
                React is a JavaScript library for building user interfaces.
            </div>
        </div>
    );
}

// ═══════════════════════════════════════════════════════════
// HEADLESS COMBOBOX/AUTOCOMPLETE
// ═══════════════════════════════════════════════════════════

interface UseComboboxOptions<T> {
    items: T[];
    itemToString: (item: T | null) => string;
    onSelectedItemChange?: (item: T | null) => void;
    filterItems?: (items: T[], inputValue: string) => T[];
}

interface UseComboboxReturn<T> {
    isOpen: boolean;
    inputValue: string;
    highlightedIndex: number;
    selectedItem: T | null;
    filteredItems: T[];
    getInputProps: () => React.InputHTMLAttributes<HTMLInputElement>;
    getMenuProps: () => React.HTMLAttributes<HTMLUListElement>;
    getItemProps: (index: number) => React.LiHTMLAttributes<HTMLLIElement>;
    openMenu: () => void;
    closeMenu: () => void;
    selectItem: (item: T) => void;
}

function useCombobox<T>({
    items,
    itemToString,
    onSelectedItemChange,
    filterItems = (items, value) =>
        items.filter(item =>
            itemToString(item).toLowerCase().includes(value.toLowerCase())
        )
}: UseComboboxOptions<T>): UseComboboxReturn<T> {
    const [isOpen, setIsOpen] = useState(false);
    const [inputValue, setInputValue] = useState('');
    const [highlightedIndex, setHighlightedIndex] = useState(-1);
    const [selectedItem, setSelectedItem] = useState<T | null>(null);

    const filteredItems = useMemo(
        () => filterItems(items, inputValue),
        [items, inputValue, filterItems]
    );

    const openMenu = useCallback(() => setIsOpen(true), []);
    const closeMenu = useCallback(() => {
        setIsOpen(false);
        setHighlightedIndex(-1);
    }, []);

    const selectItem = useCallback((item: T) => {
        setSelectedItem(item);
        setInputValue(itemToString(item));
        closeMenu();
        onSelectedItemChange?.(item);
    }, [itemToString, closeMenu, onSelectedItemChange]);

    const getInputProps = useCallback(() => ({
        value: inputValue,
        onChange: (e: React.ChangeEvent<HTMLInputElement>) => {
            setInputValue(e.target.value);
            openMenu();
        },
        onFocus: openMenu,
        onKeyDown: (e: React.KeyboardEvent) => {
            switch (e.key) {
                case 'ArrowDown':
                    e.preventDefault();
                    setHighlightedIndex(prev =>
                        Math.min(prev + 1, filteredItems.length - 1)
                    );
                    break;
                case 'ArrowUp':
                    e.preventDefault();
                    setHighlightedIndex(prev => Math.max(prev - 1, 0));
                    break;
                case 'Enter':
                    if (highlightedIndex >= 0) {
                        selectItem(filteredItems[highlightedIndex]);
                    }
                    break;
                case 'Escape':
                    closeMenu();
                    break;
            }
        },
        role: 'combobox',
        'aria-expanded': isOpen,
        'aria-autocomplete': 'list' as const
    }), [inputValue, isOpen, highlightedIndex, filteredItems, openMenu, closeMenu, selectItem]);

    const getMenuProps = useCallback(() => ({
        role: 'listbox',
        hidden: !isOpen || filteredItems.length === 0
    }), [isOpen, filteredItems.length]);

    const getItemProps = useCallback((index: number) => ({
        role: 'option',
        'aria-selected': index === highlightedIndex,
        onClick: () => selectItem(filteredItems[index]),
        onMouseEnter: () => setHighlightedIndex(index),
        className: index === highlightedIndex ? 'highlighted' : ''
    }), [highlightedIndex, filteredItems, selectItem]);

    return {
        isOpen,
        inputValue,
        highlightedIndex,
        selectedItem,
        filteredItems,
        getInputProps,
        getMenuProps,
        getItemProps,
        openMenu,
        closeMenu,
        selectItem
    };
}

// Usage
interface Country {
    code: string;
    name: string;
}

const countries: Country[] = [
    { code: 'US', name: 'United States' },
    { code: 'UK', name: 'United Kingdom' },
    { code: 'CA', name: 'Canada' }
];

function CountryAutocomplete() {
    const {
        isOpen,
        filteredItems,
        getInputProps,
        getMenuProps,
        getItemProps
    } = useCombobox({
        items: countries,
        itemToString: (item) => item?.name ?? '',
        onSelectedItemChange: (item) => console.log('Selected:', item)
    });

    return (
        <div className="combobox">
            <input {...getInputProps()} placeholder="Search countries..." />
            <ul {...getMenuProps()}>
                {filteredItems.map((country, index) => (
                    <li key={country.code} {...getItemProps(index)}>
                        {country.name}
                    </li>
                ))}
            </ul>
        </div>
    );
}
