import { renderHook, act, waitFor } from '@testing-library/react';

// Custom hook to test
function useCounter(initialValue = 0) {
    const [count, setCount] = useState(initialValue);

    const increment = useCallback(() => setCount(c => c + 1), []);
    const decrement = useCallback(() => setCount(c => c - 1), []);
    const reset = useCallback(() => setCount(initialValue), [initialValue]);
    const setValue = useCallback((value: number) => setCount(value), []);

    return { count, increment, decrement, reset, setValue };
}

describe('useCounter', () => {
    it('initializes with default value', () => {
        const { result } = renderHook(() => useCounter());

        expect(result.current.count).toBe(0);
    });

    it('initializes with provided value', () => {
        const { result } = renderHook(() => useCounter(10));

        expect(result.current.count).toBe(10);
    });

    it('increments count', () => {
        const { result } = renderHook(() => useCounter());

        act(() => {
            result.current.increment();
        });

        expect(result.current.count).toBe(1);
    });

    it('decrements count', () => {
        const { result } = renderHook(() => useCounter(5));

        act(() => {
            result.current.decrement();
        });

        expect(result.current.count).toBe(4);
    });

    it('resets to initial value', () => {
        const { result } = renderHook(() => useCounter(5));

        act(() => {
            result.current.increment();
            result.current.increment();
        });

        expect(result.current.count).toBe(7);

        act(() => {
            result.current.reset();
        });

        expect(result.current.count).toBe(5);
    });

    it('sets specific value', () => {
        const { result } = renderHook(() => useCounter());

        act(() => {
            result.current.setValue(42);
        });

        expect(result.current.count).toBe(42);
    });

    it('updates reset behavior when initialValue changes', () => {
        const { result, rerender } = renderHook(
            ({ initial }) => useCounter(initial),
            { initialProps: { initial: 5 } }
        );

        act(() => {
            result.current.setValue(100);
        });

        // Change initial value
        rerender({ initial: 10 });

        act(() => {
            result.current.reset();
        });

        expect(result.current.count).toBe(10);
    });
});

// ═══════════════════════════════════════════════════════════
// TESTING ASYNC HOOKS
// ═══════════════════════════════════════════════════════════

interface UseFetchResult<T> {
    data: T | null;
    loading: boolean;
    error: Error | null;
    refetch: () => Promise<void>;
}

function useFetch<T>(url: string): UseFetchResult<T> {
    const [data, setData] = useState<T | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<Error | null>(null);

    const fetchData = useCallback(async () => {
        setLoading(true);
        setError(null);

        try {
            const response = await fetch(url);
            if (!response.ok) {
                throw new Error(`HTTP error! status: ${response.status}`);
            }
            const result = await response.json();
            setData(result);
        } catch (err) {
            setError(err as Error);
        } finally {
            setLoading(false);
        }
    }, [url]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    return { data, loading, error, refetch: fetchData };
}

describe('useFetch', () => {
    const mockData = { id: 1, name: 'Test' };

    beforeEach(() => {
        vi.clearAllMocks();
    });

    it('starts in loading state', () => {
        vi.spyOn(global, 'fetch').mockImplementation(
            () => new Promise(() => {})
        );

        const { result } = renderHook(() => useFetch('/api/data'));

        expect(result.current.loading).toBe(true);
        expect(result.current.data).toBe(null);
        expect(result.current.error).toBe(null);
    });

    it('returns data on successful fetch', async () => {
        vi.spyOn(global, 'fetch').mockResolvedValueOnce({
            ok: true,
            json: async () => mockData
        } as Response);

        const { result } = renderHook(() => useFetch('/api/data'));

        await waitFor(() => {
            expect(result.current.loading).toBe(false);
        });

        expect(result.current.data).toEqual(mockData);
        expect(result.current.error).toBe(null);
    });

    it('returns error on failed fetch', async () => {
        vi.spyOn(global, 'fetch').mockResolvedValueOnce({
            ok: false,
            status: 404
        } as Response);

        const { result } = renderHook(() => useFetch('/api/data'));

        await waitFor(() => {
            expect(result.current.loading).toBe(false);
        });

        expect(result.current.data).toBe(null);
        expect(result.current.error).toBeInstanceOf(Error);
        expect(result.current.error?.message).toContain('404');
    });

    it('refetches data when refetch is called', async () => {
        const fetchMock = vi.spyOn(global, 'fetch');
        fetchMock.mockResolvedValue({
            ok: true,
            json: async () => mockData
        } as Response);

        const { result } = renderHook(() => useFetch('/api/data'));

        await waitFor(() => {
            expect(result.current.loading).toBe(false);
        });

        expect(fetchMock).toHaveBeenCalledTimes(1);

        await act(async () => {
            await result.current.refetch();
        });

        expect(fetchMock).toHaveBeenCalledTimes(2);
    });

    it('refetches when URL changes', async () => {
        const fetchMock = vi.spyOn(global, 'fetch');
        fetchMock.mockResolvedValue({
            ok: true,
            json: async () => mockData
        } as Response);

        const { result, rerender } = renderHook(
            ({ url }) => useFetch(url),
            { initialProps: { url: '/api/data/1' } }
        );

        await waitFor(() => {
            expect(result.current.loading).toBe(false);
        });

        rerender({ url: '/api/data/2' });

        await waitFor(() => {
            expect(fetchMock).toHaveBeenCalledTimes(2);
            expect(fetchMock).toHaveBeenLastCalledWith('/api/data/2');
        });
    });
});

