// HARD 2: Implement a complete modal system with stacking
// ═══════════════════════════════════════════════════════════

interface ModalConfig {
    id: string;
    component: ReactNode;
    props?: Record<string, any>;
    onClose?: () => void;
    closeOnOverlay?: boolean;
    closeOnEscape?: boolean;
}

interface ModalContextValue {
    openModal: (config: Omit<ModalConfig, 'id'>) => string;
    closeModal: (id: string) => void;
    closeAllModals: () => void;
    modals: ModalConfig[];
}

const ModalContext = createContext<ModalContextValue | null>(null);

function ModalProvider({ children }: { children: ReactNode }) {
    const [modals, setModals] = useState<ModalConfig[]>([]);

    const openModal = useCallback((config: Omit<ModalConfig, 'id'>) => {
        const id = crypto.randomUUID();
        setModals(prev => [...prev, { ...config, id }]);
        return id;
    }, []);

    const closeModal = useCallback((id: string) => {
        setModals(prev => {
            const modal = prev.find(m => m.id === id);
            modal?.onClose?.();
            return prev.filter(m => m.id !== id);
        });
    }, []);

    const closeAllModals = useCallback(() => {
        setModals(prev => {
            prev.forEach(m => m.onClose?.());
            return [];
        });
    }, []);

    // Handle escape key for top-most modal
    useEffect(() => {
        const handleEscape = (e: KeyboardEvent) => {
            if (e.key === 'Escape' && modals.length > 0) {
                const topModal = modals[modals.length - 1];
                if (topModal.closeOnEscape !== false) {
                    closeModal(topModal.id);
                }
            }
        };

        document.addEventListener('keydown', handleEscape);
        return () => document.removeEventListener('keydown', handleEscape);
    }, [modals, closeModal]);

    // Prevent body scroll when modals are open
    useEffect(() => {
        if (modals.length > 0) {
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = '';
        }

        return () => {
            document.body.style.overflow = '';
        };
    }, [modals.length]);

    return (
        <ModalContext.Provider value={{ openModal, closeModal, closeAllModals, modals }}>
            {children}
            <ModalContainer modals={modals} closeModal={closeModal} />
        </ModalContext.Provider>
    );
}

function ModalContainer({
    modals,
    closeModal
}: {
    modals: ModalConfig[];
    closeModal: (id: string) => void;
}) {
    if (modals.length === 0) return null;

    return createPortal(
        <div className="modal-container">
            {modals.map((modal, index) => (
                <ModalWrapper
                    key={modal.id}
                    modal={modal}
                    index={index}
                    total={modals.length}
                    onClose={() => closeModal(modal.id)}
                />
            ))}
        </div>,
        document.body
    );
}

interface ModalWrapperProps {
    modal: ModalConfig;
    index: number;
    total: number;
    onClose: () => void;
}

function ModalWrapper({ modal, index, total, onClose }: ModalWrapperProps) {
    const modalRef = useRef<HTMLDivElement>(null);
    const previousActiveElement = useRef<Element | null>(null);
    const isTopModal = index === total - 1;

    // Focus management
    useEffect(() => {
        if (isTopModal) {
            previousActiveElement.current = document.activeElement;
            modalRef.current?.focus();
        }

        return () => {
            if (isTopModal && previousActiveElement.current) {
                (previousActiveElement.current as HTMLElement)?.focus();
            }
        };
    }, [isTopModal]);

    // Focus trap
    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (!isTopModal || e.key !== 'Tab') return;

        const focusableElements = modalRef.current?.querySelectorAll(
            'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
        );

        if (!focusableElements?.length) return;

        const first = focusableElements[0] as HTMLElement;
        const last = focusableElements[focusableElements.length - 1] as HTMLElement;

        if (e.shiftKey && document.activeElement === first) {
            e.preventDefault();
            last.focus();
        } else if (!e.shiftKey && document.activeElement === last) {
            e.preventDefault();
            first.focus();
        }
    };

    const handleOverlayClick = (e: React.MouseEvent) => {
        if (e.target === e.currentTarget && modal.closeOnOverlay !== false) {
            onClose();
        }
    };

    return (
        <div
            className={`modal-overlay ${isTopModal ? 'active' : ''}`}
            style={{
                zIndex: 1000 + index,
                backgroundColor: `rgba(0, 0, 0, ${0.3 + index * 0.1})`
            }}
            onClick={handleOverlayClick}
        >
            <div
                ref={modalRef}
                className="modal-content"
                role="dialog"
                aria-modal="true"
                tabIndex={-1}
                onKeyDown={handleKeyDown}
                style={{
                    transform: `scale(${1 - (total - 1 - index) * 0.05})`,
                    opacity: isTopModal ? 1 : 0.8
                }}
            >
                <button
                    className="modal-close"
                    onClick={onClose}
                    aria-label="Close modal"
                >
                    ×
                </button>
                {modal.component}
            </div>
        </div>
    );
}

function useModal() {
    const context = useContext(ModalContext);
    if (!context) {
        throw new Error('useModal must be used within ModalProvider');
    }
    return context;
}

// Usage:
function App() {
    const { openModal, closeModal } = useModal();

    const handleOpenConfirm = () => {
        const modalId = openModal({
            component: (
                <div>
                    <h2>Confirm Action</h2>
                    <p>Are you sure you want to proceed?</p>
                    <button onClick={() => closeModal(modalId)}>Cancel</button>
                    <button onClick={() => {
                        console.log('Confirmed!');
                        closeModal(modalId);
                    }}>
                        Confirm
                    </button>
                </div>
            ),
            onClose: () => console.log('Modal closed')
        });
    };

    return <button onClick={handleOpenConfirm}>Open Modal</button>;
}
