// ═══════════════════════════════════════════════════════════
// HARD 3: Implement undo/redo functionality
// ═══════════════════════════════════════════════════════════

interface UseUndoRedoOptions<T> {
    maxHistory?: number;
}

interface UseUndoRedoReturn<T> {
    state: T;
    set: (newState: T | ((prev: T) => T)) => void;
    undo: () => void;
    redo: () => void;
    canUndo: boolean;
    canRedo: boolean;
    history: T[];
    historyIndex: number;
    reset: (newState: T) => void;
}

function useUndoRedo<T>(
    initialState: T,
    options: UseUndoRedoOptions<T> = {}
): UseUndoRedoReturn<T> {
    const { maxHistory = 50 } = options;

    const [history, setHistory] = useState<T[]>([initialState]);
    const [historyIndex, setHistoryIndex] = useState(0);

    const state = history[historyIndex];

    const set = useCallback((newState: T | ((prev: T) => T)) => {
        setHistory(prev => {
            const currentState = prev[historyIndex];
            const nextState = typeof newState === 'function'
                ? (newState as (prev: T) => T)(currentState)
                : newState;

            // Don't add to history if state hasn't changed
            if (Object.is(nextState, currentState)) {
                return prev;
            }

            // Remove any future history (if we undid and then made a new change)
            const newHistory = prev.slice(0, historyIndex + 1);

            // Add new state
            newHistory.push(nextState);

            // Limit history size
            if (newHistory.length > maxHistory) {
                newHistory.shift();
                // Don't update historyIndex since we're removing from the beginning
                return newHistory;
            }

            return newHistory;
        });

        setHistoryIndex(prev => Math.min(prev + 1, maxHistory - 1));
    }, [historyIndex, maxHistory]);

    const undo = useCallback(() => {
        setHistoryIndex(prev => Math.max(prev - 1, 0));
    }, []);

    const redo = useCallback(() => {
        setHistoryIndex(prev => Math.min(prev + 1, history.length - 1));
    }, [history.length]);

    const reset = useCallback((newState: T) => {
        setHistory([newState]);
        setHistoryIndex(0);
    }, []);

    const canUndo = historyIndex > 0;
    const canRedo = historyIndex < history.length - 1;

    // Keyboard shortcuts
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if ((e.metaKey || e.ctrlKey) && e.key === 'z') {
                e.preventDefault();
                if (e.shiftKey) {
                    redo();
                } else {
                    undo();
                }
            }
        };

        document.addEventListener('keydown', handleKeyDown);
        return () => document.removeEventListener('keydown', handleKeyDown);
    }, [undo, redo]);

    return {
        state,
        set,
        undo,
        redo,
        canUndo,
        canRedo,
        history,
        historyIndex,
        reset
    };
}

// Usage with a drawing app:
interface DrawingState {
    strokes: Array<{ points: Array<{ x: number; y: number }>; color: string }>;
    currentColor: string;
}

function DrawingApp() {
    const {
        state,
        set,
        undo,
        redo,
        canUndo,
        canRedo
    } = useUndoRedo<DrawingState>({
        strokes: [],
        currentColor: '#000000'
    });

    const [isDrawing, setIsDrawing] = useState(false);
    const [currentStroke, setCurrentStroke] = useState<{ x: number; y: number }[]>([]);
    const canvasRef = useRef<HTMLCanvasElement>(null);

    const handleMouseDown = (e: React.MouseEvent<HTMLCanvasElement>) => {
        setIsDrawing(true);
        const point = getPoint(e);
        setCurrentStroke([point]);
    };

    const handleMouseMove = (e: React.MouseEvent<HTMLCanvasElement>) => {
        if (!isDrawing) return;
        const point = getPoint(e);
        setCurrentStroke(prev => [...prev, point]);
    };

    const handleMouseUp = () => {
        if (!isDrawing) return;
        setIsDrawing(false);

        if (currentStroke.length > 0) {
            set(prev => ({
                ...prev,
                strokes: [
                    ...prev.strokes,
                    { points: currentStroke, color: state.currentColor }
                ]
            }));
        }

        setCurrentStroke([]);
    };

    const getPoint = (e: React.MouseEvent<HTMLCanvasElement>) => {
        const rect = canvasRef.current!.getBoundingClientRect();
        return {
            x: e.clientX - rect.left,
            y: e.clientY - rect.top
        };
    };

    // Draw strokes
    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;

        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        // Clear canvas
        ctx.clearRect(0, 0, canvas.width, canvas.height);

        // Draw all strokes
        [...state.strokes, { points: currentStroke, color: state.currentColor }]
            .forEach(stroke => {
                if (stroke.points.length < 2) return;

                ctx.beginPath();
                ctx.strokeStyle = stroke.color;
                ctx.lineWidth = 2;
                ctx.lineCap = 'round';
                ctx.lineJoin = 'round';

                ctx.moveTo(stroke.points[0].x, stroke.points[0].y);
                stroke.points.forEach(point => {
                    ctx.lineTo(point.x, point.y);
                });
                ctx.stroke();
            });
    }, [state.strokes, currentStroke, state.currentColor]);

    return (
        <div className="drawing-app">
            <div className="toolbar">
                <button onClick={undo} disabled={!canUndo}>Undo</button>
                <button onClick={redo} disabled={!canRedo}>Redo</button>
                <input
                    type="color"
                    value={state.currentColor}
                    onChange={(e) => set(prev => ({
                        ...prev,
                        currentColor: e.target.value
                    }))}
                />
            </div>
            <canvas
                ref={canvasRef}
                width={800}
                height={600}
                onMouseDown={handleMouseDown}
                onMouseMove={handleMouseMove}
                onMouseUp={handleMouseUp}
                onMouseLeave={handleMouseUp}
            />
        </div>
    );
}
