// Create a Toggle component that:
// - Shows "ON" or "OFF" based on state
// - Toggles when clicked
// - Accepts an onChange callback
interface ToggleProps {
    initialValue?: boolean;
    onChange?: (isOn: boolean) => void;
}
function Toggle({ initialValue = false, onChange }: ToggleProps) {
    const [isOn, setIsOn] = useState(initialValue);
    const handleToggle = () => {
        const newValue = !isOn;
        setIsOn(newValue);
        onChange?.(newValue);
    };
    return (
        <button
            onClick={handleToggle}
            aria-pressed={isOn}
            className={`toggle ${isOn ? 'on' : 'off'}`}
        >
            {isOn ? 'ON' : 'OFF'}
        </button>
    );
}

interface TextInputProps {
    value: string;
    onChange: (value: string) => void;
    label: string;
    placeholder?: string;
    error?: string;
}
function TextInput({
    value,
    onChange,
    label,
    placeholder,
    error
}: TextInputProps) {
    const id = useId();
    return (
        <div className="text-input">
            <label htmlFor={id}>{label}</label>
            <input
                id={id}
                type="text"
                value={value}
                onChange={(e) => onChange(e.target.value)}
                placeholder={placeholder}
                aria-invalid={!!error}
                aria-describedby={error ? `${id}-error` : undefined}
            />
            {error && (
                <span id={`${id}-error`} className="error" role="alert">
                    {error}
                </span>
            )}
        </div>
    );
}

