function useLocalStorage<T>(
    key: string,
    initialValue: T
): [T, (value: T | ((prev: T) => T)) => void] {
    // Lazy initialization to read from localStorage
    const [storedValue, setStoredValue] = useState<T>(() => {
        try {
            const item = window.localStorage.getItem(key);
            return item ? JSON.parse(item) : initialValue;
        } catch (error) {
            console.error('Error reading from localStorage:', error);
            return initialValue;
        }
    });
    // Wrapper function to update both state and localStorage
    const setValue = useCallback((value: T | ((prev: T) => T)) => {
        try {
            setStoredValue(prev => {
                const valueToStore = value instanceof Function ? value(prev) : value;
                window.localStorage.setItem(key, JSON.stringify(valueToStore));
                return valueToStore;
            });
        } catch (error) {
            console.error('Error writing to localStorage:', error);
        }
    }, [key]);
    // Sync with other tabs/windows
    useEffect(() => {
        const handleStorageChange = (e: StorageEvent) => {
            if (e.key === key && e.newValue) {
                try {
                    setStoredValue(JSON.parse(e.newValue));
                } catch (error) {
                    console.error('Error parsing storage event:', error);
                }
            }
        };
        window.addEventListener('storage', handleStorageChange);
        return () => window.removeEventListener('storage', handleStorageChange);
    }, [key]);
    return [storedValue, setValue];
}
// Usage:
function App() {
    const [theme, setTheme] = useLocalStorage('theme', 'light');
    const [user, setUser] = useLocalStorage<User | null>('user', null);
    return (
        <div className={theme}>
            <button onClick={() => setTheme(t => t === 'light' ? 'dark' : 'light')}>
                Toggle Theme
            </button>
        </div>
    );
}

interface AutocompleteProps<T> {
    items: T[];
    getLabel: (item: T) => string;
    onSelect: (item: T) => void;
    placeholder?: string;
    debounceMs?: number;
}
function Autocomplete<T>({
    items,
    getLabel,
    onSelect,
    placeholder = 'Search...',
    debounceMs = 300
}: AutocompleteProps<T>) {
    const [query, setQuery] = useState('');
    const [isOpen, setIsOpen] = useState(false);
    const [highlightedIndex, setHighlightedIndex] = useState(-1);
    const inputRef = useRef<HTMLInputElement>(null);
    const listRef = useRef<HTMLUListElement>(null);
    // Debounce the query
    const debouncedQuery = useDebounce(query, debounceMs);
    // Filter items
    const filteredItems = useMemo(() => {
        if (!debouncedQuery) return [];
        const lowerQuery = debouncedQuery.toLowerCase();
        return items.filter(item =>
            getLabel(item).toLowerCase().includes(lowerQuery)
        );
    }, [items, debouncedQuery, getLabel]);
    // Handle keyboard navigation
    const handleKeyDown = (e: React.KeyboardEvent) => {
        switch (e.key) {
            case 'ArrowDown':
                e.preventDefault();
                setHighlightedIndex(prev =>
                    prev < filteredItems.length - 1 ? prev + 1 : prev
                );
                break;
            case 'ArrowUp':
                e.preventDefault();
                setHighlightedIndex(prev => prev > 0 ? prev - 1 : prev);
                break;
            case 'Enter':
                e.preventDefault();
                if (highlightedIndex >= 0) {
                    handleSelect(filteredItems[highlightedIndex]);
                }
                break;
            case 'Escape':
                setIsOpen(false);
                inputRef.current?.blur();
                break;
        }
    };
    const handleSelect = (item: T) => {
        setQuery(getLabel(item));
        setIsOpen(false);
        setHighlightedIndex(-1);
        onSelect(item);
    };
    // Close on outside click
    useEffect(() => {
        const handleClickOutside = (e: MouseEvent) => {
            if (!inputRef.current?.contains(e.target as Node) &&
                !listRef.current?.contains(e.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, []);
    // Scroll highlighted item into view
    useEffect(() => {
        if (highlightedIndex >= 0 && listRef.current) {
            const item = listRef.current.children[highlightedIndex] as HTMLElement;
            item?.scrollIntoView({ block: 'nearest' });
        }
    }, [highlightedIndex]);
    return (
        <div className="autocomplete">
            <input
                ref={inputRef}
                type="text"
                value={query}
                onChange={(e) => {
                    setQuery(e.target.value);
                    setIsOpen(true);
                    setHighlightedIndex(-1);
                }}
                onFocus={() => query && setIsOpen(true)}
                onKeyDown={handleKeyDown}
                placeholder={placeholder}
                role="combobox"
                aria-expanded={isOpen}
                aria-autocomplete="list"
                aria-controls="autocomplete-list"
            />
            {isOpen && filteredItems.length > 0 && (
                <ul
                    ref={listRef}
                    id="autocomplete-list"
                    className="autocomplete-list"
                    role="listbox"
                >
                    {filteredItems.map((item, index) => (
                        <li
                            key={index}
                            role="option"
                            aria-selected={index === highlightedIndex}
                            className={index === highlightedIndex ? 'highlighted' : ''}
                            onClick={() => handleSelect(item)}
                            onMouseEnter={() => setHighlightedIndex(index)}
                        >
                            {getLabel(item)}
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
}

interface UseInfiniteScrollOptions<T> {
    fetchPage: (page: number) => Promise<{ data: T[]; hasMore: boolean }>;
    pageSize?: number;
}
function useInfiniteScroll<T>({ fetchPage, pageSize = 20 }: UseInfiniteScrollOptions<T>) {
    const [items, setItems] = useState<T[]>([]);
    const [page, setPage] = useState(1);
    const [loading, setLoading] = useState(false);
    const [hasMore, setHasMore] = useState(true);
    const [error, setError] = useState<Error | null>(null);
    const loadMore = useCallback(async () => {
        if (loading || !hasMore) return;
        setLoading(true);
        setError(null);
        try {
            const result = await fetchPage(page);
            setItems(prev => [...prev, ...result.data]);
            setHasMore(result.hasMore);
            setPage(prev => prev + 1);
        } catch (err) {
            setError(err as Error);
        } finally {
            setLoading(false);
        }
    }, [fetchPage, page, loading, hasMore]);
    const reset = useCallback(() => {
        setItems([]);
        setPage(1);
        setHasMore(true);
        setError(null);
    }, []);
    // Load first page on mount
    useEffect(() => {
        loadMore();
    }, []); // eslint-disable-line react-hooks/exhaustive-deps
    return { items, loading, hasMore, error, loadMore, reset };
}
function InfiniteList() {
    const parentRef = useRef<HTMLDivElement>(null);
    const { items, loading, hasMore, loadMore } = useInfiniteScroll({
        fetchPage: async (page) => {
            const response = await fetch(`/api/items?page=${page}`);
            return response.json();
        }
    });
    // Virtualization with tanstack virtual
    const virtualizer = useVirtualizer({
        count: hasMore ? items.length + 1 : items.length,
        getScrollElement: () => parentRef.current,
        estimateSize: () => 50,
        overscan: 5
    });
    // Load more when reaching end
    useEffect(() => {
        const lastItem = virtualizer.getVirtualItems().slice(-1)[0];
        if (lastItem && lastItem.index >= items.length - 1 && hasMore && !loading) {
            loadMore();
        }
    }, [virtualizer.getVirtualItems(), items.length, hasMore, loading, loadMore]);
    return (
        <div ref={parentRef} className="scroll-container">
            <div
                style={{
                    height: `${virtualizer.getTotalSize()}px`,
                    position: 'relative'
                }}
            >
                {virtualizer.getVirtualItems().map(virtualRow => {
                    const isLoaderRow = virtualRow.index >= items.length;
                    return (
                        <div
                            key={virtualRow.key}
                            style={{
                                position: 'absolute',
                                top: 0,
                                left: 0,
                                width: '100%',
                                height: `${virtualRow.size}px`,
                                transform: `translateY(${virtualRow.start}px)`
                            }}
                        >
                            {isLoaderRow ? (
                                loading ? 'Loading...' : null
                            ) : (
                                <div className="item">
                                    {items[virtualRow.index].name}
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
}

interface DynamicFormField {
    id: string;
    type: 'text' | 'email' | 'number' | 'select';
    label: string;
    required?: boolean;
    options?: { value: string; label: string }[]; // For select
    validation?: (value: string) => string | null;
}
interface DynamicFormProps {
    fields: DynamicFormField[];
    onSubmit: (values: Record<string, string>) => void;
    submitLabel?: string;
}
function DynamicForm({ fields, onSubmit, submitLabel = 'Submit' }: DynamicFormProps) {
    const [values, setValues] = useState<Record<string, string>>(() =>
        fields.reduce((acc, field) => ({ ...acc, [field.id]: '' }), {})
    );
    const [errors, setErrors] = useState<Record<string, string>>({});
    const [touched, setTouched] = useState<Record<string, boolean>>({});
    const handleChange = (id: string, value: string) => {
        setValues(prev => ({ ...prev, [id]: value }));
        // Clear error when user types
        if (errors[id]) {
            setErrors(prev => {
                const { [id]: _, ...rest } = prev;
                return rest;
            });
        }
    };
    const handleBlur = (id: string) => {
        setTouched(prev => ({ ...prev, [id]: true }));
        validateField(id);
    };
    const validateField = (id: string): boolean => {
        const field = fields.find(f => f.id === id);
        if (!field) return true;
        const value = values[id];
        // Required validation
        if (field.required && !value.trim()) {
            setErrors(prev => ({ ...prev, [id]: `${field.label} is required` }));
            return false;
        }
        // Custom validation
        if (field.validation) {
            const error = field.validation(value);
            if (error) {
                setErrors(prev => ({ ...prev, [id]: error }));
                return false;
            }
        }
        // Email validation
        if (field.type === 'email' && value && !/\S+@\S+\.\S+/.test(value)) {
            setErrors(prev => ({ ...prev, [id]: 'Invalid email format' }));
            return false;
        }
        return true;
    };
    const validateAll = (): boolean => {
        let isValid = true;
        fields.forEach(field => {
            if (!validateField(field.id)) {
                isValid = false;
            }
        });
        // Mark all as touched
        setTouched(fields.reduce((acc, f) => ({ ...acc, [f.id]: true }), {}));
        return isValid;
    };
    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (validateAll()) {
            onSubmit(values);
        }
    };
    const renderField = (field: DynamicFormField) => {
        const commonProps = {
            id: field.id,
            value: values[field.id],
            onChange: (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) =>
                handleChange(field.id, e.target.value),
            onBlur: () => handleBlur(field.id),
            'aria-invalid': !!errors[field.id],
            'aria-describedby': errors[field.id] ? `${field.id}-error` : undefined
        };
        switch (field.type) {
            case 'select':
                return (
                    <select {...commonProps}>
                        <option value="">Select {field.label}</option>
                        {field.options?.map(opt => (
                            <option key={opt.value} value={opt.value}>
                                {opt.label}
                            </option>
                        ))}
                    </select>
                );
            default:
                return <input type={field.type} {...commonProps} />;
        }
    };
    return (
        <form onSubmit={handleSubmit} noValidate>
            {fields.map(field => (
                <div key={field.id} className="form-field">
                    <label htmlFor={field.id}>
                        {field.label}
                        {field.required && <span className="required">*</span>}
                    </label>
                    {renderField(field)}
                    {touched[field.id] && errors[field.id] && (
                        <span id={`${field.id}-error`} className="error" role="alert">
                            {errors[field.id]}
                        </span>
                    )}
                </div>
            ))}
            <button type="submit">{submitLabel}</button>
        </form>
    );
}
// Usage:
const formFields: DynamicFormField[] = [
    { id: 'name', type: 'text', label: 'Name', required: true },
    { id: 'email', type: 'email', label: 'Email', required: true },
    { id: 'age', type: 'number', label: 'Age', validation: (v) =>
        parseInt(v) < 18 ? 'Must be 18 or older' : null
    },
    {
        id: 'country',
        type: 'select',
        label: 'Country',
        options: [
            { value: 'us', label: 'United States' },
            { value: 'uk', label: 'United Kingdom' }
        ]
    }
];

