interface DraggableItem {
    id: string;
    content: ReactNode;
}
interface DragDropListProps {
    items: DraggableItem[];
    onReorder: (startIndex: number, endIndex: number) => void;
    renderItem?: (item: DraggableItem, isDragging: boolean) => ReactNode;
}
interface DragState {
    draggedIndex: number | null;
    dragOverIndex: number | null;
}
function DragDropList({ items, onReorder, renderItem }: DragDropListProps) {
    const [dragState, setDragState] = useState<DragState>({
        draggedIndex: null,
        dragOverIndex: null
    });
    const draggedItemRef = useRef<DraggableItem | null>(null);
    const handleDragStart = (e: React.DragEvent, index: number) => {
        draggedItemRef.current = items[index];
        setDragState({ draggedIndex: index, dragOverIndex: null });
        // Required for Firefox
        e.dataTransfer.effectAllowed = 'move';
        e.dataTransfer.setData('text/plain', index.toString());
        // Make the dragged element semi-transparent
        requestAnimationFrame(() => {
            (e.target as HTMLElement).style.opacity = '0.5';
        });
    };
    const handleDragEnd = (e: React.DragEvent) => {
        (e.target as HTMLElement).style.opacity = '1';
        const { draggedIndex, dragOverIndex } = dragState;
        if (draggedIndex !== null && dragOverIndex !== null && draggedIndex !== dragOverIndex) {
            onReorder(draggedIndex, dragOverIndex);
        }
        setDragState({ draggedIndex: null, dragOverIndex: null });
        draggedItemRef.current = null;
    };
    const handleDragOver = (e: React.DragEvent, index: number) => {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';
        if (dragState.dragOverIndex !== index) {
            setDragState(prev => ({ ...prev, dragOverIndex: index }));
        }
    };
    const handleDragLeave = (e: React.DragEvent) => {
        // Only reset if leaving the list entirely
        const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
        const { clientX, clientY } = e;
        if (
            clientX < rect.left ||
            clientX > rect.right ||
            clientY < rect.top ||
            clientY > rect.bottom
        ) {
            setDragState(prev => ({ ...prev, dragOverIndex: null }));
        }
    };
    const getItemStyle = (index: number): React.CSSProperties => {
        const { draggedIndex, dragOverIndex } = dragState;
        if (draggedIndex === null) return {};
        if (index === draggedIndex) {
            return { opacity: 0.5 };
        }
        if (dragOverIndex === null) return {};
        // Calculate transform for items between dragged and drop position
        if (draggedIndex < dragOverIndex) {
            if (index > draggedIndex && index <= dragOverIndex) {
                return { transform: 'translateY(-100%)' };
            }
        } else {
            if (index >= dragOverIndex && index < draggedIndex) {
                return { transform: 'translateY(100%)' };
            }
        }
        return {};
    };
    return (
        <ul
            className="drag-drop-list"
            onDragLeave={handleDragLeave}
        >
            {items.map((item, index) => (
                <li
                    key={item.id}
                    draggable
                    onDragStart={(e) => handleDragStart(e, index)}
                    onDragEnd={handleDragEnd}
                    onDragOver={(e) => handleDragOver(e, index)}
                    className={`drag-item ${
                        dragState.draggedIndex === index ? 'dragging' : ''
                    } ${
                        dragState.dragOverIndex === index ? 'drag-over' : ''
                    }`}
                    style={{
                        ...getItemStyle(index),
                        transition: dragState.draggedIndex !== null ? 'transform 0.2s' : 'none'
                    }}
                >
                    <div className="drag-handle">⋮⋮</div>
                    {renderItem
                        ? renderItem(item, dragState.draggedIndex === index)
                        : item.content
                    }
                </li>
            ))}
        </ul>
    );
}
// Reorder utility function
function reorder<T>(list: T[], startIndex: number, endIndex: number): T[] {
    const result = Array.from(list);
    const [removed] = result.splice(startIndex, 1);
    result.splice(endIndex, 0, removed);
    return result;
}
// Usage:
function TodoApp() {
    const [todos, setTodos] = useState<DraggableItem[]>([
        { id: '1', content: 'Learn React' },
        { id: '2', content: 'Build a project' },
        { id: '3', content: 'Deploy to production' }
    ]);
    const handleReorder = (startIndex: number, endIndex: number) => {
        setTodos(reorder(todos, startIndex, endIndex));
    };
    return (
        <DragDropList
            items={todos}
            onReorder={handleReorder}
            renderItem={(item, isDragging) => (
                <div className={`todo ${isDragging ? 'dragging' : ''}`}>
                    {item.content}
                </div>
            )}
        />
    );
}

interface ModalConfig {
    id: string;
    component: ReactNode;
    props?: Record<string, any>;
    onClose?: () => void;
    closeOnOverlay?: boolean;
    closeOnEscape?: boolean;
}
interface ModalContextValue {
    openModal: (config: Omit<ModalConfig, 'id'>) => string;
    closeModal: (id: string) => void;
    closeAllModals: () => void;
    modals: ModalConfig[];
