const ModalContext = createContext<ModalContextValue | null>(null);
function ModalProvider({ children }: { children: ReactNode }) {
    const [modals, setModals] = useState<ModalConfig[]>([]);
    const openModal = useCallback((config: Omit<ModalConfig, 'id'>) => {
        const id = crypto.randomUUID();
        setModals(prev => [...prev, { ...config, id }]);
        return id;
    }, []);
    const closeModal = useCallback((id: string) => {
        setModals(prev => {
            const modal = prev.find(m => m.id === id);
            modal?.onClose?.();
            return prev.filter(m => m.id !== id);
        });
    }, []);
    const closeAllModals = useCallback(() => {
        setModals(prev => {
            prev.forEach(m => m.onClose?.());
            return [];
        });
    }, []);
    // Handle escape key for top-most modal
    useEffect(() => {
        const handleEscape = (e: KeyboardEvent) => {
            if (e.key === 'Escape' && modals.length > 0) {
                const topModal = modals[modals.length - 1];
                if (topModal.closeOnEscape !== false) {
                    closeModal(topModal.id);
                }
            }
        };
        document.addEventListener('keydown', handleEscape);
        return () => document.removeEventListener('keydown', handleEscape);
    }, [modals, closeModal]);
    // Prevent body scroll when modals are open
    useEffect(() => {
        if (modals.length > 0) {
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = '';
        }
        return () => {
            document.body.style.overflow = '';
        };
    }, [modals.length]);
    return (
        <ModalContext.Provider value={{ openModal, closeModal, closeAllModals, modals }}>
            {children}
            <ModalContainer modals={modals} closeModal={closeModal} />
        </ModalContext.Provider>
    );
}
function ModalContainer({
    modals,
    closeModal
