    modals: ModalConfig[];
    closeModal: (id: string) => void;
}) {
    if (modals.length === 0) return null;
    return createPortal(
        <div className="modal-container">
            {modals.map((modal, index) => (
                <ModalWrapper
                    key={modal.id}
                    modal={modal}
                    index={index}
                    total={modals.length}
                    onClose={() => closeModal(modal.id)}
