            revalidateOnReconnect: true,
            refreshInterval: 30000, // Refresh every 30 seconds
        }
    );

    if (isLoading) return <div>Loading...</div>;
    if (error) return <div>Error loading user</div>;

    return (
        <div>
            <h1>{data.name}</h1>
            <button onClick={() => mutate()}>Refresh</button>
