// ═══════════════════════════════════════════════════════════
// WHAT ARE SERVER ACTIONS?
// ═══════════════════════════════════════════════════════════

/*
╔═══════════════════════════════════════════════════════════════╗
║                      SERVER ACTIONS                           ║
╠═══════════════════════════════════════════════════════════════╣
║                                                               ║
║  Server Actions are asynchronous functions that run on the    ║
║  server. They can be used in Server and Client Components     ║
║  to handle form submissions and data mutations.               ║
║                                                               ║
║  Benefits:                                                    ║
║  • No need to create API routes for simple mutations          ║
║  • Type-safe end-to-end                                       ║
║  • Progressive enhancement (works without JS)                 ║
║  • Integrated with React's form handling                      ║
║  • Automatic revalidation                                     ║
║                                                               ║
╚═══════════════════════════════════════════════════════════════╝
*/

// ═══════════════════════════════════════════════════════════
// BASIC SERVER ACTION
// ═══════════════════════════════════════════════════════════

// actions/posts.ts
'use server';

import { db } from '@/lib/db';
import { revalidatePath } from 'next/cache';
import { z } from 'zod';

// Validation schema
const CreatePostSchema = z.object({
    title: z.string().min(1).max(100),
    content: z.string().min(1),
});

export async function createPost(formData: FormData) {
    // Validate input
    const validatedFields = CreatePostSchema.safeParse({
        title: formData.get('title'),
        content: formData.get('content'),
    });

    if (!validatedFields.success) {
        return {
            errors: validatedFields.error.flatten().fieldErrors,
        };
    }

    const { title, content } = validatedFields.data;

    try {
        // Create post in database
        await db.post.create({
            data: { title, content },
        });

        // Revalidate the posts page
        revalidatePath('/posts');

        return { success: true };
    } catch (error) {
        return {
            error: 'Failed to create post',
        };
    }
}

