// actions/checkout.ts
'use server';

import { db } from '@/lib/db';
import { getCurrentUser } from '@/lib/auth';
import { redirect } from 'next/navigation';
import { revalidatePath } from 'next/cache';
import { z } from 'zod';

const CheckoutSchema = z.object({
    addressId: z.string(),
    paymentMethodId: z.string(),
    promoCode: z.string().optional(),
});

export type CheckoutState = {
    errors?: {
        addressId?: string[];
        paymentMethodId?: string[];
        promoCode?: string[];
        _form?: string[];
    };
    success?: boolean;
    orderId?: string;
};

export async function checkout(
    prevState: CheckoutState,
    formData: FormData
): Promise<CheckoutState> {
    // Authentication
    const user = await getCurrentUser();
    if (!user) {
        return {
            errors: {
                _form: ['You must be logged in to checkout'],
            },
        };
    }

    // Validation
    const validatedFields = CheckoutSchema.safeParse({
        addressId: formData.get('addressId'),
        paymentMethodId: formData.get('paymentMethodId'),
        promoCode: formData.get('promoCode'),
    });

    if (!validatedFields.success) {
        return {
            errors: validatedFields.error.flatten().fieldErrors,
        };
    }

    const { addressId, paymentMethodId, promoCode } = validatedFields.data;

    try {
        // Get cart items
        const cart = await db.cart.findUnique({
            where: { userId: user.id },
            include: { items: { include: { product: true } } },
        });

        if (!cart || cart.items.length === 0) {
            return {
                errors: {
                    _form: ['Your cart is empty'],
                },
            };
        }

        // Calculate total
        let total = cart.items.reduce(
            (sum, item) => sum + item.product.price * item.quantity,
            0
        );

        // Apply promo code
        if (promoCode) {
            const promo = await db.promoCode.findUnique({
                where: { code: promoCode },
            });

            if (promo && promo.expiresAt > new Date()) {
                total = total * (1 - promo.discount);
            } else {
                return {
                    errors: {
                        promoCode: ['Invalid or expired promo code'],
                    },
                };
            }
        }

        // Create order
        const order = await db.order.create({
            data: {
                userId: user.id,
                addressId,
                paymentMethodId,
                total,
                items: {
                    create: cart.items.map(item => ({
                        productId: item.productId,
                        quantity: item.quantity,
                        price: item.product.price,
                    })),
                },
            },
        });

        // Clear cart
        await db.cartItem.deleteMany({
            where: { cartId: cart.id },
        });

        // Process payment (simplified)
        await processPayment(order.id, paymentMethodId);

        // Revalidate relevant paths
        revalidatePath('/cart');
        revalidatePath('/orders');

        return {
            success: true,
            orderId: order.id,
        };
    } catch (error) {
        console.error('Checkout error:', error);
        return {
            errors: {
                _form: ['An error occurred during checkout. Please try again.'],
            },
        };
    }
}

