// ═══════════════════════════════════════════════════════════
// NEXT.JS MIDDLEWARE
// ═══════════════════════════════════════════════════════════

/*
╔═══════════════════════════════════════════════════════════════╗
║                      MIDDLEWARE                               ║
╠═══════════════════════════════════════════════════════════════╣
║                                                               ║
║  Middleware runs BEFORE a request is completed. It can:       ║
║                                                               ║
║  • Rewrite URLs                                               ║
║  • Redirect requests                                          ║
║  • Modify request/response headers                            ║
║  • Respond directly                                           ║
║  • Authentication/Authorization                               ║
║  • A/B Testing                                                ║
║  • Feature flags                                              ║
║  • Geolocation-based content                                  ║
║                                                               ║
║  Runs on the Edge Runtime (V8, not Node.js)                  ║
║                                                               ║
╚═══════════════════════════════════════════════════════════════╝
*/

// middleware.ts (root of project)
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

export function middleware(request: NextRequest) {
    // Get pathname
    const { pathname } = request.nextUrl;

    // Example: Add custom header
    const response = NextResponse.next();
    response.headers.set('x-custom-header', 'my-value');

    return response;
}

// Configure which paths middleware runs on
export const config = {
    matcher: [
        /*
         * Match all request paths except:
         * - api (API routes)
         * - _next/static (static files)
         * - _next/image (image optimization files)
         * - favicon.ico (favicon file)
         */
        '/((?!api|_next/static|_next/image|favicon.ico).*)',
    ],
};

// ═══════════════════════════════════════════════════════════
// AUTHENTICATION MIDDLEWARE
// ═══════════════════════════════════════════════════════════

// middleware.ts
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';
import { verifyToken } from '@/lib/auth';

// Routes that require authentication
const protectedRoutes = ['/dashboard', '/profile', '/settings', '/api/protected'];

// Routes that should redirect if authenticated
const authRoutes = ['/login', '/register'];

export async function middleware(request: NextRequest) {
    const { pathname } = request.nextUrl;

    // Get token from cookie
    const token = request.cookies.get('auth-token')?.value;

    // Check if route is protected
    const isProtectedRoute = protectedRoutes.some(route =>
        pathname.startsWith(route)
    );

    // Check if route is auth route
    const isAuthRoute = authRoutes.some(route =>
        pathname.startsWith(route)
    );

    // Verify token
    const user = token ? await verifyToken(token) : null;

    // Redirect logic
    if (isProtectedRoute && !user) {
        // Redirect to login with return URL
        const url = new URL('/login', request.url);
        url.searchParams.set('returnUrl', pathname);
        return NextResponse.redirect(url);
    }

    if (isAuthRoute && user) {
        // Redirect to dashboard if already authenticated
        return NextResponse.redirect(new URL('/dashboard', request.url));
    }

    // Add user info to headers for use in Server Components
    const response = NextResponse.next();
    if (user) {
        response.headers.set('x-user-id', user.id);
        response.headers.set('x-user-role', user.role);
    }

    return response;
}

export const config = {
    matcher: [
        '/dashboard/:path*',
        '/profile/:path*',
        '/settings/:path*',
        '/api/protected/:path*',
        '/login',
        '/register',
    ],
};

// ═══════════════════════════════════════════════════════════
// ROLE-BASED ACCESS CONTROL
// ═══════════════════════════════════════════════════════════

// middleware.ts
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

interface RouteConfig {
    path: string;
    roles: string[];
}

const routeConfigs: RouteConfig[] = [
    { path: '/admin', roles: ['admin'] },
    { path: '/dashboard', roles: ['admin', 'user'] },
    { path: '/moderator', roles: ['admin', 'moderator'] },
];

export async function middleware(request: NextRequest) {
    const { pathname } = request.nextUrl;

    // Find matching route config
    const routeConfig = routeConfigs.find(config =>
        pathname.startsWith(config.path)
    );

    if (!routeConfig) {
        return NextResponse.next();
    }

    // Get user from token
    const token = request.cookies.get('auth-token')?.value;
    const user = token ? await verifyToken(token) : null;

    if (!user) {
        return NextResponse.redirect(new URL('/login', request.url));
    }

    // Check role
    if (!routeConfig.roles.includes(user.role)) {
        return NextResponse.redirect(new URL('/unauthorized', request.url));
    }

    return NextResponse.next();
}

// ═══════════════════════════════════════════════════════════
// GEOLOCATION AND INTERNATIONALIZATION
// ═══════════════════════════════════════════════════════════

// middleware.ts
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

const locales = ['en', 'es', 'fr', 'de'];
const defaultLocale = 'en';

function getLocale(request: NextRequest): string {
    // Check cookie first
    const localeCookie = request.cookies.get('NEXT_LOCALE')?.value;
    if (localeCookie && locales.includes(localeCookie)) {
        return localeCookie;
    }

    // Check Accept-Language header
    const acceptLanguage = request.headers.get('accept-language');
    if (acceptLanguage) {
        const preferredLocale = acceptLanguage
            .split(',')
            .map(lang => lang.split(';')[0].trim().substring(0, 2))
            .find(lang => locales.includes(lang));

        if (preferredLocale) {
            return preferredLocale;
        }
    }

    // Check geolocation (Vercel provides this)
    const country = request.geo?.country;
    const countryToLocale: Record<string, string> = {
        US: 'en',
        GB: 'en',
        ES: 'es',
        MX: 'es',
        FR: 'fr',
        DE: 'de',
    };

    if (country && countryToLocale[country]) {
        return countryToLocale[country];
    }

    return defaultLocale;
}

export function middleware(request: NextRequest) {
    const { pathname } = request.nextUrl;

    // Check if pathname already has locale
    const pathnameHasLocale = locales.some(
        locale => pathname.startsWith(`/${locale}/`) || pathname === `/${locale}`
    );

    if (pathnameHasLocale) {
        return NextResponse.next();
    }

    // Redirect to localized version
    const locale = getLocale(request);
    const url = new URL(`/${locale}${pathname}`, request.url);

    return NextResponse.redirect(url);
}

export const config = {
    matcher: [
        // Skip internal paths
        '/((?!api|_next/static|_next/image|favicon.ico).*)',
    ],
};

// ═══════════════════════════════════════════════════════════
// A/B TESTING MIDDLEWARE
// ═══════════════════════════════════════════════════════════

// middleware.ts
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';

const EXPERIMENTS = {
    'new-homepage': {
        variants: ['control', 'variant-a', 'variant-b'],
        weights: [0.34, 0.33, 0.33],
    },
    'checkout-flow': {
        variants: ['control', 'simplified'],
        weights: [0.5, 0.5],
    },
};

function getVariant(experimentId: string, existingVariant?: string): string {
    const experiment = EXPERIMENTS[experimentId as keyof typeof EXPERIMENTS];
    if (!experiment) return 'control';

    // Return existing variant if valid
    if (existingVariant && experiment.variants.includes(existingVariant)) {
        return existingVariant;
    }

    // Assign new variant based on weights
    const random = Math.random();
    let cumulative = 0;

    for (let i = 0; i < experiment.variants.length; i++) {
        cumulative += experiment.weights[i];
        if (random < cumulative) {
            return experiment.variants[i];
        }
    }

    return experiment.variants[0];
}

export function middleware(request: NextRequest) {
    const { pathname } = request.nextUrl;
    const response = NextResponse.next();

    // Homepage experiment
    if (pathname === '/') {
        const cookieName = 'exp-new-homepage';
        const existingVariant = request.cookies.get(cookieName)?.value;
        const variant = getVariant('new-homepage', existingVariant);

        // Set cookie if new assignment
        if (!existingVariant) {
            response.cookies.set(cookieName, variant, {
                maxAge: 60 * 60 * 24 * 30, // 30 days
            });
        }

        // Rewrite to variant page
        if (variant !== 'control') {
            const url = request.nextUrl.clone();
            url.pathname = `/_variants/homepage/${variant}`;
            return NextResponse.rewrite(url);
        }
    }

    return response;
}
