                <Image
                    key={index}
                    src={image.src}
                    alt={`Gallery image ${index + 1}`}
                    width={image.width || 400}
                    height={image.height || 300}
                    placeholder={image.blurDataURL ? 'blur' : 'empty'}
                    blurDataURL={image.blurDataURL}
                />
            ))}
        </div>
    );
