    text?: string;
    length?: number;
    userId: string;
    timestamp: number;
}

interface Document {
    id: string;
    content: string;
    version: number;
    operations: TextOperation[];
    users: Map<string, User>;
    cursors: Map<string, Cursor>;
}

class CollaborationServer {
    private io: SocketServer;
    private documents: Map<string, Document> = new Map();

    constructor(httpServer: HTTPServer) {
        this.io = new SocketServer(httpServer, {
            cors: {
                origin: process.env.NEXT_PUBLIC_APP_URL,
                methods: ['GET', 'POST']
            }
        });

        this.setupSocketHandlers();
    }

    private setupSocketHandlers() {
        this.io.on('connection', (socket: Socket) => {
            console.log('Client connected:', socket.id);

            socket.on('join-document', (data: { documentId: string; user: User }) => {
                this.handleJoinDocument(socket, data);
            });

            socket.on('leave-document', (documentId: string) => {
                this.handleLeaveDocument(socket, documentId);
            });

            socket.on('text-operation', (data: { documentId: string; operation: TextOperation }) => {
                this.handleTextOperation(socket, data);
            });

            socket.on('cursor-move', (data: { documentId: string; cursor: Cursor }) => {
                this.handleCursorMove(socket, data);
            });

            socket.on('disconnect', () => {
                this.handleDisconnect(socket);
            });
        });
    }

    private handleJoinDocument(socket: Socket, data: { documentId: string; user: User }) {
        const { documentId, user } = data;

        // Create document if it doesn't exist
        if (!this.documents.has(documentId)) {
            this.documents.set(documentId, {
                id: documentId,
                content: '',
                version: 0,
                operations: [],
                users: new Map(),
                cursors: new Map()
            });
        }

        const doc = this.documents.get(documentId)!;

        // Add user to document
        doc.users.set(user.id, user);

        // Join socket room
        socket.join(documentId);

        // Store user info on socket
        socket.data.userId = user.id;
        socket.data.documentId = documentId;

        // Send current document state
        socket.emit('document-state', {
            content: doc.content,
            version: doc.version,
            users: Array.from(doc.users.values()),
            cursors: Array.from(doc.cursors.values())
        });

        // Notify others
        socket.to(documentId).emit('user-joined', user);
    }

    private handleLeaveDocument(socket: Socket, documentId: string) {
        const doc = this.documents.get(documentId);
        if (!doc) return;

        const userId = socket.data.userId;

        doc.users.delete(userId);
        doc.cursors.delete(userId);

        socket.leave(documentId);
        socket.to(documentId).emit('user-left', userId);

        // Clean up empty documents
        if (doc.users.size === 0) {
            this.documents.delete(documentId);
        }
    }

    private handleTextOperation(
        socket: Socket,
        data: { documentId: string; operation: TextOperation }
    ) {
        const { documentId, operation } = data;
        const doc = this.documents.get(documentId);
        if (!doc) return;

        // Apply operation
        const transformedOp = this.transformOperation(doc, operation);
        doc.content = this.applyOperation(doc.content, transformedOp);
        doc.version++;
        doc.operations.push(transformedOp);

        // Broadcast to others
        socket.to(documentId).emit('remote-operation', {
            operation: transformedOp,
            version: doc.version
        });

        // Acknowledge to sender
        socket.emit('operation-ack', {
            version: doc.version
        });
    }

    private handleCursorMove(socket: Socket, data: { documentId: string; cursor: Cursor }) {
        const { documentId, cursor } = data;
        const doc = this.documents.get(documentId);
        if (!doc) return;

        doc.cursors.set(cursor.userId, cursor);
        socket.to(documentId).emit('cursor-update', cursor);
    }

    private handleDisconnect(socket: Socket) {
        const { userId, documentId } = socket.data;
        if (documentId) {
            this.handleLeaveDocument(socket, documentId);
        }
    }

    private transformOperation(doc: Document, operation: TextOperation): TextOperation {
        // Simple OT (Operational Transformation)
        // In production, use a proper OT library like ot.js
        let position = operation.position;

        // Transform against concurrent operations
        for (const existingOp of doc.operations.slice(-10)) {
            if (existingOp.timestamp >= operation.timestamp) continue;

            if (existingOp.type === 'insert' && existingOp.position <= position) {
                position += existingOp.text?.length || 0;
            } else if (existingOp.type === 'delete' && existingOp.position < position) {
                position -= Math.min(existingOp.length || 0, position - existingOp.position);
            }
        }

        return { ...operation, position };
    }

    private applyOperation(content: string, operation: TextOperation): string {
        if (operation.type === 'insert' && operation.text) {
            return (
                content.slice(0, operation.position) +
                operation.text +
                content.slice(operation.position)
            );
        } else if (operation.type === 'delete' && operation.length) {
            return (
                content.slice(0, operation.position) +
                content.slice(operation.position + operation.length)
            );
        }
        return content;
    }
}

export { CollaborationServer };
