// hooks/useCollaborativeEditor.ts
'use client';

import { useState, useEffect, useCallback, useRef } from 'react';
import { io, Socket } from 'socket.io-client';

interface User {
    id: string;
    name: string;
    color: string;
}

interface Cursor {
    userId: string;
    position: { line: number; column: number };
}

interface TextOperation {
    type: 'insert' | 'delete';
    position: number;
    text?: string;
    length?: number;
    userId: string;
    timestamp: number;
}

interface UseCollaborativeEditorOptions {
    documentId: string;
    user: User;
    onContentChange?: (content: string) => void;
}

export function useCollaborativeEditor({
    documentId,
    user,
    onContentChange
}: UseCollaborativeEditorOptions) {
    const [content, setContent] = useState('');
    const [users, setUsers] = useState<User[]>([]);
    const [cursors, setCursors] = useState<Cursor[]>([]);
    const [isConnected, setIsConnected] = useState(false);
    const [version, setVersion] = useState(0);

    const socketRef = useRef<Socket | null>(null);
    const pendingOperationsRef = useRef<TextOperation[]>([]);

    // Connect to collaboration server
    useEffect(() => {
        const socket = io(process.env.NEXT_PUBLIC_COLLABORATION_URL!, {
            transports: ['websocket']
        });

        socketRef.current = socket;

        socket.on('connect', () => {
            setIsConnected(true);
            socket.emit('join-document', { documentId, user });
        });

        socket.on('disconnect', () => {
            setIsConnected(false);
        });

        socket.on('document-state', (state) => {
            setContent(state.content);
            setVersion(state.version);
            setUsers(state.users);
            setCursors(state.cursors);
        });

        socket.on('user-joined', (newUser: User) => {
            setUsers(prev => [...prev, newUser]);
        });

        socket.on('user-left', (userId: string) => {
            setUsers(prev => prev.filter(u => u.id !== userId));
            setCursors(prev => prev.filter(c => c.userId !== userId));
        });

        socket.on('remote-operation', ({ operation, version: newVersion }) => {
            applyRemoteOperation(operation);
            setVersion(newVersion);
        });

        socket.on('cursor-update', (cursor: Cursor) => {
            setCursors(prev => {
                const existing = prev.findIndex(c => c.userId === cursor.userId);
                if (existing >= 0) {
                    const updated = [...prev];
                    updated[existing] = cursor;
                    return updated;
                }
                return [...prev, cursor];
            });
        });

        socket.on('operation-ack', ({ version: newVersion }) => {
            setVersion(newVersion);
            pendingOperationsRef.current.shift();
        });

        return () => {
            socket.emit('leave-document', documentId);
            socket.disconnect();
        };
    }, [documentId, user]);

    const applyRemoteOperation = useCallback((operation: TextOperation) => {
        setContent(prev => {
            if (operation.type === 'insert' && operation.text) {
                return (
                    prev.slice(0, operation.position) +
                    operation.text +
                    prev.slice(operation.position)
                );
            } else if (operation.type === 'delete' && operation.length) {
                return (
                    prev.slice(0, operation.position) +
                    prev.slice(operation.position + operation.length)
                );
            }
            return prev;
        });
    }, []);

    const insertText = useCallback((position: number, text: string) => {
        const operation: TextOperation = {
            type: 'insert',
            position,
            text,
            userId: user.id,
            timestamp: Date.now()
        };

        // Apply locally
        setContent(prev =>
            prev.slice(0, position) + text + prev.slice(position)
        );

        // Send to server
        pendingOperationsRef.current.push(operation);
        socketRef.current?.emit('text-operation', { documentId, operation });
    }, [documentId, user.id]);

    const deleteText = useCallback((position: number, length: number) => {
        const operation: TextOperation = {
            type: 'delete',
            position,
            length,
            userId: user.id,
            timestamp: Date.now()
        };

        // Apply locally
        setContent(prev =>
            prev.slice(0, position) + prev.slice(position + length)
        );

        // Send to server
        pendingOperationsRef.current.push(operation);
        socketRef.current?.emit('text-operation', { documentId, operation });
    }, [documentId, user.id]);

    const moveCursor = useCallback((position: { line: number; column: number }) => {
        const cursor: Cursor = { userId: user.id, position };
        socketRef.current?.emit('cursor-move', { documentId, cursor });
    }, [documentId, user.id]);

    // Notify parent of content changes
    useEffect(() => {
        onContentChange?.(content);
    }, [content, onContentChange]);

    return {
        content,
        users,
        cursors,
        isConnected,
        version,
        insertText,
        deleteText,
        moveCursor
    };
}
