// components/CollaborativeEditor.tsx
'use client';

import { useRef, useEffect, useState, useCallback } from 'react';
import { useCollaborativeEditor } from '@/hooks/useCollaborativeEditor';

interface CollaborativeEditorProps {
    documentId: string;
    userId: string;
    userName: string;
}

export function CollaborativeEditor({
    documentId,
    userId,
    userName
}: CollaborativeEditorProps) {
    const editorRef = useRef<HTMLTextAreaElement>(null);
    const [localCursor, setLocalCursor] = useState({ line: 0, column: 0 });

    const user = {
        id: userId,
        name: userName,
        color: `hsl(${Math.random() * 360}, 70%, 50%)`
    };

    const {
        content,
        users,
        cursors,
        isConnected,
        insertText,
        deleteText,
        moveCursor
    } = useCollaborativeEditor({
        documentId,
        user
    });

    // Handle text changes
    const handleChange = useCallback((e: React.ChangeEvent<HTMLTextAreaElement>) => {
        const newValue = e.target.value;
        const oldValue = content;
        const cursorPos = e.target.selectionStart;

        if (newValue.length > oldValue.length) {
            // Text inserted
            const insertedText = newValue.slice(cursorPos - (newValue.length - oldValue.length), cursorPos);
            const insertPosition = cursorPos - insertedText.length;
            insertText(insertPosition, insertedText);
        } else if (newValue.length < oldValue.length) {
            // Text deleted
            const deleteLength = oldValue.length - newValue.length;
            deleteText(cursorPos, deleteLength);
        }
    }, [content, insertText, deleteText]);

    // Handle cursor movement
    const handleSelect = useCallback(() => {
        if (!editorRef.current) return;

        const textarea = editorRef.current;
        const cursorPos = textarea.selectionStart;

        // Calculate line and column
        const textBeforeCursor = textarea.value.slice(0, cursorPos);
        const lines = textBeforeCursor.split('\n');
        const line = lines.length - 1;
        const column = lines[lines.length - 1].length;

        setLocalCursor({ line, column });
        moveCursor({ line, column });
    }, [moveCursor]);

    // Render remote cursors
    const renderRemoteCursors = () => {
        return cursors
            .filter(c => c.userId !== userId)
            .map(cursor => {
                const cursorUser = users.find(u => u.id === cursor.userId);
                if (!cursorUser) return null;

                return (
                    <div
                        key={cursor.userId}
                        className="remote-cursor"
                        style={{
                            position: 'absolute',
                            left: `${cursor.position.column * 8}px`, // Approximate char width
                            top: `${cursor.position.line * 20}px`, // Approximate line height
                            borderLeft: `2px solid ${cursorUser.color}`
                        }}
                    >
                        <span
                            className="cursor-label"
                            style={{ backgroundColor: cursorUser.color }}
                        >
                            {cursorUser.name}
                        </span>
                    </div>
                );
            });
    };

    return (
        <div className="collaborative-editor">
            <div className="editor-header">
                <div className="connection-status">
                    <span className={`status-dot ${isConnected ? 'connected' : 'disconnected'}`} />
                    {isConnected ? 'Connected' : 'Disconnected'}
                </div>

                <div className="active-users">
                    {users.map(u => (
                        <div
                            key={u.id}
                            className="user-avatar"
                            style={{ backgroundColor: u.color }}
                            title={u.name}
                        >
                            {u.name[0].toUpperCase()}
                        </div>
                    ))}
                </div>
            </div>

            <div className="editor-container">
                <div className="cursors-layer">
                    {renderRemoteCursors()}
                </div>

                <textarea
                    ref={editorRef}
                    value={content}
                    onChange={handleChange}
                    onSelect={handleSelect}
                    onKeyUp={handleSelect}
                    onClick={handleSelect}
                    className="editor-textarea"
                    spellCheck={false}
                />
            </div>
        </div>
    );
}

