// contexts/CheckoutContext.tsx
'use client';

import { createContext, useContext, useReducer, ReactNode, useMemo } from 'react';

type CheckoutStep = 'cart' | 'shipping' | 'payment' | 'review' | 'confirmation';

interface CheckoutState {
    step: CheckoutStep;
    cart: CartItem[];
    shippingAddress: ShippingAddress | null;
    shippingOption: ShippingOption | null;
    paymentMethod: PaymentMethod | null;
    order: Order | null;
    isProcessing: boolean;
    error: string | null;
}

type CheckoutAction =
    | { type: 'SET_STEP'; payload: CheckoutStep }
    | { type: 'UPDATE_CART'; payload: CartItem[] }
    | { type: 'ADD_TO_CART'; payload: CartItem }
    | { type: 'REMOVE_FROM_CART'; payload: string }
    | { type: 'UPDATE_QUANTITY'; payload: { productId: string; quantity: number } }
    | { type: 'SET_SHIPPING_ADDRESS'; payload: ShippingAddress }
    | { type: 'SET_SHIPPING_OPTION'; payload: ShippingOption }
    | { type: 'SET_PAYMENT_METHOD'; payload: PaymentMethod }
    | { type: 'START_PROCESSING' }
    | { type: 'PROCESSING_SUCCESS'; payload: Order }
    | { type: 'PROCESSING_ERROR'; payload: string }
    | { type: 'RESET_CHECKOUT' };

const initialState: CheckoutState = {
    step: 'cart',
    cart: [],
    shippingAddress: null,
    shippingOption: null,
    paymentMethod: null,
    order: null,
    isProcessing: false,
    error: null
};

