function checkoutReducer(state: CheckoutState, action: CheckoutAction): CheckoutState {
    switch (action.type) {
        case 'SET_STEP':
            return { ...state, step: action.payload, error: null };

        case 'UPDATE_CART':
            return { ...state, cart: action.payload };

        case 'ADD_TO_CART': {
            const existing = state.cart.find(item => item.productId === action.payload.productId);
            if (existing) {
                return {
                    ...state,
                    cart: state.cart.map(item =>
                        item.productId === action.payload.productId
                            ? { ...item, quantity: item.quantity + action.payload.quantity }
                            : item
                    )
                };
            }
            return { ...state, cart: [...state.cart, action.payload] };
        }

        case 'REMOVE_FROM_CART':
            return {
                ...state,
                cart: state.cart.filter(item => item.productId !== action.payload)
            };

        case 'UPDATE_QUANTITY':
            return {
                ...state,
                cart: state.cart.map(item =>
                    item.productId === action.payload.productId
                        ? { ...item, quantity: action.payload.quantity }
                        : item
                ).filter(item => item.quantity > 0)
            };

        case 'SET_SHIPPING_ADDRESS':
            return { ...state, shippingAddress: action.payload };

        case 'SET_SHIPPING_OPTION':
            return { ...state, shippingOption: action.payload };

        case 'SET_PAYMENT_METHOD':
            return { ...state, paymentMethod: action.payload };

        case 'START_PROCESSING':
            return { ...state, isProcessing: true, error: null };

        case 'PROCESSING_SUCCESS':
            return {
                ...state,
                isProcessing: false,
                order: action.payload,
                step: 'confirmation',
                cart: []
            };

        case 'PROCESSING_ERROR':
            return { ...state, isProcessing: false, error: action.payload };

        case 'RESET_CHECKOUT':
            return initialState;

        default:
            return state;
    }
}

interface CheckoutContextValue {
    state: CheckoutState;
    // Cart actions
    addToCart: (item: CartItem) => void;
    removeFromCart: (productId: string) => void;
    updateQuantity: (productId: string, quantity: number) => void;
    // Navigation
    goToStep: (step: CheckoutStep) => void;
    nextStep: () => void;
    prevStep: () => void;
    // Checkout data
    setShippingAddress: (address: ShippingAddress) => void;
    setShippingOption: (option: ShippingOption) => void;
    setPaymentMethod: (method: PaymentMethod) => void;
    // Processing
    processOrder: () => Promise<void>;
    // Computed values
    subtotal: number;
    shippingCost: number;
    tax: number;
    total: number;
}

const CheckoutContext = createContext<CheckoutContextValue | null>(null);

const STEPS_ORDER: CheckoutStep[] = ['cart', 'shipping', 'payment', 'review', 'confirmation'];

export function CheckoutProvider({ children }: { children: ReactNode }) {
    const [state, dispatch] = useReducer(checkoutReducer, initialState);

    // Computed values
    const subtotal = useMemo(() =>
        state.cart.reduce((sum, item) => sum + item.price * item.quantity, 0),
        [state.cart]
    );

    const shippingCost = state.shippingOption?.price || 0;

    const tax = useMemo(() => subtotal * 0.08, [subtotal]); // 8% tax

    const total = subtotal + shippingCost + tax;

    // Cart actions
    const addToCart = (item: CartItem) => {
        dispatch({ type: 'ADD_TO_CART', payload: item });
    };

    const removeFromCart = (productId: string) => {
        dispatch({ type: 'REMOVE_FROM_CART', payload: productId });
    };

    const updateQuantity = (productId: string, quantity: number) => {
        dispatch({ type: 'UPDATE_QUANTITY', payload: { productId, quantity } });
    };

    // Navigation
    const goToStep = (step: CheckoutStep) => {
        dispatch({ type: 'SET_STEP', payload: step });
    };

    const nextStep = () => {
        const currentIndex = STEPS_ORDER.indexOf(state.step);
        if (currentIndex < STEPS_ORDER.length - 1) {
            dispatch({ type: 'SET_STEP', payload: STEPS_ORDER[currentIndex + 1] });
        }
    };

    const prevStep = () => {
        const currentIndex = STEPS_ORDER.indexOf(state.step);
        if (currentIndex > 0) {
            dispatch({ type: 'SET_STEP', payload: STEPS_ORDER[currentIndex - 1] });
        }
    };

    // Checkout data
    const setShippingAddress = (address: ShippingAddress) => {
        dispatch({ type: 'SET_SHIPPING_ADDRESS', payload: address });
    };

    const setShippingOption = (option: ShippingOption) => {
        dispatch({ type: 'SET_SHIPPING_OPTION', payload: option });
    };

    const setPaymentMethod = (method: PaymentMethod) => {
        dispatch({ type: 'SET_PAYMENT_METHOD', payload: method });
    };

    // Process order
    const processOrder = async () => {
        dispatch({ type: 'START_PROCESSING' });

        try {
            const response = await fetch('/api/orders', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    items: state.cart,
                    shippingAddress: state.shippingAddress,
                    shippingOption: state.shippingOption,
                    paymentMethod: state.paymentMethod,
                    subtotal,
                    shippingCost,
                    tax,
                    total
                })
            });

            if (!response.ok) {
                throw new Error('Failed to process order');
            }

            const order = await response.json();
            dispatch({ type: 'PROCESSING_SUCCESS', payload: order });
        } catch (error) {
            dispatch({
                type: 'PROCESSING_ERROR',
                payload: (error as Error).message
            });
        }
    };

    const value: CheckoutContextValue = {
        state,
        addToCart,
        removeFromCart,
        updateQuantity,
        goToStep,
        nextStep,
        prevStep,
        setShippingAddress,
        setShippingOption,
        setPaymentMethod,
        processOrder,
        subtotal,
        shippingCost,
        tax,
        total
    };

    return (
        <CheckoutContext.Provider value={value}>
            {children}
        </CheckoutContext.Provider>
    );
}

export function useCheckout() {
    const context = useContext(CheckoutContext);
    if (!context) {
        throw new Error('useCheckout must be used within CheckoutProvider');
    }
    return context;
}

