// components/checkout/ShippingStep.tsx
'use client';

import { useState } from 'react';
import { useCheckout } from '@/contexts/CheckoutContext';
import { z } from 'zod';

const shippingSchema = z.object({
    firstName: z.string().min(1, 'First name is required'),
    lastName: z.string().min(1, 'Last name is required'),
    address1: z.string().min(1, 'Address is required'),
    address2: z.string().optional(),
    city: z.string().min(1, 'City is required'),
    state: z.string().min(1, 'State is required'),
    postalCode: z.string().min(5, 'Valid postal code required'),
    country: z.string().min(1, 'Country is required'),
    phone: z.string().min(10, 'Valid phone number required')
});

const SHIPPING_OPTIONS: ShippingOption[] = [
    { id: 'standard', name: 'Standard Shipping', price: 5.99, estimatedDays: 5 },
    { id: 'express', name: 'Express Shipping', price: 12.99, estimatedDays: 2 },
    { id: 'overnight', name: 'Overnight Shipping', price: 24.99, estimatedDays: 1 }
];

export function ShippingStep() {
    const { state, setShippingAddress, setShippingOption, nextStep, prevStep } = useCheckout();

    const [formData, setFormData] = useState<ShippingAddress>(
        state.shippingAddress || {
            firstName: '',
            lastName: '',
            address1: '',
            address2: '',
            city: '',
            state: '',
            postalCode: '',
            country: 'US',
            phone: ''
        }
    );

    const [selectedShipping, setSelectedShipping] = useState(
        state.shippingOption?.id || 'standard'
    );

    const [errors, setErrors] = useState<Record<string, string>>({});

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));

        // Clear error on change
        if (errors[name]) {
            setErrors(prev => {
                const { [name]: _, ...rest } = prev;
                return rest;
            });
        }
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();

        // Validate
        const result = shippingSchema.safeParse(formData);

        if (!result.success) {
            const fieldErrors: Record<string, string> = {};
            result.error.issues.forEach(issue => {
                fieldErrors[issue.path[0]] = issue.message;
            });
            setErrors(fieldErrors);
            return;
        }

        // Save shipping info
        setShippingAddress(formData);
        setShippingOption(SHIPPING_OPTIONS.find(o => o.id === selectedShipping)!);

        nextStep();
    };

    return (
        <div className="shipping-step">
            <h2>Shipping Information</h2>

            <form onSubmit={handleSubmit}>
                <div className="form-section">
                    <h3>Delivery Address</h3>

                    <div className="form-row">
                        <div className="form-group">
                            <label htmlFor="firstName">First Name</label>
                            <input
                                id="firstName"
                                name="firstName"
                                value={formData.firstName}
                                onChange={handleChange}
                                className={errors.firstName ? 'error' : ''}
                            />
                            {errors.firstName && <span className="error-message">{errors.firstName}</span>}
                        </div>

                        <div className="form-group">
                            <label htmlFor="lastName">Last Name</label>
                            <input
                                id="lastName"
                                name="lastName"
                                value={formData.lastName}
                                onChange={handleChange}
                                className={errors.lastName ? 'error' : ''}
                            />
                            {errors.lastName && <span className="error-message">{errors.lastName}</span>}
                        </div>
                    </div>

                    <div className="form-group">
                        <label htmlFor="address1">Address</label>
                        <input
                            id="address1"
                            name="address1"
                            value={formData.address1}
                            onChange={handleChange}
                            className={errors.address1 ? 'error' : ''}
                        />
                        {errors.address1 && <span className="error-message">{errors.address1}</span>}
                    </div>

                    <div className="form-group">
                        <label htmlFor="address2">Apartment, suite, etc. (optional)</label>
                        <input
                            id="address2"
                            name="address2"
                            value={formData.address2}
                            onChange={handleChange}
                        />
                    </div>

                    <div className="form-row">
                        <div className="form-group">
                            <label htmlFor="city">City</label>
                            <input
                                id="city"
                                name="city"
                                value={formData.city}
                                onChange={handleChange}
                                className={errors.city ? 'error' : ''}
                            />
                            {errors.city && <span className="error-message">{errors.city}</span>}
                        </div>

                        <div className="form-group">
                            <label htmlFor="state">State</label>
                            <input
                                id="state"
                                name="state"
                                value={formData.state}
                                onChange={handleChange}
                                className={errors.state ? 'error' : ''}
                            />
                            {errors.state && <span className="error-message">{errors.state}</span>}
                        </div>

                        <div className="form-group">
                            <label htmlFor="postalCode">Postal Code</label>
                            <input
                                id="postalCode"
                                name="postalCode"
                                value={formData.postalCode}
                                onChange={handleChange}
                                className={errors.postalCode ? 'error' : ''}
                            />
                            {errors.postalCode && <span className="error-message">{errors.postalCode}</span>}
                        </div>
                    </div>

                    <div className="form-group">
                        <label htmlFor="phone">Phone</label>
                        <input
                            id="phone"
                            name="phone"
                            type="tel"
                            value={formData.phone}
                            onChange={handleChange}
                            className={errors.phone ? 'error' : ''}
                        />
                        {errors.phone && <span className="error-message">{errors.phone}</span>}
                    </div>
                </div>

                <div className="form-section">
                    <h3>Shipping Method</h3>

                    <div className="shipping-options">
                        {SHIPPING_OPTIONS.map(option => (
                            <label key={option.id} className="shipping-option">
                                <input
                                    type="radio"
                                    name="shipping"
                                    value={option.id}
                                    checked={selectedShipping === option.id}
                                    onChange={(e) => setSelectedShipping(e.target.value)}
                                />
                                <div className="option-details">
                                    <span className="option-name">{option.name}</span>
                                    <span className="option-estimate">
                                        {option.estimatedDays} business day{option.estimatedDays > 1 ? 's' : ''}
                                    </span>
                                </div>
                                <span className="option-price">${option.price.toFixed(2)}</span>
                            </label>
                        ))}
                    </div>
                </div>

                <div className="form-actions">
                    <button type="button" className="btn-secondary" onClick={prevStep}>
                        Back to Cart
                    </button>
                    <button type="submit" className="btn-primary">
                        Continue to Payment
                    </button>
                </div>
            </form>
        </div>
    );
}
