// components/checkout/PaymentStep.tsx
'use client';

import { useState } from 'react';
import { useCheckout } from '@/contexts/CheckoutContext';
import { loadStripe } from '@stripe/stripe-js';
import { Elements, CardElement, useStripe, useElements } from '@stripe/react-stripe-js';

const stripePromise = loadStripe(process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY!);

function PaymentForm() {
    const { setPaymentMethod, nextStep, prevStep, state } = useCheckout();
    const stripe = useStripe();
    const elements = useElements();

    const [paymentType, setPaymentType] = useState<'card' | 'paypal'>('card');
    const [isProcessing, setIsProcessing] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        if (paymentType === 'card') {
            if (!stripe || !elements) return;

            setIsProcessing(true);
            setError(null);

            const cardElement = elements.getElement(CardElement);
            if (!cardElement) return;

            // Create payment method
            const { error: stripeError, paymentMethod } = await stripe.createPaymentMethod({
                type: 'card',
                card: cardElement
            });

            if (stripeError) {
                setError(stripeError.message || 'Payment failed');
                setIsProcessing(false);
                return;
            }

            // Save payment method ID (in real app, you'd send this to your server)
            setPaymentMethod({
                type: 'card',
                cardNumber: `****${paymentMethod.card?.last4}`
            });

            setIsProcessing(false);
            nextStep();
        } else if (paymentType === 'paypal') {
            // Handle PayPal payment
            setPaymentMethod({ type: 'paypal' });
            nextStep();
        }
    };

    return (
        <div className="payment-step">
            <h2>Payment Method</h2>

            <form onSubmit={handleSubmit}>
                <div className="payment-options">
                    <label className="payment-option">
                        <input
                            type="radio"
                            name="paymentType"
                            value="card"
                            checked={paymentType === 'card'}
                            onChange={() => setPaymentType('card')}
                        />
                        <span>Credit/Debit Card</span>
                    </label>

                    <label className="payment-option">
                        <input
                            type="radio"
                            name="paymentType"
                            value="paypal"
                            checked={paymentType === 'paypal'}
                            onChange={() => setPaymentType('paypal')}
                        />
                        <span>PayPal</span>
                    </label>
                </div>

                {paymentType === 'card' && (
                    <div className="card-input">
                        <CardElement
                            options={{
                                style: {
                                    base: {
                                        fontSize: '16px',
                                        color: '#424770',
                                        '::placeholder': {
                                            color: '#aab7c4'
                                        }
                                    },
                                    invalid: {
                                        color: '#9e2146'
                                    }
                                }
                            }}
                        />
                    </div>
                )}

                {error && (
                    <div className="error-message" role="alert">
                        {error}
                    </div>
                )}

                <div className="form-actions">
                    <button type="button" className="btn-secondary" onClick={prevStep}>
                        Back to Shipping
                    </button>
                    <button
                        type="submit"
                        className="btn-primary"
                        disabled={isProcessing || !stripe}
                    >
                        {isProcessing ? 'Processing...' : 'Review Order'}
                    </button>
                </div>
            </form>
        </div>
    );
}

export function PaymentStep() {
    return (
        <Elements stripe={stripePromise}>
            <PaymentForm />
        </Elements>
    );
}

