// lib/performance.ts
interface PerformanceMetric {
    name: string;
    value: number;
    unit: string;
    timestamp: number;
    metadata?: Record<string, any>;
}

class PerformanceMonitor {
    private metrics: PerformanceMetric[] = [];
    private marks: Map<string, number> = new Map();

    // Mark start of an operation
    mark(name: string) {
        this.marks.set(name, performance.now());
    }

    // Measure time since mark
    measure(name: string, metadata?: Record<string, any>): number {
        const start = this.marks.get(name);
        if (!start) {
            console.warn(`No mark found for: ${name}`);
            return 0;
        }

        const duration = performance.now() - start;
        this.marks.delete(name);

        const metric: PerformanceMetric = {
            name,
            value: duration,
            unit: 'ms',
            timestamp: Date.now(),
            metadata
        };

        this.metrics.push(metric);
        this.reportMetric(metric);

        return duration;
    }

    // Track custom metric
    track(name: string, value: number, unit: string, metadata?: Record<string, any>) {
        const metric: PerformanceMetric = {
            name,
            value,
            unit,
            timestamp: Date.now(),
            metadata
        };

        this.metrics.push(metric);
        this.reportMetric(metric);
    }

    // Report metric to backend
    private reportMetric(metric: PerformanceMetric) {
        if (typeof window !== 'undefined' && navigator.sendBeacon) {
            navigator.sendBeacon(
                '/api/analytics/performance',
                JSON.stringify(metric)
            );
        }
    }

    // Get all metrics
    getMetrics(): PerformanceMetric[] {
        return [...this.metrics];
    }

    // Clear metrics
    clear() {
        this.metrics = [];
        this.marks.clear();
    }
}

export const performanceMonitor = new PerformanceMonitor();

// Usage example
async function fetchWithPerformanceTracking() {
    performanceMonitor.mark('api-call');

    const response = await fetch('/api/data');
    const data = await response.json();

    performanceMonitor.measure('api-call', {
        endpoint: '/api/data',
        responseSize: JSON.stringify(data).length
    });

    return data;
}

// React hook for performance tracking
function usePerformanceTrack(name: string) {
    useEffect(() => {
        performanceMonitor.mark(name);

        return () => {
            performanceMonitor.measure(name);
        };
    }, [name]);
}

function SlowComponent() {
    usePerformanceTrack('SlowComponent-render');

    // ... component logic

    return <div>...</div>;
}
