// lib/api-helpers.ts
import { NextRequest, NextResponse } from 'next/server';
import { auth } from '@/auth';
import { Ratelimit } from '@upstash/ratelimit';
import { Redis } from '@upstash/redis';
const redis = new Redis({
url: process.env.UPSTASH_REDIS_URL!,
token: process.env.UPSTASH_REDIS_TOKEN!,
});
const ratelimit = new Ratelimit({
redis,
limiter: Ratelimit.slidingWindow(10, '60 s'),
});
type ApiHandler = (
request: NextRequest,
context: { user: { id: string; email: string; role: string } }
) => Promise<NextResponse>;
interface ApiOptions {
requireAuth?: boolean;
allowedRoles?: string[];
rateLimit?: boolean;
}
export function createApiHandler(handler: ApiHandler, options: ApiOptions = {}) {
const {
requireAuth = true,
allowedRoles = [],
rateLimit: enableRateLimit = true,
} = options;
return async (request: NextRequest) => {
try {
// Rate limiting
if (enableRateLimit) {
const ip = request.ip ?? 'anonymous';
const { success, remaining } = await ratelimit.limit(ip);
if (!success) {
return NextResponse.json(
{ error: 'Too many requests' },
{
status: 429,
headers: {
'X-RateLimit-Remaining': remaining.toString(),
},
}
);
}
}
// Authentication
if (requireAuth) {
const session = await auth();
if (!session?.user) {
return NextResponse.json(
{ error: 'Unauthorized' },
{ status: 401 }
);
}
// Role-based access
if (allowedRoles.length > 0 && !allowedRoles.includes(session.user.role)) {
return NextResponse.json(
{ error: 'Forbidden' },
{ status: 403 }
);
}
return handler(request, { user: session.user });
}
return handler(request, { user: null as any });
} catch (error) {
console.error('API Error:', error);
return NextResponse.json(
{ error: 'Internal server error' },
{ status: 500 }
);
}
};
}

