'use client';
import { useOptimistic, useTransition } from 'react';
import { toggleTodo, deleteTodo, addTodo } from '@/actions/todos';
interface Todo {
id: string;
text: string;
completed: boolean;
}
interface TodoListProps {
initialTodos: Todo[];
}
type OptimisticAction =
| { type: 'add'; todo: Todo }
| { type: 'toggle'; id: string }
| { type: 'delete'; id: string };
export function TodoList({ initialTodos }: TodoListProps) {
const [isPending, startTransition] = useTransition();
const [optimisticTodos, updateOptimisticTodos] = useOptimistic(
initialTodos,
(state: Todo[], action: OptimisticAction) => {
switch (action.type) {
case 'add':
return [...state, action.todo];
case 'toggle':
return state.map(todo =>
todo.id === action.id
? { ...todo, completed: !todo.completed }
: todo
);
case 'delete':
return state.filter(todo => todo.id !== action.id);
default:
return state;
}
}
);
const handleAdd = async (formData: FormData) => {
const text = formData.get('text') as string;
const tempId = `temp-${Date.now()}`;
startTransition(async () => {
updateOptimisticTodos({
type: 'add',
todo: { id: tempId, text, completed: false },
});
await addTodo(text);
});
};
const handleToggle = (id: string) => {
startTransition(async () => {
updateOptimisticTodos({ type: 'toggle', id });
await toggleTodo(id);
});
};
const handleDelete = (id: string) => {
startTransition(async () => {
updateOptimisticTodos({ type: 'delete', id });
await deleteTodo(id);
});
};
return (
<div className="todo-list">
<form action={handleAdd}>
<input
name="text"
placeholder="Add a new todo..."
required
/>
<button type="submit">Add</button>
</form>
<ul>
{optimisticTodos.map(todo => (
<li
key={todo.id}
className={todo.completed ? 'completed' : ''}
>
<input
type="checkbox"
checked={todo.completed}
onChange={() => handleToggle(todo.id)}
/>
<span>{todo.text}</span>
<button onClick={() => handleDelete(todo.id)}>
Delete
</button>
</li>
))}
</ul>
</div>
);
}

