// lib/auth.ts - Authentication utilities
import { SignJWT, jwtVerify } from 'jose';
import { cookies } from 'next/headers';
import { NextRequest, NextResponse } from 'next/server';
import bcrypt from 'bcryptjs';
const JWT_SECRET = new TextEncoder().encode(process.env.JWT_SECRET!);
const COOKIE_NAME = 'auth_token';
interface UserPayload {
    id: string;
    email: string;
    role: 'user' | 'admin';
}
interface Session {
    user: UserPayload;
    expires: Date;
}
// Create JWT token
async function createToken(payload: UserPayload): Promise<string> {
    return new SignJWT({ ...payload })
        .setProtectedHeader({ alg: 'HS256' })
        .setIssuedAt()
        .setExpirationTime('7d')
        .sign(JWT_SECRET);
}
// Verify JWT token
async function verifyToken(token: string): Promise<UserPayload | null> {
    try {
        const { payload } = await jwtVerify(token, JWT_SECRET);
        return payload as unknown as UserPayload;
    } catch {
        return null;
    }
}
// Get session from cookies
export async function getSession(): Promise<Session | null> {
    const cookieStore = cookies();
    const token = cookieStore.get(COOKIE_NAME)?.value;
    if (!token) return null;
    const payload = await verifyToken(token);
    if (!payload) return null;
    return {
        user: payload,
        expires: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000)
    };
}
// Set session cookie
export async function setSession(user: UserPayload): Promise<void> {
    const token = await createToken(user);
    const cookieStore = cookies();
    cookieStore.set(COOKIE_NAME, token, {
        httpOnly: true,
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'lax',
        maxAge: 7 * 24 * 60 * 60, // 7 days
        path: '/'
    });
}
// Clear session
export async function clearSession(): Promise<void> {
    const cookieStore = cookies();
    cookieStore.delete(COOKIE_NAME);
}
// Hash password
export async function hashPassword(password: string): Promise<string> {
    return bcrypt.hash(password, 12);
}
// Verify password
export async function verifyPassword(
    password: string,
    hashedPassword: string
): Promise<boolean> {
    return bcrypt.compare(password, hashedPassword);
}
// Middleware for route protection
// middleware.ts
import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';
const publicPaths = ['/login', '/register', '/forgot-password', '/api/auth'];
const adminPaths = ['/admin'];
export async function middleware(request: NextRequest) {
    const { pathname } = request.nextUrl;
    // Check if path is public
    const isPublicPath = publicPaths.some(path => pathname.startsWith(path));
    // Get token from cookie
    const token = request.cookies.get(COOKIE_NAME)?.value;
    // Verify token
    let user: UserPayload | null = null;
    if (token) {
        user = await verifyToken(token);
    }
    // Redirect logic
    if (!user && !isPublicPath) {
        // Not authenticated, redirect to login
        const loginUrl = new URL('/login', request.url);
        loginUrl.searchParams.set('callbackUrl', pathname);
        return NextResponse.redirect(loginUrl);
    }
    if (user && isPublicPath && pathname !== '/api/auth/logout') {
        // Already authenticated, redirect to dashboard
        return NextResponse.redirect(new URL('/dashboard', request.url));
    }
    // Check admin routes
    const isAdminPath = adminPaths.some(path => pathname.startsWith(path));
    if (isAdminPath && user?.role !== 'admin') {
        return NextResponse.redirect(new URL('/unauthorized', request.url));
    }
    // Add user to request headers for server components
    const response = NextResponse.next();
    if (user) {
        response.headers.set('x-user-id', user.id);
        response.headers.set('x-user-email', user.email);
        response.headers.set('x-user-role', user.role);
    }
    return response;
}
export const config = {
    matcher: [
        '/((?!_next/static|_next/image|favicon.ico|public).*)'
    ]
};
// API Routes for authentication
// app/api/auth/register/route.ts
import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import { prisma } from '@/lib/prisma';
import { hashPassword, setSession } from '@/lib/auth';
const registerSchema = z.object({
    name: z.string().min(2).max(100),
    email: z.string().email(),
    password: z.string().min(8).max(100)
});
export async function POST(request: NextRequest) {
    try {
        const body = await request.json();
        // Validate input
        const result = registerSchema.safeParse(body);
        if (!result.success) {
            return NextResponse.json(
                { error: 'Validation failed', issues: result.error.issues },
                { status: 400 }
            );
        }
        const { name, email, password } = result.data;
        // Check if user exists
        const existingUser = await prisma.user.findUnique({
            where: { email }
        });
        if (existingUser) {
            return NextResponse.json(
                { error: 'Email already registered' },
                { status: 409 }
            );
        }
        // Hash password and create user
        const hashedPassword = await hashPassword(password);
        const user = await prisma.user.create({
            data: {
                name,
                email,
                password: hashedPassword,
                role: 'user'
            },
            select: {
                id: true,
                name: true,
                email: true,
                role: true
            }
        });
        // Set session
        await setSession({
            id: user.id,
            email: user.email,
            role: user.role
        });
        return NextResponse.json({ user }, { status: 201 });
    } catch (error) {
        console.error('Registration error:', error);
        return NextResponse.json(
            { error: 'Internal server error' },
            { status: 500 }
        );
    }
}
// app/api/auth/login/route.ts
import { NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';
import { prisma } from '@/lib/prisma';
import { verifyPassword, setSession } from '@/lib/auth';
const loginSchema = z.object({
    email: z.string().email(),
    password: z.string()
});
export async function POST(request: NextRequest) {
    try {
        const body = await request.json();
        const result = loginSchema.safeParse(body);
        if (!result.success) {
            return NextResponse.json(
                { error: 'Invalid credentials' },
                { status: 400 }
            );
        }
        const { email, password } = result.data;
        // Find user
        const user = await prisma.user.findUnique({
            where: { email }
        });
        if (!user) {
            return NextResponse.json(
                { error: 'Invalid credentials' },
                { status: 401 }
            );
        }
        // Verify password
        const isValid = await verifyPassword(password, user.password);
        if (!isValid) {
            return NextResponse.json(
                { error: 'Invalid credentials' },
                { status: 401 }
            );
        }
        // Set session
        await setSession({
            id: user.id,
            email: user.email,
            role: user.role
        });
        return NextResponse.json({
            user: {
                id: user.id,
                name: user.name,
                email: user.email,
                role: user.role
            }
        });
    } catch (error) {
        console.error('Login error:', error);
        return NextResponse.json(
            { error: 'Internal server error' },
            { status: 500 }
        );
    }
}

// lib/collaboration.ts
import { Server as HTTPServer } from 'http';
import { Server as SocketServer, Socket } from 'socket.io';
interface User {
    id: string;
    name: string;
    color: string;
}
interface Cursor {
    userId: string;
    position: { line: number; column: number };
}
interface TextOperation {
    type: 'insert' | 'delete';
    position: number;
    text?: string;
    length?: number;
    userId: string;
    timestamp: number;
}
interface Document {
    id: string;
    content: string;
    version: number;
    operations: TextOperation[];
    users: Map<string, User>;
    cursors: Map<string, Cursor>;
}
class CollaborationServer {
    private io: SocketServer;
    private documents: Map<string, Document> = new Map();
    constructor(httpServer: HTTPServer) {
        this.io = new SocketServer(httpServer, {
            cors: {
                origin: process.env.NEXT_PUBLIC_APP_URL,
                methods: ['GET', 'POST']
            }
        });
        this.setupSocketHandlers();
    }
    private setupSocketHandlers() {
        this.io.on('connection', (socket: Socket) => {
            console.log('Client connected:', socket.id);
            socket.on('join-document', (data: { documentId: string; user: User }) => {
                this.handleJoinDocument(socket, data);
            });
            socket.on('leave-document', (documentId: string) => {
                this.handleLeaveDocument(socket, documentId);
            });
            socket.on('text-operation', (data: { documentId: string; operation: TextOperation }) => {
                this.handleTextOperation(socket, data);
            });
            socket.on('cursor-move', (data: { documentId: string; cursor: Cursor }) => {
                this.handleCursorMove(socket, data);
            });
            socket.on('disconnect', () => {
                this.handleDisconnect(socket);
            });
        });
    }
    private handleJoinDocument(socket: Socket, data: { documentId: string; user: User }) {
        const { documentId, user } = data;
        // Create document if it doesn't exist
        if (!this.documents.has(documentId)) {
            this.documents.set(documentId, {
                id: documentId,
                content: '',
                version: 0,
                operations: [],
                users: new Map(),
                cursors: new Map()
            });
        }
        const doc = this.documents.get(documentId)!;
        // Add user to document
        doc.users.set(user.id, user);
        // Join socket room
        socket.join(documentId);
        // Store user info on socket
        socket.data.userId = user.id;
        socket.data.documentId = documentId;
        // Send current document state
        socket.emit('document-state', {
            content: doc.content,
            version: doc.version,
            users: Array.from(doc.users.values()),
            cursors: Array.from(doc.cursors.values())
        });
        // Notify others
        socket.to(documentId).emit('user-joined', user);
    }
    private handleLeaveDocument(socket: Socket, documentId: string) {
        const doc = this.documents.get(documentId);
        if (!doc) return;
        const userId = socket.data.userId;
        doc.users.delete(userId);
        doc.cursors.delete(userId);
        socket.leave(documentId);
        socket.to(documentId).emit('user-left', userId);
        // Clean up empty documents
        if (doc.users.size === 0) {
            this.documents.delete(documentId);
        }
    }
    private handleTextOperation(
        socket: Socket,
        data: { documentId: string; operation: TextOperation }
    ) {
        const { documentId, operation } = data;
        const doc = this.documents.get(documentId);
        if (!doc) return;
        // Apply operation
        const transformedOp = this.transformOperation(doc, operation);
        doc.content = this.applyOperation(doc.content, transformedOp);
        doc.version++;
        doc.operations.push(transformedOp);
        // Broadcast to others
        socket.to(documentId).emit('remote-operation', {
            operation: transformedOp,
            version: doc.version
        });
        // Acknowledge to sender
        socket.emit('operation-ack', {
            version: doc.version
        });
    }
    private handleCursorMove(socket: Socket, data: { documentId: string; cursor: Cursor }) {
        const { documentId, cursor } = data;
        const doc = this.documents.get(documentId);
        if (!doc) return;
        doc.cursors.set(cursor.userId, cursor);
        socket.to(documentId).emit('cursor-update', cursor);
    }
    private handleDisconnect(socket: Socket) {
        const { userId, documentId } = socket.data;
        if (documentId) {
            this.handleLeaveDocument(socket, documentId);
        }
    }
    private transformOperation(doc: Document, operation: TextOperation): TextOperation {
        // Simple OT (Operational Transformation)
        // In production, use a proper OT library like ot.js
        let position = operation.position;
        // Transform against concurrent operations
        for (const existingOp of doc.operations.slice(-10)) {
            if (existingOp.timestamp >= operation.timestamp) continue;
            if (existingOp.type === 'insert' && existingOp.position <= position) {
                position += existingOp.text?.length || 0;
            } else if (existingOp.type === 'delete' && existingOp.position < position) {
                position -= Math.min(existingOp.length || 0, position - existingOp.position);
            }
        }
        return { ...operation, position };
    }
    private applyOperation(content: string, operation: TextOperation): string {
        if (operation.type === 'insert' && operation.text) {
            return (
                content.slice(0, operation.position) +
                operation.text +
                content.slice(operation.position)
            );
        } else if (operation.type === 'delete' && operation.length) {
            return (
                content.slice(0, operation.position) +
                content.slice(operation.position + operation.length)
            );
        }
        return content;
    }
}
export { CollaborationServer };

