function ProductListContainer({ categoryId }: ProductListContainerProps) {
    const { data: products, isLoading, error } = useProducts(categoryId);
    const [sortBy, setSortBy] = useState<SortOption>('newest');
    const [filters, setFilters] = useState<Filters>({});

    const filteredProducts = useMemo(() => {
        return filterAndSortProducts(products, filters, sortBy);
    }, [products, filters, sortBy]);

    const handleAddToCart = useCallback((productId: string) => {
        // Business logic
        addToCart(productId);
        trackEvent('add_to_cart', { productId });
    }, []);

    if (isLoading) return <ProductListSkeleton />;
    if (error) return <ErrorState error={error} />;

    return (
        <ProductListPresentation
            products={filteredProducts}
            sortBy={sortBy}
            onSortChange={setSortBy}
            filters={filters}
            onFilterChange={setFilters}
            onAddToCart={handleAddToCart}
        />
    );
}

// Presentation Component (Dumb) - pure UI
