            </div>

            <div className="product-list__grid">
                {products.map(product => (
                    <ProductCard
                        key={product.id}
                        product={product}
                        onAddToCart={() => onAddToCart(product.id)}
                    />
                ))}
            </div>
        </div>
    );
}

// 2. COMPOUND COMPONENT PATTERN

interface SelectContextValue {
    value: string;
    onChange: (value: string) => void;
    isOpen: boolean;
    setIsOpen: (open: boolean) => void;
}

const SelectContext = createContext<SelectContextValue | null>(null);

function Select({
    children,
    value,
    onChange
}: {
    children: ReactNode;
    value: string;
    onChange: (value: string) => void;
}) {
    const [isOpen, setIsOpen] = useState(false);

    return (
        <SelectContext.Provider value={{ value, onChange, isOpen, setIsOpen }}>
            <div className="select">{children}</div>
        </SelectContext.Provider>
    );
}

function SelectTrigger({ children }: { children: ReactNode }) {
    const ctx = useContext(SelectContext)!;
    return (
        <button onClick={() => ctx.setIsOpen(!ctx.isOpen)}>
            {children}
        </button>
    );
}

function SelectContent({ children }: { children: ReactNode }) {
    const ctx = useContext(SelectContext)!;
    if (!ctx.isOpen) return null;
    return <div className="select-content">{children}</div>;
}

function SelectItem({ value, children }: { value: string; children: ReactNode }) {
    const ctx = useContext(SelectContext)!;
    return (
        <div
            className={`select-item ${ctx.value === value ? 'selected' : ''}`}
            onClick={() => {
                ctx.onChange(value);
                ctx.setIsOpen(false);
            }}
        >
            {children}
        </div>
    );
}

// Attach sub-components
Select.Trigger = SelectTrigger;
Select.Content = SelectContent;
Select.Item = SelectItem;

// Usage
function Example() {
    const [value, setValue] = useState('');

    return (
        <Select value={value} onChange={setValue}>
            <Select.Trigger>
                {value || 'Select an option'}
            </Select.Trigger>
            <Select.Content>
                <Select.Item value="option1">Option 1</Select.Item>
                <Select.Item value="option2">Option 2</Select.Item>
                <Select.Item value="option3">Option 3</Select.Item>
            </Select.Content>
        </Select>
    );
}

// 3. RENDER PROPS PATTERN (for flexibility)

interface DataFetcherProps<T> {
    url: string;
    children: (state: {
        data: T | null;
        loading: boolean;
        error: Error | null;
        refetch: () => void;
    }) => ReactNode;
}

function DataFetcher<T>({ url, children }: DataFetcherProps<T>) {
    const [data, setData] = useState<T | null>(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<Error | null>(null);

    const fetchData = useCallback(async () => {
        setLoading(true);
        setError(null);
        try {
            const response = await fetch(url);
            const result = await response.json();
            setData(result);
        } catch (err) {
            setError(err as Error);
        } finally {
            setLoading(false);
        }
    }, [url]);

    useEffect(() => {
        fetchData();
    }, [fetchData]);

    return <>{children({ data, loading, error, refetch: fetchData })}</>;
}

// Usage
function UserProfile({ userId }: { userId: string }) {
    return (
        <DataFetcher<User> url={`/api/users/${userId}`}>
            {({ data, loading, error, refetch }) => {
                if (loading) return <Spinner />;
                if (error) return <ErrorMessage error={error} onRetry={refetch} />;
                if (!data) return null;

                return (
                    <div>
                        <h1>{data.name}</h1>
                        <p>{data.email}</p>
                    </div>
                );
            }}
        </DataFetcher>
    );
}

// 4. POLYMORPHIC COMPONENT PATTERN

type AsProp<C extends React.ElementType> = {
    as?: C;
};

type PropsToOmit<C extends React.ElementType, P> = keyof (AsProp<C> & P);

type PolymorphicComponentProp<
    C extends React.ElementType,
    Props = {}
> = React.PropsWithChildren<Props & AsProp<C>> &
    Omit<React.ComponentPropsWithoutRef<C>, PropsToOmit<C, Props>>;

interface ButtonOwnProps {
    variant?: 'primary' | 'secondary' | 'ghost';
    size?: 'sm' | 'md' | 'lg';
}

type ButtonProps<C extends React.ElementType = 'button'> =
    PolymorphicComponentProp<C, ButtonOwnProps>;

function Button<C extends React.ElementType = 'button'>({
    as,
    variant = 'primary',
    size = 'md',
    children,
    ...props
}: ButtonProps<C>) {
    const Component = as || 'button';

    return (
        <Component
            className={`btn btn--${variant} btn--${size}`}
            {...props}
        >
            {children}
        </Component>
    );
}

// Usage
function Example() {
    return (
        <>
            {/* As button */}
            <Button onClick={() => {}}>Click me</Button>

            {/* As anchor */}
            <Button as="a" href="/page">Link</Button>

            {/* As Next.js Link */}
            <Button as={Link} href="/page">Next Link</Button>
        </>
    );
}
