                })),

                removeNotification: (id) => set((state) => ({
                    notifications: state.notifications.filter(n => n.id !== id)
                }))
            }),
            {
                name: 'ui-storage',
                partialize: (state) => ({
                    theme: state.theme,
                    sidebarOpen: state.sidebarOpen
                })
            }
        ),
        { name: 'UIStore' }
    )
);

