## 📚 Section 4: Data Fetching and Caching Strategies

### 🎯 4.1 Data Fetching Patterns

```
// ═══════════════════════════════════════════════════════════
// DATA FETCHING ARCHITECTURE
// ═══════════════════════════════════════════════════════════

/*
┌─────────────────────────────────────────────────────────────────────────────┐
│                         DATA FETCHING STRATEGIES                            │
├─────────────────────────────────────────────────────────────────────────────┤
│                                                                             │
│  1. FETCH ON RENDER (Traditional)                                           │
│     Component renders → fetch starts → loading state → data renders         │
│     ❌ Waterfall requests                                                   │
│     ❌ Poor perceived performance                                           │
│                                                                             │
│  2. FETCH THEN RENDER (Prefetch)                                            │
│     Start fetch → wait for all data → render component                      │
│     ✅ No waterfalls                                                        │
│     ❌ Blocked on slowest request                                           │
│                                                                             │
│  3. RENDER AS YOU FETCH (Suspense)                                          │
│     Start fetch → render immediately → suspend for data → resume            │
│     ✅ Best perceived performance                                           │
│     ✅ Parallel fetching                                                    │
│     ✅ Streaming                                                            │
│                                                                             │
└─────────────────────────────────────────────────────────────────────────────┘
*/

// ═══════════════════════════════════════════════════════════
// API CLIENT SETUP
// ═══════════════════════════════════════════════════════════

// lib/api/client.ts
interface RequestConfig extends RequestInit {
    params?: Record<string, string | number | boolean | undefined>;
    timeout?: number;
}

interface ApiResponse<T> {
    data: T;
    status: number;
    headers: Headers;
}

class ApiClient {
    private baseUrl: string;
    private defaultHeaders: HeadersInit;

    constructor(baseUrl: string, defaultHeaders: HeadersInit = {}) {
        this.baseUrl = baseUrl;
        this.defaultHeaders = defaultHeaders;
    }

    private async request<T>(
        endpoint: string,
        config: RequestConfig = {}
    ): Promise<ApiResponse<T>> {
        const { params, timeout = 30000, ...init } = config;

        // Build URL with query params
        let url = `${this.baseUrl}${endpoint}`;
        if (params) {
            const searchParams = new URLSearchParams();
            Object.entries(params).forEach(([key, value]) => {
                if (value !== undefined) {
                    searchParams.append(key, String(value));
                }
            });
            const queryString = searchParams.toString();
            if (queryString) {
                url += `?${queryString}`;
            }
        }

        // Create abort controller for timeout
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), timeout);

        try {
            const response = await fetch(url, {
                ...init,
                headers: {
                    'Content-Type': 'application/json',
                    ...this.defaultHeaders,
                    ...init.headers
                },
                signal: controller.signal
            });

            clearTimeout(timeoutId);

            if (!response.ok) {
                throw new ApiError(
                    response.status,
                    await response.text()
                );
            }

            const data = await response.json();

            return {
                data,
                status: response.status,
                headers: response.headers
            };
        } catch (error) {
            clearTimeout(timeoutId);

            if (error instanceof Error && error.name === 'AbortError') {
                throw new ApiError(408, 'Request timeout');
            }

            throw error;
        }
    }

    async get<T>(endpoint: string, config?: RequestConfig) {
        return this.request<T>(endpoint, { ...config, method: 'GET' });
    }

    async post<T>(endpoint: string, body?: unknown, config?: RequestConfig) {
        return this.request<T>(endpoint, {
            ...config,
            method: 'POST',
            body: body ? JSON.stringify(body) : undefined
        });
    }

    async put<T>(endpoint: string, body?: unknown, config?: RequestConfig) {
        return this.request<T>(endpoint, {
            ...config,
            method: 'PUT',
            body: body ? JSON.stringify(body) : undefined
        });
    }

    async patch<T>(endpoint: string, body?: unknown, config?: RequestConfig) {
        return this.request<T>(endpoint, {
            ...config,
            method: 'PATCH',
            body: body ? JSON.stringify(body) : undefined
        });
    }

    async delete<T>(endpoint: string, config?: RequestConfig) {
        return this.request<T>(endpoint, { ...config, method: 'DELETE' });
    }

    // Set auth token
    setAuthToken(token: string | null) {
        if (token) {
            this.defaultHeaders = {
                ...this.defaultHeaders,
                Authorization: `Bearer ${token}`
            };
        } else {
            const { Authorization, ...rest } = this.defaultHeaders as Record<string, string>;
            this.defaultHeaders = rest;
        }
    }
}

class ApiError extends Error {
    constructor(
        public status: number,
        public message: string,
        public data?: unknown
    ) {
        super(message);
        this.name = 'ApiError';
    }
}

export const apiClient = new ApiClient(
    process.env.NEXT_PUBLIC_API_URL || '/api'
);

