// features/products/hooks/useProducts.ts
import { useQuery, useMutation, useQueryClient, useInfiniteQuery } from '@tanstack/react-query';
import { queryKeys } from '@/lib/query-client';
import { apiClient } from '@/lib/api/client';

interface ProductFilters {
    category?: string;
    minPrice?: number;
    maxPrice?: number;
    search?: string;
    sort?: 'price_asc' | 'price_desc' | 'newest' | 'popular';
}

interface ProductsResponse {
    products: Product[];
    total: number;
    page: number;
    pageSize: number;
    totalPages: number;
}

// List products with pagination
export function useProducts(filters: ProductFilters & { page?: number }) {
    return useQuery({
        queryKey: queryKeys.products.list(filters),
        queryFn: async () => {
            const { data } = await apiClient.get<ProductsResponse>('/products', {
                params: {
                    ...filters,
                    page: filters.page || 1,
                    pageSize: 20
                }
            });
            return data;
        },
        placeholderData: (previousData) => previousData,
        staleTime: 1000 * 60 * 5 // 5 minutes
    });
}

// Infinite scroll products
export function useInfiniteProducts(filters: ProductFilters) {
    return useInfiniteQuery({
        queryKey: queryKeys.products.infinite(filters),
        queryFn: async ({ pageParam = 1 }) => {
            const { data } = await apiClient.get<ProductsResponse>('/products', {
                params: {
                    ...filters,
                    page: pageParam,
                    pageSize: 20
                }
            });
            return data;
        },
        getNextPageParam: (lastPage) => {
            if (lastPage.page < lastPage.totalPages) {
                return lastPage.page + 1;
            }
            return undefined;
        },
        initialPageParam: 1
    });
}

// Single product
export function useProduct(id: string) {
    return useQuery({
        queryKey: queryKeys.products.detail(id),
        queryFn: async () => {
            const { data } = await apiClient.get<Product>(`/products/${id}`);
            return data;
        },
        enabled: !!id
    });
}

// Prefetch product (for hover)
export function usePrefetchProduct() {
    const queryClient = useQueryClient();

    return (id: string) => {
        queryClient.prefetchQuery({
            queryKey: queryKeys.products.detail(id),
            queryFn: async () => {
                const { data } = await apiClient.get<Product>(`/products/${id}`);
                return data;
            },
            staleTime: 1000 * 60 * 5
        });
    };
}

// Create product
export function useCreateProduct() {
    const queryClient = useQueryClient();

    return useMutation({
        mutationFn: async (product: CreateProductInput) => {
            const { data } = await apiClient.post<Product>('/products', product);
            return data;
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: queryKeys.products.lists() });
        }
    });
}

// Update product
export function useUpdateProduct() {
    const queryClient = useQueryClient();

    return useMutation({
        mutationFn: async ({ id, ...data }: UpdateProductInput & { id: string }) => {
            const { data: product } = await apiClient.patch<Product>(
                `/products/${id}`,
                data
            );
            return product;
        },
        onMutate: async (variables) => {
            // Cancel outgoing refetches
            await queryClient.cancelQueries({
                queryKey: queryKeys.products.detail(variables.id)
            });

            // Snapshot previous value
            const previousProduct = queryClient.getQueryData<Product>(
                queryKeys.products.detail(variables.id)
            );

            // Optimistically update
            if (previousProduct) {
                queryClient.setQueryData<Product>(
                    queryKeys.products.detail(variables.id),
                    { ...previousProduct, ...variables }
                );
            }

            return { previousProduct };
        },
        onError: (err, variables, context) => {
            // Rollback on error
            if (context?.previousProduct) {
                queryClient.setQueryData(
                    queryKeys.products.detail(variables.id),
                    context.previousProduct
                );
            }
        },
        onSettled: (data, error, variables) => {
            // Refetch after error or success
            queryClient.invalidateQueries({
                queryKey: queryKeys.products.detail(variables.id)
            });
            queryClient.invalidateQueries({
                queryKey: queryKeys.products.lists()
            });
        }
    });
}

// Delete product
export function useDeleteProduct() {
    const queryClient = useQueryClient();

    return useMutation({
        mutationFn: async (id: string) => {
            await apiClient.delete(`/products/${id}`);
            return id;
        },
        onMutate: async (id) => {
            await queryClient.cancelQueries({ queryKey: queryKeys.products.lists() });

            // Optimistically remove from all lists
            queryClient.setQueriesData<ProductsResponse>(
                { queryKey: queryKeys.products.lists() },
                (old) => old ? {
                    ...old,
                    products: old.products.filter(p => p.id !== id),
                    total: old.total - 1
                } : old
            );
        },
        onSettled: () => {
            queryClient.invalidateQueries({ queryKey: queryKeys.products.lists() });
        }
    });
}
