// ═══════════════════════════════════════════════════════════
// CACHING STRATEGIES
// ═══════════════════════════════════════════════════════════

/*
┌─────────────────────────────────────────────────────────────────────────────┐
│                           CACHING STRATEGIES                                │
├─────────────────────────────────────────────────────────────────────────────┤
│                                                                             │
│  1. STALE-WHILE-REVALIDATE (Default React Query)                            │
│     • Return cached data immediately                                        │
│     • Fetch fresh data in background                                        │
│     • Update when new data arrives                                          │
│                                                                             │
│  2. CACHE-FIRST                                                             │
│     • Always return cached data if available                                │
│     • Only fetch if cache is empty                                          │
│     • Good for rarely changing data                                         │
│                                                                             │
│  3. NETWORK-FIRST                                                           │
│     • Always try network first                                              │
│     • Fall back to cache if network fails                                   │
│     • Good for frequently changing data                                     │
│                                                                             │
│  4. CACHE-ONLY                                                              │
│     • Never make network requests                                           │
│     • Only use cached data                                                  │
│     • Good for offline mode                                                 │
│                                                                             │
│  5. NETWORK-ONLY                                                            │
│     • Never use cache                                                       │
│     • Always fetch fresh data                                               │
│     • Good for real-time data                                               │
│                                                                             │
└─────────────────────────────────────────────────────────────────────────────┘
*/

// Implementing different cache strategies with React Query

// Cache-first (long stale time)
export function useStaticContent(slug: string) {
    return useQuery({
        queryKey: ['static-content', slug],
        queryFn: () => fetchStaticContent(slug),
        staleTime: Infinity, // Never stale
        gcTime: 1000 * 60 * 60 * 24 // Keep in cache for 24 hours
    });
}

// Network-first (short stale time)
export function useLiveData() {
    return useQuery({
        queryKey: ['live-data'],
        queryFn: fetchLiveData,
        staleTime: 0, // Always stale
        refetchInterval: 5000 // Refetch every 5 seconds
    });
}

// Offline-first with background sync
export function useOfflineCapableData(key: string) {
    const queryClient = useQueryClient();

    return useQuery({
        queryKey: ['offline-data', key],
        queryFn: async () => {
            try {
                const data = await fetchFromNetwork(key);
                // Save to IndexedDB for offline access
                await saveToIndexedDB(key, data);
                return data;
            } catch (error) {
                // Network failed, try IndexedDB
                const cachedData = await getFromIndexedDB(key);
                if (cachedData) {
                    return cachedData;
                }
                throw error;
            }
        },
        staleTime: 1000 * 60 * 5,
        gcTime: Infinity, // Keep forever for offline access
        networkMode: 'offlineFirst'
    });
}

// ═══════════════════════════════════════════════════════════
// OPTIMISTIC UPDATES
// ═══════════════════════════════════════════════════════════

// Complex optimistic update example: Task reordering
interface Task {
    id: string;
    title: string;
    status: 'todo' | 'in_progress' | 'done';
    order: number;
}

export function useReorderTasks() {
    const queryClient = useQueryClient();

    return useMutation({
        mutationFn: async (params: {
            taskId: string;
            newStatus: Task['status'];
            newOrder: number;
        }) => {
            return apiClient.patch(`/tasks/${params.taskId}/reorder`, {
                status: params.newStatus,
                order: params.newOrder
            });
        },

        onMutate: async ({ taskId, newStatus, newOrder }) => {
            // Cancel any outgoing refetches
            await queryClient.cancelQueries({ queryKey: ['tasks'] });

            // Snapshot the previous value
            const previousTasks = queryClient.getQueryData<Task[]>(['tasks']);

            // Optimistically update
            queryClient.setQueryData<Task[]>(['tasks'], (old) => {
                if (!old) return old;

                const taskIndex = old.findIndex(t => t.id === taskId);
                if (taskIndex === -1) return old;

                const task = old[taskIndex];
                const newTasks = [...old];

                // Remove from old position
                newTasks.splice(taskIndex, 1);

                // Update task
                const updatedTask = { ...task, status: newStatus, order: newOrder };

                // Find new position
                let insertIndex = newTasks.findIndex(
                    t => t.status === newStatus && t.order > newOrder
                );

                if (insertIndex === -1) {
                    // Add at end of status group
                    insertIndex = newTasks.filter(t => t.status === newStatus).length;
                    const statusStartIndex = newTasks.findIndex(t => t.status === newStatus);
                    insertIndex = statusStartIndex === -1
                        ? newTasks.length
                        : statusStartIndex + insertIndex;
                }

                newTasks.splice(insertIndex, 0, updatedTask);

                // Recalculate orders
                return newTasks.map((t, i) => ({ ...t, order: i }));
            });

            return { previousTasks };
        },

        onError: (err, variables, context) => {
            // Rollback
            if (context?.previousTasks) {
                queryClient.setQueryData(['tasks'], context.previousTasks);
            }
        },

        onSettled: () => {
            queryClient.invalidateQueries({ queryKey: ['tasks'] });
        }
    });
}
