// 1. Route-based code splitting
import { lazy, Suspense } from 'react';

// Lazy load pages
const Dashboard = lazy(() => import('./pages/Dashboard'));
const Products = lazy(() => import('./pages/Products'));
const Settings = lazy(() => import('./pages/Settings'));
const Analytics = lazy(() => import('./pages/Analytics'));

// With preload capability
const lazyWithPreload = <T extends React.ComponentType<any>>(
    factory: () => Promise<{ default: T }>
) => {
    const Component = lazy(factory);
    (Component as any).preload = factory;
    return Component as typeof Component & { preload: typeof factory };
};

const HeavyChart = lazyWithPreload(() => import('./components/HeavyChart'));

// Navigation with preloading
function NavLink({ to, children, component }: {
    to: string;
    children: React.ReactNode;
    component?: { preload: () => void };
}) {
    return (
        <Link
            to={to}
            onMouseEnter={() => component?.preload?.()}
            onFocus={() => component?.preload?.()}
        >
            {children}
        </Link>
    );
}

// 2. Component-based code splitting
function FeaturePanel({ feature }: { feature: string }) {
    const FeatureComponent = useMemo(() => {
        switch (feature) {
            case 'charts':
                return lazy(() => import('./features/Charts'));
            case 'reports':
                return lazy(() => import('./features/Reports'));
            case 'exports':
                return lazy(() => import('./features/Exports'));
            default:
                return null;
        }
    }, [feature]);

    if (!FeatureComponent) return null;

    return (
        <Suspense fallback={<FeatureSkeleton />}>
            <FeatureComponent />
        </Suspense>
    );
}

// 3. Library-based code splitting
function useHeavyLibrary() {
    const [lib, setLib] = useState<typeof import('heavy-library') | null>(null);

    useEffect(() => {
        let mounted = true;

        import('heavy-library').then((module) => {
            if (mounted) {
                setLib(module);
            }
        });

        return () => {
            mounted = false;
        };
    }, []);

    return lib;
}
