// 3. Debounce expensive operations
function SearchInput() {
    const [inputValue, setInputValue] = useState('');
    const [debouncedValue] = useDebounce(inputValue, 300);

    // Only fetch when debounced value changes
    const { data } = useSearchResults(debouncedValue);

    return (
        <input
            value={inputValue}
            onChange={(e) => setInputValue(e.target.value)}
        />
    );
}

// 4. Use transitions for non-urgent updates
function FilterableList({ items }: { items: Item[] }) {
    const [filter, setFilter] = useState('');
    const [isPending, startTransition] = useTransition();

    const handleFilterChange = (value: string) => {
        // Urgent: update input immediately
        setFilter(value);

        // Non-urgent: filter list can be deferred
        startTransition(() => {
            // This update is marked as non-urgent
            // React can interrupt it if more urgent updates come in
        });
    };

    const filteredItems = useMemo(() => {
        return items.filter((item) =>
            item.name.toLowerCase().includes(filter.toLowerCase())
        );
    }, [items, filter]);

    return (
        <div>
            <input
                value={filter}
                onChange={(e) => handleFilterChange(e.target.value)}
            />
            <div style={{ opacity: isPending ? 0.7 : 1 }}>
                {filteredItems.map((item) => (
                    <ItemCard key={item.id} item={item} />
                ))}
            </div>
        </div>
    );
}
