```
// ═══════════════════════════════════════════════════════════
// REAL-TIME ARCHITECTURE
// ═══════════════════════════════════════════════════════════

/*
┌─────────────────────────────────────────────────────────────────────────────┐
│                       REAL-TIME COMMUNICATION OPTIONS                       │
├─────────────────────────────────────────────────────────────────────────────┤
│                                                                             │
│  1. POLLING                                                                 │
│     Pros: Simple, works everywhere, no special server setup                 │
│     Cons: High latency, wasteful, not truly real-time                       │
│     Use case: Status updates, low-frequency data                            │
│                                                                             │
│  2. LONG POLLING                                                            │
│     Pros: Lower latency than polling, works everywhere                      │
│     Cons: Complex, resource intensive                                       │
│     Use case: Fallback for WebSocket                                        │
│                                                                             │
│  3. SERVER-SENT EVENTS (SSE)                                                │
│     Pros: Simple, auto-reconnect, HTTP-based                                │
│     Cons: One-way (server to client), limited browser support               │
│     Use case: Notifications, live feeds, stock prices                       │
│                                                                             │
│  4. WEBSOCKETS                                                              │
│     Pros: Full duplex, low latency, efficient                               │
│     Cons: Complex, requires special server                                  │
│     Use case: Chat, gaming, collaborative editing                           │
│                                                                             │
│  5. WEBRTC                                                                  │
│     Pros: P2P, lowest latency, audio/video support                          │
│     Cons: Complex, NAT traversal issues                                     │
│     Use case: Video calls, screen sharing, P2P gaming                       │
│                                                                             │
└─────────────────────────────────────────────────────────────────────────────┘
*/

// ═══════════════════════════════════════════════════════════
// WEBSOCKET CLIENT IMPLEMENTATION
// ═══════════════════════════════════════════════════════════

// lib/websocket/client.ts
type MessageHandler = (data: any) => void;
type ConnectionHandler = () => void;

interface WebSocketMessage {
    type: string;
    payload: any;
    timestamp?: number;
}

class WebSocketClient {
    private socket: WebSocket | null = null;
    private url: string;
    private reconnectAttempts = 0;
    private maxReconnectAttempts = 5;
    private reconnectInterval = 1000;
    private messageHandlers = new Map<string, Set<MessageHandler>>();
    private connectionHandlers = {
        open: new Set<ConnectionHandler>(),
        close: new Set<ConnectionHandler>(),
        error: new Set<(error: Event) => void>()
    };
    private messageQueue: WebSocketMessage[] = [];
    private isConnecting = false;

    constructor(url: string) {
        this.url = url;
    }

    connect(): Promise<void> {
        return new Promise((resolve, reject) => {
            if (this.socket?.readyState === WebSocket.OPEN) {
                resolve();
                return;
            }

            if (this.isConnecting) {
                // Wait for existing connection attempt
                this.onOpen(() => resolve());
                return;
            }

            this.isConnecting = true;

            try {
                this.socket = new WebSocket(this.url);

                this.socket.onopen = () => {
                    this.isConnecting = false;
                    this.reconnectAttempts = 0;
                    this.connectionHandlers.open.forEach((handler) => handler());
                    this.flushMessageQueue();
                    resolve();
                };

                this.socket.onclose = () => {
                    this.isConnecting = false;
                    this.connectionHandlers.close.forEach((handler) => handler());
                    this.attemptReconnect();
                };

                this.socket.onerror = (error) => {
                    this.isConnecting = false;
                    this.connectionHandlers.error.forEach((handler) => handler(error));
                    reject(error);
                };

                this.socket.onmessage = (event) => {
                    try {
                        const message: WebSocketMessage = JSON.parse(event.data);
                        this.handleMessage(message);
                    } catch (error) {
                        console.error('Failed to parse message:', error);
                    }
                };
            } catch (error) {
                this.isConnecting = false;
                reject(error);
            }
        });
    }

    disconnect() {
        if (this.socket) {
            this.socket.close();
            this.socket = null;
        }
        this.reconnectAttempts = this.maxReconnectAttempts; // Prevent reconnection
    }

    send(type: string, payload: any) {
        const message: WebSocketMessage = {
            type,
            payload,
            timestamp: Date.now()
        };

        if (this.socket?.readyState === WebSocket.OPEN) {
            this.socket.send(JSON.stringify(message));
        } else {
            // Queue message for when connection is established
            this.messageQueue.push(message);
            this.connect();
        }
    }

    subscribe(type: string, handler: MessageHandler): () => void {
        if (!this.messageHandlers.has(type)) {
            this.messageHandlers.set(type, new Set());
        }
        this.messageHandlers.get(type)!.add(handler);

        return () => {
            this.messageHandlers.get(type)?.delete(handler);
        };
    }

    onOpen(handler: ConnectionHandler): () => void {
        this.connectionHandlers.open.add(handler);
        return () => this.connectionHandlers.open.delete(handler);
    }

    onClose(handler: ConnectionHandler): () => void {
        this.connectionHandlers.close.add(handler);
        return () => this.connectionHandlers.close.delete(handler);
    }

    onError(handler: (error: Event) => void): () => void {
        this.connectionHandlers.error.add(handler);
        return () => this.connectionHandlers.error.delete(handler);
    }

    get isConnected(): boolean {
        return this.socket?.readyState === WebSocket.OPEN;
    }

    private handleMessage(message: WebSocketMessage) {
        const handlers = this.messageHandlers.get(message.type);
        handlers?.forEach((handler) => {
            try {
                handler(message.payload);
            } catch (error) {
                console.error('Message handler error:', error);
            }
        });
    }

    private attemptReconnect() {
        if (this.reconnectAttempts >= this.maxReconnectAttempts) {
            console.error('Max reconnection attempts reached');
            return;
        }

        const delay = this.reconnectInterval * Math.pow(2, this.reconnectAttempts);
        this.reconnectAttempts++;

        console.log(`Attempting reconnect in ${delay}ms (attempt ${this.reconnectAttempts})`);

        setTimeout(() => {
            this.connect().catch(() => {
                // Reconnection failed, will be retried by onclose handler
            });
        }, delay);
    }

    private flushMessageQueue() {
        while (this.messageQueue.length > 0) {
            const message = this.messageQueue.shift()!;
            this.socket?.send(JSON.stringify(message));
        }
    }
}

// Singleton instance
export const wsClient = new WebSocketClient(
    process.env.NEXT_PUBLIC_WS_URL || 'ws://localhost:3001'
);
