// REACT HOOKS FOR WEBSOCKET
// ═══════════════════════════════════════════════════════════

// hooks/useWebSocket.ts
interface UseWebSocketOptions {
    autoConnect?: boolean;
    onConnect?: () => void;
    onDisconnect?: () => void;
    onError?: (error: Event) => void;
}

export function useWebSocket(options: UseWebSocketOptions = {}) {
    const {
        autoConnect = true,
        onConnect,
        onDisconnect,
        onError
    } = options;

    const [isConnected, setIsConnected] = useState(wsClient.isConnected);

    useEffect(() => {
        if (autoConnect) {
            wsClient.connect();
        }

        const unsubOpen = wsClient.onOpen(() => {
            setIsConnected(true);
            onConnect?.();
        });

        const unsubClose = wsClient.onClose(() => {
            setIsConnected(false);
            onDisconnect?.();
        });

        const unsubError = wsClient.onError((error) => {
            onError?.(error);
        });

        return () => {
            unsubOpen();
            unsubClose();
            unsubError();
        };
    }, [autoConnect, onConnect, onDisconnect, onError]);

    const send = useCallback((type: string, payload: any) => {
        wsClient.send(type, payload);
    }, []);

    const connect = useCallback(() => {
        return wsClient.connect();
    }, []);

    const disconnect = useCallback(() => {
        wsClient.disconnect();
    }, []);

    return { isConnected, send, connect, disconnect };
}

// hooks/useSubscription.ts
export function useSubscription<T>(
    type: string,
    handler: (data: T) => void,
    deps: any[] = []
) {
    useEffect(() => {
        const unsubscribe = wsClient.subscribe(type, handler);
        return unsubscribe;
    }, [type, ...deps]);
}

// hooks/useRealtimeQuery.ts
export function useRealtimeQuery<T>(
    queryKey: string[],
    subscriptionType: string,
    options?: UseQueryOptions<T>
) {
    const queryClient = useQueryClient();

    // Subscribe to real-time updates
    useSubscription(subscriptionType, (data: Partial<T>) => {
        queryClient.setQueryData<T>(queryKey, (old) => {
            if (!old) return old;
            return { ...old, ...data };
        });
    }, [queryKey.join(',')]);

    // Also fetch initial data
    return useQuery<T>({
        queryKey,
        ...options
    });
}
