// ═══════════════════════════════════════════════════════════
// REAL-TIME CHAT IMPLEMENTATION
// ═══════════════════════════════════════════════════════════

interface Message {
    id: string;
    roomId: string;
    userId: string;
    userName: string;
    content: string;
    timestamp: number;
    status: 'sending' | 'sent' | 'delivered' | 'read';
}

interface ChatRoom {
    id: string;
    name: string;
    participants: string[];
    lastMessage?: Message;
}

// Chat store
interface ChatState {
    rooms: Map<string, ChatRoom>;
    messages: Map<string, Message[]>;
    activeRoomId: string | null;
    typingUsers: Map<string, Set<string>>; // roomId -> userIds
}

interface ChatActions {
    setActiveRoom: (roomId: string) => void;
    addMessage: (message: Message) => void;
    updateMessageStatus: (messageId: string, status: Message['status']) => void;
    setTypingUser: (roomId: string, userId: string, isTyping: boolean) => void;
}

const useChatStore = create<ChatState & ChatActions>()(
    immer((set) => ({
        rooms: new Map(),
        messages: new Map(),
        activeRoomId: null,
        typingUsers: new Map(),

        setActiveRoom: (roomId) => {
            set({ activeRoomId: roomId });
        },

        addMessage: (message) => {
            set((state) => {
                const roomMessages = state.messages.get(message.roomId) || [];
                state.messages.set(message.roomId, [...roomMessages, message]);

                // Update last message in room
                const room = state.rooms.get(message.roomId);
                if (room) {
                    room.lastMessage = message;
                }
            });
        },

        updateMessageStatus: (messageId, status) => {
            set((state) => {
                state.messages.forEach((messages) => {
                    const message = messages.find((m) => m.id === messageId);
                    if (message) {
                        message.status = status;
                    }
                });
            });
        },

        setTypingUser: (roomId, userId, isTyping) => {
            set((state) => {
                if (!state.typingUsers.has(roomId)) {
                    state.typingUsers.set(roomId, new Set());
                }

                const users = state.typingUsers.get(roomId)!;
                if (isTyping) {
                    users.add(userId);
                } else {
                    users.delete(userId);
                }
            });
        }
    }))
);

// Chat hook
function useChat(roomId: string) {
    const { send, isConnected } = useWebSocket();
    const messages = useChatStore((state) => state.messages.get(roomId) || []);
    const typingUsers = useChatStore((state) => state.typingUsers.get(roomId) || new Set());
    const addMessage = useChatStore((state) => state.addMessage);
    const updateMessageStatus = useChatStore((state) => state.updateMessageStatus);
    const setTypingUser = useChatStore((state) => state.setTypingUser);

    // Subscribe to room events
    useEffect(() => {
        // Join room
        send('join_room', { roomId });

        return () => {
            send('leave_room', { roomId });
        };
    }, [roomId, send]);

    // Subscribe to messages
    useSubscription<Message>('new_message', (message) => {
        if (message.roomId === roomId) {
            addMessage(message);
        }
    }, [roomId, addMessage]);

    // Subscribe to typing indicators
    useSubscription<{ roomId: string; userId: string; isTyping: boolean }>(
        'typing',
        (data) => {
            if (data.roomId === roomId) {
                setTypingUser(roomId, data.userId, data.isTyping);
            }
        },
        [roomId, setTypingUser]
    );

    // Subscribe to message status updates
    useSubscription<{ messageId: string; status: Message['status'] }>(
        'message_status',
        (data) => {
            updateMessageStatus(data.messageId, data.status);
        },
        [updateMessageStatus]
    );

    const sendMessage = useCallback((content: string) => {
        const tempId = crypto.randomUUID();
        const message: Message = {
            id: tempId,
            roomId,
            userId: 'current-user', // Replace with actual user
            userName: 'Current User',
            content,
            timestamp: Date.now(),
            status: 'sending'
        };

        // Optimistic update
        addMessage(message);

        // Send to server
        send('send_message', message);
    }, [roomId, addMessage, send]);

    const setTyping = useCallback((isTyping: boolean) => {
        send('typing', { roomId, isTyping });
    }, [roomId, send]);

    return {
        messages,
        typingUsers: Array.from(typingUsers),
        sendMessage,
        setTyping,
        isConnected
    };
}

// Chat component
function ChatRoom({ roomId }: { roomId: string }) {
    const { messages, typingUsers, sendMessage, setTyping, isConnected } = useChat(roomId);
    const [inputValue, setInputValue] = useState('');
    const messagesEndRef = useRef<HTMLDivElement>(null);

    // Auto-scroll to bottom
    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }, [messages]);

    // Typing indicator debounce
    const debouncedSetTyping = useMemo(
        () => debounce((isTyping: boolean) => setTyping(isTyping), 300),
        [setTyping]
    );

    const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setInputValue(e.target.value);
        debouncedSetTyping(e.target.value.length > 0);
    };

    const handleSend = () => {
        if (inputValue.trim()) {
            sendMessage(inputValue.trim());
            setInputValue('');
            debouncedSetTyping(false);
        }
    };

    return (
        <div className="chat-room">
            <div className="chat-header">
                <span className={`status ${isConnected ? 'online' : 'offline'}`} />
                {isConnected ? 'Connected' : 'Disconnected'}
            </div>

            <div className="chat-messages">
                {messages.map((message) => (
                    <MessageBubble key={message.id} message={message} />
                ))}
                <div ref={messagesEndRef} />
            </div>

            {typingUsers.length > 0 && (
                <div className="typing-indicator">
                    {typingUsers.join(', ')} {typingUsers.length === 1 ? 'is' : 'are'} typing...
                </div>
            )}

            <div className="chat-input">
                <input
                    value={inputValue}
                    onChange={handleInputChange}
                    onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                    placeholder="Type a message..."
                    disabled={!isConnected}
                />
                <button onClick={handleSend} disabled={!isConnected}>
                    Send
                </button>
            </div>
        </div>
    );
}
