// api/feed.ts
const feedApi = {
    async getFeed(cursor?: string): Promise<FeedResponse> {
        const { data } = await apiClient.get('/feed', {
            params: { cursor, limit: 20 }
        });
        return data;
    },

    async getPost(id: string): Promise<Post> {
        const { data } = await apiClient.get(`/posts/${id}`);
        return data;
    },

    async createPost(input: CreatePostInput): Promise<Post> {
        const { data } = await apiClient.post('/posts', input);
        return data;
    },

    async likePost(id: string): Promise<void> {
        await apiClient.post(`/posts/${id}/like`);
    },

    async unlikePost(id: string): Promise<void> {
        await apiClient.delete(`/posts/${id}/like`);
    },

    async retweet(id: string): Promise<void> {
        await apiClient.post(`/posts/${id}/retweet`);
    },

    async undoRetweet(id: string): Promise<void> {
        await apiClient.delete(`/posts/${id}/retweet`);
    }
};

// ═══════════════════════════════════════════════════════════
// REACT QUERY HOOKS
// ═══════════════════════════════════════════════════════════

// hooks/useFeed.ts
export function useFeed() {
    const queryClient = useQueryClient();

    const query = useInfiniteQuery({
        queryKey: ['feed'],
        queryFn: ({ pageParam }) => feedApi.getFeed(pageParam),
        getNextPageParam: (lastPage) => lastPage.nextCursor,
        initialPageParam: undefined as string | undefined,
        staleTime: 1000 * 60, // 1 minute
        gcTime: 1000 * 60 * 30 // 30 minutes
    });

    // Flatten posts from all pages
    const posts = useMemo(() => {
        return query.data?.pages.flatMap((page) => page.posts) ?? [];
    }, [query.data]);

    // Subscribe to real-time updates
    useSubscription<Post>('new_post', (post) => {
        queryClient.setQueryData<InfiniteData<FeedResponse>>(
            ['feed'],
            (old) => {
                if (!old) return old;

                return {
                    ...old,
                    pages: old.pages.map((page, index) => {
                        if (index === 0) {
                            return {
                                ...page,
                                posts: [post, ...page.posts]
                            };
                        }
                        return page;
                    })
                };
            }
        );
    }, [queryClient]);

    return {
        posts,
        isLoading: query.isLoading,
        isFetchingNextPage: query.isFetchingNextPage,
        hasNextPage: query.hasNextPage,
        fetchNextPage: query.fetchNextPage,
        refetch: query.refetch
    };
}

// hooks/useLikePost.ts
export function useLikePost() {
    const queryClient = useQueryClient();

    return useMutation({
        mutationFn: async ({ postId, isLiked }: { postId: string; isLiked: boolean }) => {
            if (isLiked) {
                await feedApi.unlikePost(postId);
            } else {
                await feedApi.likePost(postId);
            }
            return { postId, isLiked: !isLiked };
        },

        onMutate: async ({ postId, isLiked }) => {
            // Cancel any outgoing refetches
            await queryClient.cancelQueries({ queryKey: ['feed'] });

            // Snapshot previous value
            const previousFeed = queryClient.getQueryData<InfiniteData<FeedResponse>>(['feed']);

            // Optimistically update
            queryClient.setQueryData<InfiniteData<FeedResponse>>(
                ['feed'],
                (old) => {
                    if (!old) return old;

                    return {
                        ...old,
                        pages: old.pages.map((page) => ({
                            ...page,
                            posts: page.posts.map((post) => {
                                if (post.id === postId) {
                                    return {
                                        ...post,
                                        isLiked: !isLiked,
                                        likesCount: post.likesCount + (isLiked ? -1 : 1)
                                    };
                                }
                                return post;
                            })
                        }))
                    };
                }
            );

            return { previousFeed };
        },

        onError: (err, variables, context) => {
            if (context?.previousFeed) {
                queryClient.setQueryData(['feed'], context.previousFeed);
            }
        }
    });
}
