function Feed() {
    const { posts, isLoading, isFetchingNextPage, hasNextPage, fetchNextPage } = useFeed();
    const parentRef = useRef<HTMLDivElement>(null);

    // Virtualization
    const virtualizer = useVirtualizer({
        count: hasNextPage ? posts.length + 1 : posts.length,
        getScrollElement: () => parentRef.current,
        estimateSize: () => 200, // Estimated post height
        overscan: 5
    });

    // Load more when reaching end
    useEffect(() => {
        const lastItem = virtualizer.getVirtualItems().slice(-1)[0];

        if (
            lastItem &&
            lastItem.index >= posts.length - 1 &&
            hasNextPage &&
            !isFetchingNextPage
        ) {
            fetchNextPage();
        }
    }, [virtualizer.getVirtualItems(), posts.length, hasNextPage, isFetchingNextPage, fetchNextPage]);

    if (isLoading) {
        return <FeedSkeleton />;
    }

    return (
        <div ref={parentRef} className="feed" style={{ height: '100vh', overflow: 'auto' }}>
            <div
                style={{
                    height: `${virtualizer.getTotalSize()}px`,
                    width: '100%',
                    position: 'relative'
                }}
            >
                {virtualizer.getVirtualItems().map((virtualRow) => {
                    const isLoaderRow = virtualRow.index >= posts.length;

                    return (
                        <div
                            key={virtualRow.key}
                            style={{
                                position: 'absolute',
                                top: 0,
                                left: 0,
                                width: '100%',
                                transform: `translateY(${virtualRow.start}px)`
                            }}
                        >
                            {isLoaderRow ? (
                                isFetchingNextPage ? <PostSkeleton /> : null
                            ) : (
                                <PostCard post={posts[virtualRow.index]} />
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
}

