                <video
                    src={media.url}
                    poster={media.thumbnailUrl}
                    controls
                    onLoadedData={() => setIsLoaded(true)}
                />
            ) : (
                <img
                    src={media.url}
                    alt={media.altText || ''}
                    loading="lazy"
                    onLoad={() => setIsLoaded(true)}
                />
            )}

            {index === 3 && total > 4 && (
                <div className="media-item__more">+{total - 4}</div>
            )}
        </div>
    );
});
