// lib/api/products.ts
import { cache } from 'react';
import { unstable_cache } from 'next/cache';

// Cached product fetch for server components
export const getProduct = cache(async (slug: string): Promise<Product | null> => {
    const response = await fetch(`${process.env.API_URL}/products/${slug}`, {
        next: {
            revalidate: 60, // Revalidate every minute
            tags: [`product-${slug}`]
        }
    });

    if (!response.ok) return null;
    return response.json();
});

// Cached with unstable_cache for more control
export const getProductWithCache = unstable_cache(
    async (slug: string) => {
        const response = await fetch(`${process.env.API_URL}/products/${slug}`);
        return response.json();
    },
    ['product'],
    {
        revalidate: 60,
        tags: ['products']
    }
);

// Real-time inventory check (no cache)
export async function getInventory(variantId: string): Promise<{
    quantity: number;
    status: string;
}> {
    const response = await fetch(
        `${process.env.API_URL}/inventory/${variantId}`,
        { cache: 'no-store' }
    );
    return response.json();
}

// Reviews with pagination
export async function getReviews(
    productId: string,
    options: {
        page?: number;
        limit?: number;
        sort?: 'recent' | 'helpful' | 'rating_high' | 'rating_low';
        rating?: number;
    } = {}
): Promise<{
    reviews: ProductReview[];
    total: number;
    page: number;
    hasMore: boolean;
}> {
    const params = new URLSearchParams({
        page: String(options.page || 1),
        limit: String(options.limit || 10),
        sort: options.sort || 'recent',
        ...(options.rating && { rating: String(options.rating) })
    });

    const response = await fetch(
        `${process.env.API_URL}/products/${productId}/reviews?${params}`,
        { next: { revalidate: 300 } } // 5 minutes
    );

    return response.json();
}

// Related products
export async function getRelatedProducts(
    productId: string,
    limit: number = 8
): Promise<Product[]> {
    const response = await fetch(
        `${process.env.API_URL}/products/${productId}/related?limit=${limit}`,
        { next: { revalidate: 3600 } } // 1 hour
    );

    return response.json();
}

