} from '@/components/skeletons';

interface ProductPageProps {
    params: { slug: string };
    searchParams: { variant?: string };
}

// Generate static params for popular products
export async function generateStaticParams() {
    const response = await fetch(`${process.env.API_URL}/products/popular?limit=100`);
    const products = await response.json();

    return products.map((product: Product) => ({
        slug: product.slug
    }));
}

// Generate metadata for SEO
export async function generateMetadata({ params }: ProductPageProps) {
    const product = await getProduct(params.slug);

    if (!product) {
        return { title: 'Product Not Found' };
    }

    return {
        title: product.seo.title,
        description: product.seo.description,
        keywords: product.seo.keywords,
        openGraph: {
            title: product.seo.title,
            description: product.seo.description,
            images: product.images.map(img => ({
                url: img.variants.large,
                width: img.width,
                height: img.height,
                alt: img.alt
            })),
            type: 'product',
            locale: 'en_US'
        },
        twitter: {
            card: 'summary_large_image',
            title: product.seo.title,
            description: product.seo.description,
            images: [product.images[0]?.variants.large]
        },
        alternates: {
            canonical: product.seo.canonicalUrl
        },
        other: {
            'product:price:amount': product.salePrice || product.basePrice,
            'product:price:currency': product.currency
        }
    };
}
