export default async function ProductPage({ params, searchParams }: ProductPageProps) {
    const product = await getProduct(params.slug);

    if (!product) {
        notFound();
    }

    // Get initial selected variant
    const selectedVariantId = searchParams.variant || product.variants[0]?.id;
    const selectedVariant = product.variants.find(v => v.id === selectedVariantId);

    // Fetch initial reviews
    const initialReviews = await getReviews(product.id, { limit: 5 });

    // JSON-LD structured data
    const structuredData = {
        '@context': 'https://schema.org',
        '@type': 'Product',
        name: product.name,
        description: product.description,
        image: product.images.map(img => img.url),
        brand: {
            '@type': 'Brand',
            name: product.brand.name
        },
        offers: {
            '@type': 'Offer',
            price: product.salePrice || product.basePrice,
            priceCurrency: product.currency,
            availability: selectedVariant?.inventory.status === 'in_stock'
                ? 'https://schema.org/InStock'
                : 'https://schema.org/OutOfStock',
            seller: {
                '@type': 'Organization',
                name: 'Our Store'
            }
        },
        aggregateRating: product.rating.count > 0 ? {
            '@type': 'AggregateRating',
            ratingValue: product.rating.average,
            reviewCount: product.rating.count
        } : undefined
    };

    return (
        <>
            {/* Structured Data */}
            <script
                type="application/ld+json"
                dangerouslySetInnerHTML={{ __html: JSON.stringify(structuredData) }}
            />

            <div className="product-page">
                {/* Breadcrumbs */}
                <Breadcrumbs
                    items={[
                        { label: 'Home', href: '/' },
