// components/product/ProductGallery.tsx
'use client';

import { useState, useCallback, useMemo, useRef } from 'react';
import Image from 'next/image';
import { useSwipeable } from 'react-swipeable';
import { Lightbox } from '@/components/Lightbox';

interface ProductGalleryProps {
    images: ProductImage[];
    selectedVariant?: ProductVariant;
}

export function ProductGallery({ images, selectedVariant }: ProductGalleryProps) {
    const [activeIndex, setActiveIndex] = useState(0);
    const [isZoomed, setIsZoomed] = useState(false);
    const [zoomPosition, setZoomPosition] = useState({ x: 0, y: 0 });
    const [showLightbox, setShowLightbox] = useState(false);
    const imageRef = useRef<HTMLDivElement>(null);

    // Get images based on selected variant
    const displayImages = useMemo(() => {
        if (selectedVariant?.images.length) {
            // Find matching images or use variant-specific images
            const variantImages = images.filter(img =>
                selectedVariant.images.includes(img.id)
            );
            return variantImages.length > 0 ? variantImages : images;
        }
        return images;
    }, [images, selectedVariant]);

    // Handle thumbnail click
    const handleThumbnailClick = useCallback((index: number) => {
        setActiveIndex(index);
    }, []);

    // Handle swipe
    const swipeHandlers = useSwipeable({
        onSwipedLeft: () => {
            setActiveIndex(prev =>
                prev < displayImages.length - 1 ? prev + 1 : prev
            );
        },
        onSwipedRight: () => {
            setActiveIndex(prev => prev > 0 ? prev - 1 : prev);
        },
        trackMouse: true
    });

    // Handle zoom
    const handleMouseMove = useCallback((e: React.MouseEvent<HTMLDivElement>) => {
        if (!imageRef.current || !isZoomed) return;

        const rect = imageRef.current.getBoundingClientRect();
        const x = ((e.clientX - rect.left) / rect.width) * 100;
        const y = ((e.clientY - rect.top) / rect.height) * 100;

        setZoomPosition({ x, y });
    }, [isZoomed]);

    const activeImage = displayImages[activeIndex];

    return (
        <div className="product-gallery">
            {/* Main Image */}
            <div
                ref={imageRef}
                className={`main-image ${isZoomed ? 'zoomed' : ''}`}
                onMouseEnter={() => setIsZoomed(true)}
                onMouseLeave={() => setIsZoomed(false)}
                onMouseMove={handleMouseMove}
                onClick={() => setShowLightbox(true)}
                {...swipeHandlers}
            >
                <Image
                    src={activeImage.variants.large}
                    alt={activeImage.alt}
                    fill
                    priority
                    sizes="(max-width: 768px) 100vw, 50vw"
                    style={{ objectFit: 'contain' }}
                />

                {/* Zoom Lens */}
                {isZoomed && (
                    <div
                        className="zoom-lens"
                        style={{
                            backgroundImage: `url(${activeImage.variants.zoom})`,
                            backgroundPosition: `${zoomPosition.x}% ${zoomPosition.y}%`
                        }}
                    />
                )}

                {/* Navigation Arrows */}
                {displayImages.length > 1 && (
                    <>
                        <button
                            className="gallery-nav prev"
                            onClick={(e) => {
                                e.stopPropagation();
                                setActiveIndex(prev => prev > 0 ? prev - 1 : displayImages.length - 1);
                            }}
                            aria-label="Previous image"
                        >
                            ‹
                        </button>
                        <button
                            className="gallery-nav next"
                            onClick={(e) => {
                                e.stopPropagation();
                                setActiveIndex(prev => prev < displayImages.length - 1 ? prev + 1 : 0);
                            }}
                            aria-label="Next image"
                        >
                            ›
                        </button>
                    </>
                )}

                {/* Image Counter */}
                <div className="image-counter">
                    {activeIndex + 1} / {displayImages.length}
                </div>
            </div>

            {/* Thumbnails */}
            <div className="thumbnails">
                {displayImages.map((image, index) => (
                    <button
                        key={image.id}
                        className={`thumbnail ${index === activeIndex ? 'active' : ''}`}
                        onClick={() => handleThumbnailClick(index)}
                        aria-label={`View image ${index + 1}`}
                        aria-current={index === activeIndex}
                    >
                        <Image
                            src={image.variants.thumbnail}
                            alt={image.alt}
                            width={80}
                            height={80}
                            style={{ objectFit: 'cover' }}
                        />
                    </button>
                ))}
            </div>

            {/* Lightbox */}
            {showLightbox && (
                <Lightbox
                    images={displayImages.map(img => ({
                        src: img.variants.zoom,
                        alt: img.alt
                    }))}
                    initialIndex={activeIndex}
                    onClose={() => setShowLightbox(false)}
                />
            )}
        </div>
    );
}
