// components/product/ProductVariantSelector.tsx
'use client';

import { useCallback, useMemo } from 'react';
import { useRouter, useSearchParams, usePathname } from 'next/navigation';

interface ProductVariantSelectorProps {
    variants: ProductVariant[];
    selectedVariantId: string;
}

export function ProductVariantSelector({
    variants,
    selectedVariantId
}: ProductVariantSelectorProps) {
    const router = useRouter();
    const pathname = usePathname();
    const searchParams = useSearchParams();

    // Extract unique attribute types and values
    const attributeOptions = useMemo(() => {
        const options: Record<string, Set<string>> = {};

        variants.forEach(variant => {
            Object.entries(variant.attributes).forEach(([key, value]) => {
                if (!options[key]) {
                    options[key] = new Set();
                }
                options[key].add(value);
            });
        });

        return Object.entries(options).map(([name, values]) => ({
            name,
            values: Array.from(values)
        }));
    }, [variants]);

    // Get currently selected attributes
    const selectedVariant = variants.find(v => v.id === selectedVariantId);
    const selectedAttributes = selectedVariant?.attributes || {};

    // Check if a variant combination is available
    const isAvailable = useCallback((attributeName: string, value: string) => {
        const testAttributes = { ...selectedAttributes, [attributeName]: value };

        return variants.some(variant => {
            return Object.entries(testAttributes).every(
                ([key, val]) => variant.attributes[key] === val
            ) && variant.inventory.status !== 'out_of_stock';
        });
    }, [variants, selectedAttributes]);

    // Handle attribute selection
    const handleSelect = useCallback((attributeName: string, value: string) => {
        const newAttributes = { ...selectedAttributes, [attributeName]: value };

        // Find matching variant
        const matchingVariant = variants.find(variant =>
            Object.entries(newAttributes).every(
                ([key, val]) => variant.attributes[key] === val
            )
        );

        if (matchingVariant) {
            const params = new URLSearchParams(searchParams);
            params.set('variant', matchingVariant.id);
            router.push(`${pathname}?${params.toString()}`, { scroll: false });
        }
    }, [variants, selectedAttributes, pathname, searchParams, router]);

    return (
        <div className="variant-selector">
            {attributeOptions.map(({ name, values }) => (
                <div key={name} className="variant-group">
                    <label className="variant-label">
                        {name}: <strong>{selectedAttributes[name]}</strong>
                    </label>

                    <div className="variant-options">
                        {values.map(value => {
                            const isSelected = selectedAttributes[name] === value;
                            const available = isAvailable(name, value);

                            // Special rendering for color swatches
                            if (name.toLowerCase() === 'color') {
                                return (
                                    <button
                                        key={value}
                                        className={`variant-option color-swatch ${isSelected ? 'selected' : ''} ${!available ? 'unavailable' : ''}`}
                                        onClick={() => handleSelect(name, value)}
                                        disabled={!available}
                                        title={value}
                                        aria-label={`Select ${value}`}
                                        aria-pressed={isSelected}
                                    >
                                        <span
                                            className="swatch"
                                            style={{ backgroundColor: getColorCode(value) }}
                                        />
                                        {!available && <span className="cross" />}
                                    </button>
                                );
                            }

                            // Default button rendering
                            return (
                                <button
                                    key={value}
                                    className={`variant-option ${isSelected ? 'selected' : ''} ${!available ? 'unavailable' : ''}`}
                                    onClick={() => handleSelect(name, value)}
                                    disabled={!available}
                                    aria-pressed={isSelected}
                                >
                                    {value}
                                </button>
                            );
                        })}
                    </div>
                </div>
            ))}

            {/* Stock Status */}
            {selectedVariant && (
                <div className={`stock-status ${selectedVariant.inventory.status}`}>
                    {selectedVariant.inventory.status === 'in_stock' && (
                        <span className="in-stock">✓ In Stock</span>
                    )}
                    {selectedVariant.inventory.status === 'low_stock' && (
                        <span className="low-stock">
                            ⚠️ Only {selectedVariant.inventory.quantity} left
                        </span>
                    )}
                    {selectedVariant.inventory.status === 'out_of_stock' && (
                        <span className="out-of-stock">✗ Out of Stock</span>
                    )}
                    {selectedVariant.inventory.status === 'backorder' && (
                        <span className="backorder">
                            📦 Backorder - Ships {selectedVariant.inventory.restockDate}
                        </span>
                    )}
                </div>
            )}
        </div>
    );
}

// Helper function for color codes
function getColorCode(colorName: string): string {
    const colors: Record<string, string> = {
        'Red': '#FF0000',
        'Blue': '#0000FF',
        'Green': '#00FF00',
        'Black': '#000000',
        'White': '#FFFFFF',
        'Navy': '#000080',
        'Gray': '#808080',
        // Add more colors as needed
    };
    return colors[colorName] || colorName;
}
