    const { addItem, items } = useCart();

    // Real-time inventory check
    const { inventory, isLoading: inventoryLoading } = useInventory(
        selectedVariant?.id || '',
        { enabled: !!selectedVariant, refetchInterval: 30000 }
    );

    // Calculate max quantity
    const maxQuantity = inventory?.quantity || selectedVariant?.inventory.quantity || 0;
    const currentInCart = items.find(
        item => item.variantId === selectedVariant?.id
    )?.quantity || 0;
    const availableQuantity = Math.max(0, maxQuantity - currentInCart);

    // Reset quantity when variant changes
    useEffect(() => {
        setQuantity(1);
    }, [selectedVariant?.id]);

    // Handle quantity change
    const handleQuantityChange = useCallback((delta: number) => {
        setQuantity(prev => {
            const newQty = prev + delta;
            return Math.max(1, Math.min(newQty, availableQuantity));
        });
    }, [availableQuantity]);

    // Handle add to cart
    const handleAddToCart = useCallback(async () => {
        if (!selectedVariant) {
            toast.error('Please select a variant');
            return;
        }

        if (selectedVariant.inventory.status === 'out_of_stock') {
            toast.error('This item is out of stock');
            return;
        }

        if (quantity > availableQuantity) {
            toast.error(`Only ${availableQuantity} available`);
            return;
        }

        setIsAdding(true);

        try {
            await addItem({
                productId: product.id,
                variantId: selectedVariant.id,
                quantity,
                price: selectedVariant.salePrice || selectedVariant.price,
                name: `${product.name} - ${Object.values(selectedVariant.attributes).join(' / ')}`,
                image: product.images[0]?.variants.thumbnail,
                attributes: selectedVariant.attributes
            });

            toast.success(`Added ${quantity} item(s) to cart`, {
                action: {
                    label: 'View Cart',
                    onClick: () => window.location.href = '/cart'
                }
            });
        } catch (error) {
            toast.error('Failed to add to cart. Please try again.');
        } finally {
            setIsAdding(false);
        }
    }, [product, selectedVariant, quantity, availableQuantity, addItem]);

    // Handle buy now
    const handleBuyNow = useCallback(async () => {
        await handleAddToCart();
        window.location.href = '/checkout';
    }, [handleAddToCart]);

    const isDisabled = !selectedVariant ||
        selectedVariant.inventory.status === 'out_of_stock' ||
        availableQuantity === 0 ||
        isAdding;

    // Calculate price
    const price = selectedVariant?.salePrice || selectedVariant?.price || product.basePrice;
    const originalPrice = selectedVariant?.price || product.basePrice;
    const hasDiscount = price < originalPrice;
    const discountPercent = hasDiscount
        ? Math.round((1 - price / originalPrice) * 100)
        : 0;

    return (
        <div className="add-to-cart">
            {/* Price Display */}
            <div className="price-display">
                <span className="current-price">
                    ${price.toFixed(2)}
                </span>
                {hasDiscount && (
                    <>
                        <span className="original-price">
                            ${originalPrice.toFixed(2)}
                        </span>
                        <span className="discount-badge">
                            -{discountPercent}%
                        </span>
                    </>
                )}
            </div>

            {/* Quantity Selector */}
            <div className="quantity-selector">
                <label htmlFor="quantity">Quantity:</label>
                <div className="quantity-controls">
                    <button
                        onClick={() => handleQuantityChange(-1)}
                        disabled={quantity <= 1}
                        aria-label="Decrease quantity"
                    >
                        −
                    </button>
                    <input
                        id="quantity"
                        type="number"
                        value={quantity}
                        onChange={(e) => {
                            const val = parseInt(e.target.value);
                            if (!isNaN(val)) {
                                setQuantity(Math.max(1, Math.min(val, availableQuantity)));
                            }
                        }}
                        min={1}
                        max={availableQuantity}
                    />
                    <button
                        onClick={() => handleQuantityChange(1)}
                        disabled={quantity >= availableQuantity}
                        aria-label="Increase quantity"
                    >
                        +
                    </button>
                </div>
            </div>

            {/* Action Buttons */}
            <div className="action-buttons">
                <button
                    className="add-to-cart-btn"
                    onClick={handleAddToCart}
                    disabled={isDisabled}
                >
                    {isAdding ? (
                        <span className="loading">Adding...</span>
                    ) : selectedVariant?.inventory.status === 'out_of_stock' ? (
                        'Out of Stock'
                    ) : (
                        <>
                            <span className="icon">🛒</span>
                            Add to Cart
                        </>
                    )}
                </button>

                <button
                    className="buy-now-btn"
                    onClick={handleBuyNow}
                    disabled={isDisabled}
                >
                    Buy Now
                </button>
            </div>

            {/* Wishlist Button */}
            <button className="wishlist-btn">
                <span className="icon">♡</span>
                Add to Wishlist
            </button>
        </div>
    );
}
