// components/product/ReviewsSection.tsx
'use client';

import { useState, useCallback } from 'react';
import { useInfiniteQuery } from '@tanstack/react-query';
import { ReviewCard } from './ReviewCard';
import { ReviewForm } from './ReviewForm';
import { RatingDistribution } from './RatingDistribution';

interface ReviewsSectionProps {
    productId: string;
    rating: Product['rating'];
    initialReviews: {
        reviews: ProductReview[];
        total: number;
        hasMore: boolean;
    };
}

export function ReviewsSection({
    productId,
    rating,
    initialReviews
}: ReviewsSectionProps) {
    const [sortBy, setSortBy] = useState<'recent' | 'helpful' | 'rating_high' | 'rating_low'>('recent');
    const [filterRating, setFilterRating] = useState<number | null>(null);
    const [showReviewForm, setShowReviewForm] = useState(false);

    // Infinite query for reviews
    const {
        data,
        fetchNextPage,
        hasNextPage,
        isFetchingNextPage,
        isLoading,
        refetch
    } = useInfiniteQuery({
        queryKey: ['reviews', productId, sortBy, filterRating],
        queryFn: async ({ pageParam = 1 }) => {
            const params = new URLSearchParams({
                page: String(pageParam),
                limit: '10',
                sort: sortBy,
                ...(filterRating && { rating: String(filterRating) })
            });

            const response = await fetch(
                `/api/products/${productId}/reviews?${params}`
            );
            return response.json();
        },
        getNextPageParam: (lastPage) =>
            lastPage.hasMore ? lastPage.page + 1 : undefined,
        initialData: {
            pages: [initialReviews],
            pageParams: [1]
        }
    });

    const allReviews = data?.pages.flatMap(page => page.reviews) || [];

    // Handle helpful vote
    const handleHelpful = useCallback(async (reviewId: string) => {
        await fetch(`/api/reviews/${reviewId}/helpful`, { method: 'POST' });
        refetch();
    }, [refetch]);

    // Handle review submission
    const handleReviewSubmit = useCallback(async (reviewData: any) => {
        await fetch(`/api/products/${productId}/reviews`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(reviewData)
        });
        setShowReviewForm(false);
        refetch();
    }, [productId, refetch]);

    return (
        <div className="reviews-section">
            <div className="reviews-header">
                <h2>Customer Reviews</h2>
                <button
                    className="write-review-btn"
                    onClick={() => setShowReviewForm(true)}
                >
                    Write a Review
                </button>
            </div>

            <div className="reviews-layout">
                {/* Summary Sidebar */}
                <div className="reviews-summary">
                    <div className="overall-rating">
                        <span className="rating-value">{rating.average.toFixed(1)}</span>
                        <div className="stars">
                            {renderStars(rating.average)}
                        </div>
                        <span className="review-count">
                            Based on {rating.count} reviews
                        </span>
                    </div>

                    <RatingDistribution
                        distribution={rating.distribution}
                        total={rating.count}
                        onFilter={setFilterRating}
                        activeFilter={filterRating}
                    />
                </div>

                {/* Reviews List */}
                <div className="reviews-list">
                    {/* Filters and Sort */}
                    <div className="reviews-controls">
                        <div className="sort-select">
                            <label htmlFor="sort">Sort by:</label>
                            <select
                                id="sort"
                                value={sortBy}
                                onChange={(e) => setSortBy(e.target.value as typeof sortBy)}
                            >
                                <option value="recent">Most Recent</option>
                                <option value="helpful">Most Helpful</option>
                                <option value="rating_high">Highest Rating</option>
                                <option value="rating_low">Lowest Rating</option>
                            </select>
                        </div>

                        {filterRating && (
                            <button
                                className="clear-filter"
                                onClick={() => setFilterRating(null)}
                            >
                                Clear filter: {filterRating} stars ✕
                            </button>
                        )}
                    </div>

                    {/* Reviews */}
                    {allReviews.length === 0 ? (
                        <div className="no-reviews">
                            <p>No reviews yet. Be the first to review this product!</p>
                        </div>
                    ) : (
                        <>
                            {allReviews.map(review => (
                                <ReviewCard
                                    key={review.id}
                                    review={review}
                                    onHelpful={() => handleHelpful(review.id)}
                                />
                            ))}

                            {hasNextPage && (
                                <button
                                    className="load-more-btn"
                                    onClick={() => fetchNextPage()}
                                    disabled={isFetchingNextPage}
                                >
                                    {isFetchingNextPage ? 'Loading...' : 'Load More Reviews'}
                                </button>
                            )}
                        </>
                    )}
                </div>
            </div>

            {/* Review Form Modal */}
            {showReviewForm && (
                <ReviewForm
                    productId={productId}
                    onSubmit={handleReviewSubmit}
                    onClose={() => setShowReviewForm(false)}
                />
            )}
        </div>
    );
}

function renderStars(rating: number) {
    const fullStars = Math.floor(rating);
    const hasHalfStar = rating % 1 >= 0.5;
    const emptyStars = 5 - fullStars - (hasHalfStar ? 1 : 0);

    return (
        <>
            {'★'.repeat(fullStars)}
            {hasHalfStar && '½'}
            {'☆'.repeat(emptyStars)}
        </>
    );
}
