// 4. Cart State with Optimistic Updates
// hooks/useCart.ts
import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { immer } from 'zustand/middleware/immer';

interface CartStore {
    items: CartItem[];
    isLoading: boolean;
    addItem: (item: CartItem) => Promise<void>;
    removeItem: (variantId: string) => Promise<void>;
    updateQuantity: (variantId: string, quantity: number) => Promise<void>;
    syncWithServer: () => Promise<void>;
}

export const useCart = create<CartStore>()(
    persist(
        immer((set, get) => ({
            items: [],
            isLoading: false,

            addItem: async (item) => {
                // Optimistic update
                set((state) => {
                    const existing = state.items.find(i => i.variantId === item.variantId);
                    if (existing) {
                        existing.quantity += item.quantity;
                    } else {
                        state.items.push(item);
                    }
                });

                // Sync with server
                try {
                    await fetch('/api/cart/add', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify(item)
                    });
                } catch (error) {
                    // Rollback on error
                    set((state) => {
                        const index = state.items.findIndex(i => i.variantId === item.variantId);
                        if (index >= 0) {
                            state.items[index].quantity -= item.quantity;
                            if (state.items[index].quantity <= 0) {
                                state.items.splice(index, 1);
                            }
                        }
                    });
                    throw error;
                }
            },

            removeItem: async (variantId) => {
                const item = get().items.find(i => i.variantId === variantId);

                // Optimistic update
                set((state) => {
                    state.items = state.items.filter(i => i.variantId !== variantId);
                });

                try {
                    await fetch(`/api/cart/${variantId}`, { method: 'DELETE' });
                } catch (error) {
                    // Rollback
                    if (item) {
                        set((state) => {
                            state.items.push(item);
                        });
                    }
                    throw error;
                }
            },

            updateQuantity: async (variantId, quantity) => {
                const item = get().items.find(i => i.variantId === variantId);
                const oldQuantity = item?.quantity;

                if (quantity <= 0) {
                    return get().removeItem(variantId);
                }

                // Optimistic update
                set((state) => {
                    const item = state.items.find(i => i.variantId === variantId);
                    if (item) {
                        item.quantity = quantity;
                    }
                });

                try {
                    await fetch(`/api/cart/${variantId}`, {
                        method: 'PATCH',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ quantity })
                    });
                } catch (error) {
                    // Rollback
                    set((state) => {
                        const item = state.items.find(i => i.variantId === variantId);
                        if (item && oldQuantity) {
                            item.quantity = oldQuantity;
                        }
                    });
                    throw error;
                }
            },

            syncWithServer: async () => {
                set({ isLoading: true });
                try {
                    const response = await fetch('/api/cart');
                    const serverCart = await response.json();
                    set({ items: serverCart.items, isLoading: false });
                } catch (error) {
                    set({ isLoading: false });
                }
            }
        })),
        {
            name: 'cart-storage',
            partialize: (state) => ({ items: state.items })
        }
    )
);

// 5. Real-time Inventory Hook
// hooks/useInventory.ts
import { useQuery } from '@tanstack/react-query';

interface UseInventoryOptions {
    enabled?: boolean;
    refetchInterval?: number;
}

export function useInventory(
    variantId: string,
    options: UseInventoryOptions = {}
) {
    return useQuery({
        queryKey: ['inventory', variantId],
        queryFn: async () => {
            const response = await fetch(`/api/inventory/${variantId}`);
            if (!response.ok) throw new Error('Failed to fetch inventory');
            return response.json();
        },
        enabled: options.enabled !== false && !!variantId,
        refetchInterval: options.refetchInterval || 30000,
        staleTime: 10000 // Consider data fresh for 10 seconds
    });
}
