    loadDashboard: (id: string) => Promise<void>;
    saveDashboard: () => Promise<void>;
    updateLayout: (widgets: Widget[]) => void;
    addWidget: (widget: Omit<Widget, 'id'>) => void;
    updateWidget: (id: string, updates: Partial<Widget>) => void;
    removeWidget: (id: string) => void;
    duplicateWidget: (id: string) => void;
    setWidgetData: (widgetId: string, data: any) => void;
    setFilter: (filterId: string, value: any) => void;
    clearFilters: () => void;
    setEditing: (editing: boolean) => void;
    selectWidget: (widgetId: string | null) => void;
    setConnectionStatus: (status: 'connected' | 'disconnected' | 'reconnecting') => void;
}

export const useDashboardStore = create<DashboardStore>()(
    subscribeWithSelector(
        immer((set, get) => ({
            dashboard: null,
            widgetData: {},
            filters: {},
            isEditing: false,
            selectedWidget: null,
            connectionStatus: 'disconnected',
            lastUpdate: null,

            loadDashboard: async (id) => {
                const response = await fetch(`/api/dashboards/${id}`);
                const dashboard = await response.json();

                set((state) => {
                    state.dashboard = dashboard;
                    // Initialize filters with default values
                    dashboard.filters.forEach((filter: GlobalFilter) => {
                        if (filter.defaultValue !== undefined) {
                            state.filters[filter.id] = filter.defaultValue;
                        }
                    });
                });
            },

            saveDashboard: async () => {
                const { dashboard } = get();
                if (!dashboard) return;

                await fetch(`/api/dashboards/${dashboard.id}`, {
                    method: 'PUT',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(dashboard)
                });
            },

            updateLayout: (widgets) => {
                set((state) => {
                    if (state.dashboard) {
                        state.dashboard.widgets = widgets;
                    }
                });
            },

            addWidget: (widget) => {
                set((state) => {
                    if (state.dashboard) {
                        const newWidget: Widget = {
                            ...widget,
                            id: crypto.randomUUID()
                        };
                        state.dashboard.widgets.push(newWidget);
                        state.selectedWidget = newWidget.id;
                    }
                });
            },

            updateWidget: (id, updates) => {
                set((state) => {
                    if (state.dashboard) {
                        const widget = state.dashboard.widgets.find(w => w.id === id);
                        if (widget) {
                            Object.assign(widget, updates);
                        }
                    }
                });
            },

            removeWidget: (id) => {
                set((state) => {
                    if (state.dashboard) {
                        state.dashboard.widgets = state.dashboard.widgets.filter(
                            w => w.id !== id
                        );
                        if (state.selectedWidget === id) {
                            state.selectedWidget = null;
                        }
                        delete state.widgetData[id];
                    }
                });
            },

            duplicateWidget: (id) => {
                set((state) => {
                    if (state.dashboard) {
                        const widget = state.dashboard.widgets.find(w => w.id === id);
                        if (widget) {
                            const newWidget: Widget = {
                                ...JSON.parse(JSON.stringify(widget)),
                                id: crypto.randomUUID(),
                                position: {
                                    ...widget.position,
                                    x: widget.position.x + 1,
                                    y: widget.position.y + 1
                                },
                                title: `${widget.title} (Copy)`
                            };
                            state.dashboard.widgets.push(newWidget);
                            state.selectedWidget = newWidget.id;
                        }
                    }
                });
            },

            setWidgetData: (widgetId, data) => {
                set((state) => {
                    state.widgetData[widgetId] = data;
                    state.lastUpdate = new Date().toISOString();
                });
            },

            setFilter: (filterId, value) => {
                set((state) => {
                    state.filters[filterId] = value;
                });
            },

            clearFilters: () => {
                set((state) => {
                    state.filters = {};
                    // Re-apply defaults
                    state.dashboard?.filters.forEach((filter) => {
                        if (filter.defaultValue !== undefined) {
                            state.filters[filter.id] = filter.defaultValue;
                        }
                    });
                });
            },

            setEditing: (editing) => {
                set((state) => {
                    state.isEditing = editing;
                    if (!editing) {
                        state.selectedWidget = null;
                    }
                });
            },

            selectWidget: (widgetId) => {
                set((state) => {
                    state.selectedWidget = widgetId;
                });
            },

            setConnectionStatus: (status) => {
                set((state) => {
                    state.connectionStatus = status;
                });
            }
        }))
    )
);
