// WEBSOCKET CONNECTION MANAGER
// ═══════════════════════════════════════════════════════════

class DashboardWebSocket {
    private socket: WebSocket | null = null;
    private reconnectAttempts = 0;
    private maxReconnectAttempts = 5;
    private reconnectDelay = 1000;
    private subscriptions: Set<string> = new Set();
    private messageHandlers: Map<string, (data: any) => void> = new Map();

    constructor(private url: string) {}

    connect() {
        if (this.socket?.readyState === WebSocket.OPEN) return;

        this.socket = new WebSocket(this.url);

        this.socket.onopen = () => {
            console.log('WebSocket connected');
            useDashboardStore.getState().setConnectionStatus('connected');
            this.reconnectAttempts = 0;

            // Re-subscribe to all topics
            this.subscriptions.forEach(topic => {
                this.send({ type: 'subscribe', topic });
            });
        };

        this.socket.onclose = () => {
            console.log('WebSocket disconnected');
            useDashboardStore.getState().setConnectionStatus('disconnected');
            this.attemptReconnect();
        };

        this.socket.onerror = (error) => {
            console.error('WebSocket error:', error);
        };

        this.socket.onmessage = (event) => {
            try {
                const message = JSON.parse(event.data);
                this.handleMessage(message);
            } catch (error) {
                console.error('Failed to parse message:', error);
            }
        };
    }

    private attemptReconnect() {
        if (this.reconnectAttempts >= this.maxReconnectAttempts) {
            console.error('Max reconnection attempts reached');
            return;
        }

        useDashboardStore.getState().setConnectionStatus('reconnecting');

        setTimeout(() => {
            this.reconnectAttempts++;
            console.log(`Reconnecting... Attempt ${this.reconnectAttempts}`);
            this.connect();
        }, this.reconnectDelay * Math.pow(2, this.reconnectAttempts));
    }

    private handleMessage(message: { type: string; topic?: string; data?: any }) {
        switch (message.type) {
            case 'data':
                if (message.topic) {
                    const handler = this.messageHandlers.get(message.topic);
                    handler?.(message.data);
                }
                break;
            case 'error':
                console.error('Server error:', message.data);
                break;
            case 'ping':
                this.send({ type: 'pong' });
                break;
        }
    }

    subscribe(topic: string, handler: (data: any) => void) {
        this.subscriptions.add(topic);
        this.messageHandlers.set(topic, handler);

        if (this.socket?.readyState === WebSocket.OPEN) {
            this.send({ type: 'subscribe', topic });
        }

        return () => {
            this.unsubscribe(topic);
        };
    }

    unsubscribe(topic: string) {
        this.subscriptions.delete(topic);
        this.messageHandlers.delete(topic);

        if (this.socket?.readyState === WebSocket.OPEN) {
            this.send({ type: 'unsubscribe', topic });
        }
    }

    private send(message: any) {
        if (this.socket?.readyState === WebSocket.OPEN) {
            this.socket.send(JSON.stringify(message));
        }
    }

    disconnect() {
        this.subscriptions.clear();
        this.messageHandlers.clear();
        this.socket?.close();
        this.socket = null;
    }
}

// Singleton instance
let dashboardWS: DashboardWebSocket | null = null;

export function getDashboardWebSocket() {
    if (!dashboardWS) {
        dashboardWS = new DashboardWebSocket(
            process.env.NEXT_PUBLIC_WS_URL || 'wss://api.example.com/ws'
        );
    }
    return dashboardWS;
}
