import { useEffect, useCallback, useRef } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';

interface UseWidgetDataOptions {
    widget: Widget;
    filters: Record<string, any>;
    enabled?: boolean;
}

export function useWidgetData({ widget, filters, enabled = true }: UseWidgetDataOptions) {
    const queryClient = useQueryClient();
    const { setWidgetData } = useDashboardStore();
    const wsUnsubscribeRef = useRef<(() => void) | null>(null);

    // Build query params from filters
    const queryParams = useMemo(() => {
        const params: Record<string, any> = { ...widget.dataSource.params };

        // Apply global filters
        Object.entries(filters).forEach(([key, value]) => {
            if (value !== undefined && value !== null) {
                params[key] = value;
            }
        });

        // Apply time range
        if (widget.dataSource.timeRange) {
            const range = widget.dataSource.timeRange;
            if (range.type === 'relative' && range.relative) {
                const now = new Date();
                const start = new Date(now);

                switch (range.relative.unit) {
                    case 'minutes':
                        start.setMinutes(start.getMinutes() - range.relative.value);
                        break;
                    case 'hours':
                        start.setHours(start.getHours() - range.relative.value);
                        break;
                    case 'days':
                        start.setDate(start.getDate() - range.relative.value);
                        break;
                    case 'weeks':
                        start.setDate(start.getDate() - range.relative.value * 7);
                        break;
                    case 'months':
                        start.setMonth(start.getMonth() - range.relative.value);
                        break;
                }

                params.startTime = start.toISOString();
                params.endTime = now.toISOString();
            } else if (range.type === 'absolute' && range.absolute) {
                params.startTime = range.absolute.start;
                params.endTime = range.absolute.end;
            }
        }

        return params;
    }, [widget.dataSource.params, widget.dataSource.timeRange, filters]);

    // REST API data fetching
    const { data, isLoading, error, refetch } = useQuery({
        queryKey: ['widget', widget.id, queryParams],
        queryFn: async () => {
            if (widget.dataSource.type !== 'api' || !widget.dataSource.endpoint) {
                return null;
            }

            const url = new URL(widget.dataSource.endpoint, window.location.origin);
            Object.entries(queryParams).forEach(([key, value]) => {
                if (value !== undefined) {
                    url.searchParams.set(key, String(value));
                }
            });

            const response = await fetch(url.toString());
            if (!response.ok) throw new Error('Failed to fetch widget data');

            const data = await response.json();

            // Apply transform if specified
            if (widget.dataSource.transform) {
                try {
                    const transformFn = new Function('data', widget.dataSource.transform);
                    return transformFn(data);
                } catch (error) {
                    console.error('Transform error:', error);
                    return data;
                }
            }

            return data;
        },
        enabled: enabled && widget.dataSource.type === 'api',
        refetchInterval: widget.refreshInterval
            ? widget.refreshInterval * 1000
            : undefined
    });

    // WebSocket subscription
    useEffect(() => {
        if (!enabled || widget.dataSource.type !== 'websocket') return;

        const ws = getDashboardWebSocket();
        ws.connect();

        const topic = widget.dataSource.endpoint || widget.id;

        wsUnsubscribeRef.current = ws.subscribe(topic, (wsData) => {
            // Apply transform if specified
            let transformedData = wsData;
            if (widget.dataSource.transform) {
                try {
                    const transformFn = new Function('data', widget.dataSource.transform);
                    transformedData = transformFn(wsData);
                } catch (error) {
                    console.error('Transform error:', error);
                }
            }

            setWidgetData(widget.id, transformedData);

            // Also update React Query cache for consistency
            queryClient.setQueryData(['widget', widget.id, queryParams], transformedData);
        });

        return () => {
            wsUnsubscribeRef.current?.();
        };
    }, [enabled, widget, queryParams, setWidgetData, queryClient]);

    // Update store when REST data changes
    useEffect(() => {
        if (data && widget.dataSource.type === 'api') {
            setWidgetData(widget.id, data);
        }
    }, [data, widget.id, widget.dataSource.type, setWidgetData]);

    return {
        data,
        isLoading,
        error,
        refetch
    };
}

