'use client';

import { useCallback } from 'react';
import GridLayout, { Layout } from 'react-grid-layout';
import { useDashboardStore } from '@/stores/dashboardStore';
import { WidgetContainer } from './WidgetContainer';
import 'react-grid-layout/css/styles.css';
import 'react-resizable/css/styles.css';

interface DashboardGridProps {
    widgets: Widget[];
    layout: DashboardLayout;
    isEditing: boolean;
}

export function DashboardGrid({ widgets, layout, isEditing }: DashboardGridProps) {
    const { updateLayout, selectWidget, filters } = useDashboardStore();

    // Convert widgets to grid layout format
    const gridLayout: Layout[] = widgets.map(widget => ({
        i: widget.id,
        x: widget.position.x,
        y: widget.position.y,
        w: widget.position.width,
        h: widget.position.height,
        minW: widget.position.minWidth || 1,
        minH: widget.position.minHeight || 1,
        static: !isEditing
    }));

    // Handle layout change
    const handleLayoutChange = useCallback((newLayout: Layout[]) => {
        const updatedWidgets = widgets.map(widget => {
            const layoutItem = newLayout.find(l => l.i === widget.id);
            if (layoutItem) {
                return {
                    ...widget,
                    position: {
                        ...widget.position,
                        x: layoutItem.x,
                        y: layoutItem.y,
                        width: layoutItem.w,
                        height: layoutItem.h
                    }
                };
            }
            return widget;
        });

        updateLayout(updatedWidgets);
    }, [widgets, updateLayout]);

    // Handle widget click in edit mode
    const handleWidgetClick = useCallback((widgetId: string) => {
        if (isEditing) {
            selectWidget(widgetId);
        }
    }, [isEditing, selectWidget]);

    return (
        <GridLayout
            className="dashboard-grid"
            layout={gridLayout}
            cols={layout.columns}
            rowHeight={layout.rowHeight}
            margin={[layout.gap, layout.gap]}
            containerPadding={[layout.gap, layout.gap]}
            onLayoutChange={handleLayoutChange}
            isDraggable={isEditing}
            isResizable={isEditing}
            compactType={null}
            preventCollision={true}
        >
            {widgets.map(widget => (
                <div
                    key={widget.id}
                    onClick={() => handleWidgetClick(widget.id)}
                >
                    <WidgetContainer
                        widget={widget}
                        filters={filters}
                        isEditing={isEditing}
                    />
                </div>
            ))}
        </GridLayout>
    );
}

// components/dashboard/WidgetContainer.tsx
'use client';

import { Suspense, useMemo } from 'react';
import { useDashboardStore } from '@/stores/dashboardStore';
import { useWidgetData } from '@/hooks/useWidgetData';
import { MetricWidget } from './widgets/MetricWidget';
import { ChartWidget } from './widgets/ChartWidget';
import { TableWidget } from './widgets/TableWidget';
import { GaugeWidget } from './widgets/GaugeWidget';
import { HeatmapWidget } from './widgets/HeatmapWidget';
import { WidgetSkeleton } from './skeletons/WidgetSkeleton';
import { WidgetError } from './WidgetError';

interface WidgetContainerProps {
    widget: Widget;
    filters: Record<string, any>;
    isEditing: boolean;
}

export function WidgetContainer({ widget, filters, isEditing }: WidgetContainerProps) {
    const { selectedWidget, widgetData } = useDashboardStore();
    const isSelected = selectedWidget === widget.id;

    // Fetch widget data
    const { data, isLoading, error, refetch } = useWidgetData({
        widget,
        filters,
        enabled: !isEditing
    });

    // Get data from store (for WebSocket updates) or from query
    const displayData = widgetData[widget.id] || data;

    // Check alerts
    const activeAlerts = useMemo(() => {
        if (!widget.alerts || !displayData) return [];

        return widget.alerts.filter(alert => {
            if (!alert.enabled) return false;

            const value = getNestedValue(displayData, alert.condition.field);
            if (typeof value !== 'number') return false;

            switch (alert.condition.operator) {
                case '>': return value > alert.condition.value;
                case '<': return value < alert.condition.value;
                case '>=': return value >= alert.condition.value;
                case '<=': return value <= alert.condition.value;
                case '=': return value === alert.condition.value;
                case '!=': return value !== alert.condition.value;
                default: return false;
            }
        });
    }, [widget.alerts, displayData]);

    // Widget component based on type
    const WidgetComponent = useMemo(() => {
        switch (widget.type) {
            case 'metric': return MetricWidget;
            case 'chart': return ChartWidget;
            case 'table': return TableWidget;
            case 'gauge': return GaugeWidget;
            case 'heatmap': return HeatmapWidget;
            default: return () => <div>Unknown widget type</div>;
        }
    }, [widget.type]);

    return (
        <div
            className={`widget-container ${isSelected ? 'selected' : ''} ${activeAlerts.length > 0 ? 'has-alerts' : ''}`}
            style={{
                backgroundColor: widget.config.backgroundColor,
                border: widget.config.showBorder !== false ? undefined : 'none'
            }}
        >
            {/* Widget Header */}
            {widget.config.showTitle !== false && (
                <div className="widget-header">
                    <h3 className="widget-title">{widget.title}</h3>

                    {/* Alert indicators */}
                    {activeAlerts.length > 0 && (
                        <div className="alert-indicators">
                            {activeAlerts.map(alert => (
                                <span
                                    key={alert.id}
                                    className={`alert-indicator ${alert.severity}`}
                                    title={alert.message}
                                >
                                    ⚠
                                </span>
                            ))}
                        </div>
                    )}

                    {/* Widget actions */}
                    {!isEditing && (
                        <div className="widget-actions">
                            <button
                                onClick={() => refetch()}
                                aria-label="Refresh"
                                title="Refresh data"
                            >
                                🔄
                            </button>
                        </div>
                    )}
                </div>
            )}

            {/* Widget Content */}
            <div className="widget-content">
                {error ? (
                    <WidgetError error={error} onRetry={refetch} />
                ) : isLoading ? (
                    <WidgetSkeleton type={widget.type} />
                ) : (
                    <Suspense fallback={<WidgetSkeleton type={widget.type} />}>
                        <WidgetComponent
                            config={widget.config}
                            data={displayData}
                        />
                    </Suspense>
                )}
            </div>
        </div>
    );
}

// Helper to get nested value
function getNestedValue(obj: any, path: string): any {
    return path.split('.').reduce((acc, part) => acc?.[part], obj);
}
