// components/dashboard/widgets/MetricWidget.tsx
'use client';

import { useMemo } from 'react';
import { SparklineChart } from '@/components/charts/SparklineChart';

interface MetricWidgetProps {
    config: {
        format?: 'number' | 'currency' | 'percent' | 'bytes';
        decimals?: number;
        prefix?: string;
        suffix?: string;
        showChange?: boolean;
        showSparkline?: boolean;
        thresholds?: Array<{
            value: number;
            color: string;
        }>;
    };
    data: MetricData;
}

export function MetricWidget({ config, data }: MetricWidgetProps) {
    // Format value
    const formattedValue = useMemo(() => {
        if (!data) return '--';

        let value = data.value;
        const decimals = config.decimals ?? 2;

        switch (config.format) {
            case 'currency':
                return new Intl.NumberFormat('en-US', {
                    style: 'currency',
                    currency: 'USD',
                    minimumFractionDigits: decimals,
                    maximumFractionDigits: decimals
                }).format(value);

            case 'percent':
                return `${value.toFixed(decimals)}%`;

            case 'bytes':
                return formatBytes(value);

            default:
                return `${config.prefix || ''}${value.toLocaleString(undefined, {
                    minimumFractionDigits: decimals,
                    maximumFractionDigits: decimals
                })}${config.suffix || ''}`;
        }
    }, [data, config]);

    // Determine color based on thresholds
    const valueColor = useMemo(() => {
        if (!data || !config.thresholds) return undefined;

        const sortedThresholds = [...config.thresholds].sort((a, b) => b.value - a.value);
        const threshold = sortedThresholds.find(t => data.value >= t.value);

        return threshold?.color;
    }, [data, config.thresholds]);

    // Format change
    const changeDisplay = useMemo(() => {
        if (!data || !config.showChange || data.changePercent === undefined) {
            return null;
        }

        const isPositive = data.changePercent >= 0;
        const arrow = isPositive ? '↑' : '↓';
        const color = isPositive ? 'var(--color-success)' : 'var(--color-error)';

        return {
            text: `${arrow} ${Math.abs(data.changePercent).toFixed(1)}%`,
            color
        };
    }, [data, config.showChange]);

    return (
        <div className="metric-widget">
            <div className="metric-value" style={{ color: valueColor }}>
                {formattedValue}
            </div>

            {changeDisplay && (
                <div className="metric-change" style={{ color: changeDisplay.color }}>
                    {changeDisplay.text}
                </div>
            )}

            {config.showSparkline && data?.sparkline && (
                <div className="metric-sparkline">
                    <SparklineChart
                        data={data.sparkline}
                        color={valueColor}
                        height={40}
                    />
                </div>
            )}
        </div>
    );
}

function formatBytes(bytes: number): string {
    if (bytes === 0) return '0 B';

    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB', 'PB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));

    return `${parseFloat((bytes / Math.pow(k, i)).toFixed(2))} ${sizes[i]}`;
}

