'use client';

import { useMemo } from 'react';
import {
    Chart as ChartJS,
    CategoryScale,
    LinearScale,
    PointElement,
    LineElement,
    BarElement,
    ArcElement,
    Title,
    Tooltip,
    Legend,
    Filler
} from 'chart.js';
import { Line, Bar, Doughnut, Pie } from 'react-chartjs-2';

ChartJS.register(
    CategoryScale,
    LinearScale,
    PointElement,
    LineElement,
    BarElement,
    ArcElement,
    Title,
    Tooltip,
    Legend,
    Filler
);

interface ChartWidgetProps {
    config: {
        chartType: 'line' | 'bar' | 'area' | 'doughnut' | 'pie';
        stacked?: boolean;
        showLegend?: boolean;
        legendPosition?: 'top' | 'bottom' | 'left' | 'right';
        showGrid?: boolean;
        tension?: number; // For line smoothing
        fill?: boolean;
        colors?: string[];
    };
    data: ChartData;
}

export function ChartWidget({ config, data }: ChartWidgetProps) {
    const chartData = useMemo(() => {
        if (!data) return null;

        const colors = config.colors || [
            '#3b82f6', '#10b981', '#f59e0b', '#ef4444',
            '#8b5cf6', '#ec4899', '#06b6d4', '#84cc16'
        ];

        return {
            labels: data.labels,
            datasets: data.datasets.map((dataset, index) => ({
                label: dataset.label,
                data: dataset.data,
                backgroundColor: config.chartType === 'line' || config.chartType === 'area'
                    ? `${colors[index % colors.length]}20`
                    : colors[index % colors.length],
                borderColor: colors[index % colors.length],
                borderWidth: 2,
                fill: config.chartType === 'area' || config.fill,
                tension: config.tension ?? 0.4,
                pointRadius: config.chartType === 'line' ? 0 : undefined,
                pointHoverRadius: config.chartType === 'line' ? 4 : undefined
            }))
        };
    }, [data, config]);

    const options = useMemo(() => ({
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
            legend: {
                display: config.showLegend !== false,
                position: config.legendPosition || 'top'
            },
            tooltip: {
                mode: 'index' as const,
                intersect: false
            }
        },
        scales: config.chartType !== 'doughnut' && config.chartType !== 'pie' ? {
            x: {
                stacked: config.stacked,
                grid: {
                    display: config.showGrid !== false
                }
            },
            y: {
                stacked: config.stacked,
                grid: {
                    display: config.showGrid !== false
                },
                beginAtZero: true
            }
        } : undefined,
        interaction: {
            mode: 'nearest' as const,
            axis: 'x' as const,
            intersect: false
        }
    }), [config]);

    if (!chartData) {
        return <div className="chart-empty">No data available</div>;
    }

    const ChartComponent = useMemo(() => {
        switch (config.chartType) {
            case 'bar': return Bar;
            case 'doughnut': return Doughnut;
            case 'pie': return Pie;
            case 'line':
            case 'area':
            default:
                return Line;
        }
    }, [config.chartType]);

    return (
        <div className="chart-widget">
            <ChartComponent data={chartData} options={options} />
        </div>
    );
}
