### **Video Player Architecture**

```
// ═══════════════════════════════════════════════════════════
// ADAPTIVE BITRATE VIDEO PLAYER
// ═══════════════════════════════════════════════════════════

interface VideoQuality {
    label: string;
    resolution: string;
    bitrate: number;
    width: number;
    height: number;
}

interface VideoSource {
    manifestUrl: string;
    type: 'hls' | 'dash';
    qualities: VideoQuality[];
}

interface PlaybackState {
    currentTime: number;
    duration: number;
    buffered: TimeRanges | null;
    isPlaying: boolean;
    isPaused: boolean;
    isBuffering: boolean;
    isSeeking: boolean;
    volume: number;
    isMuted: boolean;
    playbackRate: number;
    currentQuality: VideoQuality | null;
    isFullscreen: boolean;
    error: Error | null;
}

interface VideoPlayerConfig {
    autoplay: boolean;
    muted: boolean;
    preload: 'none' | 'metadata' | 'auto';
    startTime?: number;
    maxBufferLength: number;
    maxMaxBufferLength: number;
    enableAdaptiveBitrate: boolean;
    preferredQuality?: string;
}

// Video Player Hook
function useVideoPlayer(
    videoRef: RefObject<HTMLVideoElement>,
    source: VideoSource,
    config: VideoPlayerConfig
) {
    const [state, setState] = useState<PlaybackState>({
        currentTime: 0,
        duration: 0,
        buffered: null,
        isPlaying: false,
        isPaused: true,
        isBuffering: false,
        isSeeking: false,
        volume: 1,
        isMuted: config.muted,
        playbackRate: 1,
        currentQuality: null,
        isFullscreen: false,
        error: null
    });

    const hlsRef = useRef<Hls | null>(null);
    const analyticsRef = useRef<VideoAnalytics | null>(null);

    // Initialize HLS.js for adaptive streaming
    useEffect(() => {
        const video = videoRef.current;
        if (!video || !source.manifestUrl) return;

        if (source.type === 'hls' && Hls.isSupported()) {
            const hls = new Hls({
                maxBufferLength: config.maxBufferLength,
                maxMaxBufferLength: config.maxMaxBufferLength,
                enableWorker: true,
                lowLatencyMode: false,
                startLevel: -1 // Auto quality selection
            });

            hls.loadSource(source.manifestUrl);
            hls.attachMedia(video);

            hls.on(Hls.Events.MANIFEST_PARSED, (event, data) => {
                const qualities = data.levels.map((level, index) => ({
                    label: `${level.height}p`,
                    resolution: `${level.width}x${level.height}`,
                    bitrate: level.bitrate,
                    width: level.width,
                    height: level.height,
                    levelIndex: index
                }));

                setState(prev => ({
                    ...prev,
                    availableQualities: qualities,
                    currentQuality: qualities[hls.currentLevel] || qualities[0]
                }));

                if (config.autoplay) {
                    video.play().catch(() => {
                        // Autoplay blocked, try muted
                        video.muted = true;
                        video.play();
                    });
                }
            });

            hls.on(Hls.Events.LEVEL_SWITCHED, (event, data) => {
                const quality = source.qualities[data.level];
                setState(prev => ({ ...prev, currentQuality: quality }));
                analyticsRef.current?.trackQualityChange(quality);
            });

            hls.on(Hls.Events.ERROR, (event, data) => {
                if (data.fatal) {
                    switch (data.type) {
                        case Hls.ErrorTypes.NETWORK_ERROR:
                            hls.startLoad();
                            break;
                        case Hls.ErrorTypes.MEDIA_ERROR:
                            hls.recoverMediaError();
                            break;
                        default:
                            setState(prev => ({
                                ...prev,
                                error: new Error(data.details)
                            }));
                            break;
                    }
                }
            });

            hlsRef.current = hls;

            return () => {
                hls.destroy();
            };
        } else if (video.canPlayType('application/vnd.apple.mpegurl')) {
            // Native HLS support (Safari)
            video.src = source.manifestUrl;
        }
    }, [source.manifestUrl, config]);

    // Video event listeners
    useEffect(() => {
        const video = videoRef.current;
        if (!video) return;

        const handlers = {
            loadedmetadata: () => {
                setState(prev => ({
                    ...prev,
                    duration: video.duration
                }));

                if (config.startTime && config.startTime > 0) {
                    video.currentTime = config.startTime;
                }
            },

            timeupdate: () => {
                setState(prev => ({
                    ...prev,
                    currentTime: video.currentTime,
                    buffered: video.buffered
                }));

                // Track watch progress
                analyticsRef.current?.trackProgress(video.currentTime);
            },

            play: () => {
                setState(prev => ({
                    ...prev,
                    isPlaying: true,
                    isPaused: false
                }));
                analyticsRef.current?.trackPlay();
            },

            pause: () => {
                setState(prev => ({
                    ...prev,
                    isPlaying: false,
                    isPaused: true
                }));
                analyticsRef.current?.trackPause();
            },

            waiting: () => {
                setState(prev => ({ ...prev, isBuffering: true }));
                analyticsRef.current?.trackBuffering();
            },

            playing: () => {
                setState(prev => ({ ...prev, isBuffering: false }));
            },

            seeking: () => {
                setState(prev => ({ ...prev, isSeeking: true }));
            },

            seeked: () => {
                setState(prev => ({ ...prev, isSeeking: false }));
                analyticsRef.current?.trackSeek(video.currentTime);
            },

            volumechange: () => {
                setState(prev => ({
                    ...prev,
                    volume: video.volume,
                    isMuted: video.muted
                }));
            },

            ratechange: () => {
                setState(prev => ({
                    ...prev,
                    playbackRate: video.playbackRate
                }));
            },

            ended: () => {
                setState(prev => ({
                    ...prev,
                    isPlaying: false,
                    isPaused: true
                }));
                analyticsRef.current?.trackComplete();
            },

            error: () => {
                setState(prev => ({
                    ...prev,
                    error: new Error(video.error?.message || 'Playback error')
                }));
                analyticsRef.current?.trackError(video.error);
            }
        };

        Object.entries(handlers).forEach(([event, handler]) => {
            video.addEventListener(event, handler);
        });

        return () => {
            Object.entries(handlers).forEach(([event, handler]) => {
                video.removeEventListener(event, handler);
            });
        };
    }, [config.startTime]);

    // Fullscreen handling
    useEffect(() => {
        const handleFullscreenChange = () => {
            setState(prev => ({
                ...prev,
                isFullscreen: !!document.fullscreenElement
            }));
        };

        document.addEventListener('fullscreenchange', handleFullscreenChange);
        return () => {
            document.removeEventListener('fullscreenchange', handleFullscreenChange);
        };
    }, []);
