interface VideoPlayerProps {
    videoId: string;
    source: VideoSource;
    poster?: string;
    title: string;
    onTimeUpdate?: (time: number) => void;
    onEnded?: () => void;
}

function VideoPlayer({
    videoId,
    source,
    poster,
    title,
    onTimeUpdate,
    onEnded
}: VideoPlayerProps) {
    const videoRef = useRef<HTMLVideoElement>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [showControls, setShowControls] = useState(true);
    const hideControlsTimeoutRef = useRef<NodeJS.Timeout>();

    const { state, controls } = useVideoPlayer(videoRef, source, {
        autoplay: true,
        muted: false,
        preload: 'metadata',
        maxBufferLength: 30,
        maxMaxBufferLength: 60,
        enableAdaptiveBitrate: true
    });

    // Auto-hide controls
    const handleMouseMove = useCallback(() => {
        setShowControls(true);

        if (hideControlsTimeoutRef.current) {
            clearTimeout(hideControlsTimeoutRef.current);
        }

        if (state.isPlaying) {
            hideControlsTimeoutRef.current = setTimeout(() => {
                setShowControls(false);
            }, 3000);
        }
    }, [state.isPlaying]);

    // Keyboard shortcuts
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            if (e.target instanceof HTMLInputElement) return;

            switch (e.key) {
                case ' ':
                case 'k':
                    e.preventDefault();
                    controls.toggle();
                    break;
                case 'ArrowLeft':
                    e.preventDefault();
                    controls.seekRelative(-10);
                    break;
                case 'ArrowRight':
                    e.preventDefault();
                    controls.seekRelative(10);
                    break;
                case 'ArrowUp':
                    e.preventDefault();
                    controls.setVolume(state.volume + 0.1);
                    break;
                case 'ArrowDown':
                    e.preventDefault();
                    controls.setVolume(state.volume - 0.1);
                    break;
                case 'm':
                    controls.toggleMute();
                    break;
                case 'f':
                    controls.toggleFullscreen();
                    break;
                case '0':
                case '1':
                case '2':
                case '3':
                case '4':
                case '5':
                case '6':
                case '7':
                case '8':
                case '9':
                    const percent = parseInt(e.key) * 10;
                    controls.seek((state.duration * percent) / 100);
                    break;
                case '<':
                    controls.setPlaybackRate(Math.max(0.25, state.playbackRate - 0.25));
                    break;
                case '>':
                    controls.setPlaybackRate(Math.min(2, state.playbackRate + 0.25));
                    break;
            }
        };

        document.addEventListener('keydown', handleKeyDown);
        return () => document.removeEventListener('keydown', handleKeyDown);
    }, [controls, state.volume, state.duration, state.playbackRate]);
