    // Handle video end
    useEffect(() => {
        if (!state.isPlaying && state.currentTime >= state.duration && state.duration > 0) {
            onEnded?.();
        }
    }, [state.isPlaying, state.currentTime, state.duration, onEnded]);

    // Format time
    const formatTime = (seconds: number): string => {
        const h = Math.floor(seconds / 3600);
        const m = Math.floor((seconds % 3600) / 60);
        const s = Math.floor(seconds % 60);

        if (h > 0) {
            return `${h}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
        }
        return `${m}:${s.toString().padStart(2, '0')}`;
    };

    // Calculate buffer percentage
    const getBufferPercent = (): number => {
        if (!state.buffered || state.buffered.length === 0) return 0;

        const bufferedEnd = state.buffered.end(state.buffered.length - 1);
        return (bufferedEnd / state.duration) * 100;
    };

    return (
        <div
            ref={containerRef}
            className={`video-player ${state.isFullscreen ? 'fullscreen' : ''}`}
            onMouseMove={handleMouseMove}
            onMouseLeave={() => state.isPlaying && setShowControls(false)}
        >
            <video
                ref={videoRef}
                poster={poster}
                playsInline
                onClick={controls.toggle}
                className="video-element"
            />

            {/* Loading spinner */}
            {state.isBuffering && (
                <div className="video-loading">
                    <div className="spinner" />
                </div>
            )}

            {/* Error display */}
            {state.error && (
                <div className="video-error">
                    <span>⚠️ {state.error.message}</span>
                    <button onClick={() => window.location.reload()}>
                        Retry
                    </button>
                </div>
            )}

            {/* Controls overlay */}
            <div className={`video-controls ${showControls ? 'visible' : 'hidden'}`}>
                {/* Progress bar */}
                <div className="progress-container">
                    <div className="progress-bar">
                        <div
                            className="progress-buffer"
                            style={{ width: `${getBufferPercent()}%` }}
                        />
                        <div
                            className="progress-current"
                            style={{ width: `${(state.currentTime / state.duration) * 100}%` }}
                        />
                        <input
                            type="range"
                            min={0}
                            max={state.duration || 0}
                            value={state.currentTime}
                            onChange={(e) => controls.seek(parseFloat(e.target.value))}
                            className="progress-input"
                        />
                    </div>

                    {/* Chapter markers would go here */}
                </div>

                {/* Control buttons */}
                <div className="controls-row">
                    <div className="controls-left">
                        {/* Play/Pause */}
                        <button onClick={controls.toggle} aria-label={state.isPlaying ? 'Pause' : 'Play'}>
                            {state.isPlaying ? <PauseIcon /> : <PlayIcon />}
                        </button>

                        {/* Skip buttons */}
                        <button onClick={() => controls.seekRelative(-10)} aria-label="Rewind 10 seconds">
                            <Rewind10Icon />
                        </button>
                        <button onClick={() => controls.seekRelative(10)} aria-label="Forward 10 seconds">
                            <Forward10Icon />
                        </button>

                        {/* Volume */}
                        <div className="volume-control">
                            <button onClick={controls.toggleMute} aria-label={state.isMuted ? 'Unmute' : 'Mute'}>
                                {state.isMuted || state.volume === 0 ? (
                                    <VolumeOffIcon />
                                ) : state.volume < 0.5 ? (
                                    <VolumeLowIcon />
                                ) : (
                                    <VolumeHighIcon />
                                )}
                            </button>
                            <input
                                type="range"
                                min={0}
                                max={1}
                                step={0.1}
                                value={state.isMuted ? 0 : state.volume}
                                onChange={(e) => controls.setVolume(parseFloat(e.target.value))}
                                className="volume-slider"
                            />
                        </div>

                        {/* Time display */}
                        <span className="time-display">
                            {formatTime(state.currentTime)} / {formatTime(state.duration)}
                        </span>
                    </div>

                    <div className="controls-right">
                        {/* Playback speed */}
                        <PlaybackSpeedMenu
                            currentSpeed={state.playbackRate}
                            onSpeedChange={controls.setPlaybackRate}
                        />

                        {/* Quality selector */}
                        <QualityMenu
                            qualities={source.qualities}
                            currentQuality={state.currentQuality}
                            onQualityChange={controls.setQuality}
                        />

                        {/* Subtitles */}
                        <SubtitlesMenu videoId={videoId} />

                        {/* Picture-in-Picture */}
                        <button
                            onClick={controls.requestPictureInPicture}
                            aria-label="Picture in picture"
                        >
                            <PipIcon />
                        </button>

                        {/* Fullscreen */}
                        <button onClick={controls.toggleFullscreen} aria-label="Fullscreen">
                            {state.isFullscreen ? <ExitFullscreenIcon /> : <FullscreenIcon />}
                        </button>
                    </div>
                </div>
            </div>

            {/* Title overlay (visible when paused) */}
            {state.isPaused && (
                <div className="video-title-overlay">
                    <h1>{title}</h1>
                </div>
            )}
        </div>
    );
}
