function useVideoUpload() {
    const [uploads, setUploads] = useState<Map<string, VideoUpload>>(new Map());

    const uploadVideo = useCallback(async (file: File, metadata: VideoMetadata) => {
        const uploadId = crypto.randomUUID();

        // Initialize upload
        setUploads(prev => new Map(prev).set(uploadId, {
            id: uploadId,
            file,
            status: 'pending',
            progress: { uploaded: 0, total: file.size, percentage: 0, speed: 0, remainingTime: 0 }
        }));

        try {
            // 1. Request upload URL from server
            const { uploadUrl, videoId } = await fetch('/api/videos/upload-url', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    filename: file.name,
                    filesize: file.size,
                    contentType: file.type,
                    ...metadata
                })
            }).then(res => res.json());

            // 2. Upload file in chunks
            const CHUNK_SIZE = 5 * 1024 * 1024; // 5MB chunks
            const totalChunks = Math.ceil(file.size / CHUNK_SIZE);
            let uploadedBytes = 0;
            let startTime = Date.now();

            setUploads(prev => {
                const updated = new Map(prev);
                const upload = updated.get(uploadId)!;
                updated.set(uploadId, { ...upload, status: 'uploading', videoId });
                return updated;
            });

            for (let chunkIndex = 0; chunkIndex < totalChunks; chunkIndex++) {
                const start = chunkIndex * CHUNK_SIZE;
                const end = Math.min(start + CHUNK_SIZE, file.size);
                const chunk = file.slice(start, end);

                await uploadChunk(uploadUrl, chunk, chunkIndex, totalChunks);

                uploadedBytes += chunk.size;
                const elapsed = (Date.now() - startTime) / 1000;
                const speed = uploadedBytes / elapsed;
                const remaining = (file.size - uploadedBytes) / speed;

                setUploads(prev => {
                    const updated = new Map(prev);
                    const upload = updated.get(uploadId)!;
                    updated.set(uploadId, {
                        ...upload,
                        progress: {
                            uploaded: uploadedBytes,
                            total: file.size,
                            percentage: (uploadedBytes / file.size) * 100,
                            speed,
                            remainingTime: remaining
                        }
                    });
                    return updated;
                });
            }

            // 3. Finalize upload and start processing
            await fetch(`/api/videos/${videoId}/finalize`, {
                method: 'POST'
            });

            setUploads(prev => {
                const updated = new Map(prev);
                const upload = updated.get(uploadId)!;
                updated.set(uploadId, { ...upload, status: 'processing' });
                return updated;
            });

            // 4. Poll for processing status
            await pollProcessingStatus(videoId, (status) => {
                if (status === 'complete') {
                    setUploads(prev => {
                        const updated = new Map(prev);
                        const upload = updated.get(uploadId)!;
                        updated.set(uploadId, { ...upload, status: 'complete' });
                        return updated;
                    });
                }
            });

            return videoId;

        } catch (error) {
            setUploads(prev => {
                const updated = new Map(prev);
                const upload = updated.get(uploadId)!;
                updated.set(uploadId, {
                    ...upload,
                    status: 'error',
                    error: (error as Error).message
                });
                return updated;
            });
            throw error;
        }
    }, []);

    const cancelUpload = useCallback((uploadId: string) => {
        // Cancel ongoing upload
        setUploads(prev => {
            const updated = new Map(prev);
            updated.delete(uploadId);
            return updated;
        });
    }, []);

    return { uploads, uploadVideo, cancelUpload };
}

async function uploadChunk(
    uploadUrl: string,
    chunk: Blob,
    chunkIndex: number,
    totalChunks: number
): Promise<void> {
    const response = await fetch(uploadUrl, {
        method: 'PUT',
        headers: {
            'Content-Type': 'application/octet-stream',
            'X-Chunk-Index': chunkIndex.toString(),
            'X-Total-Chunks': totalChunks.toString()
        },
        body: chunk
    });

    if (!response.ok) {
        throw new Error(`Chunk upload failed: ${response.statusText}`);
    }
}

async function pollProcessingStatus(
    videoId: string,
    onStatusChange: (status: string) => void
): Promise<void> {
    return new Promise((resolve, reject) => {
        const poll = async () => {
            try {
                const response = await fetch(`/api/videos/${videoId}/status`);
                const { status, progress } = await response.json();

                onStatusChange(status);

                if (status === 'complete') {
                    resolve();
                } else if (status === 'error') {
                    reject(new Error('Video processing failed'));
                } else {
                    setTimeout(poll, 2000);
                }
            } catch (error) {
                reject(error);
            }
        };

        poll();
    });
}
