interface VideoRecommendation {
    videoId: string;
    title: string;
    thumbnail: string;
    duration: number;
    views: number;
    uploadedAt: Date;
    channel: {
        id: string;
        name: string;
        avatar: string;
    };
    score: number;
    reason: 'watch_history' | 'similar' | 'trending' | 'subscribed' | 'popular';
}

function useRecommendations(currentVideoId: string) {
    const [recommendations, setRecommendations] = useState<VideoRecommendation[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        let cancelled = false;

        async function fetchRecommendations() {
            setIsLoading(true);

            try {
                // Fetch from multiple sources in parallel
                const [similar, trending, personalized] = await Promise.all([
                    fetch(`/api/videos/${currentVideoId}/similar`).then(r => r.json()),
                    fetch('/api/videos/trending').then(r => r.json()),
                    fetch('/api/recommendations/personalized').then(r => r.json())
                ]);

                if (cancelled) return;

                // Merge and deduplicate
                const allRecommendations = [
                    ...similar.map((v: any) => ({ ...v, reason: 'similar' })),
                    ...personalized.map((v: any) => ({ ...v, reason: 'watch_history' })),
                    ...trending.map((v: any) => ({ ...v, reason: 'trending' }))
                ];

                // Remove duplicates and current video
                const unique = allRecommendations.reduce((acc, video) => {
                    if (video.videoId !== currentVideoId && !acc.find(v => v.videoId === video.videoId)) {
                        acc.push(video);
                    }
                    return acc;
                }, [] as VideoRecommendation[]);

                // Sort by score
                unique.sort((a, b) => b.score - a.score);

                setRecommendations(unique.slice(0, 20));
            } catch (error) {
                console.error('Failed to fetch recommendations:', error);
            } finally {
                if (!cancelled) {
                    setIsLoading(false);
                }
            }
        }

        fetchRecommendations();

        return () => {
            cancelled = true;
        };
    }, [currentVideoId]);

    return { recommendations, isLoading };
}

