interface LiveStream {
    streamId: string;
    streamKey: string;
    rtmpUrl: string;
    playbackUrl: string;
    status: 'idle' | 'connecting' | 'live' | 'ended';
    viewerCount: number;
    startedAt?: Date;
}

function useLiveStream(streamId: string) {
    const [stream, setStream] = useState<LiveStream | null>(null);
    const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
    const socketRef = useRef<WebSocket | null>(null);

    useEffect(() => {
        // Connect to WebSocket for real-time updates
        const socket = new WebSocket(`wss://live.example.com/ws/${streamId}`);

        socket.onopen = () => {
            socket.send(JSON.stringify({ type: 'join', streamId }));
        };

        socket.onmessage = (event) => {
            const message = JSON.parse(event.data);

            switch (message.type) {
                case 'stream_update':
                    setStream(prev => ({ ...prev, ...message.data }));
                    break;
                case 'viewer_count':
                    setStream(prev => prev ? { ...prev, viewerCount: message.count } : null);
                    break;
                case 'chat_message':
                    setChatMessages(prev => [...prev, message.data].slice(-100));
                    break;
                case 'stream_ended':
                    setStream(prev => prev ? { ...prev, status: 'ended' } : null);
                    break;
            }
        };

        socketRef.current = socket;

        return () => {
            socket.close();
        };
    }, [streamId]);

    const sendChatMessage = useCallback((text: string) => {
        socketRef.current?.send(JSON.stringify({
            type: 'chat_message',
            text
        }));
    }, []);

    return { stream, chatMessages, sendChatMessage };
}

function LiveStreamPlayer({ streamId }: { streamId: string }) {
    const { stream, chatMessages, sendChatMessage } = useLiveStream(streamId);
    const videoRef = useRef<HTMLVideoElement>(null);

    // Initialize low-latency HLS player
    useEffect(() => {
        if (!stream?.playbackUrl || !videoRef.current) return;

        const hls = new Hls({
            lowLatencyMode: true,
            liveSyncDuration: 3,
            liveMaxLatencyDuration: 10,
            liveDurationInfinity: true,
            highBufferWatchdogPeriod: 1
        });

        hls.loadSource(stream.playbackUrl);
        hls.attachMedia(videoRef.current);

        return () => hls.destroy();
    }, [stream?.playbackUrl]);

    if (!stream) {
        return <div className="stream-loading">Loading stream...</div>;
    }

    if (stream.status === 'ended') {
        return <div className="stream-ended">Stream has ended</div>;
    }

    return (
        <div className="live-stream-container">
            <div className="stream-player">
                <video ref={videoRef} autoPlay muted playsInline />

                <div className="stream-overlay">
                    <div className="live-badge">
                        <span className="live-dot" />
                        LIVE
                    </div>
                    <div className="viewer-count">
                        👁 {formatNumber(stream.viewerCount)} watching
                    </div>
                </div>
            </div>

            <div className="stream-chat">
                <div className="chat-messages">
                    {chatMessages.map((msg, index) => (
                        <div key={index} className="chat-message">
                            <span className="chat-author">{msg.author}</span>
                            <span className="chat-text">{msg.text}</span>
                        </div>
                    ))}
                </div>

                <ChatInput onSend={sendChatMessage} />
            </div>
        </div>
    );
}
