### **Video Analytics and Watch History**

```
// ═══════════════════════════════════════════════════════════
// VIDEO ANALYTICS TRACKER
// ═══════════════════════════════════════════════════════════

interface WatchSession {
    sessionId: string;
    videoId: string;
    userId?: string;
    startTime: number;
    watchDuration: number;
    totalDuration: number;
    completionRate: number;
    qualityChanges: { time: number; quality: string }[];
    bufferingEvents: { time: number; duration: number }[];
    seekEvents: { time: number; from: number; to: number }[];
    pauseEvents: { time: number; duration: number }[];
}

class VideoAnalytics {
    private session: WatchSession;
    private lastUpdateTime: number = 0;
    private pauseStartTime: number | null = null;
    private bufferStartTime: number | null = null;
    private flushInterval: NodeJS.Timeout | null = null;

    constructor(videoId: string, totalDuration: number, userId?: string) {
        this.session = {
            sessionId: crypto.randomUUID(),
            videoId,
            userId,
            startTime: Date.now(),
            watchDuration: 0,
            totalDuration,
            completionRate: 0,
            qualityChanges: [],
            bufferingEvents: [],
            seekEvents: [],
            pauseEvents: []
        };

        // Flush analytics every 30 seconds
        this.flushInterval = setInterval(() => this.flush(), 30000);
    }

    trackProgress(currentTime: number) {
        const now = Date.now();
        if (this.lastUpdateTime > 0) {
            const timeDelta = (now - this.lastUpdateTime) / 1000;
            // Only count if reasonable (< 2 seconds between updates)
            if (timeDelta < 2) {
                this.session.watchDuration += timeDelta;
            }
        }
        this.lastUpdateTime = now;
        this.session.completionRate = currentTime / this.session.totalDuration;
    }

    trackPlay() {
        if (this.pauseStartTime !== null) {
            const pauseDuration = Date.now() - this.pauseStartTime;
            this.session.pauseEvents.push({
                time: this.pauseStartTime,
                duration: pauseDuration
            });
            this.pauseStartTime = null;
        }
    }

    trackPause() {
        this.pauseStartTime = Date.now();
    }

    trackBuffering() {
        this.bufferStartTime = Date.now();
    }

    trackBufferingEnd() {
        if (this.bufferStartTime !== null) {
            const bufferDuration = Date.now() - this.bufferStartTime;
            this.session.bufferingEvents.push({
                time: this.bufferStartTime,
                duration: bufferDuration
            });
            this.bufferStartTime = null;
        }
    }

    trackSeek(toTime: number) {
        this.session.seekEvents.push({
            time: Date.now(),
            from: this.lastUpdateTime,
            to: toTime
        });
    }

    trackQualityChange(quality: VideoQuality) {
        this.session.qualityChanges.push({
            time: Date.now(),
            quality: quality.label
        });
    }

    trackComplete() {
        this.session.completionRate = 1;
        this.flush();
    }

    trackError(error: MediaError | null) {
        // Send error event immediately
        this.sendEvent('error', {
            code: error?.code,
            message: error?.message
        });
    }

    private async flush() {
        try {
            await fetch('/api/analytics/watch-session', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(this.session),
                keepalive: true
            });
        } catch (error) {
            console.error('Failed to flush analytics:', error);
        }
    }

    private sendEvent(eventType: string, data: any) {
        navigator.sendBeacon('/api/analytics/event', JSON.stringify({
            sessionId: this.session.sessionId,
            videoId: this.session.videoId,
            eventType,
            data,
            timestamp: Date.now()
        }));
    }

    destroy() {
        if (this.flushInterval) {
            clearInterval(this.flushInterval);
        }
        this.flush();
    }
}

// ═══════════════════════════════════════════════════════════
// WATCH HISTORY MANAGEMENT
// ═══════════════════════════════════════════════════════════

interface WatchHistoryEntry {
    videoId: string;
    watchedAt: Date;
    progress: number;
    duration: number;
    completed: boolean;
}

function useWatchHistory() {
    const [history, setHistory] = useState<WatchHistoryEntry[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    // Load history on mount
    useEffect(() => {
        loadHistory();
    }, []);

    const loadHistory = async () => {
        try {
            const response = await fetch('/api/user/watch-history');
            const data = await response.json();
            setHistory(data);
        } catch (error) {
            console.error('Failed to load watch history:', error);
        } finally {
            setIsLoading(false);
        }
    };

    const updateProgress = useCallback(async (
        videoId: string,
        progress: number,
        duration: number
    ) => {
        // Update locally
        setHistory(prev => {
            const existing = prev.findIndex(h => h.videoId === videoId);
            const entry: WatchHistoryEntry = {
                videoId,
                watchedAt: new Date(),
                progress,
                duration,
                completed: progress >= duration * 0.9
            };

            if (existing >= 0) {
                const updated = [...prev];
                updated[existing] = entry;
                return updated;
            }
            return [entry, ...prev];
        });

        // Sync to server (debounced)
        debouncedSyncProgress(videoId, progress, duration);
    }, []);

    const removeFromHistory = useCallback(async (videoId: string) => {
        setHistory(prev => prev.filter(h => h.videoId !== videoId));

        await fetch(`/api/user/watch-history/${videoId}`, {
            method: 'DELETE'
        });
    }, []);

    const clearHistory = useCallback(async () => {
        setHistory([]);
        await fetch('/api/user/watch-history', { method: 'DELETE' });
    }, []);

    const getProgress = useCallback((videoId: string): number => {
        const entry = history.find(h => h.videoId === videoId);
        return entry?.progress || 0;
    }, [history]);

    return {
        history,
        isLoading,
        updateProgress,
        removeFromHistory,
        clearHistory,
        getProgress
    };
}

const debouncedSyncProgress = debounce(
    async (videoId: string, progress: number, duration: number) => {
        await fetch('/api/user/watch-history', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ videoId, progress, duration })
        });
    },
    5000
);
