### **CRDT-Based Real-Time Editing**

```
// ═══════════════════════════════════════════════════════════
// CRDT (Conflict-free Replicated Data Type) IMPLEMENTATION
// ═══════════════════════════════════════════════════════════

/*
CRDTs allow concurrent edits without conflicts by ensuring that:
1. All operations are commutative (order doesn't matter)
2. All replicas eventually converge to the same state
3. No central coordination is needed

We'll use a sequence CRDT (like RGA or YATA) for text editing
*/

interface CRDTCharacter {
    id: string;              // Unique identifier
    value: string;           // The character
    isDeleted: boolean;      // Tombstone for deletions
    lamportTimestamp: number;
    siteId: string;          // Which client created this
    leftOrigin: string | null;   // ID of character to the left when inserted
    rightOrigin: string | null;  // ID of character to the right when inserted
    formatting?: TextFormatting;
}

interface TextFormatting {
    bold?: boolean;
    italic?: boolean;
    underline?: boolean;
    strikethrough?: boolean;
    fontSize?: number;
    fontFamily?: string;
    color?: string;
    backgroundColor?: string;
    link?: string;
}

interface CRDTOperation {
    type: 'insert' | 'delete' | 'format';
    characterId: string;
    character?: CRDTCharacter;
    formatting?: Partial<TextFormatting>;
    lamportTimestamp: number;
    siteId: string;
}

class TextCRDT {
    private characters: Map<string, CRDTCharacter> = new Map();
    private lamportClock: number = 0;
    private siteId: string;
    private orderedIds: string[] = [];

    constructor(siteId: string) {
        this.siteId = siteId;

        // Initialize with start and end markers
        const startMarker: CRDTCharacter = {
            id: 'START',
            value: '',
            isDeleted: false,
            lamportTimestamp: 0,
            siteId: 'SYSTEM',
            leftOrigin: null,
            rightOrigin: 'END'
        };

        const endMarker: CRDTCharacter = {
            id: 'END',
            value: '',
            isDeleted: false,
            lamportTimestamp: 0,
            siteId: 'SYSTEM',
            leftOrigin: 'START',
            rightOrigin: null
        };

        this.characters.set('START', startMarker);
        this.characters.set('END', endMarker);
        this.orderedIds = ['START', 'END'];
    }

    // Insert a character at the given position
    insert(position: number, value: string, formatting?: TextFormatting): CRDTOperation {
        this.lamportClock++;

        const leftId = this.orderedIds[position] || 'START';
        const rightId = this.orderedIds[position + 1] || 'END';

        const char: CRDTCharacter = {
            id: `${this.siteId}-${this.lamportClock}`,
            value,
            isDeleted: false,
            lamportTimestamp: this.lamportClock,
            siteId: this.siteId,
            leftOrigin: leftId,
            rightOrigin: rightId,
            formatting
        };

        this.integrateInsert(char);

        return {
            type: 'insert',
            characterId: char.id,
            character: char,
            lamportTimestamp: this.lamportClock,
            siteId: this.siteId
        };
    }

    // Delete a character at the given position
    delete(position: number): CRDTOperation | null {
        const charId = this.getVisibleCharacterIdAtPosition(position);
        if (!charId) return null;

        const char = this.characters.get(charId);
        if (!char) return null;

        this.lamportClock++;
        char.isDeleted = true;

        return {
            type: 'delete',
            characterId: charId,
            lamportTimestamp: this.lamportClock,
            siteId: this.siteId
        };
    }

    // Apply formatting to a range
    format(
        startPosition: number,
        endPosition: number,
        formatting: Partial<TextFormatting>
    ): CRDTOperation[] {
        const operations: CRDTOperation[] = [];

        for (let i = startPosition; i < endPosition; i++) {
            const charId = this.getVisibleCharacterIdAtPosition(i);
            if (!charId) continue;

            const char = this.characters.get(charId);
            if (!char) continue;

            this.lamportClock++;
            char.formatting = { ...char.formatting, ...formatting };

            operations.push({
                type: 'format',
                characterId: charId,
                formatting,
                lamportTimestamp: this.lamportClock,
                siteId: this.siteId
            });
        }

        return operations;
    }

    // Apply a remote operation
    applyOperation(operation: CRDTOperation) {
        this.lamportClock = Math.max(this.lamportClock, operation.lamportTimestamp) + 1;

        switch (operation.type) {
            case 'insert':
                if (operation.character) {
                    this.integrateInsert(operation.character);
                }
                break;

            case 'delete':
                const char = this.characters.get(operation.characterId);
                if (char) {
                    char.isDeleted = true;
                }
                break;

            case 'format':
                const formatChar = this.characters.get(operation.characterId);
                if (formatChar && operation.formatting) {
                    formatChar.formatting = { ...formatChar.formatting, ...operation.formatting };
                }
                break;
        }
    }

    // Integrate a new character into the correct position
    private integrateInsert(char: CRDTCharacter) {
        this.characters.set(char.id, char);

        // Find the correct position using origins
        let leftIndex = this.orderedIds.indexOf(char.leftOrigin || 'START');
        let rightIndex = this.orderedIds.indexOf(char.rightOrigin || 'END');

        // Handle conflicts - characters with same origins
        let insertIndex = leftIndex + 1;

        while (insertIndex < rightIndex) {
            const existingChar = this.characters.get(this.orderedIds[insertIndex]);
            if (!existingChar) break;

            // Use lamport timestamp and site ID for deterministic ordering
            if (this.shouldInsertBefore(char, existingChar)) {
                break;
            }
            insertIndex++;
        }

        this.orderedIds.splice(insertIndex, 0, char.id);
    }

    private shouldInsertBefore(newChar: CRDTCharacter, existingChar: CRDTCharacter): boolean {
        // First compare by lamport timestamp
        if (newChar.lamportTimestamp !== existingChar.lamportTimestamp) {
            return newChar.lamportTimestamp < existingChar.lamportTimestamp;
        }
        // Break ties by site ID (lexicographic)
        return newChar.siteId < existingChar.siteId;
    }

    private getVisibleCharacterIdAtPosition(position: number): string | null {
        let visibleCount = -1; // Start at -1 to account for START marker

        for (const id of this.orderedIds) {
            const char = this.characters.get(id);
            if (char && !char.isDeleted && id !== 'START' && id !== 'END') {
                visibleCount++;
                if (visibleCount === position) {
                    return id;
                }
            }
        }

        return null;
    }

    // Convert CRDT to plain text
    toString(): string {
        let result = '';

        for (const id of this.orderedIds) {
            const char = this.characters.get(id);
            if (char && !char.isDeleted && id !== 'START' && id !== 'END') {
                result += char.value;
            }
        }

        return result;
    }

    // Get document with formatting
    toFormattedSegments(): Array<{ text: string; formatting?: TextFormatting }> {
        const segments: Array<{ text: string; formatting?: TextFormatting }> = [];
        let currentSegment: { text: string; formatting?: TextFormatting } | null = null;

        for (const id of this.orderedIds) {
            const char = this.characters.get(id);
            if (!char || char.isDeleted || id === 'START' || id === 'END') continue;

            const formatting = char.formatting;

            if (currentSegment && this.formattingEquals(currentSegment.formatting, formatting)) {
                currentSegment.text += char.value;
            } else {
                if (currentSegment) {
                    segments.push(currentSegment);
                }
                currentSegment = { text: char.value, formatting };
            }
        }

        if (currentSegment) {
            segments.push(currentSegment);
        }

        return segments;
    }

    private formattingEquals(a?: TextFormatting, b?: TextFormatting): boolean {
        if (!a && !b) return true;
        if (!a || !b) return false;
        return JSON.stringify(a) === JSON.stringify(b);
    }

    // Get the current state for persistence
    getState(): { characters: CRDTCharacter[]; orderedIds: string[] } {
        return {
            characters: Array.from(this.characters.values()),
            orderedIds: this.orderedIds
        };
    }

    // Load state from persistence
    loadState(state: { characters: CRDTCharacter[]; orderedIds: string[] }) {
        this.characters.clear();
        state.characters.forEach(char => this.characters.set(char.id, char));
        this.orderedIds = state.orderedIds;
    }
}
