// ═══════════════════════════════════════════════════════════
// DOCUMENT EDITOR HOOK
// ═══════════════════════════════════════════════════════════

interface EditorState {
    content: string;
    segments: Array<{ text: string; formatting?: TextFormatting }>;
    selection: { start: number; end: number } | null;
    remoteSelection: Map<string, { userId: string; start: number; end: number; color: string }>;
    users: Map<string, { id: string; name: string; color: string; cursor: number }>;
    isSynced: boolean;
    pendingOperations: CRDTOperation[];
}

function useCollaborativeDocument(documentId: string, userId: string) {
    const crdtRef = useRef<TextCRDT>(new TextCRDT(userId));
    const socketRef = useRef<WebSocket | null>(null);
    const [state, setState] = useState<EditorState>({
        content: '',
        segments: [],
        selection: null,
        remoteSelection: new Map(),
        users: new Map(),
        isSynced: false,
        pendingOperations: []
    });

    // Connect to collaboration server
    useEffect(() => {
        const socket = new WebSocket(`wss://collab.example.com/documents/${documentId}`);

        socket.onopen = () => {
            // Request initial document state
            socket.send(JSON.stringify({
                type: 'join',
                userId,
                documentId
            }));
        };

        socket.onmessage = (event) => {
            const message = JSON.parse(event.data);
            handleServerMessage(message);
        };

        socket.onclose = () => {
            setState(prev => ({ ...prev, isSynced: false }));
            // Attempt reconnection
            setTimeout(() => {
                // Reconnection logic
            }, 1000);
        };

        socketRef.current = socket;

        return () => {
            socket.close();
        };
    }, [documentId, userId]);

    const handleServerMessage = useCallback((message: any) => {
        switch (message.type) {
            case 'initial_state':
                // Load document state
                crdtRef.current.loadState(message.state);
                setState(prev => ({
                    ...prev,
                    content: crdtRef.current.toString(),
                    segments: crdtRef.current.toFormattedSegments(),
                    isSynced: true
                }));
                break;

            case 'operation':
                // Apply remote operation
                crdtRef.current.applyOperation(message.operation);
                setState(prev => ({
                    ...prev,
                    content: crdtRef.current.toString(),
                    segments: crdtRef.current.toFormattedSegments()
                }));
                break;

            case 'presence':
                // Update user presence
                setState(prev => {
                    const users = new Map(prev.users);
                    users.set(message.userId, {
                        id: message.userId,
                        name: message.userName,
                        color: message.color,
                        cursor: message.cursor
                    });

                    const remoteSelection = new Map(prev.remoteSelection);
                    if (message.selection) {
                        remoteSelection.set(message.userId, {
                            userId: message.userId,
                            ...message.selection,
                            color: message.color
                        });
                    } else {
                        remoteSelection.delete(message.userId);
                    }

                    return { ...prev, users, remoteSelection };
                });
                break;

            case 'user_left':
                setState(prev => {
                    const users = new Map(prev.users);
                    users.delete(message.userId);
                    const remoteSelection = new Map(prev.remoteSelection);
                    remoteSelection.delete(message.userId);
                    return { ...prev, users, remoteSelection };
                });
                break;

            case 'ack':
                // Remove acknowledged operation from pending
                setState(prev => ({
                    ...prev,
                    pendingOperations: prev.pendingOperations.filter(
                        op => op.lamportTimestamp !== message.timestamp
                    )
                }));
                break;
        }
    }, []);

    // Local operations
    const insertText = useCallback((position: number, text: string, formatting?: TextFormatting) => {
        const operations: CRDTOperation[] = [];

        for (let i = 0; i < text.length; i++) {
            const op = crdtRef.current.insert(position + i, text[i], formatting);
            operations.push(op);
        }

        // Update local state immediately
        setState(prev => ({
            ...prev,
            content: crdtRef.current.toString(),
            segments: crdtRef.current.toFormattedSegments(),
            pendingOperations: [...prev.pendingOperations, ...operations]
        }));

        // Send to server
        operations.forEach(op => {
            socketRef.current?.send(JSON.stringify({
                type: 'operation',
                operation: op
            }));
        });
    }, []);

    const deleteText = useCallback((startPosition: number, endPosition: number) => {
        const operations: CRDTOperation[] = [];

        // Delete in reverse order to maintain positions
        for (let i = endPosition - 1; i >= startPosition; i--) {
            const op = crdtRef.current.delete(i);
            if (op) operations.push(op);
        }

        setState(prev => ({
            ...prev,
            content: crdtRef.current.toString(),
            segments: crdtRef.current.toFormattedSegments(),
            pendingOperations: [...prev.pendingOperations, ...operations]
        }));

        operations.forEach(op => {
            socketRef.current?.send(JSON.stringify({
                type: 'operation',
                operation: op
            }));
        });
    }, []);

    const formatText = useCallback((
        startPosition: number,
        endPosition: number,
        formatting: Partial<TextFormatting>
    ) => {
        const operations = crdtRef.current.format(startPosition, endPosition, formatting);

        setState(prev => ({
            ...prev,
            segments: crdtRef.current.toFormattedSegments(),
            pendingOperations: [...prev.pendingOperations, ...operations]
        }));

        operations.forEach(op => {
            socketRef.current?.send(JSON.stringify({
                type: 'operation',
                operation: op
            }));
        });
    }, []);

    const updateSelection = useCallback((selection: { start: number; end: number } | null) => {
        setState(prev => ({ ...prev, selection }));

        socketRef.current?.send(JSON.stringify({
            type: 'presence',
            userId,
            cursor: selection?.end ?? 0,
            selection
        }));
    }, [userId]);

    return {
        state,
        insertText,
        deleteText,
        formatText,
        updateSelection
    };
}
