// RICH TEXT EDITOR COMPONENT
// ═══════════════════════════════════════════════════════════

interface RichTextEditorProps {
    documentId: string;
    userId: string;
    userName: string;
}

function RichTextEditor({ documentId, userId, userName }: RichTextEditorProps) {
    const editorRef = useRef<HTMLDivElement>(null);
    const {
        state,
        insertText,
        deleteText,
        formatText,
        updateSelection
    } = useCollaborativeDocument(documentId, userId);

    // Handle text input
    const handleInput = useCallback((e: React.FormEvent<HTMLDivElement>) => {
        e.preventDefault();

        const selection = window.getSelection();
        if (!selection || selection.rangeCount === 0) return;

        const range = selection.getRangeAt(0);
        const position = getCaretPosition(editorRef.current!, range);

        // Get the input text
        const inputEvent = e.nativeEvent as InputEvent;

        if (inputEvent.inputType === 'insertText' && inputEvent.data) {
            insertText(position, inputEvent.data);
        } else if (inputEvent.inputType === 'deleteContentBackward') {
            if (state.selection && state.selection.start !== state.selection.end) {
                deleteText(state.selection.start, state.selection.end);
            } else if (position > 0) {
                deleteText(position - 1, position);
            }
        } else if (inputEvent.inputType === 'deleteContentForward') {
            if (state.selection && state.selection.start !== state.selection.end) {
                deleteText(state.selection.start, state.selection.end);
            } else {
                deleteText(position, position + 1);
            }
        }
    }, [insertText, deleteText, state.selection]);

    // Handle selection changes
    useEffect(() => {
        const handleSelectionChange = () => {
            const selection = window.getSelection();
            if (!selection || selection.rangeCount === 0) return;

            if (!editorRef.current?.contains(selection.anchorNode)) return;

            const range = selection.getRangeAt(0);
            const start = getCaretPosition(editorRef.current!, range.startContainer, range.startOffset);
            const end = getCaretPosition(editorRef.current!, range.endContainer, range.endOffset);

            updateSelection({ start, end });
        };

        document.addEventListener('selectionchange', handleSelectionChange);
        return () => document.removeEventListener('selectionchange', handleSelectionChange);
    }, [updateSelection]);

    // Handle keyboard shortcuts for formatting
    const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
        if (!state.selection) return;

        if (e.metaKey || e.ctrlKey) {
            switch (e.key) {
                case 'b':
                    e.preventDefault();
                    formatText(state.selection.start, state.selection.end, { bold: true });
                    break;
                case 'i':
                    e.preventDefault();
                    formatText(state.selection.start, state.selection.end, { italic: true });
                    break;
                case 'u':
                    e.preventDefault();
                    formatText(state.selection.start, state.selection.end, { underline: true });
                    break;
            }
        }
    }, [formatText, state.selection]);

    // Handle paste
    const handlePaste = useCallback((e: React.ClipboardEvent) => {
        e.preventDefault();

        const text = e.clipboardData.getData('text/plain');
        if (!text || !state.selection) return;

        // Delete selected text first
        if (state.selection.start !== state.selection.end) {
            deleteText(state.selection.start, state.selection.end);
        }

        insertText(state.selection.start, text);
    }, [insertText, deleteText, state.selection]);

    // Render formatted content
    const renderContent = useMemo(() => {
        return state.segments.map((segment, index) => {
            const style: React.CSSProperties = {};

            if (segment.formatting) {
                if (segment.formatting.bold) style.fontWeight = 'bold';
                if (segment.formatting.italic) style.fontStyle = 'italic';
                if (segment.formatting.underline) style.textDecoration = 'underline';
                if (segment.formatting.strikethrough) {
                    style.textDecoration = (style.textDecoration || '') + ' line-through';
                }
                if (segment.formatting.fontSize) style.fontSize = segment.formatting.fontSize;
                if (segment.formatting.fontFamily) style.fontFamily = segment.formatting.fontFamily;
                if (segment.formatting.color) style.color = segment.formatting.color;
                if (segment.formatting.backgroundColor) {
                    style.backgroundColor = segment.formatting.backgroundColor;
                }
            }

            if (segment.formatting?.link) {
                return (
                    <a key={index} href={segment.formatting.link} style={style}>
                        {segment.text}
                    </a>
                );
            }

            return <span key={index} style={style}>{segment.text}</span>;
        });
    }, [state.segments]);

    // Render remote cursors
    const renderRemoteCursors = useMemo(() => {
        return Array.from(state.users.values())
            .filter(user => user.id !== userId)
            .map(user => {
                const cursorPosition = getCursorPixelPosition(editorRef.current!, user.cursor);

                return (
                    <div
                        key={user.id}
                        className="remote-cursor"
                        style={{
                            position: 'absolute',
                            left: cursorPosition.x,
                            top: cursorPosition.y,
                            borderLeft: `2px solid ${user.color}`,
                            height: '1.2em'
                        }}
                    >
                        <span
                            className="cursor-label"
                            style={{ backgroundColor: user.color }}
                        >
                            {user.name}
                        </span>
                    </div>
                );
            });
    }, [state.users, userId]);

    // Render remote selections
    const renderRemoteSelections = useMemo(() => {
        return Array.from(state.remoteSelection.values()).map(selection => {
            const rects = getSelectionRects(editorRef.current!, selection.start, selection.end);

            return rects.map((rect, index) => (
                <div
                    key={`${selection.userId}-${index}`}
                    className="remote-selection"
                    style={{
                        position: 'absolute',
                        left: rect.left,
                        top: rect.top,
                        width: rect.width,
                        height: rect.height,
                        backgroundColor: selection.color,
                        opacity: 0.3,
                        pointerEvents: 'none'
                    }}
                />
            ));
        });
    }, [state.remoteSelection]);

    return (
        <div className="editor-container">
            {/* Toolbar */}
            <EditorToolbar
                onFormat={formatText}
                selection={state.selection}
            />

            {/* Editor */}
            <div className="editor-wrapper">
                {/* Remote selections layer */}
                <div className="selections-layer">
                    {renderRemoteSelections}
                </div>

                {/* Remote cursors layer */}
                <div className="cursors-layer">
                    {renderRemoteCursors}
                </div>

                {/* Content editable */}
                <div
                    ref={editorRef}
                    className="editor-content"
                    contentEditable
                    suppressContentEditableWarning
                    onInput={handleInput}
                    onKeyDown={handleKeyDown}
                    onPaste={handlePaste}
                    spellCheck
                >
                    {renderContent}
                </div>
            </div>

            {/* Status bar */}
            <div className="editor-status">
                <span className={`sync-status ${state.isSynced ? 'synced' : 'syncing'}`}>
                    {state.isSynced ? '✓ Saved' : '⟳ Saving...'}
                </span>
                <span className="collaborators">
                    {state.users.size} collaborator{state.users.size !== 1 ? 's' : ''}
                </span>
                {state.pendingOperations.length > 0 && (
                    <span className="pending">
                        {state.pendingOperations.length} pending changes
                    </span>
                )}
            </div>
        </div>
    );
}

