// ═══════════════════════════════════════════════════════════
// HELPER FUNCTIONS
// ═══════════════════════════════════════════════════════════

function getCaretPosition(
    container: HTMLElement,
    node: Node,
    offset: number
): number {
    let position = 0;
    const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT);

    while (walker.nextNode()) {
        if (walker.currentNode === node) {
            return position + offset;
        }
        position += (walker.currentNode as Text).length;
    }

    return position;
}

function getCursorPixelPosition(
    container: HTMLElement,
    position: number
): { x: number; y: number } {
    // Create a range at the position
    const range = document.createRange();
    const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT);

    let currentPos = 0;
    while (walker.nextNode()) {
        const textNode = walker.currentNode as Text;
        const length = textNode.length;

        if (currentPos + length >= position) {
            range.setStart(textNode, position - currentPos);
            range.setEnd(textNode, position - currentPos);
            break;
        }
        currentPos += length;
    }

    const rect = range.getBoundingClientRect();
    const containerRect = container.getBoundingClientRect();

    return {
        x: rect.left - containerRect.left,
        y: rect.top - containerRect.top
    };
}

function getSelectionRects(
    container: HTMLElement,
    start: number,
    end: number
): DOMRect[] {
    const range = document.createRange();
    const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT);

    let currentPos = 0;
    let startNode: Text | null = null;
    let startOffset = 0;
    let endNode: Text | null = null;
    let endOffset = 0;

    while (walker.nextNode()) {
        const textNode = walker.currentNode as Text;
        const length = textNode.length;

        if (!startNode && currentPos + length >= start) {
            startNode = textNode;
            startOffset = start - currentPos;
        }

        if (currentPos + length >= end) {
            endNode = textNode;
            endOffset = end - currentPos;
            break;
        }

        currentPos += length;
    }

    if (startNode && endNode) {
        range.setStart(startNode, startOffset);
        range.setEnd(endNode, endOffset);
        return Array.from(range.getClientRects());
    }

    return [];
}
