const useFeedStore = create<FeedStore>()(
    devtools(
        subscribeWithSelector(
            immer((set, get) => ({
                // Initial state
                posts: new Map(),
                feedOrder: [],
                cursor: null,
                hasMore: true,
                isLoading: false,
                isRefreshing: false,
                error: null,
                newPostsCount: 0,
                pendingPosts: [],

                // Fetch feed
                fetchFeed: async (refresh = false) => {
                    const state = get();

                    if (state.isLoading) return;

                    set((draft) => {
                        draft.isLoading = true;
                        draft.isRefreshing = refresh;
                        draft.error = null;
                    });

                    try {
                        const response = await feedApi.getFeed({
                            cursor: refresh ? null : state.cursor,
                            limit: 20
                        });

                        set((draft) => {
                            if (refresh) {
                                draft.posts = new Map();
                                draft.feedOrder = [];
                            }

                            response.posts.forEach((post) => {
                                draft.posts.set(post.id, post);
                                if (!draft.feedOrder.includes(post.id)) {
                                    draft.feedOrder.push(post.id);
                                }
                            });

                            draft.cursor = response.nextCursor;
                            draft.hasMore = response.hasMore;
                            draft.isLoading = false;
                            draft.isRefreshing = false;
                        });
                    } catch (error) {
                        set((draft) => {
                            draft.error = (error as Error).message;
                            draft.isLoading = false;
                            draft.isRefreshing = false;
                        });
                    }
                },

                // Load more posts
                loadMore: async () => {
                    const state = get();
                    if (state.isLoading || !state.hasMore) return;

                    await state.fetchFeed(false);
                },

                // Add new post
                addPost: (post) => {
                    set((draft) => {
                        draft.posts.set(post.id, post);
                        draft.feedOrder.unshift(post.id);
                    });
                },

                // Update post
                updatePost: (postId, updates) => {
                    set((draft) => {
                        const post = draft.posts.get(postId);
                        if (post) {
                            Object.assign(post, updates);
                        }
                    });
                },

                // Remove post
                removePost: (postId) => {
                    set((draft) => {
                        draft.posts.delete(postId);
                        draft.feedOrder = draft.feedOrder.filter(id => id !== postId);
                    });
                },

                // Toggle like with optimistic update
                toggleLike: async (postId) => {
                    const post = get().posts.get(postId);
                    if (!post) return;

                    // Optimistic update
                    get().optimisticLike(postId);

                    try {
                        if (post.isLiked) {
                            await feedApi.unlikePost(postId);
                        } else {
                            await feedApi.likePost(postId);
                        }
                    } catch (error) {
                        // Rollback on error
                        get().rollbackLike(postId);
                    }
                },

                // Optimistic like
                optimisticLike: (postId) => {
                    set((draft) => {
                        const post = draft.posts.get(postId);
                        if (post) {
                            post.isLiked = !post.isLiked;
                            post.likeCount += post.isLiked ? 1 : -1;
                        }
                    });
                },

                // Rollback like
                rollbackLike: (postId) => {
                    set((draft) => {
                        const post = draft.posts.get(postId);
                        if (post) {
                            post.isLiked = !post.isLiked;
                            post.likeCount += post.isLiked ? 1 : -1;
                        }
                    });
                },

                // Toggle bookmark
                toggleBookmark: async (postId) => {
                    const post = get().posts.get(postId);
                    if (!post) return;

                    set((draft) => {
                        const p = draft.posts.get(postId);
                        if (p) p.isBookmarked = !p.isBookmarked;
                    });

                    try {
                        if (post.isBookmarked) {
                            await feedApi.unbookmarkPost(postId);
                        } else {
                            await feedApi.bookmarkPost(postId);
                        }
                    } catch (error) {
                        // Rollback
                        set((draft) => {
                            const p = draft.posts.get(postId);
                            if (p) p.isBookmarked = !p.isBookmarked;
                        });
                    }
                },

                // Repost
                repost: async (postId) => {
                    const post = get().posts.get(postId);
                    if (!post || post.isReposted) return;

                    set((draft) => {
                        const p = draft.posts.get(postId);
                        if (p) {
                            p.isReposted = true;
                            p.shareCount++;
                        }
                    });

                    try {
                        await feedApi.repost(postId);
                    } catch (error) {
                        set((draft) => {
                            const p = draft.posts.get(postId);
                            if (p) {
                                p.isReposted = false;
                                p.shareCount--;
                            }
                        });
                    }
                },

                // Add pending post (real-time)
                addPendingPost: (post) => {
                    set((draft) => {
                        draft.pendingPosts.unshift(post);
                        draft.newPostsCount++;
                    });
                },

                // Show pending posts
                showPendingPosts: () => {
                    set((draft) => {
                        draft.pendingPosts.forEach((post) => {
                            draft.posts.set(post.id, post);
                            draft.feedOrder.unshift(post.id);
                        });
                        draft.pendingPosts = [];
                        draft.newPostsCount = 0;
                    });
                }
            }))
        ),
        { name: 'FeedStore' }
    )
);
