// components/Feed/VirtualizedFeed.tsx
'use client';

import { useRef, useCallback, useEffect, useState } from 'react';
import { useVirtualizer, VirtualItem } from '@tanstack/react-virtual';
import { useFeedStore } from '@/stores/feedStore';
import { PostCard } from './PostCard';
import { FeedSkeleton } from './FeedSkeleton';
import { NewPostsBanner } from './NewPostsBanner';

interface VirtualizedFeedProps {
    onPostClick?: (postId: string) => void;
}

export function VirtualizedFeed({ onPostClick }: VirtualizedFeedProps) {
    const parentRef = useRef<HTMLDivElement>(null);
    const [itemHeights, setItemHeights] = useState<Map<string, number>>(new Map());

    const {
        posts,
        feedOrder,
        isLoading,
        isRefreshing,
        hasMore,
        newPostsCount,
        fetchFeed,
        loadMore,
        showPendingPosts
    } = useFeedStore();

    // Calculate estimated item size
    const estimateSize = useCallback((index: number) => {
        const postId = feedOrder[index];
        return itemHeights.get(postId) || 400; // Default height
    }, [feedOrder, itemHeights]);

    // Virtualizer
    const virtualizer = useVirtualizer({
        count: feedOrder.length,
        getScrollElement: () => parentRef.current,
        estimateSize,
        overscan: 5,
        getItemKey: (index) => feedOrder[index]
    });

    // Measure item heights
    const measureItem = useCallback((postId: string, height: number) => {
        setItemHeights((prev) => {
            if (prev.get(postId) === height) return prev;
            const next = new Map(prev);
            next.set(postId, height);
            return next;
        });
    }, []);

    // Infinite scroll
    const virtualItems = virtualizer.getVirtualItems();

    useEffect(() => {
        const lastItem = virtualItems[virtualItems.length - 1];

        if (
            lastItem &&
            lastItem.index >= feedOrder.length - 5 &&
            hasMore &&
            !isLoading
        ) {
            loadMore();
        }
    }, [virtualItems, feedOrder.length, hasMore, isLoading, loadMore]);

    // Initial fetch
    useEffect(() => {
        fetchFeed(true);
    }, [fetchFeed]);

    // Pull to refresh
    const [pullDistance, setPullDistance] = useState(0);
    const [isPulling, setIsPulling] = useState(false);
    const startY = useRef(0);

    const handleTouchStart = useCallback((e: React.TouchEvent) => {
        if (parentRef.current?.scrollTop === 0) {
            startY.current = e.touches[0].clientY;
            setIsPulling(true);
        }
    }, []);

    const handleTouchMove = useCallback((e: React.TouchEvent) => {
        if (!isPulling) return;

        const currentY = e.touches[0].clientY;
        const distance = Math.max(0, Math.min(100, currentY - startY.current));
        setPullDistance(distance);
    }, [isPulling]);

    const handleTouchEnd = useCallback(() => {
        if (pullDistance > 60) {
            fetchFeed(true);
        }
        setPullDistance(0);
        setIsPulling(false);
    }, [pullDistance, fetchFeed]);

    // Render loading state
    if (isLoading && feedOrder.length === 0) {
        return <FeedSkeleton count={5} />;
    }

    return (
        <div className="feed-container">
            {/* New posts banner */}
            {newPostsCount > 0 && (
                <NewPostsBanner
                    count={newPostsCount}
                    onClick={showPendingPosts}
                />
            )}

            {/* Pull to refresh indicator */}
            {pullDistance > 0 && (
                <div
                    className="pull-indicator"
                    style={{
                        height: pullDistance,
                        opacity: pullDistance / 60
                    }}
                >
                    <div className={`spinner ${pullDistance > 60 ? 'ready' : ''}`} />
                </div>
            )}

            {/* Virtualized list */}
            <div
                ref={parentRef}
                className="feed-scroll-container"
                onTouchStart={handleTouchStart}
                onTouchMove={handleTouchMove}
                onTouchEnd={handleTouchEnd}
            >
                <div
                    style={{
                        height: `${virtualizer.getTotalSize()}px`,
                        width: '100%',
                        position: 'relative'
                    }}
                >
                    {virtualItems.map((virtualItem) => {
                        const postId = feedOrder[virtualItem.index];
                        const post = posts.get(postId);

                        if (!post) return null;

                        return (
                            <div
                                key={virtualItem.key}
                                data-index={virtualItem.index}
                                ref={virtualizer.measureElement}
                                style={{
                                    position: 'absolute',
                                    top: 0,
                                    left: 0,
                                    width: '100%',
                                    transform: `translateY(${virtualItem.start}px)`
                                }}
                            >
                                <PostCard
                                    post={post}
                                    onClick={() => onPostClick?.(postId)}
                                    onHeightChange={(height) => measureItem(postId, height)}
                                />
                            </div>
                        );
                    })}
                </div>

                {/* Loading indicator */}
                {isLoading && feedOrder.length > 0 && (
                    <div className="loading-more">
                        <div className="spinner" />
                    </div>
                )}

                {/* End of feed */}
                {!hasMore && feedOrder.length > 0 && (
                    <div className="end-of-feed">
                        You're all caught up!
                    </div>
                )}
            </div>
        </div>
    );
}
