// components/Feed/PostCard.tsx
'use client';

import { memo, useRef, useEffect, useState, useCallback } from 'react';
import { formatDistanceToNow } from 'date-fns';
import { useFeedStore } from '@/stores/feedStore';
import { PostMedia } from './PostMedia';
import { PostActions } from './PostActions';
import { UserAvatar } from '../User/UserAvatar';
import { RichText } from '../Common/RichText';

interface PostCardProps {
    post: Post;
    onClick?: () => void;
    onHeightChange?: (height: number) => void;
    isDetail?: boolean;
}

export const PostCard = memo(function PostCard({
    post,
    onClick,
    onHeightChange,
    isDetail = false
}: PostCardProps) {
    const cardRef = useRef<HTMLDivElement>(null);
    const [isVisible, setIsVisible] = useState(false);

    // Track visibility for analytics
    useEffect(() => {
        const observer = new IntersectionObserver(
            ([entry]) => {
                if (entry.isIntersecting && !isVisible) {
                    setIsVisible(true);
                    trackPostImpression(post.id);
                }
            },
            { threshold: 0.5 }
        );

        if (cardRef.current) {
            observer.observe(cardRef.current);
        }

        return () => observer.disconnect();
    }, [post.id, isVisible]);

    // Report height changes
    useEffect(() => {
        if (!onHeightChange || !cardRef.current) return;

        const resizeObserver = new ResizeObserver(([entry]) => {
            onHeightChange(entry.contentRect.height);
        });

        resizeObserver.observe(cardRef.current);
        return () => resizeObserver.disconnect();
    }, [onHeightChange]);

    // Engagement handlers
    const { toggleLike, toggleBookmark, repost } = useFeedStore();

    const handleLike = useCallback((e: React.MouseEvent) => {
        e.stopPropagation();
        toggleLike(post.id);
    }, [post.id, toggleLike]);

    const handleBookmark = useCallback((e: React.MouseEvent) => {
        e.stopPropagation();
        toggleBookmark(post.id);
    }, [post.id, toggleBookmark]);

    const handleRepost = useCallback((e: React.MouseEvent) => {
        e.stopPropagation();
        repost(post.id);
    }, [post.id, repost]);

    const handleShare = useCallback(async (e: React.MouseEvent) => {
        e.stopPropagation();

        if (navigator.share) {
            try {
                await navigator.share({
                    title: `Post by ${post.author.displayName}`,
                    text: post.content.slice(0, 100),
                    url: `${window.location.origin}/post/${post.id}`
                });
            } catch (error) {
                // User cancelled or error
            }
        } else {
            // Fallback: copy link
            await navigator.clipboard.writeText(
                `${window.location.origin}/post/${post.id}`
            );
        }
    }, [post]);

    return (
        <article
            ref={cardRef}
            className={`post-card ${isDetail ? 'post-card--detail' : ''}`}
            onClick={onClick}
            role="article"
            aria-labelledby={`post-${post.id}-author`}
        >
            {/* Quoted/Reposted indicator */}
            {post.quotedPost && (
                <div className="post-card__repost-indicator">
                    <svg className="icon" aria-hidden="true">
                        <use href="#icon-repost" />
                    </svg>
                    <span>You reposted</span>
                </div>
            )}

            <div className="post-card__main">
                {/* Author info */}
                <div className="post-card__header">
                    <UserAvatar
                        user={post.author}
                        size={isDetail ? 'large' : 'medium'}
                    />

                    <div className="post-card__author-info">
                        <div className="post-card__author-line">
                            <span
                                id={`post-${post.id}-author`}
                                className="post-card__author-name"
                            >
                                {post.author.displayName}
                            </span>

                            {post.author.isVerified && (
                                <svg
                                    className="verified-badge"
                                    aria-label="Verified account"
                                >
                                    <use href="#icon-verified" />
                                </svg>
                            )}

                            <span className="post-card__author-username">
                                @{post.author.username}
                            </span>

                            <span className="post-card__separator">·</span>

                            <time
                                className="post-card__time"
                                dateTime={post.createdAt}
                                title={new Date(post.createdAt).toLocaleString()}
                            >
                                {formatDistanceToNow(new Date(post.createdAt), {
                                    addSuffix: false
                                })}
                            </time>
                        </div>

                        {post.location && (
                            <span className="post-card__location">
                                📍 {post.location.name}
                            </span>
                        )}
                    </div>

                    <button
                        className="post-card__menu-button"
                        onClick={(e) => e.stopPropagation()}
                        aria-label="Post options"
                    >
                        <svg className="icon">
                            <use href="#icon-more" />
                        </svg>
                    </button>
                </div>

                {/* Post content */}
                <div className="post-card__content">
                    <RichText
                        content={post.content}
                        mentions={post.mentions}
                        hashtags={post.hashtags}
                    />
                </div>

                {/* Media */}
                {post.media.length > 0 && (
                    <PostMedia
                        media={post.media}
                        postId={post.id}
                    />
                )}

                {/* Quoted post */}
                {post.quotedPost && (
                    <div className="post-card__quoted">
                        <PostCard
                            post={post.quotedPost}
                            isDetail={false}
                        />
                    </div>
                )}

                {/* Actions */}
                <PostActions
                    post={post}
                    onLike={handleLike}
                    onComment={() => onClick?.()}
                    onRepost={handleRepost}
                    onShare={handleShare}
                    onBookmark={handleBookmark}
                />
            </div>
        </article>
    );
});

