// components/Feed/PostMedia.tsx
'use client';

import { useState, useRef, useCallback, useEffect } from 'react';
import Image from 'next/image';
import { useInView } from 'react-intersection-observer';

interface PostMediaProps {
    media: MediaItem[];
    postId: string;
}

export function PostMedia({ media, postId }: PostMediaProps) {
    const [selectedIndex, setSelectedIndex] = useState<number | null>(null);
    const [loadedImages, setLoadedImages] = useState<Set<string>>(new Set());

    // Determine grid layout
    const getGridClass = () => {
        switch (media.length) {
            case 1: return 'media-grid--single';
            case 2: return 'media-grid--duo';
            case 3: return 'media-grid--trio';
            default: return 'media-grid--quad';
        }
    };

    const handleImageLoad = (id: string) => {
        setLoadedImages((prev) => new Set(prev).add(id));
    };

    return (
        <>
            <div className={`media-grid ${getGridClass()}`}>
                {media.slice(0, 4).map((item, index) => (
                    <MediaItem
                        key={item.id}
                        item={item}
                        index={index}
                        onClick={() => setSelectedIndex(index)}
                        isLoaded={loadedImages.has(item.id)}
                        onLoad={() => handleImageLoad(item.id)}
                        showOverlay={index === 3 && media.length > 4}
                        overlayCount={media.length - 4}
                    />
                ))}
            </div>

            {/* Lightbox */}
            {selectedIndex !== null && (
                <MediaLightbox
                    media={media}
                    initialIndex={selectedIndex}
                    onClose={() => setSelectedIndex(null)}
                />
            )}
        </>
    );
}

interface MediaItemProps {
    item: MediaItem;
    index: number;
    onClick: () => void;
    isLoaded: boolean;
    onLoad: () => void;
    showOverlay?: boolean;
    overlayCount?: number;
}

function MediaItem({
    item,
    index,
    onClick,
    isLoaded,
    onLoad,
    showOverlay,
    overlayCount
}: MediaItemProps) {
    const { ref, inView } = useInView({
        threshold: 0,
        triggerOnce: true
    });

    const videoRef = useRef<HTMLVideoElement>(null);
    const [isPlaying, setIsPlaying] = useState(false);
    const [isMuted, setIsMuted] = useState(true);

    // Auto-play video when in view
    useEffect(() => {
        if (item.type === 'video' && videoRef.current) {
            if (inView) {
                videoRef.current.play().catch(() => {});
                setIsPlaying(true);
            } else {
                videoRef.current.pause();
                setIsPlaying(false);
            }
        }
    }, [inView, item.type]);

    // Calculate aspect ratio
    const aspectRatio = item.width / item.height;
    const isPortrait = aspectRatio < 1;
    const isSquare = Math.abs(aspectRatio - 1) < 0.1;

    return (
        <div
            ref={ref}
            className={`media-item ${isPortrait ? 'media-item--portrait' : ''} ${isSquare ? 'media-item--square' : ''}`}
            onClick={onClick}
            role="button"
            tabIndex={0}
            aria-label={item.altText || `Media ${index + 1}`}
        >
            {/* Blurhash placeholder */}
            {!isLoaded && item.blurhash && (
                <div className="media-item__placeholder">
                    <BlurhashCanvas
                        hash={item.blurhash}
                        width={32}
                        height={32}
                    />
                </div>
            )}

            {item.type === 'image' || item.type === 'gif' ? (
                <Image
                    src={inView ? item.url : item.thumbnailUrl}
                    alt={item.altText || ''}
                    fill
                    sizes="(max-width: 768px) 100vw, 600px"
                    className={`media-item__image ${isLoaded ? 'loaded' : ''}`}
                    onLoad={onLoad}
                    priority={index === 0}
                />
            ) : (
                <div className="media-item__video-container">
                    <video
                        ref={videoRef}
                        src={inView ? item.url : undefined}
                        poster={item.thumbnailUrl}
                        loop
                        muted={isMuted}
                        playsInline
                        className="media-item__video"
                    />

                    {/* Video controls */}
                    <div className="media-item__video-controls">
                        <button
                            className="video-control"
                            onClick={(e) => {
                                e.stopPropagation();
                                if (videoRef.current) {
                                    if (isPlaying) {
                                        videoRef.current.pause();
                                    } else {
                                        videoRef.current.play();
                                    }
                                    setIsPlaying(!isPlaying);
                                }
                            }}
                        >
                            {isPlaying ? '⏸' : '▶️'}
                        </button>

                        <button
                            className="video-control"
                            onClick={(e) => {
                                e.stopPropagation();
                                setIsMuted(!isMuted);
                            }}
                        >
                            {isMuted ? '🔇' : '🔊'}
                        </button>

                        {item.duration && (
                            <span className="video-duration">
                                {formatDuration(item.duration)}
                            </span>
                        )}
                    </div>
                </div>
            )}

            {/* Overlay for "more" indicator */}
            {showOverlay && (
                <div className="media-item__overlay">
                    <span>+{overlayCount}</span>
                </div>
            )}

            {/* Alt text indicator */}
            {item.altText && (
                <button
                    className="media-item__alt-badge"
                    onClick={(e) => {
                        e.stopPropagation();
                        // Show alt text modal
                    }}
                    aria-label="View image description"
                >
                    ALT
                </button>
            )}
        </div>
    );
}
