// hooks/useFeedSocket.ts
'use client';

import { useEffect, useRef, useCallback } from 'react';
import { useFeedStore } from '@/stores/feedStore';

interface FeedSocketMessage {
    type: 'new_post' | 'post_update' | 'post_delete' | 'engagement_update';
    payload: any;
}

export function useFeedSocket() {
    const socketRef = useRef<WebSocket | null>(null);
    const reconnectTimeoutRef = useRef<NodeJS.Timeout>();
    const reconnectAttemptsRef = useRef(0);
    const maxReconnectAttempts = 5;

    const { addPendingPost, updatePost, removePost } = useFeedStore();

    const connect = useCallback(() => {
        if (socketRef.current?.readyState === WebSocket.OPEN) return;

        const socket = new WebSocket(
            `${process.env.NEXT_PUBLIC_WS_URL}/feed`
        );

        socket.onopen = () => {
            console.log('Feed socket connected');
            reconnectAttemptsRef.current = 0;
        };

        socket.onmessage = (event) => {
            try {
                const message: FeedSocketMessage = JSON.parse(event.data);

                switch (message.type) {
                    case 'new_post':
                        // Add to pending posts (user needs to click to see)
                        addPendingPost(message.payload);
                        break;

                    case 'post_update':
                        updatePost(message.payload.id, message.payload);
                        break;

                    case 'post_delete':
                        removePost(message.payload.id);
                        break;

                    case 'engagement_update':
                        // Update like/comment counts
                        updatePost(message.payload.postId, {
                            likeCount: message.payload.likeCount,
                            commentCount: message.payload.commentCount,
                            shareCount: message.payload.shareCount
                        });
                        break;
                }
            } catch (error) {
                console.error('Failed to parse socket message:', error);
            }
        };

        socket.onclose = (event) => {
            if (!event.wasClean && reconnectAttemptsRef.current < maxReconnectAttempts) {
                const delay = Math.min(1000 * Math.pow(2, reconnectAttemptsRef.current), 30000);
                reconnectTimeoutRef.current = setTimeout(() => {
                    reconnectAttemptsRef.current++;
                    connect();
                }, delay);
            }
        };

        socket.onerror = (error) => {
            console.error('Feed socket error:', error);
        };

        socketRef.current = socket;
    }, [addPendingPost, updatePost, removePost]);

    const disconnect = useCallback(() => {
        if (reconnectTimeoutRef.current) {
            clearTimeout(reconnectTimeoutRef.current);
        }

        if (socketRef.current) {
            socketRef.current.close();
            socketRef.current = null;
        }
    }, []);

    useEffect(() => {
        connect();

        // Reconnect on visibility change
        const handleVisibilityChange = () => {
            if (document.visibilityState === 'visible') {
                connect();
            }
        };

        document.addEventListener('visibilitychange', handleVisibilityChange);

        return () => {
            disconnect();
            document.removeEventListener('visibilitychange', handleVisibilityChange);
        };
    }, [connect, disconnect]);

    return { connect, disconnect };
}

