'use client';

import { useState, useRef, useCallback } from 'react';
import { useDropzone } from 'react-dropzone';
import { useFeedStore } from '@/stores/feedStore';
import { useAuth } from '@/contexts/AuthContext';
import { UserAvatar } from '../User/UserAvatar';
import { MentionInput } from './MentionInput';

interface PostComposerProps {
    replyTo?: Post;
    quotedPost?: Post;
    onSuccess?: () => void;
    onCancel?: () => void;
}

const MAX_CHARS = 280;
const MAX_MEDIA = 4;
const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10MB

export function PostComposer({
    replyTo,
    quotedPost,
    onSuccess,
    onCancel
}: PostComposerProps) {
    const { user } = useAuth();
    const { addPost } = useFeedStore();

    const [content, setContent] = useState('');
    const [media, setMedia] = useState<File[]>([]);
    const [mediaPreviews, setMediaPreviews] = useState<string[]>([]);
    const [isPosting, setIsPosting] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [uploadProgress, setUploadProgress] = useState<number[]>([]);

    const textareaRef = useRef<HTMLTextAreaElement>(null);

    // Character count
    const charCount = content.length;
    const isOverLimit = charCount > MAX_CHARS;
    const remainingChars = MAX_CHARS - charCount;

    // Handle media drop
    const onDrop = useCallback((acceptedFiles: File[]) => {
        const newFiles = acceptedFiles.slice(0, MAX_MEDIA - media.length);

        // Validate files
        const validFiles = newFiles.filter((file) => {
            if (file.size > MAX_FILE_SIZE) {
                setError(`File ${file.name} is too large`);
                return false;
            }
            if (!file.type.startsWith('image/') && !file.type.startsWith('video/')) {
                setError(`File ${file.name} is not a valid media type`);
                return false;
            }
            return true;
        });

        setMedia((prev) => [...prev, ...validFiles]);

        // Create previews
        validFiles.forEach((file) => {
            const reader = new FileReader();
            reader.onload = (e) => {
                setMediaPreviews((prev) => [...prev, e.target?.result as string]);
            };
            reader.readAsDataURL(file);
        });
    }, [media.length]);

    const { getRootProps, getInputProps, isDragActive } = useDropzone({
        onDrop,
        accept: {
            'image/*': ['.png', '.jpg', '.jpeg', '.gif', '.webp'],
            'video/*': ['.mp4', '.mov', '.webm']
        },
        maxSize: MAX_FILE_SIZE,
        maxFiles: MAX_MEDIA - media.length,
        noClick: true
    });

    // Remove media
    const removeMedia = (index: number) => {
        setMedia((prev) => prev.filter((_, i) => i !== index));
        setMediaPreviews((prev) => prev.filter((_, i) => i !== index));
    };

    // Submit post
    const handleSubmit = async () => {
        if (!content.trim() && media.length === 0) return;
        if (isOverLimit) return;

        setIsPosting(true);
        setError(null);

        try {
            // Upload media first
            let uploadedMedia: MediaItem[] = [];

            if (media.length > 0) {
                uploadedMedia = await uploadMedia(media, (progress) => {
                    setUploadProgress(progress);
                });
            }

            // Create post
            const newPost = await feedApi.createPost({
                content: content.trim(),
                media: uploadedMedia.map((m) => m.id),
                replyTo: replyTo?.id,
                quotedPost: quotedPost?.id
            });

            // Add to feed
            addPost(newPost);

            // Reset form
            setContent('');
            setMedia([]);
            setMediaPreviews([]);
            setUploadProgress([]);

            onSuccess?.();
        } catch (error) {
            setError((error as Error).message);
        } finally {
            setIsPosting(false);
        }
    };
