                            </button>
                        </div>

                        <div className="post-composer__submit-area">
                            {/* Character counter */}
                            {content.length > 0 && (
                                <div className={`char-counter ${isOverLimit ? 'over-limit' : ''}`}>
                                    <svg className="char-counter-circle" viewBox="0 0 36 36">
                                        <circle
                                            cx="18"
                                            cy="18"
                                            r="15"
                                            fill="none"
                                            stroke={isOverLimit ? '#f44336' : '#1da1f2'}
                                            strokeWidth="3"
                                            strokeDasharray={`${Math.min(charCount / MAX_CHARS, 1) * 94.2} 94.2`}
                                            transform="rotate(-90 18 18)"
                                        />
                                    </svg>
                                    {remainingChars <= 20 && (
                                        <span className={remainingChars < 0 ? 'negative' : ''}>
                                            {remainingChars}
                                        </span>
                                    )}
                                </div>
                            )}

                            {onCancel && (
                                <button
                                    className="btn-secondary"
                                    onClick={onCancel}
                                    disabled={isPosting}
                                >
                                    Cancel
                                </button>
                            )}

                            <button
                                className="btn-primary"
                                onClick={handleSubmit}
                                disabled={
                                    isPosting ||
                                    isOverLimit ||
                                    (!content.trim() && media.length === 0)
                                }
                            >
                                {isPosting ? 'Posting...' : replyTo ? 'Reply' : 'Post'}
                            </button>
                        </div>
                    </div>
