// components/Stories/StoriesBar.tsx
'use client';

import { useState, useRef, useEffect } from 'react';
import { useQuery } from '@tanstack/react-query';
import { UserAvatar } from '../User/UserAvatar';
import { StoryViewer } from './StoryViewer';

export function StoriesBar() {
    const scrollRef = useRef<HTMLDivElement>(null);
    const [selectedStoryIndex, setSelectedStoryIndex] = useState<number | null>(null);
    const [canScrollLeft, setCanScrollLeft] = useState(false);
    const [canScrollRight, setCanScrollRight] = useState(false);

    const { data: stories, isLoading } = useQuery({
        queryKey: ['stories'],
        queryFn: () => feedApi.getStories(),
        refetchInterval: 60000 // Refetch every minute
    });

    // Check scroll position
    useEffect(() => {
        const checkScroll = () => {
            if (scrollRef.current) {
                const { scrollLeft, scrollWidth, clientWidth } = scrollRef.current;
                setCanScrollLeft(scrollLeft > 0);
                setCanScrollRight(scrollLeft + clientWidth < scrollWidth - 10);
            }
        };

        checkScroll();
        scrollRef.current?.addEventListener('scroll', checkScroll);
        window.addEventListener('resize', checkScroll);

        return () => {
            scrollRef.current?.removeEventListener('scroll', checkScroll);
            window.removeEventListener('resize', checkScroll);
        };
    }, [stories]);

    const scroll = (direction: 'left' | 'right') => {
        if (scrollRef.current) {
            const scrollAmount = 200;
            scrollRef.current.scrollBy({
                left: direction === 'left' ? -scrollAmount : scrollAmount,
                behavior: 'smooth'
            });
        }
    };

    if (isLoading) {
        return (
            <div className="stories-bar stories-bar--loading">
                {Array.from({ length: 6 }).map((_, i) => (
                    <div key={i} className="story-item story-item--skeleton">
                        <div className="story-avatar-skeleton" />
                        <div className="story-name-skeleton" />
                    </div>
                ))}
            </div>
        );
    }

    if (!stories?.length) return null;

    return (
        <>
            <div className="stories-bar">
                {/* Scroll buttons */}
                {canScrollLeft && (
                    <button
                        className="scroll-button scroll-button--left"
                        onClick={() => scroll('left')}
                        aria-label="Scroll stories left"
                    >
                        <svg className="icon"><use href="#icon-chevron-left" /></svg>
                    </button>
                )}

                {canScrollRight && (
                    <button
                        className="scroll-button scroll-button--right"
                        onClick={() => scroll('right')}
                        aria-label="Scroll stories right"
                    >
                        <svg className="icon"><use href="#icon-chevron-right" /></svg>
                    </button>
                )}

                {/* Stories list */}
                <div ref={scrollRef} className="stories-scroll">
                    {/* Create story button */}
                    <button className="story-item story-item--create">
                        <div className="story-avatar-wrapper">
                            <UserAvatar user={currentUser} size="large" />
                            <div className="create-badge">+</div>
                        </div>
                        <span className="story-name">Your story</span>
                    </button>

                    {/* Story items */}
                    {stories.map((story, index) => (
                        <button
                            key={story.id}
                            className={`story-item ${story.viewedAt ? 'story-item--viewed' : ''}`}
                            onClick={() => setSelectedStoryIndex(index)}
                        >
                            <div className={`story-avatar-wrapper ${!story.viewedAt ? 'has-unviewed' : ''}`}>
                                <UserAvatar user={story.author} size="large" />
                            </div>
                            <span className="story-name">
                                {story.author.displayName}
                            </span>
                        </button>
                    ))}
                </div>
            </div>

            {/* Story viewer modal */}
            {selectedStoryIndex !== null && stories && (
                <StoryViewer
                    stories={stories}
                    initialIndex={selectedStoryIndex}
                    onClose={() => setSelectedStoryIndex(null)}
                    onNavigate={setSelectedStoryIndex}
                />
            )}
        </>
    );
}
