// components/Stories/StoryViewer.tsx
'use client';

import { useState, useEffect, useRef, useCallback } from 'react';
import { createPortal } from 'react-dom';
import Image from 'next/image';

interface StoryViewerProps {
    stories: Story[];
    initialIndex: number;
    onClose: () => void;
    onNavigate: (index: number) => void;
}

export function StoryViewer({
    stories,
    initialIndex,
    onClose,
    onNavigate
}: StoryViewerProps) {
    const [storyIndex, setStoryIndex] = useState(initialIndex);
    const [itemIndex, setItemIndex] = useState(0);
    const [progress, setProgress] = useState(0);
    const [isPaused, setIsPaused] = useState(false);

    const currentStory = stories[storyIndex];
    const currentItem = currentStory?.items[itemIndex];
    const progressInterval = useRef<NodeJS.Timeout>();
    const videoRef = useRef<HTMLVideoElement>(null);

    // Progress animation
    useEffect(() => {
        if (!currentItem || isPaused) return;

        const duration = currentItem.type === 'video'
            ? currentItem.duration * 1000
            : 5000; // 5 seconds for images

        const startTime = Date.now();

        const updateProgress = () => {
            const elapsed = Date.now() - startTime;
            const newProgress = Math.min((elapsed / duration) * 100, 100);
            setProgress(newProgress);

            if (newProgress >= 100) {
                goToNext();
            }
        };

        progressInterval.current = setInterval(updateProgress, 50);

        return () => {
            if (progressInterval.current) {
                clearInterval(progressInterval.current);
            }
        };
    }, [currentItem, itemIndex, storyIndex, isPaused]);

    // Mark as viewed
    useEffect(() => {
        if (currentStory && !currentStory.viewedAt) {
            feedApi.markStoryViewed(currentStory.id);
        }
    }, [currentStory]);

    // Navigation
    const goToNext = useCallback(() => {
        if (itemIndex < currentStory.items.length - 1) {
            setItemIndex(itemIndex + 1);
            setProgress(0);
        } else if (storyIndex < stories.length - 1) {
            setStoryIndex(storyIndex + 1);
            setItemIndex(0);
            setProgress(0);
            onNavigate(storyIndex + 1);
        } else {
            onClose();
        }
    }, [itemIndex, storyIndex, currentStory, stories.length, onNavigate, onClose]);

    const goToPrev = useCallback(() => {
        if (itemIndex > 0) {
            setItemIndex(itemIndex - 1);
            setProgress(0);
        } else if (storyIndex > 0) {
            setStoryIndex(storyIndex - 1);
            const prevStory = stories[storyIndex - 1];
            setItemIndex(prevStory.items.length - 1);
            setProgress(0);
            onNavigate(storyIndex - 1);
        }
    }, [itemIndex, storyIndex, stories, onNavigate]);

    // Keyboard navigation
    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => {
            switch (e.key) {
                case 'ArrowLeft':
                    goToPrev();
                    break;
                case 'ArrowRight':
                    goToNext();
                    break;
                case 'Escape':
                    onClose();
                    break;
                case ' ':
                    e.preventDefault();
                    setIsPaused(!isPaused);
                    break;
            }
        };

        document.addEventListener('keydown', handleKeyDown);
        return () => document.removeEventListener('keydown', handleKeyDown);
    }, [goToPrev, goToNext, onClose, isPaused]);

    // Touch handling for mobile
    const touchStartX = useRef(0);

    const handleTouchStart = (e: React.TouchEvent) => {
        touchStartX.current = e.touches[0].clientX;
        setIsPaused(true);
    };

    const handleTouchEnd = (e: React.TouchEvent) => {
        const touchEndX = e.changedTouches[0].clientX;
        const diff = touchEndX - touchStartX.current;

        if (Math.abs(diff) > 50) {
            if (diff > 0) {
                goToPrev();
            } else {
                goToNext();
            }
        }

        setIsPaused(false);
    };

    // Tap zones
    const handleClick = (e: React.MouseEvent) => {
        const rect = e.currentTarget.getBoundingClientRect();
        const x = e.clientX - rect.left;
        const width = rect.width;

        if (x < width / 3) {
            goToPrev();
        } else if (x > (width * 2) / 3) {
            goToNext();
        } else {
            setIsPaused(!isPaused);
        }
    };

    if (!currentStory || !currentItem) return null;

    return createPortal(
        <div className="story-viewer" role="dialog" aria-modal="true">
            {/* Close button */}
            <button
                className="story-viewer__close"
                onClick={onClose}
                aria-label="Close stories"
            >
                <svg className="icon"><use href="#icon-close" /></svg>
            </button>

            {/* Progress bars */}
            <div className="story-viewer__progress">
                {currentStory.items.map((item, idx) => (
                    <div key={item.id} className="progress-bar">
                        <div
                            className="progress-fill"
                            style={{
                                width: idx < itemIndex
                                    ? '100%'
                                    : idx === itemIndex
                                        ? `${progress}%`
                                        : '0%'
                            }}
                        />
                    </div>
                ))}
            </div>

            {/* Header */}
            <div className="story-viewer__header">
                <UserAvatar user={currentStory.author} size="small" />
                <div className="story-author-info">
                    <span className="author-name">{currentStory.author.displayName}</span>
                    <span className="story-time">
                        {formatDistanceToNow(new Date(currentItem.createdAt))}
                    </span>
                </div>

                <button
                    className="pause-button"
                    onClick={() => setIsPaused(!isPaused)}
                    aria-label={isPaused ? 'Play' : 'Pause'}
                >
                    <svg className="icon">
                        <use href={isPaused ? '#icon-play' : '#icon-pause'} />
                    </svg>
                </button>
            </div>

            {/* Content */}
            <div
                className="story-viewer__content"
                onClick={handleClick}
                onTouchStart={handleTouchStart}
                onTouchEnd={handleTouchEnd}
            >
                {currentItem.type === 'image' ? (
                    <Image
                        src={currentItem.url}
                        alt=""
                        fill
                        style={{ objectFit: 'contain' }}
                        priority
                    />
                ) : (
                    <video
                        ref={videoRef}
                        src={currentItem.url}
                        autoPlay
                        muted={false}
                        playsInline
                        onPause={() => setIsPaused(true)}
                        onPlay={() => setIsPaused(false)}
                    />
                )}
            </div>

            {/* Navigation hints */}
            <div className="story-viewer__nav-prev" aria-hidden="true" />
            <div className="story-viewer__nav-next" aria-hidden="true" />

            {/* Reply input */}
            <div className="story-viewer__reply">
                <input
                    type="text"
                    placeholder={`Reply to ${currentStory.author.displayName}...`}
                    onFocus={() => setIsPaused(true)}
                    onBlur={() => setIsPaused(false)}
                />
                <button className="send-button">
                    <svg className="icon"><use href="#icon-send" /></svg>
                </button>
            </div>

            {/* Story navigation indicators */}
            {storyIndex > 0 && (
                <button
                    className="story-nav-button story-nav-button--prev"
                    onClick={(e) => {
                        e.stopPropagation();
                        setStoryIndex(storyIndex - 1);
                        setItemIndex(0);
                        onNavigate(storyIndex - 1);
                    }}
                    aria-label="Previous story"
                >
                    <div className="story-preview">
                        <UserAvatar user={stories[storyIndex - 1].author} size="small" />
                    </div>
                </button>
            )}

            {storyIndex < stories.length - 1 && (
                <button
                    className="story-nav-button story-nav-button--next"
                    onClick={(e) => {
                        e.stopPropagation();
                        setStoryIndex(storyIndex + 1);
                        setItemIndex(0);
                        onNavigate(storyIndex + 1);
                    }}
                    aria-label="Next story"
                >
                    <div className="story-preview">
                        <UserAvatar user={stories[storyIndex + 1].author} size="small" />
                    </div>
                </button>
            )}
        </div>,
        document.body
    );
}
