// components/Feed/CommentsSection.tsx
'use client';

import { useState, useCallback } from 'react';
import { useInfiniteQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { useVirtualizer } from '@tanstack/react-virtual';
import { formatDistanceToNow } from 'date-fns';
import { UserAvatar } from '../User/UserAvatar';

interface CommentsSectionProps {
    postId: string;
    initialComments?: Comment[];
}

export function CommentsSection({ postId, initialComments }: CommentsSectionProps) {
    const queryClient = useQueryClient();
    const parentRef = useRef<HTMLDivElement>(null);
    const [replyTo, setReplyTo] = useState<Comment | null>(null);
    const [newComment, setNewComment] = useState('');

    // Fetch comments
    const {
        data,
        fetchNextPage,
        hasNextPage,
        isFetchingNextPage
    } = useInfiniteQuery({
        queryKey: ['comments', postId],
        queryFn: ({ pageParam }) => feedApi.getComments(postId, { cursor: pageParam }),
        initialPageParam: null as string | null,
        getNextPageParam: (lastPage) => lastPage.nextCursor,
        initialData: initialComments ? {
            pages: [{ comments: initialComments, nextCursor: null }],
            pageParams: [null]
        } : undefined
    });

    const comments = data?.pages.flatMap((page) => page.comments) ?? [];

    // Virtualizer
    const virtualizer = useVirtualizer({
        count: comments.length,
        getScrollElement: () => parentRef.current,
        estimateSize: () => 100,
        overscan: 5
    });

    // Add comment mutation
    const addCommentMutation = useMutation({
        mutationFn: (data: { content: string; replyToId?: string }) =>
            feedApi.addComment(postId, data),
        onSuccess: (newComment) => {
            queryClient.setQueryData(['comments', postId], (old: any) => ({
                ...old,
                pages: old.pages.map((page: any, index: number) =>
                    index === 0
                        ? { ...page, comments: [newComment, ...page.comments] }
                        : page
                )
            }));
            setNewComment('');
            setReplyTo(null);
        }
    });

    // Like comment mutation
    const likeCommentMutation = useMutation({
        mutationFn: (commentId: string) => feedApi.likeComment(commentId),
        onMutate: async (commentId) => {
            await queryClient.cancelQueries({ queryKey: ['comments', postId] });

            queryClient.setQueryData(['comments', postId], (old: any) => ({
                ...old,
                pages: old.pages.map((page: any) => ({
                    ...page,
                    comments: page.comments.map((c: Comment) =>
                        c.id === commentId
                            ? { ...c, isLiked: !c.isLiked, likeCount: c.likeCount + (c.isLiked ? -1 : 1) }
                            : c
                    )
                }))
            }));
        }
    });

    const handleSubmit = useCallback((e: React.FormEvent) => {
        e.preventDefault();
        if (!newComment.trim()) return;

        addCommentMutation.mutate({
            content: newComment,
            replyToId: replyTo?.id
        });
    }, [newComment, replyTo, addCommentMutation]);

    return (
        <div className="comments-section">
            {/* Comment input */}
            <form className="comment-form" onSubmit={handleSubmit}>
                {replyTo && (
                    <div className="reply-indicator">
                        Replying to <span>@{replyTo.author.username}</span>
                        <button type="button" onClick={() => setReplyTo(null)}>×</button>
                    </div>
                )}

                <div className="comment-input-wrapper">
                    <UserAvatar user={currentUser} size="small" />
                    <input
                        type="text"
                        value={newComment}
                        onChange={(e) => setNewComment(e.target.value)}
                        placeholder="Write a comment..."
                        disabled={addCommentMutation.isPending}
                    />
                    <button
                        type="submit"
                        disabled={!newComment.trim() || addCommentMutation.isPending}
                    >
                        {addCommentMutation.isPending ? '...' : 'Post'}
                    </button>
                </div>
            </form>

            {/* Comments list */}
            <div ref={parentRef} className="comments-list">
                <div
                    style={{
                        height: `${virtualizer.getTotalSize()}px`,
                        position: 'relative'
                    }}
                >
                    {virtualizer.getVirtualItems().map((virtualItem) => {
                        const comment = comments[virtualItem.index];

                        return (
                            <div
                                key={virtualItem.key}
                                ref={virtualizer.measureElement}
                                data-index={virtualItem.index}
                                style={{
                                    position: 'absolute',
                                    top: 0,
                                    left: 0,
                                    width: '100%',
                                    transform: `translateY(${virtualItem.start}px)`
                                }}
                            >
                                <CommentItem
                                    comment={comment}
                                    onReply={() => setReplyTo(comment)}
                                    onLike={() => likeCommentMutation.mutate(comment.id)}
                                />
                            </div>
                        );
                    })}
                </div>

                {hasNextPage && (
                    <button
                        className="load-more-comments"
                        onClick={() => fetchNextPage()}
                        disabled={isFetchingNextPage}
                    >
                        {isFetchingNextPage ? 'Loading...' : 'Load more comments'}
                    </button>
                )}
            </div>
        </div>
    );
}

interface CommentItemProps {
    comment: Comment;
    onReply: () => void;
    onLike: () => void;
    depth?: number;
}

function CommentItem({ comment, onReply, onLike, depth = 0 }: CommentItemProps) {
    const [showReplies, setShowReplies] = useState(false);
    const maxDepth = 3;

    return (
        <div
            className="comment-item"
            style={{ marginLeft: depth * 24 }}
        >
            <UserAvatar user={comment.author} size="small" />

            <div className="comment-content">
                <div className="comment-header">
                    <span className="comment-author">{comment.author.displayName}</span>
                    <span className="comment-username">@{comment.author.username}</span>
                    <span className="comment-time">
                        {formatDistanceToNow(new Date(comment.createdAt))}
                    </span>
                </div>

                <p className="comment-text">{comment.content}</p>

                <div className="comment-actions">
                    <button
                        className={`action-button ${comment.isLiked ? 'liked' : ''}`}
                        onClick={onLike}
                    >
                        <svg className="icon"><use href="#icon-heart" /></svg>
                        {comment.likeCount > 0 && <span>{comment.likeCount}</span>}
                    </button>

                    {depth < maxDepth && (
                        <button className="action-button" onClick={onReply}>
                            <svg className="icon"><use href="#icon-reply" /></svg>
                            Reply
                        </button>
                    )}
                </div>

                {/* Nested replies */}
                {comment.replyCount > 0 && depth < maxDepth && (
                    <button
                        className="show-replies-button"
                        onClick={() => setShowReplies(!showReplies)}
                    >
                        {showReplies ? 'Hide' : 'Show'} {comment.replyCount} replies
                    </button>
                )}

                {showReplies && comment.replies.map((reply) => (
                    <CommentItem
                        key={reply.id}
                        comment={reply}
                        onReply={onReply}
                        onLike={() => {}}
                        depth={depth + 1}
                    />
                ))}
            </div>
        </div>
    );
}
