// hooks/useOfflineSupport.ts
'use client';

import { useEffect, useState, useCallback } from 'react';
import { openDB, IDBPDatabase } from 'idb';
import { useFeedStore } from '@/stores/feedStore';

interface OfflineDB {
    posts: {
        key: string;
        value: Post;
        indexes: { 'by-date': string };
    };
    pendingActions: {
        key: string;
        value: {
            id: string;
            type: 'like' | 'unlike' | 'bookmark' | 'repost';
            postId: string;
            timestamp: number;
        };
    };
}

export function useOfflineSupport() {
    const [db, setDb] = useState<IDBPDatabase<OfflineDB> | null>(null);
    const [isOnline, setIsOnline] = useState(true);
    const { posts, updatePost } = useFeedStore();

    // Initialize IndexedDB
    useEffect(() => {
        const initDB = async () => {
            const database = await openDB<OfflineDB>('feed-cache', 1, {
                upgrade(db) {
                    // Posts store
                    const postStore = db.createObjectStore('posts', { keyPath: 'id' });
                    postStore.createIndex('by-date', 'createdAt');

                    // Pending actions store
                    db.createObjectStore('pendingActions', { keyPath: 'id' });
                }
            });

            setDb(database);
        };

        initDB();
    }, []);

    // Track online status
    useEffect(() => {
        const handleOnline = () => setIsOnline(true);
        const handleOffline = () => setIsOnline(false);

        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);

        setIsOnline(navigator.onLine);

        return () => {
            window.removeEventListener('online', handleOnline);
            window.removeEventListener('offline', handleOffline);
        };
    }, []);

    // Cache posts when they're loaded
    useEffect(() => {
        if (!db) return;

        const cachePosts = async () => {
            const tx = db.transaction('posts', 'readwrite');

            for (const post of posts.values()) {
                await tx.store.put(post);
            }

            await tx.done;
        };

        cachePosts();
    }, [db, posts]);

    // Load cached posts when offline
    const loadCachedPosts = useCallback(async () => {
        if (!db) return [];

        const posts = await db.getAll('posts');
        return posts.sort(
            (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
        );
    }, [db]);

    // Queue action for later sync
    const queueAction = useCallback(async (
        type: 'like' | 'unlike' | 'bookmark' | 'repost',
        postId: string
    ) => {
        if (!db) return;

        const action = {
            id: crypto.randomUUID(),
            type,
            postId,
            timestamp: Date.now()
        };

        await db.put('pendingActions', action);
    }, [db]);

    // Sync pending actions when online
    useEffect(() => {
        if (!isOnline || !db) return;

        const syncPendingActions = async () => {
            const actions = await db.getAll('pendingActions');

            for (const action of actions) {
                try {
                    switch (action.type) {
                        case 'like':
                            await feedApi.likePost(action.postId);
                            break;
                        case 'unlike':
                            await feedApi.unlikePost(action.postId);
                            break;
                        case 'bookmark':
                            await feedApi.bookmarkPost(action.postId);
                            break;
                        case 'repost':
                            await feedApi.repost(action.postId);
                            break;
                    }

                    await db.delete('pendingActions', action.id);
                } catch (error) {
                    console.error('Failed to sync action:', error);
                }
            }
        };

        syncPendingActions();
    }, [isOnline, db]);

    return {
        isOnline,
        loadCachedPosts,
        queueAction
    };
}

