// ═══════════════════════════════════════════════════════════
// TYPE DEFINITIONS
// ═══════════════════════════════════════════════════════════

// types/chat.ts
interface User {
    id: string;
    username: string;
    displayName: string;
    avatar: string;
    status: 'online' | 'offline' | 'away' | 'busy';
    lastSeen: string;
}

interface Conversation {
    id: string;
    type: 'direct' | 'group';
    name?: string; // For group chats
    avatar?: string; // For group chats
    participants: User[];
    lastMessage: Message | null;
    unreadCount: number;
    isPinned: boolean;
    isMuted: boolean;
    createdAt: string;
    updatedAt: string;
}

interface Message {
    id: string;
    conversationId: string;
    senderId: string;
    type: 'text' | 'image' | 'file' | 'voice' | 'video' | 'system';
    content: string;
    media?: MessageMedia[];
    replyTo?: Message;
    reactions: MessageReaction[];
    readBy: { userId: string; readAt: string }[];
    status: 'sending' | 'sent' | 'delivered' | 'read' | 'failed';
    createdAt: string;
    editedAt?: string;
    deletedAt?: string;
}

interface MessageMedia {
    id: string;
    type: 'image' | 'video' | 'audio' | 'file';
    url: string;
    thumbnailUrl?: string;
    fileName: string;
    fileSize: number;
    mimeType: string;
    duration?: number; // For audio/video
    dimensions?: { width: number; height: number }; // For images/videos
}

interface MessageReaction {
    emoji: string;
    users: string[];
    count: number;
}

interface TypingIndicator {
    conversationId: string;
    userId: string;
    isTyping: boolean;
    timestamp: number;
}

// WebSocket events
type ChatEvent =
    | { type: 'message:new'; payload: Message }
    | { type: 'message:update'; payload: Partial<Message> & { id: string } }
    | { type: 'message:delete'; payload: { id: string; conversationId: string } }
    | { type: 'message:delivered'; payload: { messageId: string; userId: string } }
    | { type: 'message:read'; payload: { messageIds: string[]; userId: string; conversationId: string } }
    | { type: 'typing:start'; payload: TypingIndicator }
    | { type: 'typing:stop'; payload: TypingIndicator }
    | { type: 'presence:update'; payload: { userId: string; status: User['status'] } }
    | { type: 'conversation:update'; payload: Partial<Conversation> & { id: string } };

// ═══════════════════════════════════════════════════════════
// CHAT STORE (ZUSTAND)
// ═══════════════════════════════════════════════════════════

// stores/chatStore.ts
import { create } from 'zustand';
import { devtools, persist } from 'zustand/middleware';
import { immer } from 'zustand/middleware/immer';

interface ChatState {
    // Conversations
    conversations: Map<string, Conversation>;
    conversationOrder: string[];
    activeConversationId: string | null;

    // Messages
    messages: Map<string, Map<string, Message>>; // conversationId -> messageId -> Message
    messageOrder: Map<string, string[]>; // conversationId -> messageIds in order

    // Typing indicators
    typingUsers: Map<string, Set<string>>; // conversationId -> userIds

    // User presence
    userPresence: Map<string, User['status']>;

    // Pending messages (for offline support)
    pendingMessages: Message[];

    // UI state
    isLoading: boolean;
    error: string | null;
}

interface ChatActions {
    // Conversation actions
    setActiveConversation: (id: string | null) => void;
    fetchConversations: () => Promise<void>;
    createConversation: (participants: string[], name?: string) => Promise<Conversation>;
    updateConversation: (id: string, updates: Partial<Conversation>) => void;
    markAsRead: (conversationId: string) => Promise<void>;

    // Message actions
    fetchMessages: (conversationId: string, before?: string) => Promise<void>;
    sendMessage: (conversationId: string, content: string, type?: Message['type'], media?: File[]) => Promise<void>;
    editMessage: (messageId: string, content: string) => Promise<void>;
    deleteMessage: (messageId: string) => Promise<void>;
    addReaction: (messageId: string, emoji: string) => Promise<void>;
    removeReaction: (messageId: string, emoji: string) => Promise<void>;

    // Real-time handlers
    handleNewMessage: (message: Message) => void;
    handleMessageUpdate: (update: Partial<Message> & { id: string }) => void;
    handleMessageDelete: (messageId: string, conversationId: string) => void;
    handleTypingIndicator: (indicator: TypingIndicator) => void;
    handlePresenceUpdate: (userId: string, status: User['status']) => void;

    // Typing
    startTyping: (conversationId: string) => void;
    stopTyping: (conversationId: string) => void;
}
