const useChatStore = create<ChatState & ChatActions>()(
    devtools(
        persist(
            immer((set, get) => ({
                // Initial state
                conversations: new Map(),
                conversationOrder: [],
                activeConversationId: null,
                messages: new Map(),
                messageOrder: new Map(),
                typingUsers: new Map(),
                userPresence: new Map(),
                pendingMessages: [],
                isLoading: false,
                error: null,

                // Set active conversation
                setActiveConversation: (id) => {
                    set((state) => {
                        state.activeConversationId = id;

                        // Clear unread count
                        if (id) {
                            const conv = state.conversations.get(id);
                            if (conv) {
                                conv.unreadCount = 0;
                            }
                        }
                    });

                    // Mark as read on server
                    if (id) {
                        get().markAsRead(id);
                    }
                },

                // Fetch conversations
                fetchConversations: async () => {
                    set({ isLoading: true, error: null });

                    try {
                        const conversations = await chatApi.getConversations();

                        set((state) => {
                            state.conversations = new Map(
                                conversations.map((c) => [c.id, c])
                            );
                            state.conversationOrder = conversations.map((c) => c.id);
                            state.isLoading = false;
                        });
                    } catch (error) {
                        set({ error: (error as Error).message, isLoading: false });
                    }
                },

                // Create conversation
                createConversation: async (participants, name) => {
                    const conversation = await chatApi.createConversation({
                        participants,
                        name
                    });

                    set((state) => {
                        state.conversations.set(conversation.id, conversation);
                        state.conversationOrder.unshift(conversation.id);
                    });

                    return conversation;
                },

                // Update conversation
                updateConversation: (id, updates) => {
                    set((state) => {
                        const conv = state.conversations.get(id);
                        if (conv) {
                            Object.assign(conv, updates);
                        }
                    });
                },

                // Mark as read
                markAsRead: async (conversationId) => {
                    const state = get();
                    const messageIds = state.messageOrder.get(conversationId) || [];
                    const unreadIds = messageIds.filter((id) => {
                        const msg = state.messages.get(conversationId)?.get(id);
                        return msg && msg.status !== 'read' && msg.senderId !== currentUserId;
                    });

                    if (unreadIds.length > 0) {
                        await chatApi.markAsRead(conversationId, unreadIds);
                    }
                },

                // Fetch messages
                fetchMessages: async (conversationId, before) => {
                    set({ isLoading: true });

                    try {
                        const { messages, hasMore } = await chatApi.getMessages(
                            conversationId,
                            { before, limit: 50 }
                        );

                        set((state) => {
                            // Initialize maps if needed
                            if (!state.messages.has(conversationId)) {
                                state.messages.set(conversationId, new Map());
                            }
                            if (!state.messageOrder.has(conversationId)) {
                                state.messageOrder.set(conversationId, []);
                            }

                            const msgMap = state.messages.get(conversationId)!;
                            const order = state.messageOrder.get(conversationId)!;

                            messages.forEach((msg) => {
                                msgMap.set(msg.id, msg);
                                if (!order.includes(msg.id)) {
                                    order.push(msg.id);
                                }
                            });

                            // Sort by createdAt
                            order.sort((a, b) => {
                                const msgA = msgMap.get(a);
                                const msgB = msgMap.get(b);
                                return new Date(msgA!.createdAt).getTime() -
                                       new Date(msgB!.createdAt).getTime();
                            });

                            state.isLoading = false;
                        });
                    } catch (error) {
                        set({ error: (error as Error).message, isLoading: false });
                    }
                },

                // Send message
                sendMessage: async (conversationId, content, type = 'text', media) => {
                    const tempId = `temp-${Date.now()}`;

                    // Optimistic update
                    const tempMessage: Message = {
                        id: tempId,
                        conversationId,
                        senderId: currentUserId,
                        type,
                        content,
                        reactions: [],
                        readBy: [],
                        status: 'sending',
                        createdAt: new Date().toISOString()
                    };

                    set((state) => {
                        if (!state.messages.has(conversationId)) {
                            state.messages.set(conversationId, new Map());
                        }
                        if (!state.messageOrder.has(conversationId)) {
                            state.messageOrder.set(conversationId, []);
                        }

                        state.messages.get(conversationId)!.set(tempId, tempMessage);
                        state.messageOrder.get(conversationId)!.push(tempId);

                        // Update conversation last message
                        const conv = state.conversations.get(conversationId);
                        if (conv) {
                            conv.lastMessage = tempMessage;
                            conv.updatedAt = tempMessage.createdAt;
                        }

                        // Move to top
                        state.conversationOrder = [
                            conversationId,
                            ...state.conversationOrder.filter((id) => id !== conversationId)
                        ];
                    });

                    try {
                        // Upload media if present
                        let uploadedMedia: MessageMedia[] = [];
                        if (media && media.length > 0) {
                            uploadedMedia = await chatApi.uploadMedia(media);
                        }

                        // Send message
                        const message = await chatApi.sendMessage(conversationId, {
                            content,
                            type,
                            media: uploadedMedia.map((m) => m.id)
                        });

                        // Replace temp message with real one
                        set((state) => {
                            const msgMap = state.messages.get(conversationId);
                            const order = state.messageOrder.get(conversationId);

                            if (msgMap && order) {
                                msgMap.delete(tempId);
                                msgMap.set(message.id, message);

                                const tempIndex = order.indexOf(tempId);
                                if (tempIndex !== -1) {
                                    order[tempIndex] = message.id;
                                }
                            }

                            // Update conversation
                            const conv = state.conversations.get(conversationId);
                            if (conv) {
                                conv.lastMessage = message;
                            }
                        });
                    } catch (error) {
                        // Mark as failed
                        set((state) => {
                            const msg = state.messages.get(conversationId)?.get(tempId);
                            if (msg) {
                                msg.status = 'failed';
                            }

                            // Add to pending for retry
                            state.pendingMessages.push(tempMessage);
                        });
                    }
                },

                // Edit message
                editMessage: async (messageId, content) => {
                    const state = get();
                    let conversationId: string | null = null;

                    // Find message
                    for (const [convId, msgMap] of state.messages) {
                        if (msgMap.has(messageId)) {
                            conversationId = convId;
                            break;
                        }
                    }

                    if (!conversationId) return;

                    // Optimistic update
                    set((draft) => {
                        const msg = draft.messages.get(conversationId!)?.get(messageId);
                        if (msg) {
                            msg.content = content;
                            msg.editedAt = new Date().toISOString();
                        }
                    });

                    try {
                        await chatApi.editMessage(messageId, content);
                    } catch (error) {
                        // Rollback
                        set((draft) => {
                            const msg = draft.messages.get(conversationId!)?.get(messageId);
                            if (msg) {
                                msg.content = state.messages.get(conversationId!)?.get(messageId)?.content || '';
                                msg.editedAt = undefined;
                            }
                        });
                    }
                },

                // Delete message
                deleteMessage: async (messageId) => {
                    await chatApi.deleteMessage(messageId);
                    get().handleMessageDelete(messageId, '');
                },

                // Add reaction
                addReaction: async (messageId, emoji) => {
                    await chatApi.addReaction(messageId, emoji);
                },

                // Remove reaction
                removeReaction: async (messageId, emoji) => {
                    await chatApi.removeReaction(messageId, emoji);
                },

                // Handle new message
                handleNewMessage: (message) => {
                    set((state) => {
                        const { conversationId } = message;

                        if (!state.messages.has(conversationId)) {
                            state.messages.set(conversationId, new Map());
                        }
                        if (!state.messageOrder.has(conversationId)) {
                            state.messageOrder.set(conversationId, []);
                        }

                        state.messages.get(conversationId)!.set(message.id, message);
                        state.messageOrder.get(conversationId)!.push(message.id);

                        // Update conversation
                        const conv = state.conversations.get(conversationId);
                        if (conv) {
                            conv.lastMessage = message;
                            conv.updatedAt = message.createdAt;

                            // Increment unread if not active
                            if (state.activeConversationId !== conversationId) {
                                conv.unreadCount++;
                            }
                        }

                        // Move conversation to top
                        state.conversationOrder = [
                            conversationId,
                            ...state.conversationOrder.filter((id) => id !== conversationId)
                        ];

                        // Clear typing indicator
                        state.typingUsers.get(conversationId)?.delete(message.senderId);
                    });
                },

                // Handle message update
                handleMessageUpdate: (update) => {
                    set((state) => {
                        for (const [, msgMap] of state.messages) {
                            const msg = msgMap.get(update.id);
                            if (msg) {
                                Object.assign(msg, update);
                                break;
                            }
                        }
                    });
                },

                // Handle message delete
                handleMessageDelete: (messageId, conversationId) => {
                    set((state) => {
                        for (const [convId, msgMap] of state.messages) {
                            if (msgMap.has(messageId)) {
                                const msg = msgMap.get(messageId)!;
                                msg.deletedAt = new Date().toISOString();
                                msg.content = 'This message was deleted';
                                break;
                            }
                        }
                    });
                },

                // Handle typing indicator
                handleTypingIndicator: (indicator) => {
                    set((state) => {
                        if (!state.typingUsers.has(indicator.conversationId)) {
                            state.typingUsers.set(indicator.conversationId, new Set());
                        }

                        const typingSet = state.typingUsers.get(indicator.conversationId)!;

                        if (indicator.isTyping) {
                            typingSet.add(indicator.userId);
                        } else {
                            typingSet.delete(indicator.userId);
                        }
                    });
                },

                // Handle presence update
                handlePresenceUpdate: (userId, status) => {
                    set((state) => {
                        state.userPresence.set(userId, status);
                    });
                },

                // Start typing
                startTyping: (conversationId) => {
                    socketManager.emit('typing:start', { conversationId });
                },

                // Stop typing
                stopTyping: (conversationId) => {
                    socketManager.emit('typing:stop', { conversationId });
                }
            })),
            {
                name: 'chat-storage',
                partialize: (state) => ({
                    // Only persist minimal data
                    conversationOrder: state.conversationOrder.slice(0, 20)
                })
            }
        ),
        { name: 'ChatStore' }
    )
);
