// ═══════════════════════════════════════════════════════════
// WEBSOCKET MANAGER FOR REAL-TIME UPDATES
// ═══════════════════════════════════════════════════════════

// lib/websocket/WebSocketManager.ts
type MessageHandler = (data: any) => void;
type ConnectionState = 'connecting' | 'connected' | 'disconnected' | 'reconnecting';

interface WebSocketConfig {
    url: string;
    protocols?: string | string[];
    reconnectInterval?: number;
    maxReconnectAttempts?: number;
    heartbeatInterval?: number;
    debug?: boolean;
}

interface Subscription {
    channel: string;
    handler: MessageHandler;
}

class WebSocketManager {
    private ws: WebSocket | null = null;
    private config: Required<WebSocketConfig>;
    private subscriptions: Map<string, Set<MessageHandler>> = new Map();
    private messageQueue: any[] = [];
    private reconnectAttempts = 0;
    private reconnectTimer: NodeJS.Timeout | null = null;
    private heartbeatTimer: NodeJS.Timeout | null = null;
    private state: ConnectionState = 'disconnected';
    private stateListeners: Set<(state: ConnectionState) => void> = new Set();

    constructor(config: WebSocketConfig) {
        this.config = {
            url: config.url,
            protocols: config.protocols || [],
            reconnectInterval: config.reconnectInterval || 3000,
            maxReconnectAttempts: config.maxReconnectAttempts || 10,
            heartbeatInterval: config.heartbeatInterval || 30000,
            debug: config.debug || false
        };
    }

    // ─────────────────────────────────────────────────────────
    // Connection Management
    // ─────────────────────────────────────────────────────────

    connect(): Promise<void> {
        return new Promise((resolve, reject) => {
            if (this.ws?.readyState === WebSocket.OPEN) {
                resolve();
                return;
            }

            this.setState('connecting');

            try {
                this.ws = new WebSocket(this.config.url, this.config.protocols);

                this.ws.onopen = () => {
                    this.log('Connected');
                    this.setState('connected');
                    this.reconnectAttempts = 0;
                    this.flushMessageQueue();
                    this.startHeartbeat();
                    this.resubscribeAll();
                    resolve();
                };

                this.ws.onclose = (event) => {
                    this.log('Disconnected', event.code, event.reason);
                    this.setState('disconnected');
                    this.stopHeartbeat();

                    if (!event.wasClean) {
                        this.scheduleReconnect();
                    }
                };

                this.ws.onerror = (error) => {
                    this.log('Error', error);
                    reject(error);
                };

                this.ws.onmessage = (event) => {
                    this.handleMessage(event);
                };

            } catch (error) {
                this.log('Connection failed', error);
                reject(error);
            }
        });
    }

    disconnect(): void {
        this.clearReconnectTimer();
        this.stopHeartbeat();

        if (this.ws) {
            this.ws.close(1000, 'Client disconnect');
            this.ws = null;
        }

        this.setState('disconnected');
    }

    private scheduleReconnect(): void {
        if (this.reconnectAttempts >= this.config.maxReconnectAttempts) {
            this.log('Max reconnection attempts reached');
            return;
        }

        this.setState('reconnecting');
        this.reconnectAttempts++;

        const delay = this.config.reconnectInterval * Math.pow(2, this.reconnectAttempts - 1);
        this.log(`Reconnecting in ${delay}ms (attempt ${this.reconnectAttempts})`);

        this.reconnectTimer = setTimeout(() => {
            this.connect().catch(() => {
                // Error handled in connect
            });
        }, delay);
    }

    private clearReconnectTimer(): void {
        if (this.reconnectTimer) {
            clearTimeout(this.reconnectTimer);
            this.reconnectTimer = null;
        }
    }

    // ─────────────────────────────────────────────────────────
    // Heartbeat
    // ─────────────────────────────────────────────────────────

    private startHeartbeat(): void {
        this.heartbeatTimer = setInterval(() => {
            if (this.ws?.readyState === WebSocket.OPEN) {
                this.send({ type: 'ping', timestamp: Date.now() });
            }
        }, this.config.heartbeatInterval);
    }

    private stopHeartbeat(): void {
        if (this.heartbeatTimer) {
            clearInterval(this.heartbeatTimer);
            this.heartbeatTimer = null;
        }
    }

    // ─────────────────────────────────────────────────────────
    // Message Handling
    // ─────────────────────────────────────────────────────────

    private handleMessage(event: MessageEvent): void {
        try {
            const data = JSON.parse(event.data);
            this.log('Received', data);

            // Handle system messages
            if (data.type === 'pong') {
                return;
            }

            // Route to channel subscribers
            if (data.channel) {
                const handlers = this.subscriptions.get(data.channel);
                handlers?.forEach(handler => {
                    try {
                        handler(data.payload);
                    } catch (error) {
                        console.error('Handler error:', error);
                    }
                });
            }

            // Route to wildcard subscribers
            const wildcardHandlers = this.subscriptions.get('*');
            wildcardHandlers?.forEach(handler => {
                try {
                    handler(data);
                } catch (error) {
                    console.error('Wildcard handler error:', error);
                }
            });

        } catch (error) {
            this.log('Failed to parse message', error);
        }
    }

    send(data: any): void {
        const message = JSON.stringify(data);

        if (this.ws?.readyState === WebSocket.OPEN) {
            this.ws.send(message);
            this.log('Sent', data);
        } else {
            this.log('Queued', data);
            this.messageQueue.push(message);
        }
    }

    private flushMessageQueue(): void {
        while (this.messageQueue.length > 0 && this.ws?.readyState === WebSocket.OPEN) {
            const message = this.messageQueue.shift();
            this.ws.send(message);
        }
    }

    // ─────────────────────────────────────────────────────────
    // Subscriptions
    // ─────────────────────────────────────────────────────────

    subscribe(channel: string, handler: MessageHandler): () => void {
        if (!this.subscriptions.has(channel)) {
            this.subscriptions.set(channel, new Set());
        }

        this.subscriptions.get(channel)!.add(handler);

        // Notify server of subscription
        if (this.ws?.readyState === WebSocket.OPEN) {
            this.send({
                type: 'subscribe',
                channel
            });
        }

        // Return unsubscribe function
        return () => {
            this.unsubscribe(channel, handler);
        };
    }

    unsubscribe(channel: string, handler: MessageHandler): void {
        const handlers = this.subscriptions.get(channel);

        if (handlers) {
            handlers.delete(handler);

            if (handlers.size === 0) {
                this.subscriptions.delete(channel);

                // Notify server
                if (this.ws?.readyState === WebSocket.OPEN) {
                    this.send({
                        type: 'unsubscribe',
                        channel
                    });
                }
            }
        }
    }

    private resubscribeAll(): void {
        for (const channel of this.subscriptions.keys()) {
            if (channel !== '*') {
                this.send({
                    type: 'subscribe',
                    channel
                });
            }
        }
    }
