// hooks/useWebSocket.ts
import { useState, useEffect, useCallback, useRef } from 'react';
import { getWebSocketManager } from '@/lib/websocket/WebSocketManager';

type ConnectionState = 'connecting' | 'connected' | 'disconnected' | 'reconnecting';

export function useWebSocket() {
    const [state, setState] = useState<ConnectionState>('disconnected');
    const wsRef = useRef(getWebSocketManager());

    useEffect(() => {
        const ws = wsRef.current;

        // Connect on mount
        ws.connect().catch(console.error);

        // Listen to state changes
        const unsubscribe = ws.onStateChange(setState);

        // Set initial state
        setState(ws.getState());

        return () => {
            unsubscribe();
        };
    }, []);

    const send = useCallback((data: any) => {
        wsRef.current.send(data);
    }, []);

    const subscribe = useCallback((channel: string, handler: (data: any) => void) => {
        return wsRef.current.subscribe(channel, handler);
    }, []);

    return {
        state,
        isConnected: state === 'connected',
        send,
        subscribe
    };
}

// hooks/useChannel.ts
import { useState, useEffect, useCallback } from 'react';
import { getWebSocketManager } from '@/lib/websocket/WebSocketManager';

interface UseChannelOptions<T> {
    channel: string;
    onMessage?: (data: T) => void;
    initialData?: T;
}

export function useChannel<T = any>({ channel, onMessage, initialData }: UseChannelOptions<T>) {
    const [data, setData] = useState<T | undefined>(initialData);
    const [error, setError] = useState<Error | null>(null);

    useEffect(() => {
        const ws = getWebSocketManager();

        const handler = (message: T) => {
            setData(message);
            onMessage?.(message);
        };

        const unsubscribe = ws.subscribe(channel, handler);

        return unsubscribe;
    }, [channel, onMessage]);

    const send = useCallback((payload: any) => {
        const ws = getWebSocketManager();
        ws.send({
            channel,
            payload
        });
    }, [channel]);

    return { data, error, send };
}

// hooks/usePresence.ts
interface PresenceUser {
    id: string;
    name: string;
    avatar?: string;
    status: 'online' | 'away' | 'offline';
    lastSeen: Date;
}

export function usePresence(roomId: string) {
    const [users, setUsers] = useState<PresenceUser[]>([]);
    const [myPresence, setMyPresence] = useState<Partial<PresenceUser>>({});

    useEffect(() => {
        const ws = getWebSocketManager();

        // Join presence room
        ws.send({
            type: 'presence:join',
            roomId
        });

        // Subscribe to presence updates
        const unsubscribe = ws.subscribe(`presence:${roomId}`, (data) => {
            switch (data.type) {
                case 'presence:sync':
                    setUsers(data.users);
                    break;
                case 'presence:join':
                    setUsers(prev => [...prev.filter(u => u.id !== data.user.id), data.user]);
                    break;
                case 'presence:leave':
                    setUsers(prev => prev.filter(u => u.id !== data.userId));
                    break;
                case 'presence:update':
                    setUsers(prev => prev.map(u =>
                        u.id === data.user.id ? { ...u, ...data.user } : u
                    ));
                    break;
            }
        });

        // Update own presence
        const updatePresence = () => {
            ws.send({
                type: 'presence:update',
                roomId,
                status: document.hidden ? 'away' : 'online'
            });
        };

        document.addEventListener('visibilitychange', updatePresence);

        // Heartbeat
        const heartbeat = setInterval(updatePresence, 30000);

        return () => {
            ws.send({
                type: 'presence:leave',
                roomId
            });
            unsubscribe();
            document.removeEventListener('visibilitychange', updatePresence);
            clearInterval(heartbeat);
        };
    }, [roomId]);

    const updateMyPresence = useCallback((update: Partial<PresenceUser>) => {
        setMyPresence(prev => ({ ...prev, ...update }));

        const ws = getWebSocketManager();
        ws.send({
            type: 'presence:update',
            roomId,
            ...update
        });
    }, [roomId]);

    return { users, myPresence, updateMyPresence };
}

