// hooks/useRealTimeFeed.ts
interface FeedUpdate {
    type: 'new_post' | 'update_post' | 'delete_post' | 'new_like' | 'new_comment';
    postId: string;
    data?: any;
}

export function useRealTimeFeed(userId: string) {
    const queryClient = useQueryClient();
    const { subscribe, isConnected } = useWebSocket();

    useEffect(() => {
        if (!isConnected) return;

        // Subscribe to user's feed channel
        const unsubscribe = subscribe(`feed:${userId}`, (update: FeedUpdate) => {
            switch (update.type) {
                case 'new_post':
                    // Add new post to the top of the feed
                    queryClient.setQueryData(['feed', userId], (old: any) => {
                        if (!old) return old;
                        return {
                            ...old,
                            pages: [
                                {
                                    ...old.pages[0],
                                    posts: [update.data, ...old.pages[0].posts]
                                },
                                ...old.pages.slice(1)
                            ]
                        };
                    });
                    break;

                case 'update_post':
                    // Update existing post
                    queryClient.setQueryData(['feed', userId], (old: any) => {
                        if (!old) return old;
                        return {
                            ...old,
                            pages: old.pages.map((page: any) => ({
                                ...page,
                                posts: page.posts.map((post: any) =>
                                    post.id === update.postId
                                        ? { ...post, ...update.data }
                                        : post
                                )
                            }))
                        };
                    });
                    break;

                case 'delete_post':
                    // Remove post from feed
                    queryClient.setQueryData(['feed', userId], (old: any) => {
                        if (!old) return old;
                        return {
                            ...old,
                            pages: old.pages.map((page: any) => ({
                                ...page,
                                posts: page.posts.filter((post: any) => post.id !== update.postId)
                            }))
                        };
                    });
                    break;

                case 'new_like':
                case 'new_comment':
                    // Invalidate to refresh engagement counts
                    queryClient.invalidateQueries({
                        queryKey: ['post', update.postId]
                    });
                    break;
            }
        });

        return unsubscribe;
    }, [userId, isConnected, subscribe, queryClient]);
}
