// hooks/useOnlineStatus.ts
export function useOnlineStatus(userIds: string[]) {
    const [onlineUsers, setOnlineUsers] = useState<Set<string>>(new Set());
    const { subscribe, send, isConnected } = useWebSocket();

    useEffect(() => {
        if (!isConnected || userIds.length === 0) return;

        // Request status for users
        send({
            type: 'status:query',
            userIds
        });

        // Subscribe to status updates
        const unsubscribe = subscribe('status', (data) => {
            if (data.type === 'status:batch') {
                setOnlineUsers(new Set(data.onlineUserIds));
            } else if (data.type === 'status:online') {
                setOnlineUsers(prev => new Set([...prev, data.userId]));
            } else if (data.type === 'status:offline') {
                setOnlineUsers(prev => {
                    const next = new Set(prev);
                    next.delete(data.userId);
                    return next;
                });
            }
        });

        return unsubscribe;
    }, [userIds.join(','), isConnected, subscribe, send]);

    const isOnline = useCallback((userId: string) => {
        return onlineUsers.has(userId);
    }, [onlineUsers]);

    return { onlineUsers, isOnline };
}

