// types/chat.ts
interface User {
    id: string;
    name: string;
    avatar: string;
    status: 'online' | 'away' | 'offline';
    lastSeen?: Date;
}

interface Conversation {
    id: string;
    type: 'direct' | 'group';
    name?: string; // For group chats
    avatar?: string; // For group chats
    participants: User[];
    lastMessage?: Message;
    unreadCount: number;
    isPinned: boolean;
    isMuted: boolean;
    createdAt: Date;
    updatedAt: Date;
}

interface Message {
    id: string;
    conversationId: string;
    senderId: string;
    type: 'text' | 'image' | 'video' | 'file' | 'audio' | 'system';
    content: string;
    media?: MediaAttachment[];
    replyTo?: Message;
    reactions: Reaction[];
    readBy: ReadReceipt[];
    status: 'sending' | 'sent' | 'delivered' | 'read' | 'failed';
    createdAt: Date;
    editedAt?: Date;
    deletedAt?: Date;
}

interface MediaAttachment {
    id: string;
    type: 'image' | 'video' | 'file' | 'audio';
    url: string;
    thumbnailUrl?: string;
    name: string;
    size: number;
    mimeType: string;
    duration?: number; // For audio/video
    width?: number;
    height?: number;
}

interface Reaction {
    emoji: string;
    userId: string;
    createdAt: Date;
}

interface ReadReceipt {
    userId: string;
    readAt: Date;
}

