// MESSAGE STORE WITH ZUSTAND
// ═══════════════════════════════════════════════════════════

// stores/chatStore.ts
import { create } from 'zustand';
import { immer } from 'zustand/middleware/immer';
import { persist } from 'zustand/middleware';

interface ChatState {
    conversations: Map<string, Conversation>;
    messages: Map<string, Message[]>;
    activeConversationId: string | null;
    draftMessages: Map<string, string>;

    // Actions
    setActiveConversation: (id: string | null) => void;
    addConversation: (conversation: Conversation) => void;
    updateConversation: (id: string, updates: Partial<Conversation>) => void;
    addMessage: (message: Message) => void;
    updateMessage: (id: string, updates: Partial<Message>) => void;
    deleteMessage: (id: string, conversationId: string) => void;
    addReaction: (messageId: string, emoji: string, userId: string) => void;
    removeReaction: (messageId: string, emoji: string, userId: string) => void;
    markAsRead: (conversationId: string) => void;
    setDraft: (conversationId: string, draft: string) => void;
}

export const useChatStore = create<ChatState>()(
    persist(
        immer((set, get) => ({
            conversations: new Map(),
            messages: new Map(),
            activeConversationId: null,
            draftMessages: new Map(),

            setActiveConversation: (id) => {
                set((state) => {
                    state.activeConversationId = id;
                });
            },

            addConversation: (conversation) => {
                set((state) => {
                    state.conversations.set(conversation.id, conversation);
                    if (!state.messages.has(conversation.id)) {
                        state.messages.set(conversation.id, []);
                    }
                });
            },

            updateConversation: (id, updates) => {
                set((state) => {
                    const conv = state.conversations.get(id);
                    if (conv) {
                        state.conversations.set(id, { ...conv, ...updates });
                    }
                });
            },

            addMessage: (message) => {
                set((state) => {
                    const messages = state.messages.get(message.conversationId) || [];

                    // Check for duplicate (optimistic update)
                    const existingIndex = messages.findIndex(m => m.id === message.id);
                    if (existingIndex >= 0) {
                        messages[existingIndex] = message;
                    } else {
                        messages.push(message);
                        // Sort by date
                        messages.sort((a, b) =>
                            new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()
                        );
                    }

                    state.messages.set(message.conversationId, messages);

                    // Update conversation's last message
                    const conv = state.conversations.get(message.conversationId);
                    if (conv) {
                        conv.lastMessage = message;
                        conv.updatedAt = new Date();
                    }
                });
            },

            updateMessage: (id, updates) => {
                set((state) => {
                    for (const [convId, messages] of state.messages) {
                        const index = messages.findIndex(m => m.id === id);
                        if (index >= 0) {
                            messages[index] = { ...messages[index], ...updates };
                            break;
                        }
                    }
                });
            },

            deleteMessage: (id, conversationId) => {
                set((state) => {
                    const messages = state.messages.get(conversationId);
                    if (messages) {
                        const index = messages.findIndex(m => m.id === id);
                        if (index >= 0) {
                            // Soft delete - mark as deleted
                            messages[index].deletedAt = new Date();
                            messages[index].content = 'This message was deleted';
                        }
                    }
                });
            },

            addReaction: (messageId, emoji, userId) => {
                set((state) => {
                    for (const messages of state.messages.values()) {
                        const message = messages.find(m => m.id === messageId);
                        if (message) {
                            const existingReaction = message.reactions.find(
                                r => r.emoji === emoji && r.userId === userId
                            );
                            if (!existingReaction) {
                                message.reactions.push({
                                    emoji,
                                    userId,
                                    createdAt: new Date()
                                });
                            }
                            break;
                        }
                    }
                });
            },

            removeReaction: (messageId, emoji, userId) => {
                set((state) => {
                    for (const messages of state.messages.values()) {
                        const message = messages.find(m => m.id === messageId);
                        if (message) {
                            message.reactions = message.reactions.filter(
                                r => !(r.emoji === emoji && r.userId === userId)
                            );
                            break;
                        }
                    }
                });
            },

            markAsRead: (conversationId) => {
                set((state) => {
                    const conv = state.conversations.get(conversationId);
                    if (conv) {
                        conv.unreadCount = 0;
                    }
                });
            },

            setDraft: (conversationId, draft) => {
                set((state) => {
                    if (draft) {
                        state.draftMessages.set(conversationId, draft);
                    } else {
                        state.draftMessages.delete(conversationId);
                    }
                });
            }
        })),
        {
            name: 'chat-storage',
            partialize: (state) => ({
                draftMessages: state.draftMessages
            })
        }
    )
);
