// OFFLINE STORAGE WITH INDEXEDDB
// ═══════════════════════════════════════════════════════════

// lib/offlineStorage.ts
import { openDB, DBSchema, IDBPDatabase } from 'idb';

interface ChatDB extends DBSchema {
    conversations: {
        key: string;
        value: Conversation;
        indexes: {
            'by-updated': Date;
        };
    };
    messages: {
        key: string;
        value: Message;
        indexes: {
            'by-conversation': string;
            'by-date': Date;
        };
    };
    pendingMessages: {
        key: string;
        value: Message & { retryCount: number };
    };
}

class OfflineStorage {
    private db: IDBPDatabase<ChatDB> | null = null;
    private dbName = 'chat-db';
    private version = 1;

    async init(): Promise<void> {
        this.db = await openDB<ChatDB>(this.dbName, this.version, {
            upgrade(db) {
                // Conversations store
                const conversationStore = db.createObjectStore('conversations', {
                    keyPath: 'id'
                });
                conversationStore.createIndex('by-updated', 'updatedAt');

                // Messages store
                const messageStore = db.createObjectStore('messages', {
                    keyPath: 'id'
                });
                messageStore.createIndex('by-conversation', 'conversationId');
                messageStore.createIndex('by-date', 'createdAt');

                // Pending messages (for offline sync)
                db.createObjectStore('pendingMessages', {
                    keyPath: 'id'
                });
            }
        });
    }

    // Conversations
    async saveConversation(conversation: Conversation): Promise<void> {
        await this.db?.put('conversations', conversation);
    }

    async getConversation(id: string): Promise<Conversation | undefined> {
        return this.db?.get('conversations', id);
    }

    async getAllConversations(): Promise<Conversation[]> {
        const conversations = await this.db?.getAllFromIndex(
            'conversations',
            'by-updated'
        );
        return conversations?.reverse() || [];
    }

    // Messages
    async saveMessage(message: Message): Promise<void> {
        await this.db?.put('messages', message);
    }

    async saveMessages(messages: Message[]): Promise<void> {
        const tx = this.db?.transaction('messages', 'readwrite');
        if (tx) {
            await Promise.all([
                ...messages.map(m => tx.store.put(m)),
                tx.done
            ]);
        }
    }

    async getMessages(conversationId: string, limit = 50, before?: Date): Promise<Message[]> {
        const index = this.db?.transaction('messages').store.index('by-conversation');
        const messages: Message[] = [];

        let cursor = await index?.openCursor(
            IDBKeyRange.only(conversationId),
            'prev'
        );

        while (cursor && messages.length < limit) {
            if (!before || new Date(cursor.value.createdAt) < before) {
                messages.push(cursor.value);
            }
            cursor = await cursor.continue();
        }

        return messages.reverse();
    }

    // Pending messages (offline queue)
    async addPendingMessage(message: Message): Promise<void> {
        await this.db?.put('pendingMessages', { ...message, retryCount: 0 });
    }

    async getPendingMessages(): Promise<(Message & { retryCount: number })[]> {
        return this.db?.getAll('pendingMessages') || [];
    }

    async removePendingMessage(id: string): Promise<void> {
        await this.db?.delete('pendingMessages', id);
    }

    async updatePendingMessageRetry(id: string): Promise<void> {
        const message = await this.db?.get('pendingMessages', id);
        if (message) {
            message.retryCount++;
            await this.db?.put('pendingMessages', message);
        }
    }

    // Clear all data
    async clear(): Promise<void> {
        await this.db?.clear('conversations');
        await this.db?.clear('messages');
        await this.db?.clear('pendingMessages');
    }
}

export const offlineStorage = new OfflineStorage();

// ═══════════════════════════════════════════════════════════
// SYNC MANAGER FOR OFFLINE SUPPORT
// ═══════════════════════════════════════════════════════════

// lib/syncManager.ts
class SyncManager {
    private isSyncing = false;
    private syncQueue: (() => Promise<void>)[] = [];

    constructor() {
        // Listen for online status
        if (typeof window !== 'undefined') {
            window.addEventListener('online', () => this.syncPendingMessages());
        }
    }

    async syncPendingMessages(): Promise<void> {
        if (this.isSyncing) return;

        this.isSyncing = true;

        try {
            const pendingMessages = await offlineStorage.getPendingMessages();

            for (const message of pendingMessages) {
                if (message.retryCount >= 3) {
                    // Mark as failed after 3 retries
                    useChatStore.getState().updateMessage(message.id, {
                        status: 'failed'
                    });
                    await offlineStorage.removePendingMessage(message.id);
                    continue;
                }

                try {
                    await this.sendMessage(message);
                    await offlineStorage.removePendingMessage(message.id);
                } catch (error) {
                    await offlineStorage.updatePendingMessageRetry(message.id);
                }
            }
        } finally {
            this.isSyncing = false;
        }
    }

    private async sendMessage(message: Message): Promise<void> {
        const response = await fetch('/api/messages', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(message)
        });

        if (!response.ok) {
            throw new Error('Failed to send message');
        }

        const sentMessage = await response.json();
        useChatStore.getState().updateMessage(message.id, {
            ...sentMessage,
            status: 'sent'
        });
    }

    async queueMessage(message: Message): Promise<void> {
        // Save to offline storage first
        await offlineStorage.addPendingMessage(message);

        // Try to send immediately if online
        if (navigator.onLine) {
            this.syncPendingMessages();
        }
    }
}

export const syncManager = new SyncManager();
