// components/MessageComposer.tsx
'use client';

import { useState, useRef, useEffect, useCallback } from 'react';
import { useChatStore } from '@/stores/chatStore';
import { useTypingIndicator } from '@/hooks/useTypingIndicator';
import { syncManager } from '@/lib/syncManager';

interface MessageComposerProps {
    conversationId: string;
    replyTo?: Message;
    onCancelReply?: () => void;
}

export function MessageComposer({
    conversationId,
    replyTo,
    onCancelReply
}: MessageComposerProps) {
    const [content, setContent] = useState('');
    const [attachments, setAttachments] = useState<File[]>([]);
    const [isUploading, setIsUploading] = useState(false);
    const [isSending, setIsSending] = useState(false);
    const textareaRef = useRef<HTMLTextAreaElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const { handleTyping, stopTyping } = useTypingIndicator(conversationId);
    const { addMessage, setDraft, draftMessages } = useChatStore();

    // Load draft on mount
    useEffect(() => {
        const draft = draftMessages.get(conversationId);
        if (draft) {
            setContent(draft);
        }
    }, [conversationId, draftMessages]);

    // Save draft on change
    useEffect(() => {
        const timeout = setTimeout(() => {
            setDraft(conversationId, content);
        }, 500);

        return () => clearTimeout(timeout);
    }, [content, conversationId, setDraft]);

    // Auto-resize textarea
    useEffect(() => {
        const textarea = textareaRef.current;
        if (textarea) {
            textarea.style.height = 'auto';
            textarea.style.height = `${Math.min(textarea.scrollHeight, 200)}px`;
        }
    }, [content]);

    const handleChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
        setContent(e.target.value);
        handleTyping();
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            handleSend();
        }
    };

    const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const files = Array.from(e.target.files || []);
        if (files.length === 0) return;

        // Validate files
        const maxSize = 25 * 1024 * 1024; // 25MB
        const validFiles = files.filter(file => {
            if (file.size > maxSize) {
                alert(`File ${file.name} is too large. Maximum size is 25MB.`);
                return false;
            }
            return true;
        });

        setAttachments(prev => [...prev, ...validFiles]);

        // Reset input
        if (fileInputRef.current) {
            fileInputRef.current.value = '';
        }
    };

    const removeAttachment = (index: number) => {
        setAttachments(prev => prev.filter((_, i) => i !== index));
    };

    const uploadAttachments = async (): Promise<MediaAttachment[]> => {
        if (attachments.length === 0) return [];

        setIsUploading(true);

        try {
            const uploadPromises = attachments.map(async (file) => {
                const formData = new FormData();
                formData.append('file', file);

                const response = await fetch('/api/upload', {
                    method: 'POST',
                    body: formData
                });

                if (!response.ok) {
                    throw new Error(`Failed to upload ${file.name}`);
                }

                return response.json();
            });

            return Promise.all(uploadPromises);
        } finally {
            setIsUploading(false);
        }
    };

    const handleSend = async () => {
        const trimmedContent = content.trim();
        if (!trimmedContent && attachments.length === 0) return;

        setIsSending(true);
        stopTyping();

        try {
            // Upload attachments first
            const media = await uploadAttachments();

            // Create optimistic message
            const tempId = `temp-${Date.now()}`;
            const message: Message = {
                id: tempId,
                conversationId,
                senderId: 'current-user-id', // Get from auth context
                type: media.length > 0 ? media[0].type : 'text',
                content: trimmedContent,
                media: media.length > 0 ? media : undefined,
                replyTo: replyTo,
                reactions: [],
                readBy: [],
                status: 'sending',
                createdAt: new Date()
            };

            // Add optimistic message to store
            addMessage(message);

            // Clear input
            setContent('');
            setAttachments([]);
            setDraft(conversationId, '');
            onCancelReply?.();

            // Queue for sending
            await syncManager.queueMessage(message);

        } catch (error) {
            console.error('Failed to send message:', error);
            // Show error toast
        } finally {
            setIsSending(false);
        }
    };

    return (
        <div className="message-composer">
            {/* Reply preview */}
            {replyTo && (
                <div className="reply-preview">
                    <div className="reply-content">
                        <span className="reply-author">{replyTo.senderId}</span>
                        <span className="reply-text">{replyTo.content}</span>
                    </div>
                    <button onClick={onCancelReply} aria-label="Cancel reply">
                        <XIcon className="w-4 h-4" />
                    </button>
                </div>
            )}

            {/* Attachments preview */}
            {attachments.length > 0 && (
                <div className="attachments-preview">
                    {attachments.map((file, index) => (
                        <div key={index} className="attachment-item">
                            {file.type.startsWith('image/') ? (
                                <img
                                    src={URL.createObjectURL(file)}
                                    alt={file.name}
                                    className="attachment-thumbnail"
                                />
                            ) : (
                                <div className="attachment-file">
                                    <FileIcon className="w-6 h-6" />
                                    <span>{file.name}</span>
                                </div>
                            )}
                            <button
                                onClick={() => removeAttachment(index)}
                                className="remove-attachment"
                                aria-label={`Remove ${file.name}`}
                            >
                                <XIcon className="w-4 h-4" />
                            </button>
                        </div>
                    ))}
                </div>
            )}

            {/* Input area */}
            <div className="composer-input-area">
                <button
                    onClick={() => fileInputRef.current?.click()}
                    className="attach-button"
                    aria-label="Attach file"
                    disabled={isUploading}
                >
                    <PaperclipIcon className="w-5 h-5" />
                </button>

                <input
                    ref={fileInputRef}
                    type="file"
                    multiple
                    accept="image/*,video/*,audio/*,.pdf,.doc,.docx,.xls,.xlsx"
                    onChange={handleFileSelect}
                    className="hidden"
                />

                <textarea
                    ref={textareaRef}
                    value={content}
                    onChange={handleChange}
                    onKeyDown={handleKeyDown}
                    placeholder="Type a message..."
                    rows={1}
                    className="composer-textarea"
                    disabled={isSending}
                />

                <button
                    onClick={handleSend}
                    disabled={isSending || isUploading || (!content.trim() && attachments.length === 0)}
                    className="send-button"
                    aria-label="Send message"
                >
                    {isSending || isUploading ? (
                        <SpinnerIcon className="w-5 h-5 animate-spin" />
                    ) : (
                        <SendIcon className="w-5 h-5" />
                    )}
                </button>
            </div>
        </div>
    );
}
