// components/MessageThread.tsx
'use client';

import { useRef, useEffect, useCallback, useState } from 'react';
import { useVirtualizer } from '@tanstack/react-virtual';
import { useChatStore } from '@/stores/chatStore';
import { useInfiniteQuery } from '@tanstack/react-query';
import { MessageBubble } from './MessageBubble';
import { DateDivider } from './DateDivider';
import { TypingIndicator } from './TypingIndicator';
import { useTypingIndicator } from '@/hooks/useTypingIndicator';

interface MessageThreadProps {
    conversationId: string;
}

export function MessageThread({ conversationId }: MessageThreadProps) {
    const parentRef = useRef<HTMLDivElement>(null);
    const [replyTo, setReplyTo] = useState<Message | null>(null);
    const { typingUsers } = useTypingIndicator(conversationId);

    // Fetch messages with pagination
    const {
        data,
        fetchNextPage,
        hasNextPage,
        isFetchingNextPage,
        isLoading
    } = useInfiniteQuery({
        queryKey: ['messages', conversationId],
        queryFn: async ({ pageParam }) => {
            const response = await fetch(
                `/api/conversations/${conversationId}/messages?cursor=${pageParam || ''}`
            );
            return response.json();
        },
        getNextPageParam: (lastPage) => lastPage.nextCursor,
        initialPageParam: ''
    });

    // Flatten messages with date dividers
    const items = useMemo(() => {
        const messages = data?.pages.flatMap(p => p.messages) || [];
        const result: (Message | { type: 'date'; date: Date })[] = [];

        let lastDate: string | null = null;

        for (const message of messages) {
            const messageDate = new Date(message.createdAt).toDateString();

            if (messageDate !== lastDate) {
                result.push({ type: 'date', date: new Date(message.createdAt) });
                lastDate = messageDate;
            }

            result.push(message);
        }

        return result;
    }, [data]);

    // Virtual list
    const virtualizer = useVirtualizer({
        count: items.length,
        getScrollElement: () => parentRef.current,
        estimateSize: (index) => {
            const item = items[index];
            if ('type' in item && item.type === 'date') return 40;
            return 80; // Estimate message height
        },
        overscan: 10
    });

    // Scroll to bottom on new messages
    const scrollToBottom = useCallback(() => {
        if (parentRef.current) {
            parentRef.current.scrollTop = parentRef.current.scrollHeight;
        }
    }, []);

    // Auto-scroll when new messages arrive
    useEffect(() => {
        const isAtBottom = parentRef.current &&
            parentRef.current.scrollHeight - parentRef.current.scrollTop <=
            parentRef.current.clientHeight + 100;

        if (isAtBottom) {
            scrollToBottom();
        }
    }, [items.length, scrollToBottom]);

    // Load more when scrolling to top
    const handleScroll = useCallback(() => {
        if (!parentRef.current) return;

        if (parentRef.current.scrollTop < 100 && hasNextPage && !isFetchingNextPage) {
            fetchNextPage();
        }
    }, [fetchNextPage, hasNextPage, isFetchingNextPage]);

    if (isLoading) {
        return <MessageThreadSkeleton />;
    }

    return (
        <div className="message-thread">
            <div
                ref={parentRef}
                className="message-list"
                onScroll={handleScroll}
            >
                {isFetchingNextPage && (
                    <div className="loading-more">
                        <SpinnerIcon className="w-5 h-5 animate-spin" />
                    </div>
                )}

                <div
                    style={{
                        height: `${virtualizer.getTotalSize()}px`,
                        position: 'relative'
                    }}
                >
                    {virtualizer.getVirtualItems().map(virtualRow => {
                        const item = items[virtualRow.index];

                        if ('type' in item && item.type === 'date') {
                            return (
                                <div
                                    key={`date-${item.date.getTime()}`}
                                    style={{
                                        position: 'absolute',
                                        top: 0,
                                        left: 0,
                                        width: '100%',
                                        transform: `translateY(${virtualRow.start}px)`
                                    }}
                                >
                                    <DateDivider date={item.date} />
                                </div>
                            );
                        }

                        return (
                            <div
                                key={item.id}
                                style={{
                                    position: 'absolute',
                                    top: 0,
                                    left: 0,
                                    width: '100%',
                                    transform: `translateY(${virtualRow.start}px)`
                                }}
                            >
                                <MessageBubble
                                    message={item}
                                    onReply={() => setReplyTo(item)}
                                />
                            </div>
                        );
                    })}
                </div>

                {typingUsers.length > 0 && (
                    <TypingIndicator users={typingUsers} />
                )}
            </div>

            <MessageComposer
                conversationId={conversationId}
                replyTo={replyTo}
                onCancelReply={() => setReplyTo(null)}
            />
        </div>
    );
}
