// components/MessageBubble.tsx
'use client';

import { useState, useRef } from 'react';
import { formatTime } from '@/lib/utils';
import { useAuth } from '@/contexts/AuthContext';
import { MessageReactions } from './MessageReactions';
import { MessageMenu } from './MessageMenu';

interface MessageBubbleProps {
    message: Message;
    onReply: () => void;
}

export function MessageBubble({ message, onReply }: MessageBubbleProps) {
    const { user } = useAuth();
    const [showMenu, setShowMenu] = useState(false);
    const menuRef = useRef<HTMLDivElement>(null);

    const isOwn = message.senderId === user?.id;
    const isDeleted = !!message.deletedAt;

    const handleContextMenu = (e: React.MouseEvent) => {
        e.preventDefault();
        setShowMenu(true);
    };

    return (
        <div
            className={`message-bubble ${isOwn ? 'own' : 'other'}`}
            onContextMenu={handleContextMenu}
        >
            {!isOwn && (
                <img
                    src={message.senderAvatar}
                    alt=""
                    className="sender-avatar"
                />
            )}

            <div className="bubble-content">
                {/* Reply reference */}
                {message.replyTo && (
                    <div className="reply-reference">
                        <span className="reply-author">{message.replyTo.senderId}</span>
                        <span className="reply-preview">{message.replyTo.content}</span>
                    </div>
                )}

                {/* Message content */}
                {isDeleted ? (
                    <p className="deleted-message">
                        <i>This message was deleted</i>
                    </p>
                ) : (
                    <>
                        {message.content && (
                            <p className="message-text">{message.content}</p>
                        )}

                        {/* Media attachments */}
                        {message.media && message.media.length > 0 && (
                            <MediaGrid media={message.media} />
                        )}
                    </>
                )}

                {/* Metadata */}
                <div className="message-meta">
                    <span className="message-time">
                        {formatTime(message.createdAt)}
                    </span>

                    {isOwn && (
                        <MessageStatus status={message.status} />
                    )}

                    {message.editedAt && (
                        <span className="edited-indicator">edited</span>
                    )}
                </div>

                {/* Reactions */}
                {message.reactions.length > 0 && (
                    <MessageReactions
                        reactions={message.reactions}
                        messageId={message.id}
                    />
                )}
            </div>

            {/* Context menu */}
            {showMenu && (
                <MessageMenu
                    ref={menuRef}
                    message={message}
                    isOwn={isOwn}
                    onReply={onReply}
                    onClose={() => setShowMenu(false)}
                />
            )}
        </div>
    );
}

// Message status indicator
function MessageStatus({ status }: { status: Message['status'] }) {
    switch (status) {
        case 'sending':
            return <ClockIcon className="w-3 h-3 text-gray-400" />;
        case 'sent':
            return <CheckIcon className="w-3 h-3 text-gray-400" />;
        case 'delivered':
            return <CheckCheckIcon className="w-3 h-3 text-gray-400" />;
        case 'read':
            return <CheckCheckIcon className="w-3 h-3 text-blue-500" />;
        case 'failed':
            return <AlertCircleIcon className="w-3 h-3 text-red-500" />;
        default:
            return null;
    }
}

// Media grid component
function MediaGrid({ media }: { media: MediaAttachment[] }) {
    const [selectedMedia, setSelectedMedia] = useState<MediaAttachment | null>(null);

    const gridClass = media.length === 1 ? 'single' :
                      media.length === 2 ? 'double' :
                      media.length === 3 ? 'triple' : 'quad';

    return (
        <>
            <div className={`media-grid ${gridClass}`}>
                {media.slice(0, 4).map((item, index) => (
                    <button
                        key={item.id}
                        className="media-item"
                        onClick={() => setSelectedMedia(item)}
                    >
                        {item.type === 'image' ? (
                            <img
                                src={item.thumbnailUrl || item.url}
                                alt={item.name}
                                loading="lazy"
                            />
                        ) : item.type === 'video' ? (
                            <div className="video-thumbnail">
                                <img src={item.thumbnailUrl} alt={item.name} />
                                <PlayIcon className="play-icon" />
                            </div>
                        ) : (
                            <FileAttachment file={item} />
                        )}

                        {index === 3 && media.length > 4 && (
                            <div className="more-overlay">
                                +{media.length - 4}
                            </div>
                        )}
                    </button>
                ))}
            </div>

            {selectedMedia && (
                <MediaLightbox
                    media={media}
                    initialIndex={media.indexOf(selectedMedia)}
                    onClose={() => setSelectedMedia(null)}
                />
            )}
        </>
    );
}

