// components/MessageReactions.tsx
'use client';

import { useState } from 'react';
import { useChatStore } from '@/stores/chatStore';
import { useAuth } from '@/contexts/AuthContext';
import EmojiPicker from 'emoji-picker-react';

interface MessageReactionsProps {
    reactions: Reaction[];
    messageId: string;
}

export function MessageReactions({ reactions, messageId }: MessageReactionsProps) {
    const { user } = useAuth();
    const [showPicker, setShowPicker] = useState(false);
    const { addReaction, removeReaction } = useChatStore();

    // Group reactions by emoji
    const groupedReactions = reactions.reduce((acc, reaction) => {
        if (!acc[reaction.emoji]) {
            acc[reaction.emoji] = [];
        }
        acc[reaction.emoji].push(reaction.userId);
        return acc;
    }, {} as Record<string, string[]>);

    const handleReactionClick = (emoji: string, userIds: string[]) => {
        if (user && userIds.includes(user.id)) {
            removeReaction(messageId, emoji, user.id);
            // Send to server
            fetch(`/api/messages/${messageId}/reactions`, {
                method: 'DELETE',
                body: JSON.stringify({ emoji })
            });
        } else if (user) {
            addReaction(messageId, emoji, user.id);
            // Send to server
            fetch(`/api/messages/${messageId}/reactions`, {
                method: 'POST',
                body: JSON.stringify({ emoji })
            });
        }
    };

    const handleEmojiSelect = (emojiData: any) => {
        if (user) {
            addReaction(messageId, emojiData.emoji, user.id);
            fetch(`/api/messages/${messageId}/reactions`, {
                method: 'POST',
                body: JSON.stringify({ emoji: emojiData.emoji })
            });
        }
        setShowPicker(false);
    };

    return (
        <div className="message-reactions">
            {Object.entries(groupedReactions).map(([emoji, userIds]) => (
                <button
                    key={emoji}
                    className={`reaction-chip ${user && userIds.includes(user.id) ? 'selected' : ''}`}
                    onClick={() => handleReactionClick(emoji, userIds)}
                >
                    <span className="emoji">{emoji}</span>
                    <span className="count">{userIds.length}</span>
                </button>
            ))}

            <button
                className="add-reaction-btn"
                onClick={() => setShowPicker(!showPicker)}
                aria-label="Add reaction"
            >
                <SmileIcon className="w-4 h-4" />
            </button>

            {showPicker && (
                <div className="emoji-picker-wrapper">
                    <EmojiPicker
                        onEmojiClick={handleEmojiSelect}
                        searchDisabled
                        skinTonesDisabled
                        previewConfig={{ showPreview: false }}
                    />
                </div>
            )}
        </div>
    );
}
