// contexts/AnalyticsContext.tsx
'use client';

import { createContext, useContext, useReducer, ReactNode, useMemo, useCallback } from 'react';

interface AnalyticsState {
    filters: AnalyticsFilters;
    isLive: boolean;
    refreshInterval: number;
    selectedMetrics: string[];
}

type AnalyticsAction =
    | { type: 'SET_DATE_RANGE'; payload: DateRange }
    | { type: 'SET_FILTERS'; payload: Partial<AnalyticsFilters> }
    | { type: 'TOGGLE_LIVE'; payload?: boolean }
    | { type: 'SET_REFRESH_INTERVAL'; payload: number }
    | { type: 'SET_SELECTED_METRICS'; payload: string[] };

const initialState: AnalyticsState = {
    filters: {
        dateRange: {
            start: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000),
            end: new Date(),
            preset: '7d'
        }
    },
    isLive: true,
    refreshInterval: 30000, // 30 seconds
    selectedMetrics: ['revenue', 'users', 'orders', 'conversion']
};

function analyticsReducer(state: AnalyticsState, action: AnalyticsAction): AnalyticsState {
    switch (action.type) {
        case 'SET_DATE_RANGE':
            return {
                ...state,
                filters: { ...state.filters, dateRange: action.payload }
            };
        case 'SET_FILTERS':
            return {
                ...state,
                filters: { ...state.filters, ...action.payload }
            };
        case 'TOGGLE_LIVE':
            return {
                ...state,
                isLive: action.payload ?? !state.isLive
            };
        case 'SET_REFRESH_INTERVAL':
            return {
                ...state,
                refreshInterval: action.payload
            };
        case 'SET_SELECTED_METRICS':
            return {
                ...state,
                selectedMetrics: action.payload
            };
        default:
            return state;
    }
}

interface AnalyticsContextValue {
    state: AnalyticsState;
    setDateRange: (range: DateRange) => void;
    setFilters: (filters: Partial<AnalyticsFilters>) => void;
    toggleLive: (isLive?: boolean) => void;
    setRefreshInterval: (interval: number) => void;
    setSelectedMetrics: (metrics: string[]) => void;
}

const AnalyticsContext = createContext<AnalyticsContextValue | null>(null);

export function AnalyticsProvider({ children }: { children: ReactNode }) {
    const [state, dispatch] = useReducer(analyticsReducer, initialState);

    const setDateRange = useCallback((range: DateRange) => {
        dispatch({ type: 'SET_DATE_RANGE', payload: range });
    }, []);

    const setFilters = useCallback((filters: Partial<AnalyticsFilters>) => {
        dispatch({ type: 'SET_FILTERS', payload: filters });
    }, []);

    const toggleLive = useCallback((isLive?: boolean) => {
        dispatch({ type: 'TOGGLE_LIVE', payload: isLive });
    }, []);

    const setRefreshInterval = useCallback((interval: number) => {
        dispatch({ type: 'SET_REFRESH_INTERVAL', payload: interval });
    }, []);

    const setSelectedMetrics = useCallback((metrics: string[]) => {
        dispatch({ type: 'SET_SELECTED_METRICS', payload: metrics });
    }, []);

    const value = useMemo(() => ({
        state,
        setDateRange,
        setFilters,
        toggleLive,
        setRefreshInterval,
        setSelectedMetrics
    }), [state, setDateRange, setFilters, toggleLive, setRefreshInterval, setSelectedMetrics]);

    return (
        <AnalyticsContext.Provider value={value}>
            {children}
        </AnalyticsContext.Provider>
    );
}

export function useAnalytics() {
    const context = useContext(AnalyticsContext);
    if (!context) {
        throw new Error('useAnalytics must be used within AnalyticsProvider');
    }
    return context;
}
