// hooks/useSSEMetrics.ts
import { useState, useEffect, useRef, useCallback } from 'react';

interface SSEMetric {
    id: string;
    value: number;
    timestamp: Date;
}

interface UseSSEMetricsOptions {
    url: string;
    enabled?: boolean;
    onMessage?: (metric: SSEMetric) => void;
    onError?: (error: Event) => void;
}

export function useSSEMetrics({
    url,
    enabled = true,
    onMessage,
    onError
}: UseSSEMetricsOptions) {
    const [metrics, setMetrics] = useState<Map<string, SSEMetric>>(new Map());
    const [isConnected, setIsConnected] = useState(false);
    const [error, setError] = useState<Error | null>(null);
    const eventSourceRef = useRef<EventSource | null>(null);
    const reconnectTimeoutRef = useRef<NodeJS.Timeout | null>(null);
    const reconnectAttempts = useRef(0);

    const connect = useCallback(() => {
        if (!enabled) return;

        // Clean up existing connection
        if (eventSourceRef.current) {
            eventSourceRef.current.close();
        }

        try {
            const eventSource = new EventSource(url);
            eventSourceRef.current = eventSource;

            eventSource.onopen = () => {
                setIsConnected(true);
                setError(null);
                reconnectAttempts.current = 0;
            };

            eventSource.onmessage = (event) => {
                try {
                    const data = JSON.parse(event.data) as SSEMetric;
                    data.timestamp = new Date(data.timestamp);

                    setMetrics(prev => {
                        const next = new Map(prev);
                        next.set(data.id, data);
                        return next;
                    });

                    onMessage?.(data);
                } catch (e) {
                    console.error('Failed to parse SSE message:', e);
                }
            };

            eventSource.onerror = (event) => {
                setIsConnected(false);
                setError(new Error('SSE connection error'));
                onError?.(event);

                // Reconnect with exponential backoff
                const delay = Math.min(1000 * Math.pow(2, reconnectAttempts.current), 30000);
                reconnectAttempts.current++;

                reconnectTimeoutRef.current = setTimeout(connect, delay);
            };

        } catch (e) {
            setError(e as Error);
        }
    }, [url, enabled, onMessage, onError]);

    const disconnect = useCallback(() => {
        if (reconnectTimeoutRef.current) {
            clearTimeout(reconnectTimeoutRef.current);
        }
        if (eventSourceRef.current) {
            eventSourceRef.current.close();
            eventSourceRef.current = null;
        }
        setIsConnected(false);
    }, []);

    useEffect(() => {
        connect();
        return disconnect;
    }, [connect, disconnect]);

    const getMetric = useCallback((id: string) => {
        return metrics.get(id);
    }, [metrics]);

    return {
        metrics,
        getMetric,
        isConnected,
        error,
        reconnect: connect
    };
}

