// hooks/useKPIData.ts
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { useSSEMetrics } from './useSSEMetrics';
import { useAnalytics } from '@/contexts/AnalyticsContext';

export function useKPIData() {
    const { state } = useAnalytics();
    const queryClient = useQueryClient();

    // Fetch initial/historical data
    const { data: kpis, isLoading, error } = useQuery({
        queryKey: ['kpis', state.filters.dateRange],
        queryFn: async () => {
            const params = new URLSearchParams({
                start: state.filters.dateRange.start.toISOString(),
                end: state.filters.dateRange.end.toISOString()
            });
            const response = await fetch(`/api/analytics/kpis?${params}`);
            return response.json() as Promise<KPIMetric[]>;
        },
        staleTime: 30000
    });

    // Subscribe to real-time updates
    useSSEMetrics({
        url: '/api/analytics/stream',
        enabled: state.isLive,
        onMessage: (metric) => {
            queryClient.setQueryData(['kpis', state.filters.dateRange], (old: KPIMetric[] | undefined) => {
                if (!old) return old;

                return old.map(kpi => {
                    if (kpi.id === metric.id) {
                        const change = ((metric.value - kpi.previousValue) / kpi.previousValue) * 100;
                        return {
                            ...kpi,
                            value: metric.value,
                            change,
                            changeType: change > 0 ? 'increase' : change < 0 ? 'decrease' : 'neutral',
                            trend: [...kpi.trend.slice(1), metric.value]
                        };
                    }
                    return kpi;
                });
            });
        }
    });

    return { kpis, isLoading, error };
}

