// components/TrendIndicator.tsx
interface TrendIndicatorProps {
    value: number;
    type: 'increase' | 'decrease' | 'neutral';
}

export function TrendIndicator({ value, type }: TrendIndicatorProps) {
    const color = type === 'increase' ? 'text-green-500' :
                  type === 'decrease' ? 'text-red-500' : 'text-gray-500';

    const Icon = type === 'increase' ? ArrowUpIcon :
                 type === 'decrease' ? ArrowDownIcon : MinusIcon;

    return (
        <div className={`trend-indicator ${color}`}>
            <Icon className="w-4 h-4" />
            <span>{Math.abs(value).toFixed(1)}%</span>
        </div>
    );
}

// components/SparklineChart.tsx
import { useMemo } from 'react';

interface SparklineChartProps {
    data: number[];
    color: string;
    height: number;
    width?: number;
}

export function SparklineChart({
    data,
    color,
    height,
    width = 100
}: SparklineChartProps) {
    const path = useMemo(() => {
        if (data.length < 2) return '';

        const min = Math.min(...data);
        const max = Math.max(...data);
        const range = max - min || 1;

        const points = data.map((value, index) => {
            const x = (index / (data.length - 1)) * width;
            const y = height - ((value - min) / range) * height;
            return `${x},${y}`;
        });

        return `M${points.join(' L')}`;
    }, [data, height, width]);

    return (
        <svg width={width} height={height} className="sparkline">
            <path
                d={path}
                fill="none"
                stroke={color}
                strokeWidth={2}
                strokeLinecap="round"
                strokeLinejoin="round"
            />
        </svg>
    );
}
