// components/AnalyticsChart.tsx
'use client';

import { useMemo, useState, useCallback } from 'react';
import {
    LineChart,
    Line,
    AreaChart,
    Area,
    BarChart,
    Bar,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    Legend,
    ResponsiveContainer,
    Brush
} from 'recharts';
import { useAnalytics } from '@/contexts/AnalyticsContext';
import { formatDate, formatNumber, formatCurrency } from '@/lib/formatters';

type ChartType = 'line' | 'area' | 'bar';

interface AnalyticsChartProps {
    data: TimeSeriesData[];
    title: string;
    chartType?: ChartType;
    yAxisFormat?: 'number' | 'currency' | 'percentage';
    showBrush?: boolean;
    height?: number;
}

export function AnalyticsChart({
    data,
    title,
    chartType = 'line',
    yAxisFormat = 'number',
    showBrush = false,
    height = 400
}: AnalyticsChartProps) {
    const [selectedSeries, setSelectedSeries] = useState<Set<string>>(
        new Set(data.map(d => d.id))
    );
    const [activePoint, setActivePoint] = useState<any>(null);

    // Transform data for recharts
    const chartData = useMemo(() => {
        if (data.length === 0) return [];

        // Get all unique timestamps
        const allTimestamps = new Set<string>();
        data.forEach(series => {
            series.data.forEach(point => {
                allTimestamps.add(point.timestamp.toISOString());
            });
        });

        // Create merged data points
        return Array.from(allTimestamps)
            .sort()
            .map(timestamp => {
                const point: any = { timestamp: new Date(timestamp) };

                data.forEach(series => {
                    const dataPoint = series.data.find(
                        d => d.timestamp.toISOString() === timestamp
                    );
                    point[series.id] = dataPoint?.value ?? null;
                });

                return point;
            });
    }, [data]);

    // Toggle series visibility
    const toggleSeries = useCallback((seriesId: string) => {
        setSelectedSeries(prev => {
            const next = new Set(prev);
            if (next.has(seriesId)) {
                next.delete(seriesId);
            } else {
                next.add(seriesId);
            }
            return next;
        });
    }, []);

    // Format Y axis
    const formatYAxis = useCallback((value: number) => {
        switch (yAxisFormat) {
            case 'currency':
                return formatCurrency(value, { compact: true });
            case 'percentage':
                return `${value}%`;
            default:
                return formatNumber(value, { compact: true });
        }
    }, [yAxisFormat]);

    // Custom tooltip
    const CustomTooltip = ({ active, payload, label }: any) => {
        if (!active || !payload) return null;

        return (
            <div className="chart-tooltip">
                <p className="tooltip-label">{formatDate(label, 'PPp')}</p>
                {payload.map((entry: any) => (
                    <p
                        key={entry.dataKey}
                        className="tooltip-value"
                        style={{ color: entry.color }}
                    >
                        {entry.name}: {yAxisFormat === 'currency'
                            ? formatCurrency(entry.value)
                            : formatNumber(entry.value)}
                    </p>
                ))}
            </div>
        );
    };

    // Render chart based on type
    const renderChart = () => {
        const commonProps = {
            data: chartData,
            margin: { top: 10, right: 30, left: 0, bottom: 0 }
        };

        const renderSeries = (SeriesComponent: any, additionalProps = {}) => {
            return data
                .filter(series => selectedSeries.has(series.id))
                .map(series => (
                    <SeriesComponent
                        key={series.id}
                        type="monotone"
                        dataKey={series.id}
                        name={series.name}
                        stroke={series.color}
                        fill={series.color}
                        {...additionalProps}
                    />
                ));
        };

        switch (chartType) {
            case 'area':
                return (
                    <AreaChart {...commonProps}>
                        <CartesianGrid strokeDasharray="3 3" />
                        <XAxis
                            dataKey="timestamp"
                            tickFormatter={(ts) => formatDate(ts, 'MMM d')}
                        />
                        <YAxis tickFormatter={formatYAxis} />
                        <Tooltip content={<CustomTooltip />} />
                        <Legend onClick={(e) => toggleSeries(e.dataKey as string)} />
                        {renderSeries(Area, { fillOpacity: 0.3 })}
                        {showBrush && <Brush dataKey="timestamp" height={30} />}
                    </AreaChart>
                );

            case 'bar':
                return (
                    <BarChart {...commonProps}>
                        <CartesianGrid strokeDasharray="3 3" />
                        <XAxis
                            dataKey="timestamp"
                            tickFormatter={(ts) => formatDate(ts, 'MMM d')}
                        />
                        <YAxis tickFormatter={formatYAxis} />
                        <Tooltip content={<CustomTooltip />} />
                        <Legend onClick={(e) => toggleSeries(e.dataKey as string)} />
                        {renderSeries(Bar)}
                        {showBrush && <Brush dataKey="timestamp" height={30} />}
                    </BarChart>
                );

            default:
                return (
                    <LineChart {...commonProps}>
                        <CartesianGrid strokeDasharray="3 3" />
                        <XAxis
                            dataKey="timestamp"
                            tickFormatter={(ts) => formatDate(ts, 'MMM d')}
                        />
                        <YAxis tickFormatter={formatYAxis} />
                        <Tooltip content={<CustomTooltip />} />
                        <Legend onClick={(e) => toggleSeries(e.dataKey as string)} />
                        {renderSeries(Line, {
                            strokeWidth: 2,
                            dot: false,
                            activeDot: { r: 6 }
                        })}
                        {showBrush && <Brush dataKey="timestamp" height={30} />}
                    </LineChart>
                );
        }
    };

    return (
        <div className="analytics-chart">
            <div className="chart-header">
                <h3 className="chart-title">{title}</h3>
                <div className="chart-controls">
                    <ChartTypeSelector
                        value={chartType}
                        onChange={() => {}}
                    />
                </div>
            </div>

            <ResponsiveContainer width="100%" height={height}>
                {renderChart()}
            </ResponsiveContainer>
        </div>
    );
}
