'use client';

import { useEffect, useRef } from 'react';
import { useChannel } from '@/hooks/useChannel';
import { formatRelativeTime } from '@/lib/utils';

interface Activity {
    id: string;
    type: 'order' | 'signup' | 'review' | 'refund';
    message: string;
    timestamp: Date;
    metadata?: Record<string, any>;
}

export function ActivityFeed() {
    const feedRef = useRef<HTMLDivElement>(null);
    const [activities, setActivities] = useState<Activity[]>([]);

    // Subscribe to real-time activities
    useChannel<Activity>({
        channel: 'activities',
        onMessage: (activity) => {
            setActivities(prev => [activity, ...prev].slice(0, 50));
        }
    });

    // Fetch initial activities
    useEffect(() => {
        fetch('/api/analytics/activities?limit=20')
            .then(res => res.json())
            .then(data => setActivities(data));
    }, []);

    const getActivityIcon = (type: Activity['type']) => {
        switch (type) {
            case 'order': return <ShoppingCartIcon className="text-green-500" />;
            case 'signup': return <UserPlusIcon className="text-blue-500" />;
            case 'review': return <StarIcon className="text-yellow-500" />;
            case 'refund': return <RefundIcon className="text-red-500" />;
        }
    };

    return (
        <div className="activity-feed">
            <h3 className="feed-title">Live Activity</h3>

