// QUESTION 3: How do you handle large file uploads?
// ═══════════════════════════════════════════════════════════

/*
Key Considerations:
1. Chunked uploads for large files
2. Resume capability for interrupted uploads
3. Progress tracking
4. File validation (type, size)
5. Concurrent uploads limit
6. Error handling and retry
*/

function LargeFileUploadDesign() {
    return {
        approach: "Chunked uploads with resumability",

        chunks: {
            size: "5MB typical chunk size",
            parallel: "3-5 concurrent chunk uploads",
            order: "Track chunk order for reassembly"
        },

        flow: [
            "1. Client requests upload session from server",
            "2. Server returns uploadId and presigned URLs",
            "3. Client splits file into chunks",
            "4. Upload chunks in parallel with retry",
            "5. Server assembles chunks when complete",
            "6. Client receives final file URL"
        ],

        resumability: {
            storage: "Store uploadId and completed chunks in IndexedDB",
            check: "On page reload, check for incomplete uploads",
            resume: "Request remaining chunk URLs from server",
            expire: "Sessions expire after 24h typically"
        },

        implementation: `
            async function uploadLargeFile(file: File) {
                const CHUNK_SIZE = 5 * 1024 * 1024; // 5MB
                const chunks = Math.ceil(file.size / CHUNK_SIZE);

                // Get upload session
                const { uploadId, urls } = await createUploadSession({
                    filename: file.name,
                    size: file.size,
                    chunks
                });

                // Upload chunks with progress
                const completedParts = [];
                for (let i = 0; i < chunks; i++) {
                    const start = i * CHUNK_SIZE;
                    const end = Math.min(start + CHUNK_SIZE, file.size);
                    const chunk = file.slice(start, end);

                    const etag = await uploadChunk(urls[i], chunk, {
                        onProgress: (p) => updateProgress(i, p)
                    });

                    completedParts.push({ partNumber: i + 1, etag });
                    saveProgress(uploadId, completedParts);
                }

                // Complete upload
                return await completeUpload(uploadId, completedParts);
            }
        `
    };
}
