function InfiniteScrollWithSearchDesign() {
    return {
        challenges: [
            "Resetting scroll position on new search",
            "Debouncing search input",
            "Canceling previous requests",
            "Maintaining scroll position on back navigation",
            "Memory management with many items"
        ],

        solutions: {
            virtualization: "Only render visible items (react-virtual)",
            caching: "Cache pages with React Query",
            scrollRestoration: "Save scroll position in session storage",
            debounce: "300ms debounce on search input"
        },

        implementation: `
            function useInfiniteSearchList(searchQuery: string) {
                const debouncedQuery = useDebounce(searchQuery, 300);

                const query = useInfiniteQuery({
                    queryKey: ['items', debouncedQuery],
                    queryFn: ({ pageParam }) =>
                        fetchItems({ query: debouncedQuery, cursor: pageParam }),
                    getNextPageParam: (lastPage) => lastPage.nextCursor,
                    // Reset on new search
                    enabled: true,
                    staleTime: 60000
                });

                // Virtualization
                const allItems = query.data?.pages.flatMap(p => p.items) ?? [];

                const virtualizer = useVirtualizer({
                    count: query.hasNextPage ? allItems.length + 1 : allItems.length,
                    getScrollElement: () => scrollRef.current,
                    estimateSize: () => 80,
                    overscan: 5
                });

                // Load more trigger
                useEffect(() => {
                    const lastItem = virtualizer.getVirtualItems().slice(-1)[0];
                    if (lastItem?.index >= allItems.length - 1 && query.hasNextPage) {
                        query.fetchNextPage();
                    }
                }, [virtualizer.getVirtualItems()]);

                return { virtualizer, allItems, ...query };
            }
        `
    };
}

