        concept: `
            Optimistic updates show the expected result immediately,
            then reconcile with the server response or rollback on error.
        `,

        steps: [
            "1. Store current state for potential rollback",
            "2. Immediately update UI with expected result",
            "3. Send request to server",
            "4. On success: reconcile with server response",
            "5. On error: rollback to previous state, show error"
        ],

        implementation: `
            const likeMutation = useMutation({
                mutationFn: (postId: string) => likePost(postId),

                onMutate: async (postId) => {
                    // Cancel any outgoing refetches
                    await queryClient.cancelQueries(['posts']);

                    // Snapshot previous value
                    const previousPosts = queryClient.getQueryData(['posts']);

                    // Optimistically update
                    queryClient.setQueryData(['posts'], (old) =>
                        old.map(post =>
                            post.id === postId
                                ? { ...post, liked: true, likeCount: post.likeCount + 1 }
                                : post
                        )
                    );

                    // Return context for rollback
                    return { previousPosts };
                },

                onError: (err, postId, context) => {
                    // Rollback on error
                    queryClient.setQueryData(['posts'], context.previousPosts);
                    toast.error('Failed to like post');
                },

                onSettled: () => {
                    // Refetch to ensure consistency
                    queryClient.invalidateQueries(['posts']);
                }
            });
        `,

        considerations: [
            "Race conditions with multiple rapid updates",
            "Handling conflicting server responses",
            "Showing pending state for slow operations",
            "Partial rollbacks for batch operations"
        ]
    };
