// Implement map
Array.prototype.myMap = function(callback, thisArg) {
    if (typeof callback !== 'function') {
        throw new TypeError(`${callback} is not a function`);
    }

    const result = [];
    for (let i = 0; i < this.length; i++) {
        if (i in this) { // Handle sparse arrays
            result[i] = callback.call(thisArg, this[i], i, this);
        }
    }
    return result;
};

// Implement filter
Array.prototype.myFilter = function(callback, thisArg) {
    if (typeof callback !== 'function') {
        throw new TypeError(`${callback} is not a function`);
    }

    const result = [];
    for (let i = 0; i < this.length; i++) {
        if (i in this && callback.call(thisArg, this[i], i, this)) {
            result.push(this[i]);
        }
    }
    return result;
};

// Implement reduce
Array.prototype.myReduce = function(callback, initialValue) {
    if (typeof callback !== 'function') {
        throw new TypeError(`${callback} is not a function`);
    }

    const len = this.length;
    let accumulator;
    let startIndex = 0;

    if (arguments.length >= 2) {
        accumulator = initialValue;
    } else {
        // Find first non-empty element
        while (startIndex < len && !(startIndex in this)) {
            startIndex++;
        }

        if (startIndex >= len) {
            throw new TypeError('Reduce of empty array with no initial value');
        }

        accumulator = this[startIndex];
        startIndex++;
    }

    for (let i = startIndex; i < len; i++) {
        if (i in this) {
            accumulator = callback(accumulator, this[i], i, this);
        }
    }

    return accumulator;
};

// Implement find
Array.prototype.myFind = function(callback, thisArg) {
    for (let i = 0; i < this.length; i++) {
        if (i in this && callback.call(thisArg, this[i], i, this)) {
            return this[i];
        }
    }
    return undefined;
};

// Implement flat
Array.prototype.myFlat = function(depth = 1) {
    const result = [];

    const flatten = (arr, d) => {
        for (const item of arr) {
            if (Array.isArray(item) && d > 0) {
                flatten(item, d - 1);
            } else {
                result.push(item);
            }
        }
    };

    flatten(this, depth);
    return result;
};

// Implement flatMap
Array.prototype.myFlatMap = function(callback, thisArg) {
    return this.myMap(callback, thisArg).myFlat(1);
};

// Test cases
console.log([1, 2, 3].myMap(x => x * 2)); // [2, 4, 6]
console.log([1, 2, 3, 4].myFilter(x => x % 2 === 0)); // [2, 4]
console.log([1, 2, 3, 4].myReduce((acc, x) => acc + x, 0)); // 10
console.log([1, 2, 3, 4].myFind(x => x > 2)); // 3
console.log([1, [2, [3, [4]]]].myFlat(2)); // [1, 2, 3, [4]]

