// ═══════════════════════════════════════════════════════════
// CHALLENGE 3: Object manipulation
// ═══════════════════════════════════════════════════════════

// Deep clone an object
function deepClone(obj, seen = new WeakMap()) {
    // Handle primitives and null
    if (obj === null || typeof obj !== 'object') {
        return obj;
    }

    // Handle Date
    if (obj instanceof Date) {
        return new Date(obj.getTime());
    }

    // Handle RegExp
    if (obj instanceof RegExp) {
        return new RegExp(obj.source, obj.flags);
    }

    // Handle circular references
    if (seen.has(obj)) {
        return seen.get(obj);
    }

    // Handle Array
    if (Array.isArray(obj)) {
        const arrCopy = [];
        seen.set(obj, arrCopy);
        for (let i = 0; i < obj.length; i++) {
            arrCopy[i] = deepClone(obj[i], seen);
        }
        return arrCopy;
    }

    // Handle Map
    if (obj instanceof Map) {
        const mapCopy = new Map();
        seen.set(obj, mapCopy);
        obj.forEach((value, key) => {
            mapCopy.set(deepClone(key, seen), deepClone(value, seen));
        });
        return mapCopy;
    }

    // Handle Set
    if (obj instanceof Set) {
        const setCopy = new Set();
        seen.set(obj, setCopy);
        obj.forEach(value => {
            setCopy.add(deepClone(value, seen));
        });
        return setCopy;
    }

    // Handle plain objects
    const objCopy = Object.create(Object.getPrototypeOf(obj));
    seen.set(obj, objCopy);

    for (const key of Reflect.ownKeys(obj)) {
        objCopy[key] = deepClone(obj[key], seen);
    }

    return objCopy;
}

// Deep equality check
function deepEqual(a, b, seen = new WeakMap()) {
    // Same reference or same primitive
    if (a === b) return true;

    // Different types
    if (typeof a !== typeof b) return false;

    // Handle null
    if (a === null || b === null) return a === b;

    // Handle primitives
    if (typeof a !== 'object') return a === b;

    // Handle Date
    if (a instanceof Date && b instanceof Date) {
        return a.getTime() === b.getTime();
    }

    // Handle RegExp
    if (a instanceof RegExp && b instanceof RegExp) {
        return a.toString() === b.toString();
    }

    // Handle circular references
    if (seen.has(a)) {
        return seen.get(a) === b;
    }
    seen.set(a, b);

    // Handle arrays
    if (Array.isArray(a) && Array.isArray(b)) {
        if (a.length !== b.length) return false;
        for (let i = 0; i < a.length; i++) {
            if (!deepEqual(a[i], b[i], seen)) return false;
        }
        return true;
    }

    // One is array, other is not
    if (Array.isArray(a) !== Array.isArray(b)) return false;

    // Handle objects
    const keysA = Object.keys(a);
    const keysB = Object.keys(b);

    if (keysA.length !== keysB.length) return false;

    for (const key of keysA) {
        if (!keysB.includes(key)) return false;
        if (!deepEqual(a[key], b[key], seen)) return false;
    }

    return true;
}

// Flatten nested object
function flattenObject(obj, prefix = '', result = {}) {
    for (const key in obj) {
        if (obj.hasOwnProperty(key)) {
            const newKey = prefix ? `${prefix}.${key}` : key;

            if (typeof obj[key] === 'object' && obj[key] !== null && !Array.isArray(obj[key])) {
                flattenObject(obj[key], newKey, result);
            } else {
                result[newKey] = obj[key];
            }
        }
    }
    return result;
}

console.log(flattenObject({
    a: 1,
    b: {
        c: 2,
        d: {
            e: 3
        }
    }
}));
// { 'a': 1, 'b.c': 2, 'b.d.e': 3 }

// Unflatten object
function unflattenObject(obj) {
    const result = {};

    for (const key in obj) {
        const keys = key.split('.');
        let current = result;

        for (let i = 0; i < keys.length; i++) {
            const k = keys[i];

            if (i === keys.length - 1) {
                current[k] = obj[key];
            } else {
                current[k] = current[k] || {};
                current = current[k];
            }
        }
    }

    return result;
}

// Deep merge objects
function deepMerge(...objects) {
    const result = {};

    for (const obj of objects) {
        for (const key in obj) {
            if (obj.hasOwnProperty(key)) {
                if (
                    typeof obj[key] === 'object' &&
                    obj[key] !== null &&
                    !Array.isArray(obj[key]) &&
                    typeof result[key] === 'object' &&
                    result[key] !== null &&
                    !Array.isArray(result[key])
                ) {
                    result[key] = deepMerge(result[key], obj[key]);
                } else {
                    result[key] = obj[key];
                }
            }
        }
    }

    return result;
}
