// Debounce (with promise support)
function debounce(fn, delay, options = {}) {
    const { leading = false, trailing = true, maxWait } = options;

    let timeoutId = null;
    let maxWaitTimeoutId = null;
    let lastArgs = null;
    let lastThis = null;
    let result;
    let lastCallTime = 0;
    let lastInvokeTime = 0;

    function invokeFunc(time) {
        const args = lastArgs;
        const thisArg = lastThis;

        lastArgs = lastThis = null;
        lastInvokeTime = time;
        result = fn.apply(thisArg, args);
        return result;
    }

    function startTimer(pendingFunc, wait) {
        return setTimeout(pendingFunc, wait);
    }

    function cancelTimer(id) {
        clearTimeout(id);
    }

    function trailingEdge(time) {
        timeoutId = null;

        if (trailing && lastArgs) {
            return invokeFunc(time);
        }
        lastArgs = lastThis = null;
        return result;
    }

    function leadingEdge(time) {
        lastInvokeTime = time;
        timeoutId = startTimer(timerExpired, delay);

        return leading ? invokeFunc(time) : result;
    }

    function remainingWait(time) {
        const timeSinceLastCall = time - lastCallTime;
        const timeSinceLastInvoke = time - lastInvokeTime;
        const timeWaiting = delay - timeSinceLastCall;

        return maxWait !== undefined
            ? Math.min(timeWaiting, maxWait - timeSinceLastInvoke)
            : timeWaiting;
    }

    function shouldInvoke(time) {
        const timeSinceLastCall = time - lastCallTime;
        const timeSinceLastInvoke = time - lastInvokeTime;

        return (
            lastCallTime === 0 ||
            timeSinceLastCall >= delay ||
            timeSinceLastCall < 0 ||
            (maxWait !== undefined && timeSinceLastInvoke >= maxWait)
        );
    }

    function timerExpired() {
        const time = Date.now();

        if (shouldInvoke(time)) {
            return trailingEdge(time);
        }

        timeoutId = startTimer(timerExpired, remainingWait(time));
    }

    function debounced(...args) {
        const time = Date.now();
        const isInvoking = shouldInvoke(time);

        lastArgs = args;
        lastThis = this;
        lastCallTime = time;

        if (isInvoking) {
            if (timeoutId === null) {
                return leadingEdge(time);
            }
            if (maxWait !== undefined) {
                timeoutId = startTimer(timerExpired, delay);
                return invokeFunc(time);
            }
        }

        if (timeoutId === null) {
            timeoutId = startTimer(timerExpired, delay);
        }

        return result;
    }

    debounced.cancel = function() {
        cancelTimer(timeoutId);
        cancelTimer(maxWaitTimeoutId);
        lastInvokeTime = 0;
        lastArgs = lastCallTime = lastThis = timeoutId = null;
    };

    debounced.flush = function() {
        return timeoutId === null ? result : trailingEdge(Date.now());
    };

    debounced.pending = function() {
        return timeoutId !== null;
    };

    return debounced;
}

// Throttle
function throttle(fn, limit, options = {}) {
    const { leading = true, trailing = true } = options;

    let lastCallTime = 0;
    let timeoutId = null;
    let lastArgs = null;
    let lastThis = null;

    function invoke() {
        lastCallTime = Date.now();
        fn.apply(lastThis, lastArgs);
        lastArgs = lastThis = null;
    }

    return function throttled(...args) {
        const now = Date.now();
        const remaining = limit - (now - lastCallTime);

        lastArgs = args;
        lastThis = this;

        if (remaining <= 0 || remaining > limit) {
            if (timeoutId) {
                clearTimeout(timeoutId);
                timeoutId = null;
            }

            if (leading) {
                invoke();
            } else {
                lastCallTime = now;
            }
        } else if (!timeoutId && trailing) {
            timeoutId = setTimeout(() => {
                timeoutId = null;
                invoke();
            }, remaining);
        }
    };
}

// Memoize with TTL and max size
function memoize(fn, options = {}) {
    const {
        maxSize = 100,
        ttl = Infinity,
        keyResolver = (...args) => JSON.stringify(args)
    } = options;

    const cache = new Map();

    function memoized(...args) {
        const key = keyResolver(...args);

        if (cache.has(key)) {
            const { value, expiry } = cache.get(key);

            if (Date.now() < expiry) {
                // Move to end (LRU)
                cache.delete(key);
                cache.set(key, { value, expiry });
                return value;
            }

            cache.delete(key);
        }

        const result = fn.apply(this, args);

        // Evict oldest if at capacity
        if (cache.size >= maxSize) {
            const firstKey = cache.keys().next().value;
            cache.delete(firstKey);
        }

        cache.set(key, {
            value: result,
            expiry: Date.now() + ttl
        });

        return result;
    }

    memoized.cache = cache;
    memoized.clear = () => cache.clear();

    return memoized;
}
