// CHALLENGE 4: Event Emitter implementation
// ═══════════════════════════════════════════════════════════

class EventEmitter {
    constructor() {
        this.events = new Map();
    }

    on(event, listener) {
        if (!this.events.has(event)) {
            this.events.set(event, []);
        }
        this.events.get(event).push({ listener, once: false });
        return () => this.off(event, listener);
    }

    once(event, listener) {
        if (!this.events.has(event)) {
            this.events.set(event, []);
        }
        this.events.get(event).push({ listener, once: true });
        return () => this.off(event, listener);
    }

    off(event, listener) {
        const listeners = this.events.get(event);
        if (!listeners) return;

        const index = listeners.findIndex(l => l.listener === listener);
        if (index > -1) {
            listeners.splice(index, 1);
        }

        if (listeners.length === 0) {
            this.events.delete(event);
        }
    }

    emit(event, ...args) {
        const listeners = this.events.get(event);
        if (!listeners) return false;

        const toRemove = [];

        listeners.forEach((item, index) => {
            item.listener.apply(this, args);
            if (item.once) {
                toRemove.push(index);
            }
        });

        // Remove once listeners (reverse order to maintain indices)
        for (let i = toRemove.length - 1; i >= 0; i--) {
            listeners.splice(toRemove[i], 1);
        }

        return true;
    }

    listenerCount(event) {
        return this.events.get(event)?.length || 0;
    }

    removeAllListeners(event) {
        if (event) {
            this.events.delete(event);
        } else {
            this.events.clear();
        }
    }
}

