function $(selector) {
    const elements = typeof selector === 'string'
        ? Array.from(document.querySelectorAll(selector))
        : [selector];

    return {
        elements,

        // Iterate over elements
        each(callback) {
            this.elements.forEach((el, i) => callback.call(el, i, el));
            return this;
        },

        // Add class
        addClass(className) {
            return this.each(function() {
                this.classList.add(className);
            });
        },

        // Remove class
        removeClass(className) {
            return this.each(function() {
                this.classList.remove(className);
            });
        },

        // Toggle class
        toggleClass(className) {
            return this.each(function() {
                this.classList.toggle(className);
            });
        },

        // Check if has class
        hasClass(className) {
            return this.elements.some(el => el.classList.contains(className));
        },

        // Get/Set attribute
        attr(name, value) {
            if (value === undefined) {
                return this.elements[0]?.getAttribute(name);
            }
            return this.each(function() {
                this.setAttribute(name, value);
            });
        },

        // Get/Set CSS
        css(property, value) {
            if (typeof property === 'object') {
                return this.each(function() {
                    Object.assign(this.style, property);
                });
            }
            if (value === undefined) {
                return getComputedStyle(this.elements[0])[property];
            }
            return this.each(function() {
                this.style[property] = value;
            });
        },

        // Get/Set HTML
        html(content) {
            if (content === undefined) {
                return this.elements[0]?.innerHTML;
            }
            return this.each(function() {
                this.innerHTML = content;
            });
        },

        // Get/Set text
        text(content) {
            if (content === undefined) {
                return this.elements[0]?.textContent;
            }
            return this.each(function() {
                this.textContent = content;
            });
        },

        // Event handling
        on(event, handler) {
            return this.each(function() {
                this.addEventListener(event, handler);
            });
        },

        off(event, handler) {
            return this.each(function() {
                this.removeEventListener(event, handler);
            });
        },

        // Find descendants
        find(selector) {
            const found = [];
            this.elements.forEach(el => {
                found.push(...el.querySelectorAll(selector));
            });
            return $([...new Set(found)]);
        },

        // Parent
        parent() {
            const parents = this.elements.map(el => el.parentElement).filter(Boolean);
            return $([...new Set(parents)]);
        },

        // Children
        children() {
            const children = [];
            this.elements.forEach(el => {
                children.push(...el.children);
            });
            return $(children);
        },

        // Show/Hide
        show() {
            return this.css('display', '');
        },

        hide() {
            return this.css('display', 'none');
        },

        // Append
        append(content) {
            return this.each(function() {
                if (typeof content === 'string') {
                    this.insertAdjacentHTML('beforeend', content);
                } else {
                    this.appendChild(content);
                }
            });
        },

        // Prepend
        prepend(content) {
            return this.each(function() {
                if (typeof content === 'string') {
                    this.insertAdjacentHTML('afterbegin', content);
                } else {
                    this.insertBefore(content, this.firstChild);
                }
            });
        },

        // Remove
        remove() {
            return this.each(function() {
                this.parentNode?.removeChild(this);
            });
        }
    };
}
