function delegate(parent, eventType, selector, handler) {
    const parentEl = typeof parent === 'string'
        ? document.querySelector(parent)
        : parent;

    function delegatedHandler(event) {
        let target = event.target;

        while (target && target !== parentEl) {
            if (target.matches(selector)) {
                handler.call(target, event, target);
                return;
            }
            target = target.parentElement;
        }
    }

    parentEl.addEventListener(eventType, delegatedHandler);

    // Return cleanup function
    return () => {
        parentEl.removeEventListener(eventType, delegatedHandler);
    };
}

