// CHALLENGE 2: useDebounce and useDebouncedCallback hooks
// ═══════════════════════════════════════════════════════════

function useDebounce<T>(value: T, delay: number): T {
    const [debouncedValue, setDebouncedValue] = useState(value);

    useEffect(() => {
        const timer = setTimeout(() => {
            setDebouncedValue(value);
        }, delay);

        return () => {
            clearTimeout(timer);
        };
    }, [value, delay]);

    return debouncedValue;
}

function useDebouncedCallback<T extends (...args: any[]) => any>(
    callback: T,
    delay: number
): (...args: Parameters<T>) => void {
    const callbackRef = useRef(callback);
    const timeoutRef = useRef<NodeJS.Timeout>();

    // Update ref when callback changes
    useEffect(() => {
        callbackRef.current = callback;
    }, [callback]);

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            if (timeoutRef.current) {
                clearTimeout(timeoutRef.current);
            }
        };
    }, []);

    return useCallback((...args: Parameters<T>) => {
        if (timeoutRef.current) {
            clearTimeout(timeoutRef.current);
        }

        timeoutRef.current = setTimeout(() => {
            callbackRef.current(...args);
        }, delay);
    }, [delay]);
}

// ═══════════════════════════════════════════════════════════
// CHALLENGE 3: useFetch hook with caching
// ═══════════════════════════════════════════════════════════

interface FetchState<T> {
    data: T | null;
    error: Error | null;
    isLoading: boolean;
    isValidating: boolean;
}

interface UseFetchOptions {
    revalidateOnFocus?: boolean;
    revalidateOnReconnect?: boolean;
    dedupingInterval?: number;
    refreshInterval?: number;
}

const cache = new Map<string, { data: any; timestamp: number }>();
const inflightRequests = new Map<string, Promise<any>>();

function useFetch<T>(
    url: string | null,
    options: UseFetchOptions = {}
): FetchState<T> & { mutate: () => Promise<void> } {
    const {
        revalidateOnFocus = true,
        revalidateOnReconnect = true,
        dedupingInterval = 2000,
        refreshInterval
    } = options;

    const [state, setState] = useState<FetchState<T>>({
        data: url ? cache.get(url)?.data ?? null : null,
        error: null,
        isLoading: url !== null && !cache.has(url),
        isValidating: false
    });

    const fetchData = useCallback(async (isRevalidation = false) => {
        if (!url) return;

        // Check for in-flight request (deduping)
        if (inflightRequests.has(url)) {
            return inflightRequests.get(url);
        }

        // Check cache freshness
        const cached = cache.get(url);
        if (cached && Date.now() - cached.timestamp < dedupingInterval) {
            return cached.data;
        }

        setState(prev => ({
            ...prev,
            isLoading: !prev.data,
            isValidating: true,
            error: null
        }));

        const promise = fetch(url)
            .then(async res => {
                if (!res.ok) throw new Error(`HTTP ${res.status}`);
                const data = await res.json();

                cache.set(url, { data, timestamp: Date.now() });
                setState(prev => ({
                    ...prev,
                    data,
                    isLoading: false,
                    isValidating: false
                }));

                return data;
            })
            .catch(error => {
                setState(prev => ({
                    ...prev,
                    error,
                    isLoading: false,
                    isValidating: false
                }));
                throw error;
            })
            .finally(() => {
                inflightRequests.delete(url);
            });

        inflightRequests.set(url, promise);
        return promise;
    }, [url, dedupingInterval]);

    // Initial fetch
    useEffect(() => {
        fetchData();
    }, [fetchData]);

    // Revalidate on focus
    useEffect(() => {
        if (!revalidateOnFocus) return;

        const handleFocus = () => fetchData(true);
        window.addEventListener('focus', handleFocus);
        return () => window.removeEventListener('focus', handleFocus);
    }, [revalidateOnFocus, fetchData]);

    // Revalidate on reconnect
    useEffect(() => {
        if (!revalidateOnReconnect) return;

        const handleOnline = () => fetchData(true);
        window.addEventListener('online', handleOnline);
        return () => window.removeEventListener('online', handleOnline);
    }, [revalidateOnReconnect, fetchData]);

    // Polling
    useEffect(() => {
        if (!refreshInterval) return;

        const interval = setInterval(() => {
            fetchData(true);
        }, refreshInterval);

        return () => clearInterval(interval);
    }, [refreshInterval, fetchData]);

    const mutate = useCallback(async () => {
        if (url) {
            cache.delete(url);
            await fetchData();
        }
    }, [url, fetchData]);

    return { ...state, mutate };
}
