// CHALLENGE 4: useIntersectionObserver hook
// ═══════════════════════════════════════════════════════════

interface UseIntersectionObserverOptions {
    root?: Element | null;
    rootMargin?: string;
    threshold?: number | number[];
    triggerOnce?: boolean;
}

function useIntersectionObserver<T extends Element>(
    options: UseIntersectionObserverOptions = {}
): [React.RefCallback<T>, boolean, IntersectionObserverEntry | null] {
    const { root = null, rootMargin = '0px', threshold = 0, triggerOnce = false } = options;

    const [entry, setEntry] = useState<IntersectionObserverEntry | null>(null);
    const [isIntersecting, setIsIntersecting] = useState(false);
    const observerRef = useRef<IntersectionObserver | null>(null);
    const elementRef = useRef<T | null>(null);

    const setRef = useCallback((element: T | null) => {
        // Disconnect previous observer
        if (observerRef.current) {
            observerRef.current.disconnect();
        }

        elementRef.current = element;

        if (!element) return;

        observerRef.current = new IntersectionObserver(
            ([entry]) => {
                setEntry(entry);
                setIsIntersecting(entry.isIntersecting);

                if (triggerOnce && entry.isIntersecting) {
                    observerRef.current?.disconnect();
                }
            },
            { root, rootMargin, threshold }
        );

        observerRef.current.observe(element);
    }, [root, rootMargin, threshold, triggerOnce]);

    // Cleanup on unmount
    useEffect(() => {
        return () => {
            observerRef.current?.disconnect();
        };
    }, []);

    return [setRef, isIntersecting, entry];
}

// Usage
function LazyImage({ src, alt }: { src: string; alt: string }) {
    const [ref, isIntersecting] = useIntersectionObserver<HTMLImageElement>({
        threshold: 0.1,
        triggerOnce: true
    });

    return (
        <img
            ref={ref}
            src={isIntersecting ? src : undefined}
            alt={alt}
            loading="lazy"
        />
    );
}

