// CHALLENGE 7: usePrevious hook
// ═══════════════════════════════════════════════════════════

function usePrevious<T>(value: T): T | undefined {
    const ref = useRef<T>();

    useEffect(() => {
        ref.current = value;
    }, [value]);

    return ref.current;
}

