// CHALLENGE 2: Build an Autocomplete component
// ═══════════════════════════════════════════════════════════

interface AutocompleteProps<T> {
    items: T[];
    value: T | null;
    onChange: (item: T | null) => void;
    getLabel: (item: T) => string;
    filterFn?: (item: T, query: string) => boolean;
    placeholder?: string;
    disabled?: boolean;
    loading?: boolean;
    noResultsMessage?: string;
    renderItem?: (item: T, isHighlighted: boolean) => React.ReactNode;
}

function Autocomplete<T>({
    items,
    value,
    onChange,
    getLabel,
    filterFn,
    placeholder = 'Search...',
    disabled = false,
    loading = false,
    noResultsMessage = 'No results found',
    renderItem
}: AutocompleteProps<T>) {
    const [query, setQuery] = useState('');
    const [isOpen, setIsOpen] = useState(false);
    const [highlightedIndex, setHighlightedIndex] = useState(-1);

    const inputRef = useRef<HTMLInputElement>(null);
    const listRef = useRef<HTMLUListElement>(null);
    const containerRef = useClickOutside<HTMLDivElement>(() => setIsOpen(false));

    // Filter items
    const filteredItems = useMemo(() => {
        if (!query) return items;

        const defaultFilter = (item: T, q: string) =>
            getLabel(item).toLowerCase().includes(q.toLowerCase());

        return items.filter(item => (filterFn || defaultFilter)(item, query));
    }, [items, query, filterFn, getLabel]);

    // Sync query with selected value
    useEffect(() => {
        setQuery(value ? getLabel(value) : '');
    }, [value, getLabel]);

    // Scroll highlighted item into view
    useEffect(() => {
        if (highlightedIndex >= 0 && listRef.current) {
            const item = listRef.current.children[highlightedIndex] as HTMLElement;
            item?.scrollIntoView({ block: 'nearest' });
        }
    }, [highlightedIndex]);

    function handleInputChange(e: React.ChangeEvent<HTMLInputElement>) {
        const newQuery = e.target.value;
        setQuery(newQuery);
        setIsOpen(true);
        setHighlightedIndex(-1);

        if (!newQuery) {
            onChange(null);
        }
    }

    function handleKeyDown(e: React.KeyboardEvent) {
        switch (e.key) {
            case 'ArrowDown':
                e.preventDefault();
                setIsOpen(true);
                setHighlightedIndex(prev =>
                    prev < filteredItems.length - 1 ? prev + 1 : prev
                );
                break;
            case 'ArrowUp':
                e.preventDefault();
                setHighlightedIndex(prev => (prev > 0 ? prev - 1 : prev));
                break;
            case 'Enter':
                e.preventDefault();
                if (highlightedIndex >= 0 && filteredItems[highlightedIndex]) {
                    selectItem(filteredItems[highlightedIndex]);
                }
                break;
            case 'Escape':
                setIsOpen(false);
                setQuery(value ? getLabel(value) : '');
                break;
        }
    }

    function selectItem(item: T) {
        onChange(item);
        setQuery(getLabel(item));
        setIsOpen(false);
        setHighlightedIndex(-1);
        inputRef.current?.blur();
    }

    return (
        <div ref={containerRef} className="relative">
            <input
                ref={inputRef}
                type="text"
                value={query}
                onChange={handleInputChange}
                onFocus={() => setIsOpen(true)}
                onKeyDown={handleKeyDown}
                placeholder={placeholder}
                disabled={disabled}
                className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500"
                role="combobox"
                aria-expanded={isOpen}
                aria-autocomplete="list"
                aria-controls="autocomplete-list"
                aria-activedescendant={
                    highlightedIndex >= 0 ? `option-${highlightedIndex}` : undefined
                }
            />

            {loading && (
                <div className="absolute right-3 top-1/2 -translate-y-1/2">
                    <Spinner size="sm" />
                </div>
            )}

            {isOpen && !loading && (
                <ul
                    ref={listRef}
                    id="autocomplete-list"
                    className="absolute z-10 w-full mt-1 bg-white border rounded-lg shadow-lg max-h-60 overflow-y-auto"
                    role="listbox"
                >
                    {filteredItems.length === 0 ? (
                        <li className="px-4 py-2 text-gray-500">{noResultsMessage}</li>
                    ) : (
                        filteredItems.map((item, index) => (
                            <li
                                key={index}
                                id={`option-${index}`}
                                role="option"
                                aria-selected={index === highlightedIndex}
                                className={`px-4 py-2 cursor-pointer ${
                                    index === highlightedIndex ? 'bg-blue-100' : 'hover:bg-gray-100'
                                }`}
                                onClick={() => selectItem(item)}
                                onMouseEnter={() => setHighlightedIndex(index)}
                            >
                                {renderItem
                                    ? renderItem(item, index === highlightedIndex)
                                    : getLabel(item)}
                            </li>
                        ))
                    )}
                </ul>
            )}
        </div>
    );
}
