// CHALLENGE 3: Build a DataTable component
// ═══════════════════════════════════════════════════════════

interface Column<T> {
    key: keyof T | string;
    header: string;
    render?: (value: any, row: T) => React.ReactNode;
    sortable?: boolean;
    width?: string;
}

interface DataTableProps<T> {
    columns: Column<T>[];
    data: T[];
    keyExtractor: (row: T) => string | number;
    sortable?: boolean;
    paginated?: boolean;
    pageSize?: number;
    selectable?: boolean;
    onRowClick?: (row: T) => void;
    onSelectionChange?: (selectedRows: T[]) => void;
    emptyMessage?: string;
    loading?: boolean;
}

function DataTable<T extends Record<string, any>>({
    columns,
    data,
    keyExtractor,
    sortable = false,
    paginated = false,
    pageSize = 10,
    selectable = false,
    onRowClick,
    onSelectionChange,
    emptyMessage = 'No data available',
    loading = false
}: DataTableProps<T>) {
    const [sortConfig, setSortConfig] = useState<{
        key: string;
        direction: 'asc' | 'desc';
    } | null>(null);
    const [currentPage, setCurrentPage] = useState(1);
    const [selectedRows, setSelectedRows] = useState<Set<string | number>>(new Set());

    // Sort data
    const sortedData = useMemo(() => {
        if (!sortConfig) return data;

        return [...data].sort((a, b) => {
            const aValue = a[sortConfig.key];
            const bValue = b[sortConfig.key];

            if (aValue < bValue) return sortConfig.direction === 'asc' ? -1 : 1;
            if (aValue > bValue) return sortConfig.direction === 'asc' ? 1 : -1;
            return 0;
        });
    }, [data, sortConfig]);

    // Paginate data
    const paginatedData = useMemo(() => {
        if (!paginated) return sortedData;

        const start = (currentPage - 1) * pageSize;
        return sortedData.slice(start, start + pageSize);
    }, [sortedData, paginated, currentPage, pageSize]);

    const totalPages = Math.ceil(data.length / pageSize);

    // Handle sort
    function handleSort(key: string) {
        if (!sortable) return;

        setSortConfig(prev => {
            if (prev?.key !== key) {
                return { key, direction: 'asc' };
            }
            if (prev.direction === 'asc') {
                return { key, direction: 'desc' };
            }
            return null;
        });
    }

    // Handle row selection
    function handleRowSelect(row: T) {
        const key = keyExtractor(row);

        setSelectedRows(prev => {
            const next = new Set(prev);
            if (next.has(key)) {
                next.delete(key);
            } else {
                next.add(key);
            }
            return next;
        });
    }

    function handleSelectAll() {
        if (selectedRows.size === data.length) {
            setSelectedRows(new Set());
        } else {
            setSelectedRows(new Set(data.map(keyExtractor)));
        }
    }

    // Notify parent of selection changes
    useEffect(() => {
        if (onSelectionChange) {
            const selected = data.filter(row => selectedRows.has(keyExtractor(row)));
            onSelectionChange(selected);
        }
    }, [selectedRows, data, keyExtractor, onSelectionChange]);

    // Get cell value
    function getCellValue(row: T, column: Column<T>) {
        const value = typeof column.key === 'string' && column.key.includes('.')
            ? column.key.split('.').reduce((obj, key) => obj?.[key], row as any)
            : row[column.key as keyof T];

        return column.render ? column.render(value, row) : value;
    }

    if (loading) {
        return <TableSkeleton columns={columns.length} rows={pageSize} />;
    }

    return (
        <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-gray-200">
                <thead className="bg-gray-50">
                    <tr>
                        {selectable && (
                            <th className="px-4 py-3 w-10">
                                <input
                                    type="checkbox"
                                    checked={selectedRows.size === data.length && data.length > 0}
                                    onChange={handleSelectAll}
                                    className="rounded"
                                />
                            </th>
                        )}
                        {columns.map(column => (
                            <th
                                key={String(column.key)}
                                className={`px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider ${
                                    column.sortable !== false && sortable ? 'cursor-pointer hover:bg-gray-100' : ''
                                }`}
                                style={{ width: column.width }}
                                onClick={() => column.sortable !== false && handleSort(String(column.key))}
                            >
                                <div className="flex items-center gap-2">
                                    {column.header}
                                    {sortConfig?.key === column.key && (
                                        <span>{sortConfig.direction === 'asc' ? '↑' : '↓'}</span>
                                    )}
                                </div>
                            </th>
                        ))}
                    </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                    {paginatedData.length === 0 ? (
                        <tr>
                            <td
                                colSpan={columns.length + (selectable ? 1 : 0)}
                                className="px-6 py-4 text-center text-gray-500"
                            >
                                {emptyMessage}
                            </td>
                        </tr>
                    ) : (
                        paginatedData.map(row => {
                            const key = keyExtractor(row);
                            const isSelected = selectedRows.has(key);

                            return (
                                <tr
                                    key={key}
                                    className={`${isSelected ? 'bg-blue-50' : 'hover:bg-gray-50'} ${
                                        onRowClick ? 'cursor-pointer' : ''
                                    }`}
                                    onClick={() => onRowClick?.(row)}
                                >
                                    {selectable && (
                                        <td className="px-4 py-3">
                                            <input
                                                type="checkbox"
                                                checked={isSelected}
                                                onChange={(e) => {
                                                    e.stopPropagation();
                                                    handleRowSelect(row);
                                                }}
                                                className="rounded"
                                            />
                                        </td>
                                    )}
                                    {columns.map(column => (
                                        <td
                                            key={String(column.key)}
                                            className="px-6 py-4 whitespace-nowrap"
                                        >
                                            {getCellValue(row, column)}
                                        </td>
                                    ))}
                                </tr>
                            );
                        })
                    )}
                </tbody>
            </table>

            {paginated && totalPages > 1 && (
                <div className="flex items-center justify-between px-4 py-3 bg-white border-t">
                    <div className="text-sm text-gray-500">
                        Showing {(currentPage - 1) * pageSize + 1} to{' '}
                        {Math.min(currentPage * pageSize, data.length)} of {data.length} results
                    </div>
                    <div className="flex gap-2">
                        <button
                            onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                            disabled={currentPage === 1}
                            className="px-3 py-1 border rounded disabled:opacity-50"
                        >
                            Previous
                        </button>
                        <button
                            onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                            disabled={currentPage === totalPages}
                            className="px-3 py-1 border rounded disabled:opacity-50"
                        >
                            Next
                        </button>
                    </div>
                </div>
            )}
        </div>
    );
}
