// CHALLENGE 4: Build an Infinite Scroll component
// ═══════════════════════════════════════════════════════════

interface InfiniteScrollProps<T> {
    items: T[];
    renderItem: (item: T, index: number) => React.ReactNode;
    keyExtractor: (item: T) => string | number;
    loadMore: () => void;
    hasMore: boolean;
    isLoading: boolean;
    loader?: React.ReactNode;
    endMessage?: React.ReactNode;
    threshold?: number;
    className?: string;
}

function InfiniteScroll<T>({
    items,
    renderItem,
    keyExtractor,
    loadMore,
    hasMore,
    isLoading,
    loader = <div className="py-4 text-center">Loading...</div>,
    endMessage = <div className="py-4 text-center text-gray-500">No more items</div>,
    threshold = 100,
    className
}: InfiniteScrollProps<T>) {
    const containerRef = useRef<HTMLDivElement>(null);
    const loadMoreRef = useRef(loadMore);

    // Keep loadMore ref updated
    useEffect(() => {
        loadMoreRef.current = loadMore;
    }, [loadMore]);

    // Intersection observer for infinite scroll
    const [sentinelRef, isIntersecting] = useIntersectionObserver<HTMLDivElement>({
        rootMargin: `${threshold}px`
    });

    // Trigger load more when sentinel is visible
    useEffect(() => {
        if (isIntersecting && hasMore && !isLoading) {
            loadMoreRef.current();
        }
    }, [isIntersecting, hasMore, isLoading]);

    return (
        <div ref={containerRef} className={className}>
            {items.map((item, index) => (
                <React.Fragment key={keyExtractor(item)}>
                    {renderItem(item, index)}
                </React.Fragment>
            ))}

            {/* Sentinel element for intersection observer */}
            <div ref={sentinelRef} aria-hidden="true" />

            {isLoading && loader}
            {!hasMore && !isLoading && items.length > 0 && endMessage}
        </div>
    );
}

