// ═══════════════════════════════════════════════════════════
// LRU CACHE (Common interview question)
// ═══════════════════════════════════════════════════════════

class LRUCache {
    constructor(capacity) {
        this.capacity = capacity;
        this.cache = new Map();
    }

    get(key) {
        if (!this.cache.has(key)) {
            return -1;
        }

        // Move to end (most recently used)
        const value = this.cache.get(key);
        this.cache.delete(key);
        this.cache.set(key, value);

        return value;
    }

    put(key, value) {
        if (this.cache.has(key)) {
            this.cache.delete(key);
        } else if (this.cache.size >= this.capacity) {
            // Delete least recently used (first item)
            const firstKey = this.cache.keys().next().value;
            this.cache.delete(firstKey);
        }

        this.cache.set(key, value);
    }
}

// ═══════════════════════════════════════════════════════════
// TRIE (For autocomplete)
// ═══════════════════════════════════════════════════════════

class TrieNode {
    constructor() {
        this.children = new Map();
        this.isEndOfWord = false;
        this.frequency = 0; // For ranking suggestions
    }
}

class Trie {
    constructor() {
        this.root = new TrieNode();
    }

    insert(word, frequency = 1) {
        let node = this.root;

        for (const char of word.toLowerCase()) {
            if (!node.children.has(char)) {
                node.children.set(char, new TrieNode());
            }
            node = node.children.get(char);
        }

        node.isEndOfWord = true;
        node.frequency += frequency;
    }

    search(word) {
        const node = this._findNode(word);
        return node !== null && node.isEndOfWord;
    }

    startsWith(prefix) {
        return this._findNode(prefix) !== null;
    }

    _findNode(str) {
        let node = this.root;

        for (const char of str.toLowerCase()) {
            if (!node.children.has(char)) {
                return null;
            }
            node = node.children.get(char);
        }

        return node;
    }

    // Get all words with given prefix
    getSuggestions(prefix, limit = 10) {
        const node = this._findNode(prefix);
        if (!node) return [];

        const suggestions = [];

        const dfs = (currentNode, currentWord) => {
            if (currentNode.isEndOfWord) {
                suggestions.push({
                    word: currentWord,
                    frequency: currentNode.frequency
                });
            }

            for (const [char, childNode] of currentNode.children) {
                dfs(childNode, currentWord + char);
            }
        };

        dfs(node, prefix);

        // Sort by frequency and limit
        return suggestions
            .sort((a, b) => b.frequency - a.frequency)
            .slice(0, limit)
            .map(s => s.word);
    }
}

// Usage for autocomplete
const trie = new Trie();
['apple', 'application', 'apply', 'banana', 'band'].forEach(word => {
    trie.insert(word);
});

console.log(trie.getSuggestions('app')); // ['apple', 'application', 'apply']

// ═══════════════════════════════════════════════════════════
// PRIORITY QUEUE (For task scheduling)
// ═══════════════════════════════════════════════════════════

class PriorityQueue {
    constructor(compareFn = (a, b) => a - b) {
        this.heap = [];
        this.compare = compareFn;
    }

    get size() {
        return this.heap.length;
    }

    isEmpty() {
        return this.size === 0;
    }

    peek() {
        return this.heap[0];
    }

    enqueue(value) {
        this.heap.push(value);
        this._bubbleUp(this.size - 1);
    }

    dequeue() {
        if (this.isEmpty()) return undefined;

        const result = this.heap[0];
        const last = this.heap.pop();

        if (!this.isEmpty()) {
            this.heap[0] = last;
            this._bubbleDown(0);
        }

        return result;
    }

    _bubbleUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);

            if (this.compare(this.heap[index], this.heap[parentIndex]) >= 0) {
                break;
            }

            [this.heap[index], this.heap[parentIndex]] =
                [this.heap[parentIndex], this.heap[index]];
            index = parentIndex;
        }
    }

    _bubbleDown(index) {
        while (true) {
            let smallest = index;
            const leftChild = 2 * index + 1;
            const rightChild = 2 * index + 2;

            if (leftChild < this.size &&
                this.compare(this.heap[leftChild], this.heap[smallest]) < 0) {
                smallest = leftChild;
            }

            if (rightChild < this.size &&
                this.compare(this.heap[rightChild], this.heap[smallest]) < 0) {
                smallest = rightChild;
            }

            if (smallest === index) break;

            [this.heap[index], this.heap[smallest]] =
                [this.heap[smallest], this.heap[index]];
            index = smallest;
        }
    }
}

// Usage for task scheduling
const taskQueue = new PriorityQueue((a, b) => a.priority - b.priority);
taskQueue.enqueue({ task: 'Low priority', priority: 3 });
taskQueue.enqueue({ task: 'High priority', priority: 1 });
taskQueue.enqueue({ task: 'Medium priority', priority: 2 });

while (!taskQueue.isEmpty()) {
    console.log(taskQueue.dequeue().task);
}
// High priority, Medium priority, Low priority
