// ═══════════════════════════════════════════════════════════
// INTERVAL TREE (For calendar/scheduling UI)
// ═══════════════════════════════════════════════════════════

class IntervalTree {
    constructor() {
        this.intervals = [];
    }

    insert(start, end, data = null) {
        this.intervals.push({ start, end, data });
        this.intervals.sort((a, b) => a.start - b.start);
    }

    // Find all intervals that overlap with [start, end]
    findOverlapping(start, end) {
        return this.intervals.filter(interval =>
            interval.start < end && interval.end > start
        );
    }

    // Check if a new interval would conflict
    hasConflict(start, end) {
        return this.findOverlapping(start, end).length > 0;
    }

    // Merge overlapping intervals
    mergeOverlapping() {
        if (this.intervals.length <= 1) return this.intervals;

        const merged = [this.intervals[0]];

        for (let i = 1; i < this.intervals.length; i++) {
            const current = this.intervals[i];
            const lastMerged = merged[merged.length - 1];

            if (current.start <= lastMerged.end) {
                lastMerged.end = Math.max(lastMerged.end, current.end);
            } else {
                merged.push(current);
            }
        }

        return merged;
    }

    // Find gaps between intervals
    findGaps(rangeStart, rangeEnd) {
        const gaps = [];
        let currentStart = rangeStart;

        for (const interval of this.intervals) {
            if (interval.start > currentStart) {
                gaps.push({
                    start: currentStart,
                    end: Math.min(interval.start, rangeEnd)
                });
            }
            currentStart = Math.max(currentStart, interval.end);
        }

        if (currentStart < rangeEnd) {
            gaps.push({ start: currentStart, end: rangeEnd });
        }

        return gaps;
    }
}

// Usage for calendar
const calendar = new IntervalTree();
calendar.insert(9, 10, { title: 'Meeting 1' });
calendar.insert(11, 12, { title: 'Meeting 2' });
calendar.insert(14, 16, { title: 'Meeting 3' });

console.log(calendar.hasConflict(9.5, 10.5)); // true
console.log(calendar.findGaps(8, 18));
// [{ start: 8, end: 9 }, { start: 10, end: 11 }, { start: 12, end: 14 }, { start: 16, end: 18 }]
