```react
import React, { useState, useEffect, useRef, useCallback }from "react";

function debounce(fn,delay) {
    var timer;
    var debounced = function() {
        var context= this;
        var args= arguments;
        clearTimeout(timer);
        timer= setTimeout(function() {
            fn.apply(context, args);
        }, delay);
    };
    debounced.cancel = function() {clearTimeout(timer); };
    return debounced;
}

function Autocomplete({fetchSuggestions,placeholder,onSelect }) {
    var [query, setQuery]= useState("");
    var [suggestions, setSuggestions]= useState([]);
    var [isLoading, setIsLoading]= useState(false);
    var [isOpen, setIsOpen]= useState(false);
    var [activeIndex, setActiveIndex]= useState(-1);
    var [error, setError]= useState(null);

    var inputRef= useRef(null);
    var listRef= useRef(null);
    var cacheRef= useRef({});

    var debouncedFetch= useCallback(
        debounce(function(searchQuery) {
            if (searchQuery.trim()=== "") {
                setSuggestions([]);
                setIsOpen(false);
                return;
            }

            // Check cache first
            if (cacheRef.current[searchQuery]) {
                setSuggestions(cacheRef.current[searchQuery]);
                setIsOpen(true);
                setIsLoading(false);
                return;
            }

            setIsLoading(true);
            setError(null);

            fetchSuggestions(searchQuery)
                .then(function(results) {
                    cacheRef.current[searchQuery]= results;
                    setSuggestions(results);
                    setIsOpen(true);
                    setIsLoading(false);
                })
                .catch(function(err) {
                    setError("Failed to fetch suggestions");
                    setIsLoading(false);
                    setSuggestions([]);
                });
        },300),
        [fetchSuggestions]
    );

    function handleInputChange(e) {
        var value= e.target.value;
        setQuery(value);
        setActiveIndex(-1);
        debouncedFetch(value);
    }

    function handleSelect(suggestion) {
        setQuery(suggestion.label|| suggestion);
        setSuggestions([]);
        setIsOpen(false);
        setActiveIndex(-1);
        if (onSelect)onSelect(suggestion);
    }

    function handleKeyDown(e) {
        if (!isOpen)return;

        switch (e.key) {
            case "ArrowDown":
                e.preventDefault();
                setActiveIndex(function(prev) {
                    return prev< suggestions.length - 1 ? prev+ 1 : 0;
                });
                break;

            case "ArrowUp":
                e.preventDefault();
                setActiveIndex(function(prev) {
                    return prev> 0 ? prev- 1 : suggestions.length - 1;
                });
                break;

            case "Enter":
                e.preventDefault();
                if (activeIndex>= 0 && activeIndex< suggestions.length) {
                    handleSelect(suggestions[activeIndex]);
                }
                break;

            case "Escape":
                setIsOpen(false);
                setActiveIndex(-1);
                break;
        }
    }

    // Close on outside click
    useEffect(function() {
        function handleClickOutside(e) {
            if (inputRef.current&& !inputRef.current.contains(e.target)&&
                listRef.current&& !listRef.current.contains(e.target)) {
                setIsOpen(false);
            }
        }

        document.addEventListener("mousedown", handleClickOutside);
        return function() {
            document.removeEventListener("mousedown", handleClickOutside);
        };
    }, []);

    // Scroll active item into view
    useEffect(function() {
        if (activeIndex>= 0 && listRef.current) {
            var activeItem= listRef.current.children[activeIndex];
            if (activeItem) {
                activeItem.scrollIntoView({ block:"nearest" });
            }
        }
    }, [activeIndex]);

    function highlightMatch(text,query) {
        if (!query)return text;
        var regex= new RegExp("(" + query.replace(/[.*+?^${}()|[\]\\]/g,"\\$&")+ ")","gi");
        var parts= text.split(regex);

        return parts.map(function(part,i) {
            if (part.toLowerCase()=== query.toLowerCase()) {
                return <strong key={i}style={{ color:"#1a73e8" }}>{part}</strong>;
            }
            return part;
        });
    }

    return (
        <div style={{ position:"relative", width:"100%", maxWidth:"400px" }}>
            <input
                ref={inputRef}
                type="text"
                value={query}
                onChange={handleInputChange}
                onKeyDown={handleKeyDown}
                onFocus={function() {
                    if (suggestions.length > 0)setIsOpen(true);
                }}
                placeholder={placeholder|| "Search..."}
                role="combobox"
                aria-expanded={isOpen}
                aria-autocomplete="list"
                aria-activedescendant={
                    activeIndex>= 0 ? "suggestion-" + activeIndex: undefined
                }
                style={{
                    width:"100%",
                    padding:"10px 12px",
                    fontSize:"16px",
                    border:"1px solid #ddd",
                    borderRadius:"8px",
                    outline:"none",
                    boxSizing:"border-box"
                }}
            />

            {isLoading&& (
                <div style={{
                    position:"absolute",
                    right:"12px",
                    top:"50%",
                    transform:"translateY(-50%)",
                    fontSize:"12px",
                    color:"#999"
                }}>
                    Loading...
                </div>
            )}

            {error&& (
                <div style={{ color:"red", fontSize:"12px", marginTop:"4px" }}>
                    {error}
                </div>
            )}

            {isOpen&& suggestions.length > 0 && (
                <ul
                    ref={listRef}
                    role="listbox"
                    style={{
                        position:"absolute",
                        top:"100%",
                        left:0,
                        right:0,
                        marginTop:"4px",
                        padding:0,
                        listStyle:"none",
                        background:"white",
                        border:"1px solid #ddd",
                        borderRadius:"8px",
                        boxShadow:"0 4px 12px rgba(0,0,0,0.1)",
                        maxHeight:"200px",
                        overflowY:"auto",
                        zIndex:1000
                    }}
                >
                    {suggestions.map(function(suggestion,index) {
                        var label= suggestion.label|| suggestion;
                        var isActive= index=== activeIndex;

                        return (
                            <li
                                key={index}
                                id={"suggestion-" + index}
                                role="option"
                                aria-selected={isActive}
                                onClick={function() {handleSelect(suggestion); }}
                                onMouseEnter={function() {setActiveIndex(index); }}
                                style={{
                                    padding:"10px 12px",
                                    cursor:"pointer",
                                    backgroundColor: isActive? "#f0f0f0" : "white",
                                    borderBottom:"1px solid #f5f5f5",
                                    fontSize:"14px"
                                }}
                            >
                                {highlightMatch(label, query)}
                            </li>
                        );
                    })}
                </ul>
            )}

            {isOpen&& suggestions.length === 0 && !isLoading&& query.trim()!== "" && (
                <div style={{
                    position:"absolute",
                    top:"100%",
                    left:0,
                    right:0,
                    marginTop:"4px",
                    padding:"12px",
                    background:"white",
                    border:"1px solid #ddd",
                    borderRadius:"8px",
                    color:"#999",
                    fontSize:"14px"
                }}>
                    No results found
                </div>
            )}
        </div>
    );
}

