## **🧠 B.4 — Infinite Scroll Component**

```react
import React, { useState, useEffect, useRef, useCallback }from "react";

function useInfiniteScroll(fetchData) {
    var [items, setItems]= useState([]);
    var [page, setPage]= useState(1);
    var [isLoading, setIsLoading]= useState(false);
    var [hasMore, setHasMore]= useState(true);
    var [error, setError]= useState(null);

    var observerRef= useRef(null);

    var lastItemRef= useCallback(function(node) {
        if (isLoading)return;

        if (observerRef.current) {
            observerRef.current.disconnect();
        }

        observerRef.current= new IntersectionObserver(function(entries) {
            if (entries[0].isIntersecting&& hasMore) {
                setPage(function(prev) {return prev+ 1; });
            }
        }, { threshold:0.5 });

        if (node) {
            observerRef.current.observe(node);
        }
    }, [isLoading, hasMore]);

    useEffect(function() {
        var cancelled= false;

        setIsLoading(true);
        setError(null);

        fetchData(page)
            .then(function(result) {
                if (!cancelled) {
                    setItems(function(prev) {return prev.concat(result.data); });
                    setHasMore(result.hasMore);
                    setIsLoading(false);
                }
            })
            .catch(function(err) {
                if (!cancelled) {
                    setError("Failed to load data. Click to retry.");
                    setIsLoading(false);
                }
            });

        return function() { cancelled= true; };
    }, [page, fetchData]);

    function retry() {
        setError(null);
        setPage(function(prev) {return prev; });
        // Force re-fetch
        setItems(function(prev) {return prev; });
    }

    return { items: items, isLoading: isLoading, hasMore: hasMore, error: error, lastItemRef: lastItemRef, retry: retry };
}

function InfiniteScrollList() {
    var fetchData= useCallback(function(page) {
        // Simulated API
        return new Promise(function(resolve) {
            setTimeout(function() {
                var pageSize= 20;
                var totalItems= 100;
                var start= (page- 1)* pageSize;

                var data= [];
                for (var i= start; i< Math.min(start+ pageSize, totalItems); i++) {
                    data.push({
                        id: i+ 1,
                        title:"Item " + (i+ 1),
                        description:"Description for item " + (i+ 1)
                    });
                }

                resolve({
                    data: data,
                    hasMore: start+ pageSize< totalItems
                });
            },1000);
        });
    }, []);

    var result= useInfiniteScroll(fetchData);
    var items= result.items;
    var isLoading= result.isLoading;
    var hasMore= result.hasMore;
    var error= result.error;
    var lastItemRef= result.lastItemRef;
    var retry= result.retry;

    return (
        <div style={{ maxWidth:"600px", margin:"0 auto", padding:"20px" }}>
            <h2>Infinite Scroll Demo</h2>

            <div style={{ display:"flex", flexDirection:"column", gap:"12px" }}>
                {items.map(function(item,index) {
                    var isLast= index=== items.length - 1;

                    return (
                        <div
                            key={item.id}
                            ref={isLast? lastItemRef: null}
                            style={{
                                padding:"16px",
                                border:"1px solid #e0e0e0",
                                borderRadius:"8px",
                                backgroundColor:"white"
                            }}
                        >
                            <h3 style={{ margin:"0 0 8px 0" }}>{item.title}</h3>
                            <p style={{ margin:0, color:"#666" }}>{item.description}</p>
                        </div>
                    );
                })}
            </div>

            {isLoading&& (
                <div style={{ textAlign:"center", padding:"20px", color:"#999" }}>
                    Loading more items...
                </div>
            )}

            {error&& (
                <div
                    onClick={retry}
                    style={{
                        textAlign:"center",
                        padding:"20px",
                        color:"red",
                        cursor:"pointer"
                    }}
                >
                    {error}
                </div>
            )}

            {!hasMore&& items.length > 0 && (
                <div style={{ textAlign:"center", padding:"20px", color:"#999" }}>
                    No more items to load
                </div>
            )}
        </div>
    );
}
