import React, { useState, useRef, useEffect }from "react";

function AccordionItem({title,children,isOpen,onToggle,id }) {
    var contentRef= useRef(null);
    var [contentHeight, setContentHeight]= useState(0);

    useEffect(function() {
        if (contentRef.current) {
            setContentHeight(contentRef.current.scrollHeight);
        }
    }, [children]);

    return (
        <div style={{
            border:"1px solid #e0e0e0",
            borderRadius:"8px",
            marginBottom:"8px",
            overflow:"hidden"
        }}>
            <button
                onClick={onToggle}
                aria-expanded={isOpen}
                aria-controls={"accordion-content-" + id}
                id={"accordion-header-" + id}
                style={{
                    width:"100%",
                    padding:"16px",
                    display:"flex",
                    justifyContent:"space-between",
                    alignItems:"center",
                    background: isOpen? "#f5f5f5" : "white",
                    border:"none",
                    cursor:"pointer",
                    fontSize:"16px",
                    fontWeight:"bold",
                    textAlign:"left",
                    transition:"background 0.2s ease"
                }}
            >
                <span>{title}</span>
                <span style={{
                    transform: isOpen? "rotate(180deg)" : "rotate(0deg)",
                    transition:"transform 0.3s ease",
                    fontSize:"12px"
                }}>
                    ▼
                </span>
            </button>

            <div
                id={"accordion-content-" + id}
                role="region"
                aria-labelledby={"accordion-header-" + id}
                style={{
                    maxHeight: isOpen? contentHeight+ "px" : "0px",
                    overflow:"hidden",
                    transition:"max-height 0.3s ease"
                }}
            >
                <div ref={contentRef}style={{ padding:"16px" }}>
                    {children}
                </div>
            </div>
        </div>
    );
}

function Accordion({items,allowMultiple }) {
    var [openItems, setOpenItems]= useState({});

    function handleToggle(index) {
        setOpenItems(function(prev) {
            if (allowMultiple) {
                var newState= {};
                Object.keys(prev).forEach(function(key) {
                    newState[key]= prev[key];
                });
                newState[index]= !prev[index];
                return newState;
            }

            // Single mode — close all others
            var singleState= {};
            singleState[index]= !prev[index];
            return singleState;
        });
    }

    return (
        <div>
            {items.map(function(item,index) {
                return (
                    <AccordionItem
                        key={index}
                        id={index}
                        title={item.title}
                        isOpen={!!openItems[index]}
                        onToggle={function() {handleToggle(index); }}
                    >
                        {item.content}
                    </AccordionItem>
                );
            })}
        </div>
    );
}

// Usage:
