import React, { useState, useMemo }from "react";

var FILTERS = {
    ALL:"all",
    ACTIVE:"active",
    COMPLETED:"completed"
};

function TodoApp() {
    var [todos, setTodos]= useState([]);
    var [inputValue, setInputValue]= useState("");
    var [filter, setFilter]= useState(FILTERS.ALL);
    var [editingId, setEditingId]= useState(null);
    var [editValue, setEditValue]= useState("");

    function addTodo(e) {
        e.preventDefault();
        if (inputValue.trim()=== "")return;

        var newTodo= {
            id: Date.now(),
            text: inputValue.trim(),
            completed:false,
            createdAt:new Date()
        };

        setTodos(function(prev) {return [newTodo].concat(prev); });
        setInputValue("");
    }

    function toggleTodo(id) {
        setTodos(function(prev) {
            return prev.map(function(todo) {
                if (todo.id=== id) {
                    return Object.assign({}, todo, { completed:!todo.completed });
                }
                return todo;
            });
        });
    }

    function deleteTodo(id) {
        setTodos(function(prev) {
            return prev.filter(function(todo) {return todo.id!== id; });
        });
    }

    function startEditing(todo) {
        setEditingId(todo.id);
        setEditValue(todo.text);
    }

    function saveEdit(id) {
        if (editValue.trim()=== "") {
            deleteTodo(id);
        }else {
            setTodos(function(prev) {
                return prev.map(function(todo) {
                    if (todo.id=== id) {
                        return Object.assign({}, todo, { text: editValue.trim() });
                    }
                    return todo;
                });
            });
        }
        setEditingId(null);
        setEditValue("");
    }

