        setTodos(function(prev) {
            return prev.map(function(todo) {
                return Object.assign({}, todo, { completed:!allCompleted });
            });
        });
    }

    var filteredTodos= useMemo(function() {
        switch (filter) {
            case FILTERS.ACTIVE:
                return todos.filter(function(t) {return !t.completed; });
            case FILTERS.COMPLETED:
                return todos.filter(function(t) {return t.completed; });
            default:
                return todos;
        }
    }, [todos, filter]);

    var activeCount= todos.filter(function(t) {return !t.completed; }).length;
    var completedCount= todos.filter(function(t) {return t.completed; }).length;

    var containerStyle= {
        maxWidth:"500px",
        margin:"0 auto",
        padding:"20px",
