                <input
                    type="text"
                    value={inputValue}
                    onChange={function(e) {setInputValue(e.target.value); }}
                    placeholder="What needs to be done?"
                    style={{
                        flex:1,
                        padding:"12px",
                        fontSize:"16px",
                        border:"1px solid #ddd",
                        borderRadius:"8px",
                        outline:"none"
                    }}
