                <button
                    type="submit"
                    style={{
                        padding:"12px 20px",
                        fontSize:"16px",
                        backgroundColor:"#4CAF50",
                        color:"white",
                        border:"none",
                        borderRadius:"8px",
                        cursor:"pointer"
                    }}
                >
                    Add
                </button>
            </form>

            {/* Toggle All */}
            {todos.length > 0 && (
                <div style={{ marginBottom:"12px" }}>
                    <label style={{ cursor:"pointer", fontSize:"14px" }}>
                        <input
                            type="checkbox"
                            checked={todos.length > 0 && activeCount=== 0}
                            onChange={toggleAll}
                        />
                        {" "}Mark all as complete
                    </label>
                </div>
            )}

            {/* Todo List */}
            <ul style={{ listStyle:"none", padding:0 }}>
                {filteredTodos.map(function(todo) {
                    return (
                        <li
                            key={todo.id}
                            style={{
                                display:"flex",
                                alignItems:"center",
                                gap:"12px",
                                padding:"12px",
                                borderBottom:"1px solid #f0f0f0",
                                backgroundColor: todo.completed? "#f9f9f9" : "white"
                            }}
                        >
                            <input
                                type="checkbox"
                                checked={todo.completed}
                                onChange={function() {toggleTodo(todo.id); }}
                                style={{ width:"20px", height:"20px", cursor:"pointer" }}
                            />

                            {editingId=== todo.id? (
                                <input
