                    <span>{activeCount} item{activeCount!== 1 ? "s" : ""} left</span>

                    <div style={{ display:"flex", gap:"8px" }}>
                        {[FILTERS.ALL,FILTERS.ACTIVE,FILTERS.COMPLETED].map(function(f) {
                            return (
                                <button
                                    key={f}
                                    onClick={function() {setFilter(f); }}
                                    style={{
                                        padding:"4px 12px",
                                        border: filter=== f? "1px solid #999" : "1px solid transparent",
                                        borderRadius:"4px",
                                        backgroundColor:"transparent",
                                        cursor:"pointer",
                                        textTransform:"capitalize"
                                    }}
                                >
                                    {f}
                                </button>
                            );
                        })}
                    </div>

                    {completedCount> 0 && (
                        <button
                            onClick={clearCompleted}
                            style={{
                                padding:"4px 8px",
                                backgroundColor:"transparent",
                                border:"none",
                                cursor:"pointer",
                                color:"#999",
                                textDecoration:"underline"
                            }}
                        >
                            Clear completed
                        </button>
                    )}
                </div>
            )}
        </div>
    );
}
