## **🧠 B.7 — Toast Notification System**

```react
import React, { useState, useCallback, useRef, useEffect }from "react";

var ToastContext= React.createContext(null);

function ToastProvider({children }) {
    var [toasts, setToasts]= useState([]);
    var toastIdRef= useRef(0);

    var addToast= useCallback(function(message,type,duration) {
        if (!type) type= "info";
        if (!duration) duration= 3000;

        var id= ++toastIdRef.current;

        var newToast= {
            id: id,
            message: message,
            type: type,
            duration: duration,
            createdAt: Date.now()
        };

        setToasts(function(prev) {return prev.concat([newToast]); });

        if (duration> 0) {
            setTimeout(function() {
                removeToast(id);
            }, duration);
        }

        return id;
    }, []);

    var removeToast= useCallback(function(id) {
        setToasts(function(prev) {
            return prev.filter(function(toast) {return toast.id!== id; });
        });
    }, []);

    var contextValue= {
        addToast: addToast,
        removeToast: removeToast,
        success:function(msg,duration) {return addToast(msg,"success", duration); },
        error:function(msg,duration) {return addToast(msg,"error", duration); },
        warning:function(msg,duration) {return addToast(msg,"warning", duration); },
        info:function(msg,duration) {return addToast(msg,"info", duration); }
    };

    var toastColors= {
        success: { bg:"#4CAF50", icon:"✓" },
        error: { bg:"#f44336", icon:"✕" },
        warning: { bg:"#ff9800", icon:"⚠" },
        info: { bg:"#2196F3", icon:"ℹ" }
    };

    return (
        <ToastContext.Provider value={contextValue}>
            {children}

            {/* Toast Container */}
            <div style={{
                position:"fixed",
                top:"20px",
                right:"20px",
                zIndex:9999,
                display:"flex",
                flexDirection:"column",
                gap:"8px",
                maxWidth:"400px"
            }}>
                {toasts.map(function(toast) {
                    var color= toastColors[toast.type]|| toastColors.info;

                    return (
                        <div
                            key={toast.id}
                            role="alert"
                            style={{
                                display:"flex",
                                alignItems:"center",
                                gap:"12px",
                                padding:"12px 16px",
                                backgroundColor: color.bg,
                                color:"white",
                                borderRadius:"8px",
                                boxShadow:"0 4px 12px rgba(0,0,0,0.15)",
                                animation:"slideIn 0.3s ease",
                                fontSize:"14px",
                                minWidth:"300px"
                            }}
                        >
                            <span style={{ fontSize:"18px" }}>{color.icon}</span>
                            <span style={{ flex:1 }}>{toast.message}</span>
                            <button
                                onClick={function() {removeToast(toast.id); }}
                                style={{
                                    background:"none",
                                    border:"none",
                                    color:"white",
                                    fontSize:"18px",
                                    cursor:"pointer",
                                    padding:"0 4px",
                                    opacity:0.7
                                }}
                            >
                                ×
                            </button>
                        </div>
                    );
                })}
            </div>
        </ToastContext.Provider>
    );
}

function useToast() {
    var context= React.useContext(ToastContext);
    if (!context) {
        throw new Error("useToast must be used within a ToastProvider");
    }
    return context;
}

// Usage:
function App() {
    return (
        <ToastProvider>
            <Demo />
        </ToastProvider>
    );
}

function Demo() {
    var toast= useToast();

    return (
        <div style={{ padding:"40px", display:"flex", gap:"12px" }}>
            <button onClick={function() { toast.success("Operation completed!"); }}>
                Success
            </button>
            <button onClick={function() { toast.error("Something went wrong!"); }}>
                Error
            </button>
            <button onClick={function() { toast.warning("Please check your input"); }}>
                Warning
            </button>
            <button onClick={function() { toast.info("New update available"); }}>
                Info
            </button>
        </div>
    );
}
