    }
];

function Comment({comment,onReply,onDelete,onEdit,depth }) {
    if (!depth) depth= 0;

    var [isReplying, setIsReplying]= useState(false);
    var [replyText, setReplyText]= useState("");
    var [isEditing, setIsEditing]= useState(false);
    var [editText, setEditText]= useState(comment.text);
    var [isCollapsed, setIsCollapsed]= useState(false);

    function handleReply(e) {
        e.preventDefault();
        if (replyText.trim()=== "")return;

        onReply(comment.id, replyText.trim());
        setReplyText("");
        setIsReplying(false);
    }

    function handleEdit(e) {
        e.preventDefault();
        if (editText.trim()=== "")return;

        onEdit(comment.id, editText.trim());
        setIsEditing(false);
    }

    var maxDepth= 4;

    return (
        <div style={{
            marginLeft: depth> 0 ? "24px" : "0",
            borderLeft: depth> 0 ? "2px solid #e0e0e0" : "none",
            paddingLeft: depth> 0 ? "16px" : "0",
            marginTop:"12px"
        }}>
            <div style={{ display:"flex", gap:"8px", alignItems:"center" }}>
                <div style={{
                    width:"32px",
                    height:"32px",
                    borderRadius:"50%",
                    backgroundColor:"#" + ((comment.id* 123456)% 16777215).toString(16).padStart(6,"0"),
                    display:"flex",
                    alignItems:"center",
                    justifyContent:"center",
                    color:"white",
                    fontSize:"14px",
                    fontWeight:"bold"
                }}>
                    {comment.author[0]}
                </div>

                <div>
                    <strong style={{ fontSize:"14px" }}>{comment.author}</strong>
                    <span style={{ fontSize:"12px", color:"#999", marginLeft:"8px" }}>
                        {comment.timestamp}
                    </span>
                </div>
            </div>

            {isEditing? (
                <form onSubmit={handleEdit}style={{ marginTop:"8px" }}>
                    <textarea
                        value={editText}
                        onChange={function(e) {setEditText(e.target.value); }}
                        style={{
                            width:"100%",
                            padding:"8px",
                            borderRadius:"4px",
                            border:"1px solid #ddd",
                            fontSize:"14px",
                            resize:"vertical",
                            minHeight:"60px",
                            boxSizing:"border-box"
                        }}
                    />
                    <div style={{ display:"flex", gap:"8px", marginTop:"4px" }}>
                        <button type="submit" style={{ fontSize:"12px", padding:"4px 12px" }}>
                            Save
                        </button>
                        <button
                            type="button"
                            onClick={function() {setIsEditing(false);setEditText(comment.text); }}
                            style={{ fontSize:"12px", padding:"4px 12px" }}
                        >
                            Cancel
                        </button>
                    </div>
                </form>
            ): (
                <p style={{ fontSize:"14px", color:"#333", margin:"8px 0", lineHeight:1.5 }}>
                    {comment.text}
                </p>
            )}

            {/* Action Buttons */}
            <div style={{ display:"flex", gap:"12px", fontSize:"12px" }}>
                {depth< maxDepth&& (
                    <button
                        onClick={function() {setIsReplying(!isReplying); }}
                        style={{
                            background:"none",
                            border:"none",
                            color:"#1a73e8",
                            cursor:"pointer",
                            padding:0,
                            fontSize:"12px"
                        }}
                    >
                        Reply
                    </button>
                )}

                <button
                    onClick={function() {setIsEditing(true); }}
                    style={{
                        background:"none",
                        border:"none",
                        color:"#666",
                        cursor:"pointer",
                        padding:0,
                        fontSize:"12px"
                    }}
                >
                    Edit
                </button>

                <button
                    onClick={function() {onDelete(comment.id); }}
                    style={{
                        background:"none",
                        border:"none",
                        color:"#ff4444",
                        cursor:"pointer",
                        padding:0,
                        fontSize:"12px"
                    }}
                >
                    Delete
                </button>

                {comment.replies&& comment.replies.length > 0 && (
                    <button
                        onClick={function() {setIsCollapsed(!isCollapsed); }}
                        style={{
                            background:"none",
                            border:"none",
                            color:"#666",
                            cursor:"pointer",
                            padding:0,
                            fontSize:"12px"
                        }}
                    >
                        {isCollapsed
                            ? "Show " + comment.replies.length + " replies"
                            : "Hide replies"
                        }
                    </button>
                )}
            </div>

            {/* Reply Form */}
            {isReplying&& (
                <form onSubmit={handleReply}style={{ marginTop:"8px" }}>
                    <textarea
                        value={replyText}
                        onChange={function(e) {setReplyText(e.target.value); }}
                        placeholder="Write a reply..."
                        autoFocus
                        style={{
                            width:"100%",
                            padding:"8px",
                            borderRadius:"4px",
                            border:"1px solid #ddd",
                            fontSize:"14px",
                            resize:"vertical",
                            minHeight:"60px",
                            boxSizing:"border-box"
                        }}
                    />
                    <div style={{ display:"flex", gap:"8px", marginTop:"4px" }}>
                        <button type="submit" style={{ fontSize:"12px", padding:"4px 12px" }}>
                            Post Reply
                        </button>
                        <button
                            type="button"
                            onClick={function() {setIsReplying(false);setReplyText(""); }}
                            style={{ fontSize:"12px", padding:"4px 12px" }}
                        >
                            Cancel
                        </button>
                    </div>
                </form>
            )}

            {/* Nested Replies */}
            {!isCollapsed&& comment.replies&& comment.replies.map(function(reply) {
                return (
                    <Comment
                        key={reply.id}
                        comment={reply}
                        onReply={onReply}
                        onDelete={onDelete}
                        onEdit={onEdit}
                        depth={depth+ 1}
                    />
                );
            })}
        </div>
    );
}

function CommentsSection() {
    var [comments, setComments]= useState(initialComments);
    var nextIdRef= React.useRef(100);

    function addReply(parentId,text) {
        function addReplyToComment(commentsList,targetId) {
            return commentsList.map(function(comment) {
                if (comment.id=== targetId) {
                    return Object.assign({}, comment, {
                        replies: comment.replies.concat([{
                            id:++nextIdRef.current,
                            author:"You",
                            text: text,
                            timestamp:"Just now",
                            replies: []
                        }])
                    });
                }

                if (comment.replies&& comment.replies.length > 0) {
                    return Object.assign({}, comment, {
                        replies:addReplyToComment(comment.replies, targetId)
                    });
                }

                return comment;
            });
        }

        setComments(function(prev) {return addReplyToComment(prev, parentId); });
    }

    function deleteComment(targetId) {
        function removeComment(commentsList) {
            return commentsList
                .filter(function(comment) {return comment.id!== targetId; })
                .map(function(comment) {
                    if (comment.replies&& comment.replies.length > 0) {
                        return Object.assign({}, comment, {
                            replies:removeComment(comment.replies)
                        });
                    }
                    return comment;
                });
        }

        setComments(function(prev) {return removeComment(prev); });
    }

    function editComment(targetId,newText) {
        function updateComment(commentsList) {
            return commentsList.map(function(comment) {
                if (comment.id=== targetId) {
                    return Object.assign({}, comment, { text: newText });
                }
                if (comment.replies&& comment.replies.length > 0) {
                    return Object.assign({}, comment, {
                        replies:updateComment(comment.replies)
                    });
                }
                return comment;
            });
        }

        setComments(function(prev) {return updateComment(prev); });
    }

    return (
        <div style={{ maxWidth:"600px", margin:"0 auto", padding:"20px" }}>
            <h2>Comments ({comments.length})</h2>

            {comments.map(function(comment) {
                return (
                    <Comment
                        key={comment.id}
                        comment={comment}
                        onReply={addReply}
                        onDelete={deleteComment}
                        onEdit={editComment}
                        depth={0}
                    />
                );
            })}
        </div>
    );
}
