```
// ═══════════════════════════════════════════════════════════
// LIVE CODING SESSION: Build a Debounced Search Component
// ═══════════════════════════════════════════════════════════

/*
INTERVIEWER: "Build a search component that:
1. Debounces user input
2. Shows loading state
3. Displays search results
4. Handles errors
5. Has keyboard navigation

You have 30 minutes."

APPROACH:
1. Clarify requirements (2 min)
2. Outline the solution (3 min)
3. Implement core functionality (20 min)
4. Test and refine (5 min)
*/

// ─────────────────────────────────────────────────────────────
// Step 1: Clarify Requirements
// ─────────────────────────────────────────────────────────────

/*
Questions to ask:
- "What should the debounce delay be?" → 300ms
- "Should we show recent searches?" → Nice to have
- "Is there a minimum query length?" → 2 characters
- "What does the API response look like?" → Array of { id, title, description }
- "Should clicking a result do anything specific?" → Navigate or callback
*/

// ─────────────────────────────────────────────────────────────
// Step 2: Outline the Solution (Think Aloud)
// ─────────────────────────────────────────────────────────────

/*
"I'll structure this as follows:
1. First, I'll create a useDebounce hook for the input
2. Then a useSearch hook to handle the API call
3. The main component will manage the UI state
4. I'll add keyboard navigation last if time permits

Let me start with the hooks since they're reusable..."
*/

// ─────────────────────────────────────────────────────────────
// Step 3: Implementation (Narrate as you code)
// ─────────────────────────────────────────────────────────────

import { useState, useEffect, useRef, useCallback, useMemo } from 'react';

// "First, let me create a simple debounce hook..."
function useDebounce<T>(value: T, delay: number): T {
    const [debouncedValue, setDebouncedValue] = useState(value);

    useEffect(() => {
        // "Set up a timer that updates the debounced value after the delay"
        const timer = setTimeout(() => {
            setDebouncedValue(value);
        }, delay);

        // "Clean up the timer if value changes before delay completes"
        return () => clearTimeout(timer);
    }, [value, delay]);

    return debouncedValue;
}

// "Now let me create the search hook with proper loading and error states..."
interface SearchResult {
    id: string;
    title: string;
    description: string;
}

interface UseSearchReturn {
    results: SearchResult[];
    isLoading: boolean;
    error: string | null;
}

function useSearch(query: string): UseSearchReturn {
    const [results, setResults] = useState<SearchResult[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // "I'll use a ref to track the current request and cancel stale ones"
    const abortControllerRef = useRef<AbortController | null>(null);

    useEffect(() => {
        // "Skip if query is too short"
        if (query.length < 2) {
            setResults([]);
            return;
        }

        // "Cancel any previous request"
        if (abortControllerRef.current) {
            abortControllerRef.current.abort();
        }

        // "Create new abort controller for this request"
        const abortController = new AbortController();
        abortControllerRef.current = abortController;

        const fetchResults = async () => {
            setIsLoading(true);
            setError(null);

            try {
                const response = await fetch(
                    `/api/search?q=${encodeURIComponent(query)}`,
                    { signal: abortController.signal }
                );

                if (!response.ok) {
                    throw new Error('Search failed');
                }

                const data = await response.json();
                setResults(data.results);
            } catch (err) {
                // "Don't set error for aborted requests"
                if ((err as Error).name !== 'AbortError') {
                    setError((err as Error).message);
                    setResults([]);
                }
            } finally {
                setIsLoading(false);
            }
        };

        fetchResults();

        // "Cleanup function to abort on unmount or query change"
        return () => {
            abortController.abort();
        };
    }, [query]);

    return { results, isLoading, error };
}

// "Now for the main component with keyboard navigation..."
interface SearchComponentProps {
    onSelect: (result: SearchResult) => void;
    placeholder?: string;
}

function SearchComponent({ onSelect, placeholder = 'Search...' }: SearchComponentProps) {
    const [query, setQuery] = useState('');
    const [isOpen, setIsOpen] = useState(false);
    const [highlightedIndex, setHighlightedIndex] = useState(-1);

    const inputRef = useRef<HTMLInputElement>(null);
    const listRef = useRef<HTMLUListElement>(null);

    // "Apply debounce to the query"
    const debouncedQuery = useDebounce(query, 300);

    // "Fetch search results"
    const { results, isLoading, error } = useSearch(debouncedQuery);

    // "Handle keyboard navigation"
    const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
        switch (e.key) {
            case 'ArrowDown':
                e.preventDefault();
                setHighlightedIndex(prev =>
                    prev < results.length - 1 ? prev + 1 : prev
                );
                break;
            case 'ArrowUp':
                e.preventDefault();
                setHighlightedIndex(prev => prev > 0 ? prev - 1 : prev);
                break;
            case 'Enter':
                e.preventDefault();
                if (highlightedIndex >= 0 && results[highlightedIndex]) {
                    handleSelect(results[highlightedIndex]);
                }
                break;
            case 'Escape':
                setIsOpen(false);
                inputRef.current?.blur();
                break;
        }
    }, [results, highlightedIndex]);

    // "Handle result selection"
    const handleSelect = useCallback((result: SearchResult) => {
        setQuery(result.title);
        setIsOpen(false);
        setHighlightedIndex(-1);
        onSelect(result);
    }, [onSelect]);

    // "Reset highlighted index when results change"
    useEffect(() => {
        setHighlightedIndex(-1);
    }, [results]);

    // "Open dropdown when there's input"
    useEffect(() => {
        if (query.length >= 2) {
            setIsOpen(true);
        }
    }, [query]);

    // "Scroll highlighted item into view"
    useEffect(() => {
        if (highlightedIndex >= 0 && listRef.current) {
            const item = listRef.current.children[highlightedIndex] as HTMLElement;
            item?.scrollIntoView({ block: 'nearest' });
        }
    }, [highlightedIndex]);

    return (
        <div className="search-component">
            <div className="search-input-wrapper">
                <input
                    ref={inputRef}
                    type="text"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    onFocus={() => query.length >= 2 && setIsOpen(true)}
                    onKeyDown={handleKeyDown}
                    placeholder={placeholder}
                    role="combobox"
                    aria-expanded={isOpen}
                    aria-haspopup="listbox"
                    aria-autocomplete="list"
                    aria-controls="search-results"
                    aria-activedescendant={
                        highlightedIndex >= 0 ? `result-${highlightedIndex}` : undefined
                    }
                />

                {isLoading && (
                    <span className="loading-spinner" aria-label="Loading" />
                )}
            </div>

            {isOpen && (
                <ul
                    ref={listRef}
                    id="search-results"
                    role="listbox"
                    className="search-results"
                >
                    {error && (
                        <li className="search-error" role="alert">
                            {error}
                        </li>
                    )}

                    {!error && results.length === 0 && debouncedQuery.length >= 2 && !isLoading && (
                        <li className="no-results">
                            No results found for "{debouncedQuery}"
                        </li>
                    )}

                    {results.map((result, index) => (
                        <li
                            key={result.id}
                            id={`result-${index}`}
                            role="option"
                            aria-selected={index === highlightedIndex}
                            className={`search-result ${index === highlightedIndex ? 'highlighted' : ''}`}
                            onClick={() => handleSelect(result)}
                            onMouseEnter={() => setHighlightedIndex(index)}
                        >
                            <span className="result-title">{result.title}</span>
                            <span className="result-description">{result.description}</span>
                        </li>
                    ))}
                </ul>
            )}
        </div>
    );
}

export default SearchComponent;
```

