// "I'll start with the core modal functionality and add features progressively..."

import {
    useState,
    useEffect,
    useRef,
    useCallback,
    createContext,
    useContext,
    ReactNode
} from 'react';
import { createPortal } from 'react-dom';

// "First, let me set up the types and context for modal state..."
interface ModalContextValue {
    isOpen: boolean;
    onClose: () => void;
}

const ModalContext = createContext<ModalContextValue | null>(null);

function useModalContext() {
    const context = useContext(ModalContext);
    if (!context) {
        throw new Error('Modal components must be used within Modal');
    }
    return context;
}

// "Now the main Modal component with portal rendering..."
interface ModalProps {
    isOpen: boolean;
    onClose: () => void;
    children: ReactNode;
    closeOnOverlayClick?: boolean;
    closeOnEscape?: boolean;
}

function Modal({
    isOpen,
    onClose,
    children,
    closeOnOverlayClick = true,
    closeOnEscape = true
}: ModalProps) {
    const [isMounted, setIsMounted] = useState(false);
    const [isAnimating, setIsAnimating] = useState(false);
    const modalRef = useRef<HTMLDivElement>(null);
    const previousActiveElement = useRef<HTMLElement | null>(null);

    // "Handle mounting for SSR compatibility..."
    useEffect(() => {
        setIsMounted(true);
    }, []);

    // "Handle escape key..."
    useEffect(() => {
        if (!isOpen || !closeOnEscape) return;

        const handleEscape = (e: KeyboardEvent) => {
            if (e.key === 'Escape') {
                onClose();
            }
        };

        document.addEventListener('keydown', handleEscape);
        return () => document.removeEventListener('keydown', handleEscape);
    }, [isOpen, closeOnEscape, onClose]);

    // "Focus management - save previous focus and restore on close..."
    useEffect(() => {
        if (isOpen) {
            previousActiveElement.current = document.activeElement as HTMLElement;
            modalRef.current?.focus();
            document.body.style.overflow = 'hidden';
        } else {
            document.body.style.overflow = '';
            previousActiveElement.current?.focus();
        }

        return () => {
            document.body.style.overflow = '';
        };
    }, [isOpen]);

    // "Focus trapping..."
    const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
        if (e.key !== 'Tab') return;

        const focusableElements = modalRef.current?.querySelectorAll(
            'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
        );

        if (!focusableElements?.length) return;

        const first = focusableElements[0] as HTMLElement;
        const last = focusableElements[focusableElements.length - 1] as HTMLElement;

        if (e.shiftKey && document.activeElement === first) {
            e.preventDefault();
            last.focus();
        } else if (!e.shiftKey && document.activeElement === last) {
            e.preventDefault();
            first.focus();
        }
    }, []);

    // "Handle overlay click..."
    const handleOverlayClick = useCallback((e: React.MouseEvent) => {
        if (closeOnOverlayClick && e.target === e.currentTarget) {
            onClose();
        }
    }, [closeOnOverlayClick, onClose]);

    // "Animation handling..."
    useEffect(() => {
        if (isOpen) {
            setIsAnimating(true);
        } else {
            const timer = setTimeout(() => setIsAnimating(false), 200);
            return () => clearTimeout(timer);
        }
    }, [isOpen]);

    // "Don't render on server or when not open..."
    if (!isMounted || (!isOpen && !isAnimating)) {
        return null;
    }

    const modalContent = (
        <ModalContext.Provider value={{ isOpen, onClose }}>
            <div
                className={`modal-overlay ${isOpen ? 'open' : 'closing'}`}
                onClick={handleOverlayClick}
                aria-hidden={!isOpen}
            >
                <div
                    ref={modalRef}
                    className={`modal-content ${isOpen ? 'open' : 'closing'}`}
                    role="dialog"
                    aria-modal="true"
                    tabIndex={-1}
                    onKeyDown={handleKeyDown}
                >
                    {children}
                </div>
            </div>
        </ModalContext.Provider>
    );

    return createPortal(modalContent, document.body);
}

// "Compound components for flexibility..."
function ModalHeader({ children }: { children: ReactNode }) {
    const { onClose } = useModalContext();

    return (
        <header className="modal-header">
            <h2>{children}</h2>
            <button
                onClick={onClose}
                className="modal-close"
                aria-label="Close modal"
            >
                ×
            </button>
        </header>
    );
}

function ModalBody({ children }: { children: ReactNode }) {
    return <div className="modal-body">{children}</div>;
}

function ModalFooter({ children }: { children: ReactNode }) {
    return <footer className="modal-footer">{children}</footer>;
}

// "Attach compound components..."
Modal.Header = ModalHeader;
Modal.Body = ModalBody;
Modal.Footer = ModalFooter;

export default Modal;

// "CSS for animations..."
const modalStyles = `
.modal-overlay {
    position: fixed;
    inset: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    opacity: 0;
    transition: opacity 0.2s ease;
    z-index: 1000;
}

.modal-overlay.open {
    opacity: 1;
}

.modal-overlay.closing {
    opacity: 0;
}

.modal-content {
    background: white;
    border-radius: 8px;
    max-width: 500px;
    width: 90%;
    max-height: 90vh;
    overflow-y: auto;
    transform: scale(0.9) translateY(-20px);
    transition: transform 0.2s ease;
}

.modal-content.open {
    transform: scale(1) translateY(0);
}

.modal-content.closing {
    transform: scale(0.9) translateY(-20px);
}
`;

// "Usage example..."
function ModalExample() {
    const [isOpen, setIsOpen] = useState(false);

    return (
        <>
            <button onClick={() => setIsOpen(true)}>Open Modal</button>

            <Modal isOpen={isOpen} onClose={() => setIsOpen(false)}>
                <Modal.Header>Confirm Action</Modal.Header>
                <Modal.Body>
                    <p>Are you sure you want to proceed?</p>
                </Modal.Body>
                <Modal.Footer>
