// ═══════════════════════════════════════════════════════════
// LIVE CODING SESSION: Implement useAsync Hook
// ═══════════════════════════════════════════════════════════

/*
INTERVIEWER: "Implement a useAsync hook that:
1. Handles loading, error, and success states
2. Supports immediate or manual execution
3. Provides retry functionality
4. Handles race conditions
5. Is fully typed with TypeScript

You have 20 minutes."
*/

type AsyncStatus = 'idle' | 'pending' | 'success' | 'error';

interface AsyncState<T> {
    status: AsyncStatus;
    data: T | null;
    error: Error | null;
}

interface UseAsyncOptions {
    immediate?: boolean;
    onSuccess?: (data: any) => void;
    onError?: (error: Error) => void;
}

interface UseAsyncReturn<T, Args extends any[]> {
    status: AsyncStatus;
    data: T | null;
    error: Error | null;
    isIdle: boolean;
    isPending: boolean;
    isSuccess: boolean;
    isError: boolean;
    execute: (...args: Args) => Promise<T>;
    reset: () => void;
}

function useAsync<T, Args extends any[] = []>(
    asyncFunction: (...args: Args) => Promise<T>,
    options: UseAsyncOptions = {}
): UseAsyncReturn<T, Args> {
    const { immediate = false, onSuccess, onError } = options;

    const [state, setState] = useState<AsyncState<T>>({
        status: 'idle',
        data: null,
        error: null
    });

    // "Track the latest call to handle race conditions..."
    const lastCallId = useRef(0);
    const mountedRef = useRef(true);

    // "Cleanup on unmount..."
    useEffect(() => {
        mountedRef.current = true;
        return () => {
            mountedRef.current = false;
        };
    }, []);

    // "Execute function with race condition handling..."
    const execute = useCallback(async (...args: Args): Promise<T> => {
        const callId = ++lastCallId.current;

        setState(prev => ({
            ...prev,
            status: 'pending',
            error: null
        }));

        try {
            const result = await asyncFunction(...args);

            // "Only update state if this is the latest call and component is mounted"
            if (callId === lastCallId.current && mountedRef.current) {
                setState({
                    status: 'success',
                    data: result,
                    error: null
                });
                onSuccess?.(result);
            }

            return result;
        } catch (error) {
            const err = error instanceof Error ? error : new Error(String(error));

            if (callId === lastCallId.current && mountedRef.current) {
                setState({
                    status: 'error',
                    data: null,
                    error: err
                });
                onError?.(err);
            }

            throw err;
        }
    }, [asyncFunction, onSuccess, onError]);

    // "Reset to initial state..."
    const reset = useCallback(() => {
        lastCallId.current++;
        setState({
            status: 'idle',
            data: null,
            error: null
        });
    }, []);

    // "Execute immediately if requested..."
    useEffect(() => {
        if (immediate) {
            execute(...([] as unknown as Args));
        }
    }, [immediate]); // eslint-disable-line react-hooks/exhaustive-deps

    // "Computed boolean states for convenience..."
    const isIdle = state.status === 'idle';
    const isPending = state.status === 'pending';
    const isSuccess = state.status === 'success';
    const isError = state.status === 'error';

    return {
        ...state,
        isIdle,
        isPending,
        isSuccess,
        isError,
        execute,
        reset
    };
}

// "Extended version with retry functionality..."
interface UseAsyncWithRetryOptions extends UseAsyncOptions {
    retries?: number;
    retryDelay?: number;
}

function useAsyncWithRetry<T, Args extends any[] = []>(
    asyncFunction: (...args: Args) => Promise<T>,
    options: UseAsyncWithRetryOptions = {}
): UseAsyncReturn<T, Args> & { retry: () => Promise<T> } {
    const { retries = 3, retryDelay = 1000, ...restOptions } = options;

    const [retryCount, setRetryCount] = useState(0);
    const lastArgsRef = useRef<Args | null>(null);

    const wrappedFunction = useCallback(async (...args: Args): Promise<T> => {
        lastArgsRef.current = args;
        let lastError: Error | null = null;

        for (let attempt = 0; attempt <= retries; attempt++) {
            try {
                return await asyncFunction(...args);
            } catch (error) {
                lastError = error instanceof Error ? error : new Error(String(error));

                if (attempt < retries) {
                    await new Promise(resolve =>
                        setTimeout(resolve, retryDelay * Math.pow(2, attempt))
                    );
                    setRetryCount(attempt + 1);
                }
            }
        }

        throw lastError;
    }, [asyncFunction, retries, retryDelay]);

    const asyncResult = useAsync(wrappedFunction, restOptions);

    const retry = useCallback(async () => {
        if (lastArgsRef.current) {
            setRetryCount(0);
            return asyncResult.execute(...lastArgsRef.current);
        }
        throw new Error('No previous call to retry');
    }, [asyncResult.execute]);

    return {
        ...asyncResult,
        retry
    };
}

// "Usage examples..."
function AsyncExample() {
    // Basic usage
    const { data, isPending, isError, error, execute } = useAsync(
        async (userId: string) => {
            const response = await fetch(`/api/users/${userId}`);
            if (!response.ok) throw new Error('Failed to fetch user');
            return response.json();
        }
    );

    // With immediate execution
    const userList = useAsync(
        async () => {
            const response = await fetch('/api/users');
            return response.json();
        },
        { immediate: true }
    );

    // With retry
    const { data: retryData, retry, isPending: isRetrying } = useAsyncWithRetry(
        async () => {
            const response = await fetch('/api/unstable-endpoint');
            if (!response.ok) throw new Error('Request failed');
            return response.json();
        },
        { retries: 3, retryDelay: 1000 }
    );

    return (
        <div>
            <button onClick={() => execute('123')} disabled={isPending}>
                {isPending ? 'Loading...' : 'Fetch User'}
            </button>

            {isError && (
                <div>
                    Error: {error?.message}
                    <button onClick={retry}>Retry</button>
                </div>
            )}

            {data && <pre>{JSON.stringify(data, null, 2)}</pre>}
        </div>
    );
}
