/*
CHALLENGE: "Build a todo list with the following features:
1. Add new todos
2. Toggle todo completion
3. Delete todos
4. Filter by status (all/active/completed)
5. Persist to localStorage

Focus on clean code and best practices."
*/

// "Let me start by outlining my approach..."

interface Todo {
    id: string;
    text: string;
    completed: boolean;
    createdAt: Date;
}

type FilterStatus = 'all' | 'active' | 'completed';

// "First, I'll create a custom hook for localStorage persistence..."
function useLocalStorage<T>(key: string, initialValue: T): [T, (value: T | ((prev: T) => T)) => void] {
    const [storedValue, setStoredValue] = useState<T>(() => {
        if (typeof window === 'undefined') {
            return initialValue;
        }

        try {
            const item = window.localStorage.getItem(key);
            return item ? JSON.parse(item) : initialValue;
        } catch (error) {
            console.error('Error reading from localStorage:', error);
            return initialValue;
        }
    });

    const setValue = useCallback((value: T | ((prev: T) => T)) => {
        try {
            setStoredValue(prev => {
                const valueToStore = value instanceof Function ? value(prev) : value;
                window.localStorage.setItem(key, JSON.stringify(valueToStore));
                return valueToStore;
            });
        } catch (error) {
            console.error('Error writing to localStorage:', error);
        }
    }, [key]);

    return [storedValue, setValue];
}

// "Now the main TodoList component..."
function TodoList() {
    const [todos, setTodos] = useLocalStorage<Todo[]>('todos', []);
    const [filter, setFilter] = useState<FilterStatus>('all');
    const [inputValue, setInputValue] = useState('');
    const inputRef = useRef<HTMLInputElement>(null);

    // "Generate unique ID..."
    const generateId = () => `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

    // "Add todo handler..."
    const handleAddTodo = useCallback((e: React.FormEvent) => {
        e.preventDefault();

        const text = inputValue.trim();
        if (!text) return;

        const newTodo: Todo = {
            id: generateId(),
            text,
            completed: false,
            createdAt: new Date()
        };

        setTodos(prev => [newTodo, ...prev]);
        setInputValue('');
        inputRef.current?.focus();
    }, [inputValue, setTodos]);

    // "Toggle completion..."
    const handleToggle = useCallback((id: string) => {
        setTodos(prev => prev.map(todo =>
            todo.id === id ? { ...todo, completed: !todo.completed } : todo
        ));
    }, [setTodos]);

    // "Delete todo..."
    const handleDelete = useCallback((id: string) => {
        setTodos(prev => prev.filter(todo => todo.id !== id));
    }, [setTodos]);

    // "Filter todos..."
    const filteredTodos = useMemo(() => {
        switch (filter) {
            case 'active':
                return todos.filter(todo => !todo.completed);
            case 'completed':
                return todos.filter(todo => todo.completed);
            default:
                return todos;
        }
    }, [todos, filter]);

    // "Count stats..."
    const stats = useMemo(() => ({
        total: todos.length,
        active: todos.filter(t => !t.completed).length,
        completed: todos.filter(t => t.completed).length
    }), [todos]);

    return (
        <div className="todo-list">
            <h1>Todo List</h1>

            {/* Add Todo Form */}
            <form onSubmit={handleAddTodo} className="add-todo-form">
                <input
                    ref={inputRef}
                    type="text"
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    placeholder="What needs to be done?"
                    aria-label="New todo"
                />
                <button type="submit" disabled={!inputValue.trim()}>
                    Add
                </button>
            </form>

            {/* Filter Tabs */}
            <div className="filter-tabs" role="tablist">
                {(['all', 'active', 'completed'] as FilterStatus[]).map(status => (
                    <button
                        key={status}
                        role="tab"
                        aria-selected={filter === status}
                        onClick={() => setFilter(status)}
                        className={filter === status ? 'active' : ''}
                    >
                        {status.charAt(0).toUpperCase() + status.slice(1)}
                        <span className="count">
                            ({status === 'all' ? stats.total :
                              status === 'active' ? stats.active : stats.completed})
                        </span>
                    </button>
                ))}
            </div>

            {/* Todo Items */}
            <ul className="todo-items" role="list">
                {filteredTodos.length === 0 ? (
                    <li className="empty-state">
                        {filter === 'all'
                            ? 'No todos yet. Add one above!'
                            : `No ${filter} todos.`}
                    </li>
                ) : (
                    filteredTodos.map(todo => (
                        <TodoItem
                            key={todo.id}
                            todo={todo}
                            onToggle={handleToggle}
                            onDelete={handleDelete}
                        />
                    ))
                )}
            </ul>

            {/* Stats Footer */}
            {todos.length > 0 && (
                <footer className="todo-footer">
                    <span>{stats.active} item{stats.active !== 1 ? 's' : ''} left</span>
                    {stats.completed > 0 && (
                        <button
                            onClick={() => setTodos(prev => prev.filter(t => !t.completed))}
                            className="clear-completed"
                        >
                            Clear completed ({stats.completed})
                        </button>
                    )}
                </footer>
            )}
        </div>
    );
}

// "Separate TodoItem for better performance with React.memo..."
interface TodoItemProps {
    todo: Todo;
    onToggle: (id: string) => void;
    onDelete: (id: string) => void;
}

const TodoItem = memo(function TodoItem({ todo, onToggle, onDelete }: TodoItemProps) {
    return (
        <li className={`todo-item ${todo.completed ? 'completed' : ''}`}>
            <label className="todo-label">
                <input
                    type="checkbox"
                    checked={todo.completed}
                    onChange={() => onToggle(todo.id)}
                    aria-label={`Mark "${todo.text}" as ${todo.completed ? 'incomplete' : 'complete'}`}
                />
                <span className="todo-text">{todo.text}</span>
            </label>
            <button
                onClick={() => onDelete(todo.id)}
                className="delete-btn"
                aria-label={`Delete "${todo.text}"`}
            >
                ×
            </button>
        </li>
    );
});

export default TodoList;
