### **🎯 8.1 JavaScript Cheat Sheet**

```
// ═══════════════════════════════════════════════════════════
// JAVASCRIPT QUICK REFERENCE
// ═══════════════════════════════════════════════════════════

/*
╔═══════════════════════════════════════════════════════════════╗
║                 ARRAY METHODS QUICK REFERENCE                 ║
╠═══════════════════════════════════════════════════════════════╣
║                                                               ║
║  TRANSFORM:                                                   ║
║  map(fn)       → New array with fn applied to each element   ║
║  filter(fn)    → New array with elements where fn is true    ║
║  reduce(fn, i) → Single value by applying fn cumulatively    ║
║  flatMap(fn)   → Map then flatten one level                  ║
║                                                               ║
║  SEARCH:                                                      ║
║  find(fn)      → First element where fn is true              ║
║  findIndex(fn) → Index of first element where fn is true     ║
║  includes(v)   → Boolean if array contains v                 ║
║  indexOf(v)    → Index of v, or -1                          ║
║                                                               ║
║  TEST:                                                        ║
║  every(fn)     → True if fn is true for ALL elements        ║
║  some(fn)      → True if fn is true for ANY element         ║
║                                                               ║
║  MUTATE:                                                      ║
║  push/pop      → Add/remove from end                         ║
║  shift/unshift → Remove/add from beginning                   ║
║  splice(i,n,x) → Remove n at i, insert x                     ║
║  sort(fn)      → Sort in place                               ║
║  reverse()     → Reverse in place                            ║
║                                                               ║
╚═══════════════════════════════════════════════════════════════╝
*/

// Common patterns
const arrayPatterns = {
    // Remove duplicates
    unique: (arr: any[]) => [...new Set(arr)],

    // Group by property
    groupBy: <T>(arr: T[], key: keyof T) =>
        arr.reduce((acc, item) => {
            const group = String(item[key]);
            acc[group] = acc[group] || [];
            acc[group].push(item);
            return acc;
        }, {} as Record<string, T[]>),

    // Chunk array
    chunk: <T>(arr: T[], size: number): T[][] =>
        Array.from({ length: Math.ceil(arr.length / size) }, (_, i) =>
            arr.slice(i * size, (i + 1) * size)
        ),

    // Flatten deeply
    flatten: <T>(arr: any[]): T[] =>
        arr.reduce((acc, val) =>
            Array.isArray(val) ? acc.concat(flatten(val)) : acc.concat(val), []
        ),

    // Shuffle
    shuffle: <T>(arr: T[]): T[] =>
        [...arr].sort(() => Math.random() - 0.5),

    // Sum
    sum: (arr: number[]) => arr.reduce((a, b) => a + b, 0),

    // Average
    average: (arr: number[]) => arr.reduce((a, b) => a + b, 0) / arr.length,

    // Max/Min
    max: (arr: number[]) => Math.max(...arr),
    min: (arr: number[]) => Math.min(...arr),

    // Count occurrences
    countBy: <T>(arr: T[], fn: (item: T) => string) =>
        arr.reduce((acc, item) => {
            const key = fn(item);
            acc[key] = (acc[key] || 0) + 1;
            return acc;
        }, {} as Record<string, number>)
};

/*
╔═══════════════════════════════════════════════════════════════╗
║               OBJECT METHODS QUICK REFERENCE                  ║
╠═══════════════════════════════════════════════════════════════╣
║                                                               ║
║  Object.keys(obj)      → Array of keys                        ║
║  Object.values(obj)    → Array of values                      ║
║  Object.entries(obj)   → Array of [key, value] pairs          ║
║  Object.fromEntries()  → Object from [key, value] pairs       ║
║  Object.assign(t, s)   → Copy s properties to t               ║
║  Object.freeze(obj)    → Make immutable (shallow)             ║
║  Object.seal(obj)      → Prevent add/delete (can modify)      ║
║  { ...obj }            → Shallow clone                        ║
║                                                               ║
╚═══════════════════════════════════════════════════════════════╝
*/

const objectPatterns = {
    // Pick specific keys
    pick: <T extends object, K extends keyof T>(obj: T, keys: K[]): Pick<T, K> =>
        keys.reduce((acc, key) => {
            if (key in obj) acc[key] = obj[key];
            return acc;
        }, {} as Pick<T, K>),

    // Omit specific keys
    omit: <T extends object, K extends keyof T>(obj: T, keys: K[]): Omit<T, K> => {
        const result = { ...obj };
        keys.forEach(key => delete result[key]);
        return result as Omit<T, K>;
    },

    // Deep merge
    deepMerge: <T extends object>(target: T, source: Partial<T>): T => {
        const result = { ...target };
        for (const key of Object.keys(source) as (keyof T)[]) {
            const sourceValue = source[key];
            const targetValue = target[key];

            if (isObject(sourceValue) && isObject(targetValue)) {
                (result as any)[key] = deepMerge(targetValue, sourceValue);
            } else if (sourceValue !== undefined) {
                (result as any)[key] = sourceValue;
            }
        }
        return result;
    },

    // Check if object is empty
    isEmpty: (obj: object) => Object.keys(obj).length === 0,

    // Map object values
    mapValues: <T, U>(obj: Record<string, T>, fn: (v: T) => U): Record<string, U> =>
        Object.fromEntries(
            Object.entries(obj).map(([k, v]) => [k, fn(v)])
        )
};

function isObject(item: any): item is object {
    return item && typeof item === 'object' && !Array.isArray(item);
}

```

### 🎯 8.2 React Hooks Cheat Sheet

```
// ═══════════════════════════════════════════════════════════
// REACT HOOKS QUICK REFERENCE
// ═══════════════════════════════════════════════════════════

/*
╔═══════════════════════════════════════════════════════════════╗
║                    HOOKS QUICK REFERENCE                      ║
╠═══════════════════════════════════════════════════════════════╣
║                                                               ║
║  STATE HOOKS:                                                 ║
║  useState       → Local component state                       ║
║  useReducer     → Complex state with actions                  ║
║                                                               ║
║  EFFECT HOOKS:                                                ║
║  useEffect      → Side effects (API calls, subscriptions)     ║
║  useLayoutEffect→ Before browser paint (DOM measurements)     ║
║  useInsertionEffect → Before DOM mutations (CSS-in-JS)       ║
║                                                               ║
║  PERFORMANCE HOOKS:                                           ║
║  useMemo        → Memoize computed values                     ║
║  useCallback    → Memoize functions                           ║
║  useTransition  → Non-urgent state updates                    ║
║  useDeferredValue → Defer updating a value                    ║
║                                                               ║
║  REF HOOKS:                                                   ║
║  useRef         → Mutable ref, persists across renders        ║
║  useImperativeHandle → Customize ref exposed to parent       ║
║                                                               ║
║  CONTEXT HOOKS:                                               ║
║  useContext     → Subscribe to context                        ║
║                                                               ║
║  OTHER HOOKS:                                                 ║
║  useId          → Generate unique IDs                         ║
║  useSyncExternalStore → Subscribe to external store          ║
║  useDebugValue  → Label for React DevTools                   ║
║                                                               ║
╚═══════════════════════════════════════════════════════════════╝
*/

// ═══════════════════════════════════════════════════════════
// COMMON CUSTOM HOOKS
// ═══════════════════════════════════════════════════════════

// useToggle
function useToggle(initialValue = false) {
    const [value, setValue] = useState(initialValue);
    const toggle = useCallback(() => setValue(v => !v), []);
    const setTrue = useCallback(() => setValue(true), []);
    const setFalse = useCallback(() => setValue(false), []);
    return { value, toggle, setTrue, setFalse };
}

// usePrevious
function usePrevious<T>(value: T): T | undefined {
    const ref = useRef<T>();
    useEffect(() => { ref.current = value; }, [value]);
    return ref.current;
}

// useDebounce
function useDebounce<T>(value: T, delay: number): T {
    const [debounced, setDebounced] = useState(value);
    useEffect(() => {
        const timer = setTimeout(() => setDebounced(value), delay);
        return () => clearTimeout(timer);
    }, [value, delay]);
    return debounced;
}

// useLocalStorage
function useLocalStorage<T>(key: string, initial: T) {
    const [value, setValue] = useState<T>(() => {
        try {
            const stored = localStorage.getItem(key);
            return stored ? JSON.parse(stored) : initial;
        } catch { return initial; }
    });

    useEffect(() => {
        localStorage.setItem(key, JSON.stringify(value));
    }, [key, value]);

    return [value, setValue] as const;
}

// useMediaQuery
function useMediaQuery(query: string): boolean {
    const [matches, setMatches] = useState(() =>
        typeof window !== 'undefined'
            ? window.matchMedia(query).matches
            : false
    );

    useEffect(() => {
        const mq = window.matchMedia(query);
        const handler = (e: MediaQueryListEvent) => setMatches(e.matches);
        mq.addEventListener('change', handler);
        return () => mq.removeEventListener('change', handler);
    }, [query]);

    return matches;
}

// useOnClickOutside
function useOnClickOutside(
    ref: RefObject<HTMLElement>,
    handler: (event: MouseEvent | TouchEvent) => void
) {
    useEffect(() => {
        const listener = (event: MouseEvent | TouchEvent) => {
            if (!ref.current || ref.current.contains(event.target as Node)) {
                return;
            }
            handler(event);
        };

        document.addEventListener('mousedown', listener);
        document.addEventListener('touchstart', listener);

        return () => {
            document.removeEventListener('mousedown', listener);
            document.removeEventListener('touchstart', listener);
        };
    }, [ref, handler]);
}

// useIntersectionObserver
function useIntersectionObserver(
    ref: RefObject<HTMLElement>,
    options: IntersectionObserverInit = {}
): boolean {
    const [isIntersecting, setIsIntersecting] = useState(false);

    useEffect(() => {
        const element = ref.current;
        if (!element) return;

        const observer = new IntersectionObserver(([entry]) => {
            setIsIntersecting(entry.isIntersecting);
        }, options);

        observer.observe(element);
        return () => observer.disconnect();
    }, [ref, options.threshold, options.root, options.rootMargin]);

    return isIntersecting;
}

// useAsync
function useAsync<T>(
    asyncFn: () => Promise<T>,
    deps: any[] = []
) {
    const [state, setState] = useState<{
        data: T | null;
        loading: boolean;
        error: Error | null;
    }>({ data: null, loading: true, error: null });

    useEffect(() => {
        let mounted = true;

        setState(s => ({ ...s, loading: true }));

        asyncFn()
            .then(data => mounted && setState({ data, loading: false, error: null }))
            .catch(error => mounted && setState({ data: null, loading: false, error }));

        return () => { mounted = false; };
    }, deps);

    return state;
}
```

### **🎯 8.3 TypeScript Cheat Sheet**

```
// ═══════════════════════════════════════════════════════════
// TYPESCRIPT QUICK REFERENCE
// ═══════════════════════════════════════════════════════════

/*
╔═══════════════════════════════════════════════════════════════╗
║                  UTILITY TYPES                                ║
╠═══════════════════════════════════════════════════════════════╣
║                                                               ║
║  Partial<T>      → All properties optional                    ║
║  Required<T>     → All properties required                    ║
║  Readonly<T>     → All properties readonly                    ║
║  Pick<T, K>      → Only properties K from T                   ║
║  Omit<T, K>      → All properties except K                    ║
║  Record<K, V>    → Object with keys K and values V            ║
║  Exclude<T, U>   → Types in T not in U                        ║
║  Extract<T, U>   → Types in T that are in U                   ║
║  NonNullable<T>  → Remove null and undefined                  ║
║  ReturnType<T>   → Return type of function T                  ║
║  Parameters<T>   → Parameters of function T as tuple          ║
║  InstanceType<T> → Instance type of constructor T             ║
║  Awaited<T>      → Unwrap Promise type                        ║
║                                                               ║
╚═══════════════════════════════════════════════════════════════╝
*/

// Common TypeScript patterns

// 1. Type Guards
function isString(value: unknown): value is string {
    return typeof value === 'string';
}

function isUser(obj: unknown): obj is User {
    return (
        typeof obj === 'object' &&
        obj !== null &&
        'id' in obj &&
        'name' in obj
    );
}

// 2. Discriminated Unions
type Result<T> =
    | { success: true; data: T }
    | { success: false; error: string };

function handleResult<T>(result: Result<T>) {
    if (result.success) {
        console.log(result.data); // TypeScript knows this is T
    } else {
        console.log(result.error); // TypeScript knows this is string
    }
}

// 3. Mapped Types
type Nullable<T> = { [K in keyof T]: T[K] | null };
type Optional<T> = { [K in keyof T]?: T[K] };
type ReadonlyDeep<T> = { readonly [K in keyof T]: ReadonlyDeep<T[K]> };

// 4. Conditional Types
type ArrayElement<T> = T extends (infer E)[] ? E : never;
type Flatten<T> = T extends any[] ? T[number] : T;
type UnwrapPromise<T> = T extends Promise<infer U> ? U : T;

// 5. Template Literal Types
type EventName = 'click' | 'focus' | 'blur';
type EventHandler = `on${Capitalize<EventName>}`; // 'onClick' | 'onFocus' | 'onBlur'

type HTTPMethod = 'GET' | 'POST' | 'PUT' | 'DELETE';
type Endpoint = `/${string}`;
type Route = `${HTTPMethod} ${Endpoint}`; // 'GET /users', 'POST /login', etc.

// 6. Generic Constraints
function getProperty<T, K extends keyof T>(obj: T, key: K): T[K] {
    return obj[key];
}

function merge<T extends object, U extends object>(a: T, b: U): T & U {
    return { ...a, ...b };
}

// 7. Function Overloads
function parse(value: string): object;
function parse(value: string, reviver: (key: string, value: any) => any): object;
function parse(value: string, reviver?: (key: string, value: any) => any): object {
    return reviver ? JSON.parse(value, reviver) : JSON.parse(value);
}

// 8. Const Assertions
const config = {
    api: 'https://api.example.com',
    version: 1
} as const;
// Type: { readonly api: "https://api.example.com"; readonly version: 1 }

const colors = ['red', 'green', 'blue'] as const;
type Color = typeof colors[number]; // 'red' | 'green' | 'blue'

// 9. Assertion Functions
function assertDefined<T>(value: T | null | undefined): asserts value is T {
    if (value === null || value === undefined) {
        throw new Error('Value is not defined');
    }
}

// 10. Branded Types
type UserId = string & { readonly brand: unique symbol };
type OrderId = string & { readonly brand: unique symbol };

function createUserId(id: string): UserId {
    return id as UserId;
}

// Can't accidentally pass OrderId where UserId is expected
